window.EXERCISES = [{"id":"0001","name":"3/4 sit-up","category":"waist","equipment":"body weight","target":"abs","secondary":["hip flexors","lower back"],"steps":{"en":["Lie flat on your back with your knees bent and feet flat on the ground.","Place your hands behind your head with your elbows pointing outwards.","Engaging your abs, slowly lift your upper body off the ground, curling forward until your torso is at a 45-degree angle.","Pause for a moment at the top, then slowly lower your upper body back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Sdraiati sulla schiena con le ginocchia piegate e i piedi appoggiati a terra.","Metti le mani dietro la testa con i gomiti rivolti verso l'esterno.","Coinvolgendo gli addominali, solleva lentamente la parte superiore del corpo da terra, piegandoti in avanti finché il busto non forma un angolo di 45 gradi.","Fermati per un momento in alto, quindi abbassa lentamente la parte superiore del corpo fino alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0002","name":"45° side bend","category":"waist","equipment":"body weight","target":"abs","secondary":["obliques"],"steps":{"en":["Stand with your feet shoulder-width apart and your arms extended straight down by your sides.","Keeping your back straight and your core engaged, slowly bend your torso to one side, lowering your hand towards your knee.","Pause for a moment at the bottom, then slowly return to the starting position.","Repeat on the other side.","Continue alternating sides for the desired number of repetitions."],"it":["Stai con i piedi alla larghezza delle spalle e le braccia distese lungo i fianchi.","Mantenendo la schiena dritta e il core impegnato, piega lentamente il busto da un lato, abbassando la mano verso il ginocchio.","Fermati per un momento in basso, quindi torna lentamente alla posizione di partenza.","Ripeti dall'altra parte.","Continua ad alternare i lati per il numero di ripetizioni desiderato."]}},{"id":"0003","name":"air bike","category":"waist","equipment":"body weight","target":"abs","secondary":["hip flexors"],"steps":{"en":["Lie flat on your back with your hands placed behind your head.","Lift your legs off the ground and bend your knees at a 90-degree angle.","Bring your right elbow towards your left knee while simultaneously straightening your right leg.","Return to the starting position and repeat the movement on the opposite side, bringing your left elbow towards your right knee while straightening your left leg.","Continue alternating sides in a pedaling motion for the desired number of repetitions."],"it":["Sdraiati sulla schiena con le mani dietro la testa.","Solleva le gambe da terra e piega le ginocchia con un angolo di 90 gradi.","Porta il gomito destro verso il ginocchio sinistro mentre contemporaneamente raddrizzi la gamba destra.","Ritorna alla posizione di partenza e ripeti il ​​movimento dal lato opposto, portando il gomito sinistro verso il ginocchio destro mentre raddrizzi la gamba sinistra.","Continua ad alternare i lati con un movimento di pedalata per il numero di ripetizioni desiderato."]}},{"id":"1512","name":"all fours squad stretch","category":"upper legs","equipment":"body weight","target":"quads","secondary":["hamstrings","glutes"],"steps":{"en":["Start on all fours with your hands directly under your shoulders and your knees directly under your hips.","Extend one leg straight back, keeping your knee bent and your foot flexed.","Slowly lower your hips towards the ground, feeling a stretch in your quads.","Hold this position for 20-30 seconds.","Switch legs and repeat the stretch on the other side."],"it":["Inizia a quattro zampe con le mani direttamente sotto le spalle e le ginocchia direttamente sotto i fianchi.","Estendi una gamba all'indietro, mantenendo il ginocchio piegato e il piede flesso.","Abbassa lentamente i fianchi verso terra, avvertendo l'allungamento dei quadricipiti.","Mantieni questa posizione per 20-30 secondi.","Cambia gamba e ripeti l'allungamento sull'altro lato."]}},{"id":"0006","name":"alternate heel touchers","category":"waist","equipment":"body weight","target":"abs","secondary":["obliques"],"steps":{"en":["Lie flat on your back with your knees bent and feet flat on the ground.","Extend your arms straight out to the sides, parallel to the ground.","Engaging your abs, lift your shoulders off the ground and reach your right hand towards your right heel.","Return to the starting position and repeat on the left side, reaching your left hand towards your left heel.","Continue alternating sides for the desired number of repetitions."],"it":["Sdraiati sulla schiena con le ginocchia piegate e i piedi appoggiati a terra.","Estendi le braccia verso i lati, parallele al suolo.","Coinvolgendo gli addominali, solleva le spalle da terra e allunga la mano destra verso il tallone destro.","Ritorna alla posizione iniziale e ripeti sul lato sinistro, portando la mano sinistra verso il tallone sinistro.","Continua ad alternare i lati per il numero di ripetizioni desiderato."]}},{"id":"1368","name":"ankle circles","category":"lower legs","equipment":"body weight","target":"calves","secondary":["ankle stabilizers"],"steps":{"en":["Sit on the ground with your legs extended in front of you.","Lift one leg off the ground and rotate your ankle in a circular motion.","Perform the desired number of circles in one direction, then switch to the other direction.","Repeat with the other leg."],"it":["Siediti a terra con le gambe distese davanti a te.","Solleva una gamba da terra e ruota la caviglia con un movimento circolare.","Esegui il numero desiderato di cerchi in una direzione, quindi passa all'altra direzione.","Ripeti con l'altra gamba."]}},{"id":"3293","name":"archer pull up","category":"back","equipment":"body weight","target":"lats","secondary":["biceps","forearms"],"steps":{"en":["Start by hanging from a pull-up bar with an overhand grip, slightly wider than shoulder-width apart.","Engage your core and pull your shoulder blades down and back.","As you pull yourself up, bend one arm and bring your elbow towards your side, while keeping the other arm straight.","Continue pulling until your chin is above the bar and your bent arm is fully flexed.","Lower yourself back down with control, straightening the bent arm and repeating the movement on the other side.","Alternate sides with each repetition."],"it":["Inizia appendendoti a una barra per trazioni con una presa prona, leggermente più larga della larghezza delle spalle.","Coinvolgi il tuo core e tira le scapole verso il basso e all'indietro.","Mentre ti tiri su, piega un braccio e porta il gomito verso il fianco, mantenendo l'altro braccio dritto.","Continua a tirare finché il mento non è sopra la barra e il braccio piegato è completamente flesso.","Abbassati di nuovo con controllo, raddrizzando il braccio piegato e ripetendo il movimento dall'altro lato.","Lati alternativi ad ogni ripetizione."]}},{"id":"3294","name":"archer push up","category":"chest","equipment":"body weight","target":"pectorals","secondary":["triceps","shoulders","core"],"steps":{"en":["Start in a push-up position with your hands slightly wider than shoulder-width apart.","Extend one arm straight out to the side, parallel to the ground.","Lower your body by bending your elbows, keeping your back straight and core engaged.","Push back up to the starting position.","Repeat on the other side, extending the opposite arm out to the side.","Continue alternating sides for the desired number of repetitions."],"it":["Inizia in una posizione push-up con le mani leggermente più larghe della larghezza delle spalle.","Estendi un braccio di lato, parallelo al suolo.","Abbassa il corpo piegando i gomiti, mantenendo la schiena dritta e il core impegnato.","Spingi indietro fino alla posizione di partenza.","Ripeti dall'altro lato, estendendo il braccio opposto lateralmente.","Continua ad alternare i lati per il numero di ripetizioni desiderato."]}},{"id":"2355","name":"arm slingers hanging bent knee legs","category":"waist","equipment":"body weight","target":"abs","secondary":["shoulders","back"],"steps":{"en":["Hang from a pull-up bar with your arms fully extended and your knees bent at a 90-degree angle.","Engage your core and lift your knees towards your chest, bringing them as close to your elbows as possible.","Slowly lower your legs back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Appendere a una barra per trazioni con le braccia completamente distese e le ginocchia piegate con un angolo di 90 gradi.","Coinvolgi il tuo core e solleva le ginocchia verso il petto, portandole il più vicino possibile ai gomiti.","Abbassa lentamente le gambe fino alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"2333","name":"arm slingers hanging straight legs","category":"waist","equipment":"body weight","target":"abs","secondary":["shoulders","back"],"steps":{"en":["Hang from a pull-up bar with your arms fully extended and your legs straight down.","Engage your core and lift your legs up in front of you until they are parallel to the ground.","Hold for a moment at the top, then slowly lower your legs back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Appenditi a una barra per trazioni con le braccia completamente distese e le gambe dritte verso il basso.","Coinvolgi il tuo core e solleva le gambe davanti a te finché non sono parallele al suolo.","Mantieni la posizione in alto per un momento, quindi abbassa lentamente le gambe fino alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"3214","name":"arms apart circular toe touch (male)","category":"upper legs","equipment":"body weight","target":"glutes","secondary":["hamstrings","quadriceps","calves"],"steps":{"en":["Stand with your feet shoulder-width apart and arms extended to the sides.","Keeping your legs straight, bend forward at the waist and reach down towards your toes with your right hand.","As you reach down, simultaneously lift your left leg straight up behind you, maintaining balance.","Return to the starting position and repeat the movement with your left hand reaching towards your toes and your right leg lifting up behind you.","Continue alternating sides for the desired number of repetitions."],"it":["Stare con i piedi alla larghezza delle spalle e le braccia distese ai lati.","Tenendo le gambe dritte, piegati in avanti all'altezza della vita e allunga la mano destra verso le punte dei piedi.","Mentre ti abbassi, solleva contemporaneamente la gamba sinistra dietro di te, mantenendo l'equilibrio.","Ritorna alla posizione di partenza e ripeti il ​​movimento con la mano sinistra protesa verso le dita dei piedi e la gamba destra sollevata dietro di te.","Continua ad alternare i lati per il numero di ripetizioni desiderato."]}},{"id":"3204","name":"arms overhead full sit-up (male)","category":"waist","equipment":"body weight","target":"abs","secondary":["hip flexors","lower back"],"steps":{"en":["Lie flat on your back with your knees bent and feet flat on the ground.","Extend your arms overhead, keeping them straight.","Engaging your abs, slowly lift your upper body off the ground, curling forward until your torso is upright.","Pause for a moment at the top, then slowly lower your upper body back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Sdraiati sulla schiena con le ginocchia piegate e i piedi appoggiati a terra.","Estendi le braccia sopra la testa, mantenendole dritte.","Coinvolgendo gli addominali, solleva lentamente la parte superiore del corpo da terra, piegandoti in avanti finché il busto non è in posizione verticale.","Fermati per un momento in alto, quindi abbassa lentamente la parte superiore del corpo fino alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"3220","name":"astride jumps (male)","category":"cardio","equipment":"body weight","target":"cardiovascular system","secondary":["quadriceps","hamstrings","calves"],"steps":{"en":["Stand with your feet shoulder-width apart.","Bend your knees and lower your body into a squat position.","Jump explosively upwards, extending your legs and arms.","While in the air, spread your legs apart and bring your arms out to the sides.","Land softly with your feet shoulder-width apart, bending your knees to absorb the impact.","Repeat for the desired number of repetitions."],"it":["Stai con i piedi alla larghezza delle spalle.","Piega le ginocchia e abbassa il corpo in una posizione tozza.","Salta in modo esplosivo verso l'alto, estendendo le gambe e le braccia.","Mentre sei in aria, allarga le gambe e porta le braccia ai lati.","Atterra dolcemente con i piedi alla larghezza delle spalle, piegando le ginocchia per assorbire l'impatto.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"3672","name":"back and forth step","category":"cardio","equipment":"body weight","target":"cardiovascular system","secondary":["quadriceps","hamstrings","glutes","calves"],"steps":{"en":["Stand with your feet shoulder-width apart.","Step forward with your right foot, bending your knee and lowering your body into a lunge position.","Push off with your right foot and step back to the starting position.","Repeat the movement with your left foot, alternating legs with each step.","Continue stepping back and forth, maintaining a steady pace.","Repeat for the desired duration or number of repetitions."],"it":["Stai con i piedi alla larghezza delle spalle.","Fai un passo avanti con il piede destro, piegando il ginocchio e abbassando il corpo in una posizione di affondo.","Spingi con il piede destro e torna alla posizione di partenza.","Ripeti il ​​movimento con il piede sinistro, alternando le gambe ad ogni passo.","Continua a fare passi avanti e indietro, mantenendo un ritmo costante.","Ripetere per la durata o il numero di ripetizioni desiderato."]}},{"id":"1314","name":"back extension on exercise ball","category":"back","equipment":"stability ball","target":"spine","secondary":["glutes","hamstrings"],"steps":{"en":["Place the stability ball on the ground and lie face down on top of it, with your hips resting on the ball and your feet against a wall or other stable surface.","Position your hands behind your head or crossed over your chest.","Engage your core and slowly lift your upper body off the ball, extending your back until your body forms a straight line from your head to your heels.","Pause for a moment at the top, then slowly lower your upper body back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Posiziona la palla di stabilità a terra e sdraiati a faccia in giù sopra di essa, con i fianchi appoggiati sulla palla e i piedi contro un muro o un'altra superficie stabile.","Posiziona le mani dietro la testa o incrociate sul petto.","Coinvolgi il core e solleva lentamente la parte superiore del corpo dalla palla, estendendo la schiena finché il corpo non forma una linea retta dalla testa ai talloni.","Fermati per un momento in alto, quindi abbassa lentamente la parte superiore del corpo fino alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"3297","name":"back lever","category":"back","equipment":"body weight","target":"upper back","secondary":["biceps","forearms","core"],"steps":{"en":["Start by hanging from a pull-up bar with an overhand grip, hands slightly wider than shoulder-width apart.","Engage your core and pull your shoulder blades down and back.","Bend your knees and tuck them towards your chest.","Slowly lift your legs up, keeping them straight, until your body is parallel to the ground.","Hold this position for a few seconds, then slowly lower your legs back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Inizia appendendoti a una barra per trazioni con una presa prona, con le mani leggermente più larghe della larghezza delle spalle.","Coinvolgi il tuo core e tira le scapole verso il basso e all'indietro.","Piega le ginocchia e portale verso il petto.","Solleva lentamente le gambe, mantenendole dritte, finché il tuo corpo non è parallelo al suolo.","Mantieni questa posizione per alcuni secondi, quindi abbassa lentamente le gambe fino alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"1405","name":"back pec stretch","category":"back","equipment":"body weight","target":"lats","secondary":["shoulders","chest"],"steps":{"en":["Stand tall with your feet shoulder-width apart.","Extend your arms straight out in front of you, parallel to the ground.","Cross your arms in front of your body, with your right arm over your left arm.","Interlock your fingers and rotate your palms away from your body.","Slowly raise your arms up and away from your body, feeling a stretch in your back and chest.","Hold the stretch for 15-30 seconds, then release.","Repeat on the opposite side."],"it":["Stai in piedi con i piedi alla larghezza delle spalle.","Estendi le braccia davanti a te, parallele al suolo.","Incrocia le braccia davanti al corpo, con il braccio destro sopra il braccio sinistro.","Intreccia le dita e ruota i palmi delle mani lontano dal corpo.","Alza lentamente le braccia in alto e lontano dal corpo, avvertendo un allungamento nella schiena e nel petto.","Mantieni la posizione per 15-30 secondi, quindi rilascia.","Ripeti sul lato opposto."]}},{"id":"1473","name":"backward jump","category":"upper legs","equipment":"body weight","target":"quads","secondary":["hamstrings","glutes","calves"],"steps":{"en":["Stand with your feet shoulder-width apart.","Bend your knees slightly and jump backwards, pushing off with both feet.","Land softly on the balls of your feet, bending your knees to absorb the impact.","Repeat for the desired number of repetitions."],"it":["Stai con i piedi alla larghezza delle spalle.","Piega leggermente le ginocchia e salta all'indietro, spingendoti con entrambi i piedi.","Atterra dolcemente sulle punte dei piedi, piegando le ginocchia per assorbire l'impatto.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0020","name":"balance board","category":"upper legs","equipment":"body weight","target":"quads","secondary":["calves","hamstrings","glutes"],"steps":{"en":["Place the balance board on a flat surface.","Step onto the balance board with one foot, ensuring it is centered.","Slowly shift your weight onto the foot on the balance board, keeping your core engaged.","Maintain your balance and stability as you hold the position for a desired amount of time.","Repeat the exercise with the other foot."],"it":["Posizionare la tavola di equilibrio su una superficie piana.","Sali sulla tavola di equilibrio con un piede, assicurandoti che sia centrato.","Sposta lentamente il peso sul piede sulla bilancia, mantenendo il core impegnato.","Mantieni l'equilibrio e la stabilità mentre mantieni la posizione per il periodo di tempo desiderato.","Ripeti l'esercizio con l'altro piede."]}},{"id":"0023","name":"barbell alternate biceps curl","category":"upper arms","equipment":"barbell","target":"biceps","secondary":["forearms"],"steps":{"en":["Stand up straight with your feet shoulder-width apart and hold a barbell in each hand, palms facing forward.","Keep your upper arms stationary and exhale as you curl the weights while contracting your biceps.","Continue to raise the barbells until your biceps are fully contracted and the barbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale as you slowly begin to lower the barbells back to the starting position.","Repeat for the desired number of repetitions, alternating arms."],"it":["Stai dritto con i piedi alla larghezza delle spalle e tieni un bilanciere in ciascuna mano, con i palmi rivolti in avanti.","Mantieni ferma la parte superiore delle braccia ed espira mentre pieghi i pesi mentre contrai i bicipiti.","Continua a sollevare i bilancieri finché i bicipiti non saranno completamente contratti e i bilancieri saranno all'altezza delle spalle.","Mantieni la posizione contratta per una breve pausa mentre contrai i bicipiti.","Inspira mentre inizi lentamente ad abbassare i bilancieri nella posizione iniziale.","Ripeti per il numero di ripetizioni desiderato, alternando le braccia."]}},{"id":"0024","name":"barbell bench front squat","category":"upper legs","equipment":"barbell","target":"quads","secondary":["hamstrings","glutes","calves"],"steps":{"en":["Start by standing with your feet shoulder-width apart and the barbell resting on your upper chest, just below your collarbone.","Hold the barbell with an overhand grip, keeping your elbows up and your upper arms parallel to the ground.","Lower your body down into a squat position by bending at the knees and hips, keeping your back straight and your chest up.","Pause for a moment at the bottom of the squat, then push through your heels to return to the starting position.","Repeat for the desired number of repetitions."],"it":["Inizia stando in piedi con i piedi alla larghezza delle spalle e il bilanciere appoggiato sulla parte superiore del torace, appena sotto la clavicola.","Tieni il bilanciere con una presa prona, mantenendo i gomiti sollevati e la parte superiore delle braccia parallela al suolo.","Abbassa il corpo in una posizione tozza piegando le ginocchia e i fianchi, mantenendo la schiena dritta e il petto in alto.","Fai una pausa per un momento alla fine dello squat, quindi spingi i talloni per tornare alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0025","name":"barbell bench press","category":"chest","equipment":"barbell","target":"pectorals","secondary":["triceps","shoulders"],"steps":{"en":["Lie flat on a bench with your feet flat on the ground and your back pressed against the bench.","Grasp the barbell with an overhand grip slightly wider than shoulder-width apart.","Lift the barbell off the rack and hold it directly above your chest with your arms fully extended.","Lower the barbell slowly towards your chest, keeping your elbows tucked in.","Pause for a moment when the barbell touches your chest.","Push the barbell back up to the starting position by extending your arms.","Repeat for the desired number of repetitions."],"it":["Sdraiati su una panca con i piedi appoggiati a terra e la schiena premuta contro la panca.","Afferrare il bilanciere con una presa prona leggermente più larga della larghezza delle spalle.","Solleva il bilanciere dal rack e tienilo direttamente sopra il petto con le braccia completamente distese.","Abbassa lentamente il bilanciere verso il petto, mantenendo i gomiti piegati.","Fai una pausa per un momento quando il bilanciere tocca il tuo petto.","Spingi il bilanciere nella posizione iniziale estendendo le braccia.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0026","name":"barbell bench squat","category":"upper legs","equipment":"barbell","target":"quads","secondary":["glutes","hamstrings","calves"],"steps":{"en":["Set up a barbell on a squat rack at chest height.","Stand facing away from the rack, with your feet shoulder-width apart.","Bend your knees and lower your body down into a squat position, keeping your back straight and chest up.","Grasp the barbell with an overhand grip, slightly wider than shoulder-width apart.","Lift the barbell off the rack and step back, ensuring your feet are still shoulder-width apart.","Lower your body down into a squat, keeping your knees in line with your toes.","Pause for a moment at the bottom, then push through your heels to return to the starting position.","Repeat for the desired number of repetitions."],"it":["Posiziona un bilanciere su uno squat rack all'altezza del petto.","Stai di fronte al rack, con i piedi alla larghezza delle spalle.","Piega le ginocchia e abbassa il corpo in posizione tozza, mantenendo la schiena dritta e il petto in alto.","Afferrare il bilanciere con una presa prona, leggermente più larga della larghezza delle spalle.","Solleva il bilanciere dal rack e fai un passo indietro, assicurandoti che i piedi siano ancora alla larghezza delle spalle.","Abbassa il corpo in uno squat, mantenendo le ginocchia in linea con le dita dei piedi.","Fai una pausa per un momento in fondo, quindi spingi i talloni per tornare alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"1316","name":"barbell bent arm pullover","category":"back","equipment":"barbell","target":"lats","secondary":["triceps","chest"],"steps":{"en":["Lie flat on a bench with your head at one end and your feet on the floor.","Hold a barbell with a shoulder-width grip and extend your arms straight above your chest.","Lower the barbell behind your head while keeping your arms slightly bent.","Pause for a moment, then raise the barbell back to the starting position.","Repeat for the desired number of repetitions."],"it":["Sdraiati su una panca con la testa da un lato e i piedi sul pavimento.","Tieni un bilanciere con una presa alla larghezza delle spalle ed estendi le braccia direttamente sopra il petto.","Abbassa il bilanciere dietro la testa mantenendo le braccia leggermente piegate.","Fare una pausa per un momento, quindi riportare il bilanciere nella posizione iniziale.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0027","name":"barbell bent over row","category":"back","equipment":"barbell","target":"upper back","secondary":["biceps","forearms"],"steps":{"en":["Stand with your feet shoulder-width apart and knees slightly bent.","Bend forward at the hips while keeping your back straight and chest up.","Grasp the barbell with an overhand grip, hands slightly wider than shoulder-width apart.","Pull the barbell towards your lower chest by retracting your shoulder blades and squeezing your back muscles.","Pause for a moment at the top, then slowly lower the barbell back to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai in piedi con i piedi alla larghezza delle spalle e le ginocchia leggermente piegate.","Piegati in avanti sui fianchi mantenendo la schiena dritta e il petto in alto.","Afferrare il bilanciere con una presa prona, con le mani leggermente più larghe della larghezza delle spalle.","Tirare il bilanciere verso la parte inferiore del torace ritraendo le scapole e contraendo i muscoli della schiena.","Fermati per un momento in alto, quindi abbassa lentamente il bilanciere nella posizione iniziale.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"2407","name":"barbell biceps curl (with arm blaster)","category":"upper arms","equipment":"barbell","target":"biceps","secondary":["forearms"],"steps":{"en":["Stand up straight with your feet shoulder-width apart and hold a barbell with an underhand grip, palms facing up.","Place your upper arms against the arm blaster, keeping your elbows close to your torso.","Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the barbell until your biceps are fully contracted and the bar is at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the barbell back to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai dritto con i piedi alla larghezza delle spalle e tieni un bilanciere con una presa subdola, con i palmi rivolti verso l'alto.","Posiziona la parte superiore delle braccia contro l'arm blaster, mantenendo i gomiti vicini al busto.","Mantenendo ferma la parte superiore delle braccia, espira e piega i pesi contraendo i bicipiti.","Continua a sollevare il bilanciere finché i bicipiti non sono completamente contratti e la barra è all'altezza delle spalle.","Mantieni la posizione contratta per una breve pausa mentre contrai i bicipiti.","Inspira e inizia lentamente ad abbassare il bilanciere nella posizione iniziale.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0028","name":"barbell clean and press","category":"upper legs","equipment":"barbell","target":"quads","secondary":["hamstrings","glutes","shoulders","triceps"],"steps":{"en":["Stand with your feet shoulder-width apart and the barbell on the floor in front of you.","Bend your knees and hinge at the hips to lower down and grip the barbell with an overhand grip, hands slightly wider than shoulder-width apart.","Drive through your heels and extend your hips and knees to lift the barbell off the floor, keeping it close to your body.","As the barbell reaches your thighs, explosively extend your hips, shrug your shoulders, and pull the barbell up towards your chest.","As the barbell reaches chest height, quickly drop under it and catch it at shoulder level, with your elbows pointing forward and your palms facing up.","From the catch position, press the barbell overhead by extending your arms and pushing the barbell straight up.","Lower the barbell back down to the starting position and repeat for the desired number of repetitions."],"it":["Stai con i piedi alla larghezza delle spalle e il bilanciere sul pavimento di fronte a te.","Piega le ginocchia e fai perno sui fianchi per abbassarti e afferrare il bilanciere con una presa prona, con le mani leggermente più larghe della larghezza delle spalle.","Guida attraverso i talloni ed estendi i fianchi e le ginocchia per sollevare il bilanciere dal pavimento, tenendolo vicino al corpo.","Quando il bilanciere raggiunge le cosce, estendi in modo esplosivo i fianchi, alza le spalle e tira il bilanciere verso il petto.","Quando il bilanciere raggiunge l'altezza del petto, abbassati rapidamente sotto di esso e afferralo all'altezza delle spalle, con i gomiti rivolti in avanti e i palmi rivolti verso l'alto.","Dalla posizione di presa, premi il bilanciere sopra la testa estendendo le braccia e spingendo il bilanciere verso l'alto.","Abbassare nuovamente il bilanciere nella posizione iniziale e ripetere per il numero di ripetizioni desiderato."]}},{"id":"0029","name":"barbell clean-grip front squat","category":"upper legs","equipment":"barbell","target":"glutes","secondary":["quadriceps","hamstrings","calves","core"],"steps":{"en":["Start by standing with your feet shoulder-width apart and the barbell resting on your upper chest, with your elbows pointing forward.","Lower your body by bending your knees and pushing your hips back, as if you are sitting back into a chair.","Keep your chest up and your back straight as you lower down, making sure your knees do not go past your toes.","Continue lowering until your thighs are parallel to the ground, or as low as you can comfortably go.","Pause for a moment at the bottom, then push through your heels to stand back up, extending your hips and knees.","Repeat for the desired number of repetitions."],"it":["Inizia stando in piedi con i piedi alla larghezza delle spalle e il bilanciere appoggiato sulla parte superiore del torace, con i gomiti rivolti in avanti.","Abbassa il corpo piegando le ginocchia e spingendo indietro i fianchi, come se fossi seduto su una sedia.","Tieni il petto in alto e la schiena dritta mentre ti abbassi, assicurandoti che le ginocchia non superino le dita dei piedi.","Continua ad abbassare finché le cosce non sono parallele al suolo o il più in basso possibile.","Fai una pausa per un momento in fondo, quindi spingi i talloni per rialzarti, estendendo i fianchi e le ginocchia.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0030","name":"barbell close-grip bench press","category":"upper arms","equipment":"barbell","target":"triceps","secondary":["chest","shoulders"],"steps":{"en":["Lie flat on a bench with your feet flat on the ground and your back pressed against the bench.","Grasp the barbell with a close grip, slightly narrower than shoulder-width apart.","Unrack the barbell and lower it slowly towards your chest, keeping your elbows close to your body.","Pause for a moment when the barbell touches your chest.","Push the barbell back up to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."],"it":["Sdraiati su una panca con i piedi appoggiati a terra e la schiena premuta contro la panca.","Afferrare il bilanciere con una presa stretta, leggermente più stretta della larghezza delle spalle.","Togli il bilanciere e abbassalo lentamente verso il petto, mantenendo i gomiti vicini al corpo.","Fai una pausa per un momento quando il bilanciere tocca il tuo petto.","Spingi nuovamente il bilanciere nella posizione iniziale, estendendo completamente le braccia.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0031","name":"barbell curl","category":"upper arms","equipment":"barbell","target":"biceps","secondary":["forearms"],"steps":{"en":["Stand up straight with your feet shoulder-width apart and hold a barbell with an underhand grip, palms facing forward.","Keep your elbows close to your torso and exhale as you curl the weights while contracting your biceps.","Continue to raise the bar until your biceps are fully contracted and the bar is at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale as you slowly begin to lower the bar back to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai dritto con i piedi alla larghezza delle spalle e tieni un bilanciere con una presa subdola, con i palmi rivolti in avanti.","Tieni i gomiti vicini al busto ed espira mentre pieghi i pesi mentre contrai i bicipiti.","Continua a sollevare la barra finché i bicipiti non sono completamente contratti e la barra è all'altezza delle spalle.","Mantieni la posizione contratta per una breve pausa mentre contrai i bicipiti.","Inspira mentre inizi lentamente ad abbassare la barra nella posizione iniziale.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0032","name":"barbell deadlift","category":"upper legs","equipment":"barbell","target":"glutes","secondary":["hamstrings","lower back"],"steps":{"en":["Stand with your feet shoulder-width apart and the barbell on the ground in front of you.","Bend your knees and hinge at the hips to lower your torso and grip the barbell with an overhand grip, hands slightly wider than shoulder-width apart.","Keep your back straight and chest lifted as you drive through your heels to lift the barbell off the ground, extending your hips and knees.","As you stand up straight, squeeze your glutes and keep your core engaged.","Lower the barbell back down to the ground by bending at the hips and knees, keeping your back straight.","Repeat for the desired number of repetitions."],"it":["Stai con i piedi alla larghezza delle spalle e il bilanciere a terra davanti a te.","Piega le ginocchia e fai perno sui fianchi per abbassare il busto e afferrare il bilanciere con una presa prona, con le mani leggermente più larghe della larghezza delle spalle.","Tieni la schiena dritta e il petto sollevato mentre spingi i talloni per sollevare il bilanciere da terra, estendendo i fianchi e le ginocchia.","Mentre stai in piedi, contrai i glutei e mantieni il core impegnato.","Abbassa il bilanciere a terra piegando le anche e le ginocchia, mantenendo la schiena dritta.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0033","name":"barbell decline bench press","category":"chest","equipment":"barbell","target":"pectorals","secondary":["triceps","shoulders"],"steps":{"en":["Lie on a decline bench with your feet secured and your head lower than your hips.","Grasp the barbell with an overhand grip slightly wider than shoulder-width apart.","Unrack the barbell and lower it slowly towards your chest, keeping your elbows tucked in.","Pause for a moment at the bottom, then push the barbell back up to the starting position.","Repeat for the desired number of repetitions."],"it":["Sdraiati su una panca declinata con i piedi fissati e la testa più in basso rispetto ai fianchi.","Afferrare il bilanciere con una presa prona leggermente più larga della larghezza delle spalle.","Togli il bilanciere e abbassalo lentamente verso il petto, mantenendo i gomiti piegati.","Fermati per un momento in basso, quindi riporta il bilanciere nella posizione iniziale.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0034","name":"barbell decline bent arm pullover","category":"back","equipment":"barbell","target":"lats","secondary":["triceps","chest"],"steps":{"en":["Lie down on a decline bench with your head lower than your hips and your feet secured.","Hold a barbell with a pronated grip (palms facing away from you) and extend your arms straight above your chest.","Lower the barbell behind your head in a controlled manner, keeping your arms slightly bent.","Pause for a moment, then raise the barbell back to the starting position by contracting your lats.","Repeat for the desired number of repetitions."],"it":["Sdraiati su una panca declinata con la testa più in basso rispetto ai fianchi e i piedi fissati.","Tieni un bilanciere con una presa prona (palmi rivolti lontano da te) ed estendi le braccia direttamente sopra il petto.","Abbassa il bilanciere dietro la testa in modo controllato, mantenendo le braccia leggermente piegate.","Fai una pausa per un momento, quindi riporta il bilanciere nella posizione iniziale contraendo i dorsali.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0035","name":"barbell decline close grip to skull press","category":"upper arms","equipment":"barbell","target":"triceps","secondary":["chest","shoulders"],"steps":{"en":["Lie on a decline bench with your head lower than your feet and hold a barbell with a close grip.","Lower the barbell towards your forehead by bending your elbows, keeping your upper arms stationary.","Pause for a moment, then extend your arms to press the barbell back up to the starting position.","Repeat for the desired number of repetitions."],"it":["Sdraiati su una panca declinata con la testa più bassa dei piedi e tieni un bilanciere con una presa salda.","Abbassa il bilanciere verso la fronte piegando i gomiti e mantenendo ferma la parte superiore delle braccia.","Fai una pausa per un momento, quindi estendi le braccia per riportare il bilanciere nella posizione iniziale.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"1255","name":"barbell decline pullover","category":"chest","equipment":"barbell","target":"pectorals","secondary":["triceps","shoulders"],"steps":{"en":["Lie down on a decline bench with your head lower than your hips and your feet secured.","Hold the barbell with a pronated grip (palms facing away from you) and your hands slightly wider than shoulder-width apart.","Extend your arms above your chest, keeping a slight bend in your elbows.","Lower the barbell in an arc motion behind your head, feeling a stretch in your chest and shoulders.","Pause for a moment, then return the barbell to the starting position by reversing the motion.","Repeat for the desired number of repetitions."],"it":["Sdraiati su una panca declinata con la testa più in basso rispetto ai fianchi e i piedi fissati.","Tieni il bilanciere con una presa prona (palmi rivolti lontano da te) e le mani leggermente più larghe della larghezza delle spalle.","Estendi le braccia sopra il petto, mantenendo una leggera piegatura dei gomiti.","Abbassa il bilanciere con un movimento ad arco dietro la testa, sentendo l'allungamento del petto e delle spalle.","Fare una pausa per un momento, quindi riportare il bilanciere nella posizione iniziale invertendo il movimento.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0036","name":"barbell decline wide-grip press","category":"chest","equipment":"barbell","target":"pectorals","secondary":["triceps","shoulders"],"steps":{"en":["Lie on a decline bench with your feet secured and your head lower than your hips.","Grasp the barbell with a wide grip, slightly wider than shoulder-width apart.","Lower the barbell to your chest, keeping your elbows out to the sides.","Push the barbell back up to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."],"it":["Sdraiati su una panca declinata con i piedi fissati e la testa più in basso rispetto ai fianchi.","Afferrare il bilanciere con una presa ampia, leggermente più larga della larghezza delle spalle.","Abbassa il bilanciere sul petto, mantenendo i gomiti ai lati.","Spingi nuovamente il bilanciere nella posizione iniziale, estendendo completamente le braccia.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0037","name":"barbell decline wide-grip pullover","category":"back","equipment":"barbell","target":"lats","secondary":["triceps","chest"],"steps":{"en":["Lie on a decline bench with your head lower than your hips and your feet secured.","Hold a barbell with a wide grip and extend your arms straight above your chest.","Lower the barbell behind your head in a controlled manner, keeping your arms straight.","Pause for a moment, then raise the barbell back to the starting position.","Repeat for the desired number of repetitions."],"it":["Sdraiati su una panca declinata con la testa più in basso rispetto ai fianchi e i piedi fissati.","Tieni un bilanciere con una presa ampia ed estendi le braccia direttamente sopra il petto.","Abbassa il bilanciere dietro la testa in modo controllato, mantenendo le braccia tese.","Fare una pausa per un momento, quindi riportare il bilanciere nella posizione iniziale.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0038","name":"barbell drag curl","category":"upper arms","equipment":"barbell","target":"biceps","secondary":["forearms"],"steps":{"en":["Stand with your feet shoulder-width apart and hold a barbell with an underhand grip, palms facing up.","Let the barbell hang at arm's length in front of your thighs.","Keeping your upper arms stationary, curl the barbell up towards your chest by contracting your biceps.","Pause for a moment at the top, then slowly lower the barbell back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Stare con i piedi alla larghezza delle spalle e tenere un bilanciere con una presa subdola, con i palmi rivolti verso l'alto.","Lascia che il bilanciere penda a distanza di un braccio davanti alle cosce.","Tenendo ferma la parte superiore delle braccia, piega il bilanciere verso il petto contraendo i bicipiti.","Fermati per un momento in alto, quindi abbassa lentamente il bilanciere nella posizione iniziale.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"1370","name":"barbell floor calf raise","category":"lower legs","equipment":"barbell","target":"calves","secondary":["hamstrings"],"steps":{"en":["Place a barbell on the floor in front of you.","Stand with the balls of your feet on the edge of the barbell, with your heels hanging off.","Hold onto a stable object for balance if needed.","Raise your heels as high as possible, using your calves to lift your body.","Pause for a moment at the top, then slowly lower your heels back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Posiziona un bilanciere sul pavimento di fronte a te.","Stai con le punte dei piedi sul bordo del bilanciere, con i talloni pendenti.","Se necessario, aggrapparsi a un oggetto stabile per mantenere l'equilibrio.","Alza i talloni il più in alto possibile, usando i polpacci per sollevare il corpo.","Fai una pausa per un momento in alto, quindi abbassa lentamente i talloni nella posizione iniziale.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0039","name":"barbell front chest squat","category":"upper legs","equipment":"barbell","target":"glutes","secondary":["quadriceps","hamstrings","calves","core"],"steps":{"en":["Start by standing with your feet shoulder-width apart, toes slightly turned out.","Hold the barbell in front of your chest with your hands shoulder-width apart, elbows pointing forward.","Engage your core and keep your chest up as you lower your body down into a squat position, pushing your hips back and bending your knees.","Lower until your thighs are parallel to the ground, or as low as you can comfortably go.","Pause for a moment at the bottom, then push through your heels to return to the starting position.","Repeat for the desired number of repetitions."],"it":["Inizia stando in piedi con i piedi alla larghezza delle spalle, le dita leggermente rivolte verso l'esterno.","Tieni il bilanciere davanti al petto con le mani alla larghezza delle spalle, i gomiti rivolti in avanti.","Coinvolgi il core e mantieni il petto sollevato mentre abbassi il corpo in una posizione tozza, spingendo i fianchi indietro e piegando le ginocchia.","Abbassati finché le cosce non sono parallele al suolo o il più in basso possibile.","Fai una pausa per un momento in fondo, quindi spingi i talloni per tornare alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0041","name":"barbell front raise","category":"shoulders","equipment":"barbell","target":"delts","secondary":["biceps","triceps"],"steps":{"en":["Stand with your feet shoulder-width apart and hold a barbell in front of your thighs with an overhand grip.","Keep your arms straight and lift the barbell forward and upward until it reaches shoulder level.","Pause for a moment at the top, then slowly lower the barbell back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Stare con i piedi alla larghezza delle spalle e tenere un bilanciere davanti alle cosce con una presa prona.","Tieni le braccia tese e solleva il bilanciere in avanti e verso l'alto fino a raggiungere il livello delle spalle.","Fermati per un momento in alto, quindi abbassa lentamente il bilanciere nella posizione iniziale.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0040","name":"barbell front raise and pullover","category":"chest","equipment":"barbell","target":"pectorals","secondary":["deltoids","triceps"],"steps":{"en":["Stand with your feet shoulder-width apart and hold a barbell with an overhand grip, palms facing down.","Keep your arms straight and raise the barbell in front of you until it reaches shoulder height.","Pause for a moment at the top, then slowly lower the barbell back down to the starting position.","Next, lower the barbell behind your head, keeping your arms straight.","Pause for a moment at the bottom, then raise the barbell back up to the starting position.","Repeat for the desired number of repetitions."],"it":["Stare con i piedi alla larghezza delle spalle e tenere un bilanciere con una presa prona, i palmi rivolti verso il basso.","Tieni le braccia tese e solleva il bilanciere davanti a te fino a raggiungere l'altezza delle spalle.","Fermati per un momento in alto, quindi abbassa lentamente il bilanciere nella posizione iniziale.","Successivamente, abbassa il bilanciere dietro la testa, mantenendo le braccia dritte.","Fermati per un momento in basso, quindi solleva il bilanciere nella posizione iniziale.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0042","name":"barbell front squat","category":"upper legs","equipment":"barbell","target":"glutes","secondary":["quadriceps","hamstrings","calves","core"],"steps":{"en":["Start by standing with your feet shoulder-width apart, toes slightly turned out.","Hold the barbell in front of your shoulders, resting it on your collarbone and shoulders.","Engage your core and keep your chest up as you lower your body down into a squat position, pushing your hips back and bending your knees.","Lower until your thighs are parallel to the ground, or as low as you can comfortably go.","Pause for a moment at the bottom, then push through your heels to return to the starting position.","Repeat for the desired number of repetitions."],"it":["Inizia stando in piedi con i piedi alla larghezza delle spalle, le dita leggermente rivolte verso l'esterno.","Tieni il bilanciere davanti alle spalle, appoggiandolo sulla clavicola e sulle spalle.","Coinvolgi il core e mantieni il petto sollevato mentre abbassi il corpo in una posizione tozza, spingendo i fianchi indietro e piegando le ginocchia.","Abbassati finché le cosce non sono parallele al suolo o il più in basso possibile.","Fai una pausa per un momento in fondo, quindi spingi i talloni per tornare alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0043","name":"barbell full squat","category":"upper legs","equipment":"barbell","target":"glutes","secondary":["quadriceps","hamstrings","calves","core"],"steps":{"en":["Stand with your feet shoulder-width apart, toes slightly turned out.","Hold the barbell across your upper back, resting it on your traps or rear delts.","Engage your core and keep your chest up as you begin to lower your body down.","Bend at the knees and hips, pushing your hips back and down as if sitting into a chair.","Lower yourself until your thighs are parallel to the ground or slightly below.","Keep your knees in line with your toes and your weight in your heels.","Drive through your heels to stand back up, extending your hips and knees.","Repeat for the desired number of repetitions."],"it":["Stai con i piedi alla larghezza delle spalle, le dita leggermente rivolte verso l'esterno.","Tieni il bilanciere sulla parte superiore della schiena, appoggiandolo sulle trappole o sui deltoidi posteriori.","Coinvolgi il tuo core e mantieni il petto sollevato mentre inizi ad abbassare il corpo.","Piega le ginocchia e i fianchi, spingendo i fianchi indietro e in basso come se fossi seduto su una sedia.","Abbassati finché le cosce non sono parallele al suolo o leggermente più in basso.","Tieni le ginocchia in linea con le dita dei piedi e il peso sui talloni.","Spingi i talloni per rialzarti, estendendo i fianchi e le ginocchia.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"1461","name":"barbell full squat (back pov)","category":"upper legs","equipment":"barbell","target":"glutes","secondary":["quadriceps","hamstrings","calves","core"],"steps":{"en":["Stand with your feet shoulder-width apart, toes slightly turned out.","Hold the barbell across your upper back, resting it on your traps or rear delts.","Engage your core and keep your chest up as you begin to lower your body down.","Bend at the knees and hips, pushing your hips back and down as if sitting into a chair.","Lower your body until your thighs are parallel to the ground or slightly below.","Keep your knees in line with your toes and your weight in your heels.","Drive through your heels to stand back up, extending your hips and knees.","Repeat for the desired number of repetitions."],"it":["Stai con i piedi alla larghezza delle spalle, le dita leggermente rivolte verso l'esterno.","Tieni il bilanciere sulla parte superiore della schiena, appoggiandolo sulle trappole o sui deltoidi posteriori.","Coinvolgi il tuo core e mantieni il petto sollevato mentre inizi ad abbassare il corpo.","Piega le ginocchia e i fianchi, spingendo i fianchi indietro e in basso come se fossi seduto su una sedia.","Abbassa il corpo finché le cosce non sono parallele al suolo o leggermente al di sotto.","Tieni le ginocchia in linea con le dita dei piedi e il peso sui talloni.","Spingi i talloni per rialzarti, estendendo i fianchi e le ginocchia.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"1462","name":"barbell full squat (side pov)","category":"upper legs","equipment":"barbell","target":"glutes","secondary":["quadriceps","hamstrings","calves","core"],"steps":{"en":["Stand with your feet shoulder-width apart, toes slightly turned out.","Hold the barbell across your upper back, resting it on your traps or rear delts.","Engage your core and keep your chest up as you begin to lower your body down.","Bend at the knees and hips, pushing your hips back and down as if sitting into a chair.","Lower your body until your thighs are parallel to the ground or slightly below.","Keep your knees in line with your toes and your weight in your heels.","Drive through your heels to stand back up, extending your hips and knees.","Repeat for the desired number of repetitions."],"it":["Stai con i piedi alla larghezza delle spalle, le dita leggermente rivolte verso l'esterno.","Tieni il bilanciere sulla parte superiore della schiena, appoggiandolo sulle trappole o sui deltoidi posteriori.","Coinvolgi il tuo core e mantieni il petto sollevato mentre inizi ad abbassare il corpo.","Piega le ginocchia e i fianchi, spingendo i fianchi indietro e in basso come se fossi seduto su una sedia.","Abbassa il corpo finché le cosce non sono parallele al suolo o leggermente al di sotto.","Tieni le ginocchia in linea con le dita dei piedi e il peso sui talloni.","Spingi i talloni per rialzarti, estendendo i fianchi e le ginocchia.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"1545","name":"barbell full zercher squat","category":"upper legs","equipment":"barbell","target":"glutes","secondary":["quadriceps","hamstrings","calves","core"],"steps":{"en":["Stand with your feet shoulder-width apart and toes slightly turned out.","Hold the barbell in the crooks of your elbows, with your hands gripping the barbell for stability.","Engage your core and keep your chest lifted as you lower your hips back and down into a squat position.","Keep your knees in line with your toes and your weight in your heels.","Lower until your thighs are parallel to the ground, or as low as you can comfortably go.","Drive through your heels to stand back up, squeezing your glutes at the top of the movement.","Repeat for the desired number of repetitions."],"it":["Stai con i piedi alla larghezza delle spalle e le dita dei piedi leggermente rivolte verso l'esterno.","Tieni il bilanciere nell'incavo dei gomiti, con le mani che afferrano il bilanciere per stabilità.","Coinvolgi il core e mantieni il petto sollevato mentre abbassi i fianchi indietro e in basso in una posizione tozza.","Tieni le ginocchia in linea con le dita dei piedi e il peso sui talloni.","Abbassati finché le cosce non sono parallele al suolo o il più in basso possibile.","Spingi i talloni per rialzarti, contraendo i glutei nella parte superiore del movimento.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"1409","name":"barbell glute bridge","category":"upper legs","equipment":"barbell","target":"glutes","secondary":["hamstrings","lower back"],"steps":{"en":["Start by lying flat on your back on the ground with your knees bent and feet flat on the floor.","Place a barbell across your hips, holding it securely with both hands.","Engage your glutes and core muscles, then lift your hips off the ground until your body forms a straight line from your knees to your shoulders.","Pause for a moment at the top, squeezing your glutes.","Slowly lower your hips back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Inizia sdraiandoti sulla schiena a terra con le ginocchia piegate e i piedi appoggiati sul pavimento.","Posiziona un bilanciere sui fianchi, tenendolo saldamente con entrambe le mani.","Coinvolgi i glutei e i muscoli centrali, quindi solleva i fianchi da terra finché il tuo corpo non forma una linea retta dalle ginocchia alle spalle.","Fermati un attimo in alto, contraendo i glutei.","Abbassa lentamente i fianchi fino alla posizione iniziale.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"3562","name":"barbell glute bridge two legs on bench (male)","category":"upper legs","equipment":"barbell","target":"glutes","secondary":["hamstrings","core"],"steps":{"en":["Start by sitting on the edge of a bench with your upper back resting against it and your feet flat on the ground, hip-width apart.","Place a barbell across your hips, holding it securely with both hands.","Engage your glutes and core muscles, then press through your heels to lift your hips off the bench, creating a straight line from your knees to your shoulders.","Pause for a moment at the top, squeezing your glutes.","Slowly lower your hips back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Inizia sedendoti sul bordo di una panca con la parte superiore della schiena appoggiata contro di essa e i piedi appoggiati a terra, alla larghezza dei fianchi.","Posiziona un bilanciere sui fianchi, tenendolo saldamente con entrambe le mani.","Coinvolgi i glutei e i muscoli centrali, quindi premi i talloni per sollevare i fianchi dalla panca, creando una linea retta dalle ginocchia alle spalle.","Fermati un attimo in alto, contraendo i glutei.","Abbassa lentamente i fianchi fino alla posizione iniziale.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0044","name":"barbell good morning","category":"upper legs","equipment":"barbell","target":"hamstrings","secondary":["lower back"],"steps":{"en":["Start by standing with your feet shoulder-width apart and the barbell resting on your upper back.","Keeping your back straight and your core engaged, hinge forward at the hips, pushing your buttocks back as if you were trying to touch the wall behind you with your glutes.","Lower your torso until it is parallel to the ground, feeling a stretch in your hamstrings.","Pause for a moment, then return to the starting position by squeezing your glutes and pushing your hips forward.","Repeat for the desired number of repetitions."],"it":["Inizia stando in piedi con i piedi alla larghezza delle spalle e il bilanciere appoggiato sulla parte superiore della schiena.","Mantenendo la schiena dritta e il core impegnato, fai perno in avanti sui fianchi, spingendo indietro i glutei come se stessi cercando di toccare il muro dietro di te con i glutei.","Abbassa il busto finché non è parallelo al suolo, avvertendo un allungamento nei muscoli posteriori della coscia.","Fai una pausa per un momento, quindi torna alla posizione di partenza contraendo i glutei e spingendo i fianchi in avanti.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0045","name":"barbell guillotine bench press","category":"chest","equipment":"barbell","target":"pectorals","secondary":["shoulders","triceps"],"steps":{"en":["Lie flat on a bench with your feet flat on the ground and your back pressed against the bench.","Grasp the barbell with an overhand grip, slightly wider than shoulder-width apart.","Lower the barbell slowly towards your neck, keeping your elbows pointed outwards.","Pause for a moment when the barbell is just above your neck.","Push the barbell back up to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."],"it":["Sdraiati su una panca con i piedi appoggiati a terra e la schiena premuta contro la panca.","Afferrare il bilanciere con una presa prona, leggermente più larga della larghezza delle spalle.","Abbassa lentamente il bilanciere verso il collo, mantenendo i gomiti rivolti verso l'esterno.","Fai una pausa per un momento quando il bilanciere è appena sopra il collo.","Spingi nuovamente il bilanciere nella posizione iniziale, estendendo completamente le braccia.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0046","name":"barbell hack squat","category":"upper legs","equipment":"barbell","target":"glutes","secondary":["quadriceps","hamstrings","calves"],"steps":{"en":["Start by standing with your feet shoulder-width apart and your toes slightly turned out.","Hold the barbell behind your legs, resting it on your upper thighs.","Lower your body by bending at the knees and hips, keeping your back straight and your chest up.","Continue lowering until your thighs are parallel to the ground, or as low as you can comfortably go.","Pause for a moment, then push through your heels to return to the starting position.","Repeat for the desired number of repetitions."],"it":["Inizia stando in piedi con i piedi alla larghezza delle spalle e le dita dei piedi leggermente rivolte verso l'esterno.","Tieni il bilanciere dietro le gambe, appoggiandolo sulla parte superiore delle cosce.","Abbassa il corpo piegando le ginocchia e i fianchi, mantenendo la schiena dritta e il petto in alto.","Continua ad abbassare finché le cosce non sono parallele al suolo o il più in basso possibile.","Fai una pausa per un momento, quindi spingi i talloni per tornare alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"1436","name":"barbell high bar squat","category":"upper legs","equipment":"barbell","target":"glutes","secondary":["quadriceps","hamstrings","calves","core"],"steps":{"en":["Stand with your feet shoulder-width apart, toes slightly turned out.","Place the barbell on your upper back, resting it on your traps.","Engage your core and keep your chest up as you begin to squat down, pushing your hips back and bending your knees.","Lower yourself until your thighs are parallel to the ground, or as low as you can comfortably go.","Drive through your heels to stand back up, extending your hips and knees.","Repeat for the desired number of repetitions."],"it":["Stai con i piedi alla larghezza delle spalle, le dita leggermente rivolte verso l'esterno.","Posiziona il bilanciere sulla parte superiore della schiena, appoggiandolo sulle trappole.","Coinvolgi il core e mantieni il petto sollevato mentre inizi ad accovacciarti, spingendo indietro i fianchi e piegando le ginocchia.","Abbassati finché le cosce non sono parallele al suolo o il più in basso possibile.","Spingi i talloni per rialzarti, estendendo i fianchi e le ginocchia.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0047","name":"barbell incline bench press","category":"chest","equipment":"barbell","target":"pectorals","secondary":["shoulders","triceps"],"steps":{"en":["Set up an incline bench at a 45-degree angle.","Lie down on the bench with your feet flat on the ground.","Grasp the barbell with an overhand grip, slightly wider than shoulder-width apart.","Unrack the barbell and lower it slowly towards your chest, keeping your elbows at a 45-degree angle.","Pause for a moment at the bottom, then push the barbell back up to the starting position.","Repeat for the desired number of repetitions."],"it":["Installa una panca inclinata con un angolo di 45 gradi.","Sdraiati sulla panca con i piedi appoggiati a terra.","Afferrare il bilanciere con una presa prona, leggermente più larga della larghezza delle spalle.","Togli il bilanciere e abbassalo lentamente verso il petto, mantenendo i gomiti ad un angolo di 45 gradi.","Fermati per un momento in basso, quindi riporta il bilanciere nella posizione iniziale.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"1719","name":"barbell incline close grip bench press","category":"upper arms","equipment":"barbell","target":"triceps","secondary":["chest","shoulders"],"steps":{"en":["Set up an incline bench at a 45-degree angle.","Lie down on the bench with your feet flat on the ground.","Grasp the barbell with a close grip, slightly narrower than shoulder-width apart.","Unrack the barbell and lower it slowly towards your chest, keeping your elbows close to your body.","Pause for a moment when the barbell touches your chest.","Push the barbell back up to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."],"it":["Installa una panca inclinata con un angolo di 45 gradi.","Sdraiati sulla panca con i piedi appoggiati a terra.","Afferrare il bilanciere con una presa stretta, leggermente più stretta della larghezza delle spalle.","Togli il bilanciere e abbassalo lentamente verso il petto, mantenendo i gomiti vicini al corpo.","Fai una pausa per un momento quando il bilanciere tocca il tuo petto.","Spingi nuovamente il bilanciere nella posizione iniziale, estendendo completamente le braccia.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0048","name":"barbell incline reverse-grip press","category":"upper arms","equipment":"barbell","target":"triceps","secondary":["chest","shoulders"],"steps":{"en":["Set up an incline bench at a 45-degree angle.","Lie back on the bench and grasp the barbell with a reverse grip, hands slightly wider than shoulder-width apart.","Unrack the barbell and lower it towards your upper chest, keeping your elbows tucked in.","Pause for a moment at the bottom, then push the barbell back up to the starting position.","Repeat for the desired number of repetitions."],"it":["Installa una panca inclinata con un angolo di 45 gradi.","Sdraiati sulla panca e afferra il bilanciere con una presa inversa, le mani leggermente più larghe della larghezza delle spalle.","Togli il bilanciere e abbassalo verso la parte superiore del torace, mantenendo i gomiti piegati.","Fermati per un momento in basso, quindi riporta il bilanciere nella posizione iniziale.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0049","name":"barbell incline row","category":"back","equipment":"barbell","target":"upper back","secondary":["biceps","forearms"],"steps":{"en":["Set up an incline bench at a 45-degree angle.","Lie face down on the bench with your chest against the pad and your feet flat on the ground.","Grasp the barbell with an overhand grip, slightly wider than shoulder-width apart.","Keep your back straight and your core engaged.","Pull the barbell towards your chest, squeezing your shoulder blades together.","Pause for a moment at the top, then slowly lower the barbell back to the starting position.","Repeat for the desired number of repetitions."],"it":["Installa una panca inclinata con un angolo di 45 gradi.","Sdraiati a faccia in giù sulla panca con il petto contro il cuscino e i piedi appoggiati a terra.","Afferrare il bilanciere con una presa prona, leggermente più larga della larghezza delle spalle.","Tieni la schiena dritta e il core impegnato.","Tirare il bilanciere verso il petto, stringendo insieme le scapole.","Fermati per un momento in alto, quindi abbassa lentamente il bilanciere nella posizione iniziale.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0050","name":"barbell incline shoulder raise","category":"chest","equipment":"barbell","target":"serratus anterior","secondary":["deltoids","trapezius"],"steps":{"en":["Set up an incline bench at a 45-degree angle.","Sit on the bench with your back against the pad and feet flat on the ground.","Hold a barbell with an overhand grip, slightly wider than shoulder-width apart.","Lift the barbell up to shoulder height, keeping your elbows slightly bent.","Slowly raise the barbell overhead, extending your arms fully.","Pause for a moment at the top, then slowly lower the barbell back to shoulder height.","Repeat for the desired number of repetitions."],"it":["Installa una panca inclinata con un angolo di 45 gradi.","Siediti sulla panca con la schiena appoggiata al cuscino e i piedi appoggiati a terra.","Tieni un bilanciere con una presa prona, leggermente più largo della larghezza delle spalle.","Sollevare il bilanciere all'altezza delle spalle, mantenendo i gomiti leggermente piegati.","Solleva lentamente il bilanciere sopra la testa, estendendo completamente le braccia.","Fermati per un momento in alto, quindi abbassa lentamente il bilanciere all'altezza delle spalle.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0051","name":"barbell jefferson squat","category":"upper legs","equipment":"barbell","target":"glutes","secondary":["quadriceps","hamstrings","calves"],"steps":{"en":["Stand with your feet shoulder-width apart and toes slightly turned out.","Hold the barbell with an overhand grip, resting it on the front of your body, just below your waist.","Step your left foot forward and your right foot back, keeping your feet shoulder-width apart.","Bend your knees and lower your body down into a squat position, keeping your back straight and chest up.","Push through your heels to stand back up to the starting position.","Repeat the movement, alternating your forward and back foot with each repetition."],"it":["Stai con i piedi alla larghezza delle spalle e le dita dei piedi leggermente rivolte verso l'esterno.","Tieni il bilanciere con una presa prona, appoggiandolo sulla parte anteriore del corpo, appena sotto la vita.","Porta il piede sinistro in avanti e il piede destro indietro, mantenendo i piedi alla larghezza delle spalle.","Piega le ginocchia e abbassa il corpo in posizione tozza, mantenendo la schiena dritta e il petto in alto.","Spingi i talloni per tornare alla posizione di partenza.","Ripeti il ​​movimento, alternando il piede avanti e quello posteriore ad ogni ripetizione."]}},{"id":"0052","name":"barbell jm bench press","category":"upper arms","equipment":"barbell","target":"triceps","secondary":["chest","shoulders"],"steps":{"en":["Lie flat on a bench with your feet flat on the ground and your back pressed against the bench.","Grasp the barbell with an overhand grip, slightly wider than shoulder-width apart.","Lower the barbell to your chest, keeping your elbows tucked in close to your body.","Push the barbell back up to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."],"it":["Sdraiati su una panca con i piedi appoggiati a terra e la schiena premuta contro la panca.","Afferrare il bilanciere con una presa prona, leggermente più larga della larghezza delle spalle.","Abbassa il bilanciere sul petto, mantenendo i gomiti piegati vicino al corpo.","Spingi nuovamente il bilanciere nella posizione iniziale, estendendo completamente le braccia.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0053","name":"barbell jump squat","category":"upper legs","equipment":"barbell","target":"glutes","secondary":["quadriceps","hamstrings","calves"],"steps":{"en":["Start by standing with your feet shoulder-width apart, holding a barbell across your upper back.","Lower your body into a squat position by bending your knees and pushing your hips back.","Once you reach the bottom of the squat, explode upwards by jumping off the ground.","As you jump, extend your hips, knees, and ankles, pushing through your toes.","Land softly back into the squat position and immediately repeat the movement for the desired number of repetitions."],"it":["Inizia stando in piedi con i piedi alla larghezza delle spalle, tenendo un bilanciere sulla parte superiore della schiena.","Abbassa il corpo in una posizione tozza piegando le ginocchia e spingendo indietro i fianchi.","Una volta raggiunto il fondo dello squat, esplodi verso l'alto saltando da terra.","Mentre salti, estendi i fianchi, le ginocchia e le caviglie, spingendo attraverso le dita dei piedi.","Atterra dolcemente nella posizione tozza e ripeti immediatamente il movimento per il numero di ripetizioni desiderato."]}},{"id":"1410","name":"barbell lateral lunge","category":"upper legs","equipment":"barbell","target":"glutes","secondary":["quadriceps","hamstrings","calves"],"steps":{"en":["Stand with your feet shoulder-width apart, holding a barbell across your upper back.","Take a big step to the side with your right foot, keeping your left foot planted.","Bend your right knee and lower your body down into a lunge position, keeping your left leg straight.","Push off with your right foot and return to the starting position.","Repeat on the other side, stepping with your left foot."],"it":["Stai con i piedi alla larghezza delle spalle, tenendo un bilanciere sulla parte superiore della schiena.","Fai un grande passo laterale con il piede destro, mantenendo il piede sinistro ben piantato.","Piega il ginocchio destro e abbassa il corpo in una posizione di affondo, mantenendo la gamba sinistra dritta.","Spingi con il piede destro e torna alla posizione di partenza.","Ripeti dall'altro lato, facendo un passo con il piede sinistro."]}},{"id":"1435","name":"barbell low bar squat","category":"upper legs","equipment":"barbell","target":"glutes","secondary":["quadriceps","hamstrings","calves"],"steps":{"en":["Stand with your feet shoulder-width apart and the barbell resting on your upper back.","Keeping your chest up and core engaged, slowly lower your body by bending your knees and pushing your hips back.","Continue lowering until your thighs are parallel to the ground or slightly below.","Pause for a moment, then push through your heels to return to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai con i piedi alla larghezza delle spalle e il bilanciere appoggiato sulla parte superiore della schiena.","Mantenendo il petto in alto e il core impegnato, abbassa lentamente il corpo piegando le ginocchia e spingendo indietro i fianchi.","Continua ad abbassarti finché le cosce non sono parallele al suolo o leggermente più in basso.","Fai una pausa per un momento, quindi spingi i talloni per tornare alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0054","name":"barbell lunge","category":"upper legs","equipment":"barbell","target":"glutes","secondary":["quadriceps","hamstrings","calves"],"steps":{"en":["Start by standing with your feet shoulder-width apart and a barbell resting on your upper back.","Take a step forward with your right foot, keeping your torso upright.","Lower your body by bending your right knee until your thigh is parallel to the ground.","Push through your right heel to return to the starting position.","Repeat with your left leg, alternating legs for the desired number of repetitions."],"it":["Inizia stando in piedi con i piedi alla larghezza delle spalle e un bilanciere appoggiato sulla parte superiore della schiena.","Fai un passo avanti con il piede destro, mantenendo il busto eretto.","Abbassa il corpo piegando il ginocchio destro finché la coscia non è parallela al suolo.","Spingi attraverso il tallone destro per tornare alla posizione di partenza.","Ripeti con la gamba sinistra, alternando le gambe per il numero di ripetizioni desiderato."]}},{"id":"1720","name":"barbell lying back of the head tricep extension","category":"upper arms","equipment":"barbell","target":"triceps","secondary":["shoulders"],"steps":{"en":["Lie flat on a bench with your feet flat on the ground and your head at the end of the bench.","Hold a barbell with an overhand grip, hands shoulder-width apart, and extend your arms straight up over your chest.","Keeping your upper arms stationary, slowly lower the barbell behind your head by bending your elbows.","Pause for a moment, then extend your arms back up to the starting position.","Repeat for the desired number of repetitions."],"it":["Sdraiati su una panca con i piedi appoggiati a terra e la testa all'estremità della panca.","Tieni un bilanciere con una presa prona, le mani alla larghezza delle spalle ed estendi le braccia verso l'alto sul petto.","Tenendo ferma la parte superiore delle braccia, abbassa lentamente il bilanciere dietro la testa piegando i gomiti.","Fai una pausa per un momento, quindi allunga le braccia fino alla posizione iniziale.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0055","name":"barbell lying close-grip press","category":"upper arms","equipment":"barbell","target":"triceps","secondary":["chest","shoulders"],"steps":{"en":["Lie flat on a bench with your feet flat on the ground and your back pressed against the bench.","Grasp the barbell with a close grip, hands shoulder-width apart, palms facing towards your feet.","Lift the barbell off the rack and hold it directly above your chest with your arms fully extended.","Slowly lower the barbell towards your chest, keeping your elbows close to your body.","Pause for a moment when the barbell touches your chest, then push it back up to the starting position.","Repeat for the desired number of repetitions."],"it":["Sdraiati su una panca con i piedi appoggiati a terra e la schiena premuta contro la panca.","Afferrare il bilanciere con una presa salda, le mani alla larghezza delle spalle, i palmi rivolti verso i piedi.","Solleva il bilanciere dal rack e tienilo direttamente sopra il petto con le braccia completamente distese.","Abbassa lentamente il bilanciere verso il petto, mantenendo i gomiti vicini al corpo.","Fai una pausa per un momento quando il bilanciere tocca il petto, quindi spingilo nuovamente nella posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0056","name":"barbell lying close-grip triceps extension","category":"upper arms","equipment":"barbell","target":"triceps","secondary":["shoulders"],"steps":{"en":["Lie flat on a bench with your feet flat on the ground and your head at the end of the bench.","Grasp the barbell with a close grip, hands shoulder-width apart, palms facing up.","Extend your arms fully, lifting the barbell above your chest.","Keeping your upper arms stationary, slowly lower the barbell towards your forehead by bending your elbows.","Pause for a moment at the bottom, then extend your arms back to the starting position.","Repeat for the desired number of repetitions."],"it":["Sdraiati su una panca con i piedi appoggiati a terra e la testa all'estremità della panca.","Afferrare il bilanciere con una presa salda, le mani alla larghezza delle spalle, i palmi rivolti verso l'alto.","Estendi completamente le braccia, sollevando il bilanciere sopra il petto.","Mantenendo ferma la parte superiore delle braccia, abbassare lentamente il bilanciere verso la fronte piegando i gomiti.","Fai una pausa per un momento in basso, quindi estendi le braccia nella posizione iniziale.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0057","name":"barbell lying extension","category":"upper arms","equipment":"barbell","target":"triceps","secondary":["shoulders"],"steps":{"en":["Lie flat on a bench with your feet flat on the ground and your head at the end of the bench.","Hold the barbell with an overhand grip, hands shoulder-width apart, and extend your arms straight up over your chest.","Keeping your upper arms stationary, slowly lower the barbell towards your forehead by bending your elbows.","Pause for a moment, then extend your arms back up to the starting position.","Repeat for the desired number of repetitions."],"it":["Sdraiati su una panca con i piedi appoggiati a terra e la testa all'estremità della panca.","Tieni il bilanciere con una presa prona, le mani alla larghezza delle spalle ed estendi le braccia verso l'alto sul petto.","Mantenendo ferma la parte superiore delle braccia, abbassare lentamente il bilanciere verso la fronte piegando i gomiti.","Fai una pausa per un momento, quindi allunga le braccia fino alla posizione iniziale.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0058","name":"barbell lying lifting (on hip)","category":"upper legs","equipment":"barbell","target":"glutes","secondary":["hamstrings","quadriceps"],"steps":{"en":["Lie flat on your back on a bench with your feet flat on the ground and your knees bent.","Hold the barbell with an overhand grip and position it on your hips.","Engaging your glutes, lift your hips off the bench until your body forms a straight line from your knees to your shoulders.","Pause for a moment at the top, then slowly lower your hips back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Sdraiati sulla schiena su una panca con i piedi appoggiati a terra e le ginocchia piegate.","Tieni il bilanciere con una presa prona e posizionalo sui fianchi.","Coinvolgendo i glutei, solleva i fianchi dalla panca finché il tuo corpo non forma una linea retta dalle ginocchia alle spalle.","Fai una pausa per un momento in alto, quindi abbassa lentamente i fianchi fino alla posizione iniziale.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0059","name":"barbell lying preacher curl","category":"upper arms","equipment":"barbell","target":"biceps","secondary":["forearms"],"steps":{"en":["Sit on a preacher bench with your chest against the pad and your arms extended over the edge, holding a barbell with an underhand grip.","Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the bar until your biceps are fully contracted and the bar is at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the barbell back to the starting position.","Repeat for the desired number of repetitions."],"it":["Siediti su una panca da predicatore con il petto contro il cuscino e le braccia distese oltre il bordo, tenendo un bilanciere con una presa subdola.","Mantenendo ferma la parte superiore delle braccia, espira e piega i pesi contraendo i bicipiti.","Continua a sollevare la barra finché i bicipiti non sono completamente contratti e la barra è all'altezza delle spalle.","Mantieni la posizione contratta per una breve pausa mentre contrai i bicipiti.","Inspira e inizia lentamente ad abbassare il bilanciere nella posizione iniziale.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0061","name":"barbell lying triceps extension","category":"upper arms","equipment":"barbell","target":"triceps","secondary":["shoulders"],"steps":{"en":["Lie flat on a bench with your feet flat on the ground and your head at the end of the bench.","Hold the barbell with an overhand grip, hands shoulder-width apart, and extend your arms straight up over your chest.","Keeping your upper arms stationary, slowly lower the barbell towards your forehead by bending your elbows.","Pause for a moment at the bottom, then extend your arms back up to the starting position.","Repeat for the desired number of repetitions."],"it":["Sdraiati su una panca con i piedi appoggiati a terra e la testa all'estremità della panca.","Tieni il bilanciere con una presa prona, le mani alla larghezza delle spalle ed estendi le braccia verso l'alto sul petto.","Mantenendo ferma la parte superiore delle braccia, abbassare lentamente il bilanciere verso la fronte piegando i gomiti.","Fai una pausa per un momento in basso, quindi allunga le braccia fino alla posizione iniziale.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0060","name":"barbell lying triceps extension skull crusher","category":"upper arms","equipment":"barbell","target":"triceps","secondary":["shoulders"],"steps":{"en":["Lie flat on a bench with your feet flat on the ground and your head at the end of the bench.","Hold the barbell with an overhand grip, hands shoulder-width apart, and extend your arms straight up over your chest.","Keeping your upper arms stationary, slowly lower the barbell towards your forehead by bending your elbows.","Pause for a moment when the barbell is just above your forehead, then extend your arms back up to the starting position.","Repeat for the desired number of repetitions."],"it":["Sdraiati su una panca con i piedi appoggiati a terra e la testa all'estremità della panca.","Tieni il bilanciere con una presa prona, le mani alla larghezza delle spalle ed estendi le braccia verso l'alto sul petto.","Mantenendo ferma la parte superiore delle braccia, abbassare lentamente il bilanciere verso la fronte piegando i gomiti.","Fai una pausa per un momento quando il bilanciere è appena sopra la fronte, quindi estendi le braccia fino alla posizione iniziale.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0063","name":"barbell narrow stance squat","category":"upper legs","equipment":"barbell","target":"glutes","secondary":["quadriceps","hamstrings","calves"],"steps":{"en":["Stand with your feet shoulder-width apart and toes pointing slightly outward.","Hold the barbell across your upper back, resting it on your traps or rear delts.","Engage your core and keep your chest up as you slowly lower your body by bending your knees and pushing your hips back.","Continue lowering until your thighs are parallel to the ground or slightly below.","Pause for a moment, then push through your heels to return to the starting position.","Repeat for the desired number of repetitions."],"it":["Stare con i piedi alla larghezza delle spalle e le dita dei piedi leggermente rivolte verso l'esterno.","Tieni il bilanciere sulla parte superiore della schiena, appoggiandolo sulle trappole o sui deltoidi posteriori.","Coinvolgi il core e mantieni il petto sollevato mentre abbassi lentamente il corpo piegando le ginocchia e spingendo indietro i fianchi.","Continua ad abbassarti finché le cosce non sono parallele al suolo o leggermente più in basso.","Fai una pausa per un momento, quindi spingi i talloni per tornare alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0064","name":"barbell one arm bent over row","category":"back","equipment":"barbell","target":"upper back","secondary":["biceps","forearms"],"steps":{"en":["Stand with your feet shoulder-width apart, knees slightly bent, and hold a barbell with one hand using an overhand grip.","Bend forward at the hips, keeping your back straight and your head in a neutral position.","Pull the barbell up towards your chest, keeping your elbow close to your body and squeezing your shoulder blades together.","Lower the barbell back down to the starting position in a controlled manner.","Repeat for the desired number of repetitions, then switch to the other arm."],"it":["Stare con i piedi alla larghezza delle spalle, le ginocchia leggermente piegate e tenere un bilanciere con una mano utilizzando una presa prona.","Piegati in avanti sui fianchi, mantenendo la schiena dritta e la testa in posizione neutra.","Tira il bilanciere verso il petto, tenendo il gomito vicino al corpo e unendo le scapole.","Abbassare nuovamente il bilanciere nella posizione iniziale in modo controllato.","Ripeti per il numero di ripetizioni desiderato, quindi passa all'altro braccio."]}},{"id":"0065","name":"barbell one arm floor press","category":"upper arms","equipment":"barbell","target":"triceps","secondary":["chest","shoulders"],"steps":{"en":["Lie flat on your back on the floor with your knees bent and feet flat on the ground.","Hold the barbell with one hand, palm facing up, and extend your arm straight up over your chest.","Slowly lower the barbell towards your chest, keeping your elbow close to your body.","Pause for a moment at the bottom, then push the barbell back up to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"it":["Sdraiati sulla schiena sul pavimento con le ginocchia piegate e i piedi appoggiati a terra.","Tieni il bilanciere con una mano, con il palmo rivolto verso l'alto, ed estendi il braccio verso l'alto sopra il petto.","Abbassa lentamente il bilanciere verso il petto, mantenendo il gomito vicino al corpo.","Fermati per un momento in basso, quindi riporta il bilanciere nella posizione iniziale.","Ripeti per il numero di ripetizioni desiderato, quindi cambia braccio."]}},{"id":"0066","name":"barbell one arm side deadlift","category":"upper legs","equipment":"barbell","target":"glutes","secondary":["hamstrings","quadriceps","lower back"],"steps":{"en":["Stand with your feet shoulder-width apart, holding a barbell in one hand with an overhand grip.","Keep your back straight and your core engaged.","Bend at the hips and lower the barbell towards the outside of your leg, keeping your arm straight and your chest up.","Lower the barbell as far as you can while maintaining good form.","Pause for a moment, then slowly return to the starting position.","Repeat for the desired number of repetitions, then switch sides."],"it":["Stare con i piedi alla larghezza delle spalle, tenendo un bilanciere in una mano con una presa prona.","Tieni la schiena dritta e il core impegnato.","Piegati sui fianchi e abbassa il bilanciere verso l'esterno della gamba, mantenendo il braccio dritto e il petto in alto.","Abbassa il bilanciere il più possibile mantenendo una buona forma.","Fai una pausa per un momento, quindi torna lentamente alla posizione di partenza.","Ripeti per il numero di ripetizioni desiderato, quindi cambia lato."]}},{"id":"0067","name":"barbell one arm snatch","category":"shoulders","equipment":"barbell","target":"delts","secondary":["traps","forearms","core"],"steps":{"en":["Stand with your feet shoulder-width apart, toes pointing slightly outwards.","Hold the barbell with an overhand grip, hands slightly wider than shoulder-width apart.","Bend your knees and lower your hips into a squat position, keeping your back straight and chest up.","Explosively extend your hips, knees, and ankles, driving the barbell upwards.","As the barbell reaches chest level, pull it upwards with your arm, keeping it close to your body.","Rotate your elbow under the barbell and extend your arm fully overhead, locking out your elbow.","Lower the barbell back down to the starting position in a controlled manner.","Repeat for the desired number of repetitions, then switch arms."],"it":["Stare con i piedi alla larghezza delle spalle, le dita dei piedi leggermente rivolte verso l'esterno.","Tieni il bilanciere con una presa prona, con le mani leggermente più larghe della larghezza delle spalle.","Piega le ginocchia e abbassa i fianchi in una posizione tozza, mantenendo la schiena dritta e il petto in alto.","Estendi in modo esplosivo anche, ginocchia e caviglie, spingendo il bilanciere verso l'alto.","Quando il bilanciere raggiunge l'altezza del petto, tiralo verso l'alto con il braccio, tenendolo vicino al corpo.","Ruota il gomito sotto il bilanciere ed estendi il braccio completamente sopra la testa, bloccando il gomito.","Abbassare nuovamente il bilanciere nella posizione iniziale in modo controllato.","Ripeti per il numero di ripetizioni desiderato, quindi cambia braccio."]}},{"id":"0068","name":"barbell one leg squat","category":"upper legs","equipment":"barbell","target":"quads","secondary":["glutes","hamstrings","calves"],"steps":{"en":["Stand with your feet shoulder-width apart and hold a barbell across your upper back.","Lift one foot off the ground and extend it forward, keeping it parallel to the ground.","Bend your standing leg and lower your body down as if sitting back into a chair, keeping your chest up and your back straight.","Lower yourself until your thigh is parallel to the ground, then push through your heel to return to the starting position.","Repeat for the desired number of repetitions, then switch legs and repeat."],"it":["Stai con i piedi alla larghezza delle spalle e tieni un bilanciere sulla parte superiore della schiena.","Sollevare un piede da terra ed estenderlo in avanti, mantenendolo parallelo al suolo.","Piega la gamba in piedi e abbassa il corpo come se fossi seduto su una sedia, mantenendo il petto sollevato e la schiena dritta.","Abbassati finché la coscia non è parallela al suolo, quindi spingi il tallone per tornare alla posizione di partenza.","Ripeti per il numero di ripetizioni desiderato, quindi cambia gamba e ripeti."]}},{"id":"0069","name":"barbell overhead squat","category":"upper legs","equipment":"barbell","target":"quads","secondary":["glutes","hamstrings","calves","core"],"steps":{"en":["Stand with your feet shoulder-width apart and toes slightly turned out.","Hold the barbell with a wide grip, positioning it overhead with your arms fully extended.","Engage your core and lower your body down into a squat position, keeping your chest up and knees tracking over your toes.","Pause for a moment at the bottom, then push through your heels to return to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai con i piedi alla larghezza delle spalle e le dita dei piedi leggermente rivolte verso l'esterno.","Tieni il bilanciere con una presa ampia, posizionandolo sopra la testa con le braccia completamente distese.","Coinvolgi il core e abbassa il corpo in una posizione tozza, mantenendo il petto sollevato e le ginocchia che seguono le dita dei piedi.","Fai una pausa per un momento in fondo, quindi spingi i talloni per tornare alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"1411","name":"barbell palms down wrist curl over a bench","category":"lower arms","equipment":"barbell","target":"forearms","secondary":["biceps","brachialis"],"steps":{"en":["Sit on a bench with your feet flat on the ground and your forearms resting on your thighs, palms facing down.","Hold a barbell with an overhand grip, hands shoulder-width apart.","Lower the barbell towards the ground by flexing your wrists, keeping your forearms stationary.","Pause for a moment at the bottom, then slowly raise the barbell back up by extending your wrists.","Repeat for the desired number of repetitions."],"it":["Siediti su una panca con i piedi appoggiati a terra e gli avambracci appoggiati sulle cosce, con i palmi rivolti verso il basso.","Tieni un bilanciere con una presa prona, le mani alla larghezza delle spalle.","Abbassa il bilanciere verso terra flettendo i polsi e mantenendo gli avambracci fermi.","Fai una pausa per un momento in basso, quindi solleva lentamente il bilanciere estendendo i polsi.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"1412","name":"barbell palms up wrist curl over a bench","category":"lower arms","equipment":"barbell","target":"forearms","secondary":["biceps","shoulders"],"steps":{"en":["Sit on a bench with your feet flat on the ground and hold a barbell with an underhand grip, palms facing up.","Rest your forearms on the bench, allowing your wrists to hang off the edge.","Keeping your forearms stationary, exhale and curl your wrists upwards as far as possible.","Hold the contracted position for a brief pause, then inhale and slowly lower the barbell back to the starting position.","Repeat for the desired number of repetitions."],"it":["Sedersi su una panca con i piedi appoggiati a terra e tenere un bilanciere con una presa subdola, con i palmi rivolti verso l'alto.","Appoggia gli avambracci sulla panca, lasciando che i polsi pendano dal bordo.","Mantenendo gli avambracci fermi, espira e piega i polsi verso l'alto il più possibile.","Mantieni la posizione contratta per una breve pausa, quindi inspira e riporta lentamente il bilanciere nella posizione iniziale.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"3017","name":"barbell pendlay row","category":"back","equipment":"barbell","target":"upper back","secondary":["biceps","forearms"],"steps":{"en":["Stand with your feet shoulder-width apart and your knees slightly bent.","Bend forward at the hips, keeping your back straight and your chest up.","Grasp the barbell with an overhand grip, slightly wider than shoulder-width apart.","Pull the barbell towards your upper abdomen, squeezing your shoulder blades together.","Lower the barbell back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai con i piedi alla larghezza delle spalle e le ginocchia leggermente piegate.","Piegati in avanti sui fianchi, mantenendo la schiena dritta e il petto in alto.","Afferrare il bilanciere con una presa prona, leggermente più larga della larghezza delle spalle.","Tirare il bilanciere verso la parte superiore dell'addome, stringendo insieme le scapole.","Abbassare nuovamente il bilanciere nella posizione iniziale.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"1751","name":"barbell pin presses","category":"upper arms","equipment":"barbell","target":"triceps","secondary":["shoulders"],"steps":{"en":["Set up a barbell on a power rack at chest height.","Stand facing the barbell and position yourself underneath it, with your feet shoulder-width apart.","Grip the barbell with an overhand grip, slightly wider than shoulder-width apart.","Lift the barbell off the rack and hold it directly above your chest, with your arms fully extended.","Lower the barbell down towards your chest, keeping your elbows tucked in close to your body.","Pause for a moment when the barbell touches your chest.","Push the barbell back up to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."],"it":["Posiziona un bilanciere su un power rack all'altezza del petto.","Mettiti di fronte al bilanciere e posizionati sotto di esso, con i piedi alla larghezza delle spalle.","Afferra il bilanciere con una presa prona, leggermente più larga della larghezza delle spalle.","Solleva il bilanciere dal rack e tienilo direttamente sopra il petto, con le braccia completamente distese.","Abbassa il bilanciere verso il petto, mantenendo i gomiti piegati vicino al corpo.","Fai una pausa per un momento quando il bilanciere tocca il tuo petto.","Spingi nuovamente il bilanciere nella posizione iniziale, estendendo completamente le braccia.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0070","name":"barbell preacher curl","category":"upper arms","equipment":"barbell","target":"biceps","secondary":["forearms"],"steps":{"en":["Sit on a preacher bench with your upper arms resting on the pad and your chest against the support.","Grasp the barbell with an underhand grip, slightly wider than shoulder-width apart.","Keeping your upper arms stationary, exhale and curl the barbell up towards your shoulders.","Pause for a moment at the top, squeezing your biceps.","Inhale and slowly lower the barbell back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Siediti su una panca da predicatore con la parte superiore delle braccia appoggiata sul cuscino e il petto contro il supporto.","Afferrare il bilanciere con una presa subdola, leggermente più larga della larghezza delle spalle.","Mantenendo ferma la parte superiore delle braccia, espira e porta il bilanciere verso le spalle.","Fermati un attimo in alto, contraendo i bicipiti.","Inspira e abbassa lentamente il bilanciere nella posizione iniziale.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0071","name":"barbell press sit-up","category":"waist","equipment":"barbell","target":"abs","secondary":["shoulders","chest"],"steps":{"en":["Lie flat on your back on a mat with your knees bent and feet flat on the ground.","Hold the barbell with an overhand grip, resting it on your chest.","Engaging your abs, slowly lift your upper body off the ground, curling forward until your torso is at a 45-degree angle.","Pause for a moment at the top, then slowly lower your upper body back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Sdraiati sulla schiena su un tappetino con le ginocchia piegate e i piedi appoggiati a terra.","Tieni il bilanciere con una presa prona, appoggiandolo sul petto.","Coinvolgendo gli addominali, solleva lentamente la parte superiore del corpo da terra, piegandoti in avanti finché il busto non forma un angolo di 45 gradi.","Fermati per un momento in alto, quindi abbassa lentamente la parte superiore del corpo fino alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0072","name":"barbell prone incline curl","category":"upper arms","equipment":"barbell","target":"biceps","secondary":["forearms"],"steps":{"en":["Set up an incline bench at a 45-degree angle.","Lie face down on the bench with your chest and stomach resting against it.","Hold a barbell with an underhand grip, shoulder-width apart.","Extend your arms fully, allowing the barbell to hang down towards the floor.","Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the barbell until your biceps are fully contracted and the bar is at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the barbell back to the starting position.","Repeat for the desired number of repetitions."],"it":["Installa una panca inclinata con un angolo di 45 gradi.","Sdraiati a faccia in giù sulla panca con il petto e lo stomaco appoggiati contro di essa.","Tieni un bilanciere con una presa subdola, alla larghezza delle spalle.","Estendi completamente le braccia, lasciando che il bilanciere penda verso il pavimento.","Mantenendo ferma la parte superiore delle braccia, espira e piega i pesi contraendo i bicipiti.","Continua a sollevare il bilanciere finché i bicipiti non sono completamente contratti e la barra è all'altezza delle spalle.","Mantieni la posizione contratta per una breve pausa mentre contrai i bicipiti.","Inspira e inizia lentamente ad abbassare il bilanciere nella posizione iniziale.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0073","name":"barbell pullover","category":"back","equipment":"barbell","target":"lats","secondary":["chest","triceps"],"steps":{"en":["Lie flat on a bench with your head at one end and your feet on the floor.","Hold a barbell with a shoulder-width grip and extend your arms straight above your chest.","Keeping your arms straight, lower the barbell behind your head in a controlled manner until you feel a stretch in your lats.","Pause for a moment, then raise the barbell back to the starting position.","Repeat for the desired number of repetitions."],"it":["Sdraiati su una panca con la testa da un lato e i piedi sul pavimento.","Tieni un bilanciere con una presa alla larghezza delle spalle ed estendi le braccia direttamente sopra il petto.","Tenendo le braccia tese, abbassa il bilanciere dietro la testa in modo controllato finché non senti un allungamento nei dorsali.","Fare una pausa per un momento, quindi riportare il bilanciere nella posizione iniziale.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0022","name":"barbell pullover to press","category":"back","equipment":"barbell","target":"lats","secondary":["triceps","chest","shoulders"],"steps":{"en":["Lie flat on a bench with your head at one end and your feet on the ground.","Hold the barbell with a pronated grip (palms facing away from you) and extend your arms straight above your chest.","Keeping your arms straight, lower the barbell behind your head in an arc-like motion until you feel a stretch in your lats.","Pause for a moment, then reverse the motion and press the barbell back to the starting position above your chest.","Repeat for the desired number of repetitions."],"it":["Sdraiati su una panca con la testa da un lato e i piedi a terra.","Tieni il bilanciere con una presa prona (palmi rivolti lontano da te) ed estendi le braccia direttamente sopra il petto.","Tenendo le braccia tese, abbassa il bilanciere dietro la testa con un movimento ad arco finché non senti un allungamento nei dorsali.","Fai una pausa per un momento, quindi inverti il ​​movimento e riporta il bilanciere nella posizione iniziale sopra il petto.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0074","name":"barbell rack pull","category":"upper legs","equipment":"barbell","target":"glutes","secondary":["hamstrings","lower back"],"steps":{"en":["Set up a barbell on a rack at knee height.","Stand with your feet shoulder-width apart, toes pointing slightly outwards.","Bend at the hips and knees to lower yourself down and grip the barbell with an overhand grip, hands shoulder-width apart.","Engage your core and lift the barbell by extending your hips and knees, pulling your shoulders back and squeezing your glutes at the top.","Lower the barbell back down to the starting position by bending at the hips and knees.","Repeat for the desired number of repetitions."],"it":["Posiziona un bilanciere su una rastrelliera all'altezza del ginocchio.","Stare con i piedi alla larghezza delle spalle, le dita dei piedi leggermente rivolte verso l'esterno.","Piegati sui fianchi e sulle ginocchia per abbassarti e afferra il bilanciere con una presa prona, con le mani alla larghezza delle spalle.","Coinvolgi il core e solleva il bilanciere estendendo le anche e le ginocchia, tirando indietro le spalle e contraendo i glutei in alto.","Abbassare il bilanciere nella posizione iniziale piegando le anche e le ginocchia.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0075","name":"barbell rear delt raise","category":"shoulders","equipment":"barbell","target":"delts","secondary":["traps","rhomboids"],"steps":{"en":["Stand with your feet shoulder-width apart and hold a barbell with an overhand grip, palms facing down.","Bend your knees slightly and hinge forward at the hips, keeping your back straight.","Raise the barbell out to the sides, keeping your arms straight, until they are parallel to the ground.","Pause for a moment at the top, then slowly lower the barbell back to the starting position.","Repeat for the desired number of repetitions."],"it":["Stare con i piedi alla larghezza delle spalle e tenere un bilanciere con una presa prona, i palmi rivolti verso il basso.","Piega leggermente le ginocchia e fai perno in avanti sui fianchi, mantenendo la schiena dritta.","Sollevare il bilanciere lateralmente, mantenendo le braccia tese, finché non saranno parallele al suolo.","Fermati per un momento in alto, quindi abbassa lentamente il bilanciere nella posizione iniziale.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0076","name":"barbell rear delt row","category":"shoulders","equipment":"barbell","target":"delts","secondary":["trapezius","rhomboids","biceps"],"steps":{"en":["Stand with your feet shoulder-width apart and knees slightly bent.","Hold a barbell with an overhand grip, hands slightly wider than shoulder-width apart.","Bend forward at the hips, keeping your back straight and chest up.","Pull the barbell towards your chest, squeezing your shoulder blades together.","Pause for a moment at the top, then slowly lower the barbell back to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai in piedi con i piedi alla larghezza delle spalle e le ginocchia leggermente piegate.","Tieni un bilanciere con una presa prona, con le mani leggermente più larghe della larghezza delle spalle.","Piegati in avanti sui fianchi, mantenendo la schiena dritta e il petto in alto.","Tirare il bilanciere verso il petto, stringendo insieme le scapole.","Fermati per un momento in alto, quindi abbassa lentamente il bilanciere nella posizione iniziale.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0078","name":"barbell rear lunge","category":"upper legs","equipment":"barbell","target":"glutes","secondary":["quadriceps","hamstrings","calves"],"steps":{"en":["Start by standing with your feet shoulder-width apart and a barbell resting on your upper back.","Take a step backward with your right foot, landing on the ball of your foot.","Bend both knees to lower your body until your left thigh is parallel to the ground.","Push through your left heel to return to the starting position.","Repeat with the other leg."],"it":["Inizia stando in piedi con i piedi alla larghezza delle spalle e un bilanciere appoggiato sulla parte superiore della schiena.","Fai un passo indietro con il piede destro, atterrando sulla pianta del piede.","Piega entrambe le ginocchia per abbassare il corpo finché la coscia sinistra non è parallela al suolo.","Spingi attraverso il tallone sinistro per tornare alla posizione di partenza.","Ripeti con l'altra gamba."]}},{"id":"0077","name":"barbell rear lunge v. 2","category":"upper legs","equipment":"barbell","target":"glutes","secondary":["quadriceps","hamstrings","calves"],"steps":{"en":["Stand with your feet shoulder-width apart and hold a barbell across your upper back.","Take a step backward with your right foot, landing on the ball of your foot.","Bend both knees to lower your body until your left thigh is parallel to the ground.","Push through your left heel to return to the starting position.","Repeat with the other leg."],"it":["Stai con i piedi alla larghezza delle spalle e tieni un bilanciere sulla parte superiore della schiena.","Fai un passo indietro con il piede destro, atterrando sulla pianta del piede.","Piega entrambe le ginocchia per abbassare il corpo finché la coscia sinistra non è parallela al suolo.","Spingi attraverso il tallone sinistro per tornare alla posizione di partenza.","Ripeti con l'altra gamba."]}},{"id":"0079","name":"barbell revers wrist curl v. 2","category":"lower arms","equipment":"barbell","target":"forearms","secondary":["biceps","brachialis"],"steps":{"en":["Sit on a bench with your feet flat on the ground and your knees bent.","Hold a barbell with an overhand grip, palms facing down, and your hands shoulder-width apart.","Rest your forearms on your thighs, allowing your wrists to hang off the edge.","Keeping your forearms stationary, exhale and curl your wrists upward as far as possible.","Hold the contracted position for a brief pause, then inhale and slowly lower the barbell back to the starting position.","Repeat for the desired number of repetitions."],"it":["Siediti su una panchina con i piedi appoggiati a terra e le ginocchia piegate.","Tieni un bilanciere con una presa prona, i palmi rivolti verso il basso e le mani alla larghezza delle spalle.","Appoggia gli avambracci sulle cosce, lasciando che i polsi pendano dal bordo.","Mantenendo gli avambracci fermi, espira e piega i polsi verso l'alto il più possibile.","Mantieni la posizione contratta per una breve pausa, quindi inspira e riporta lentamente il bilanciere nella posizione iniziale.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"2187","name":"barbell reverse close-grip bench press","category":"upper arms","equipment":"barbell","target":"triceps","secondary":["chest","shoulders"],"steps":{"en":["Lie flat on a bench with your feet flat on the ground and your back pressed against the bench.","Grasp the barbell with a reverse grip, hands shoulder-width apart.","Lift the barbell off the rack and hold it directly above your chest with your arms fully extended.","Slowly lower the barbell down towards your chest, keeping your elbows close to your body.","Pause for a moment when the barbell is just above your chest.","Push the barbell back up to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."],"it":["Sdraiati su una panca con i piedi appoggiati a terra e la schiena premuta contro la panca.","Afferrare il bilanciere con una presa inversa, con le mani alla larghezza delle spalle.","Solleva il bilanciere dal rack e tienilo direttamente sopra il petto con le braccia completamente distese.","Abbassa lentamente il bilanciere verso il petto, mantenendo i gomiti vicini al corpo.","Fai una pausa per un momento quando il bilanciere è appena sopra il petto.","Spingi nuovamente il bilanciere nella posizione iniziale, estendendo completamente le braccia.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0080","name":"barbell reverse curl","category":"upper arms","equipment":"barbell","target":"biceps","secondary":["forearms"],"steps":{"en":["Stand up straight with your feet shoulder-width apart and hold a barbell with an overhand grip, palms facing down.","Keep your upper arms stationary and exhale as you curl the barbell upward, contracting your biceps.","Continue to raise the barbell until your biceps are fully contracted and the barbell is at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale as you slowly lower the barbell back to the starting position, keeping your upper arms stationary.","Repeat for the desired number of repetitions."],"it":["Stai dritto con i piedi alla larghezza delle spalle e tieni un bilanciere con una presa prona, i palmi rivolti verso il basso.","Mantieni ferma la parte superiore delle braccia ed espira mentre pieghi il bilanciere verso l'alto, contraendo i bicipiti.","Continua a sollevare il bilanciere finché i bicipiti non saranno completamente contratti e il bilanciere sarà all'altezza delle spalle.","Mantieni la posizione contratta per una breve pausa mentre contrai i bicipiti.","Inspira mentre abbassi lentamente il bilanciere nella posizione iniziale, mantenendo ferma la parte superiore delle braccia.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0118","name":"barbell reverse grip bent over row","category":"back","equipment":"barbell","target":"upper back","secondary":["biceps","forearms"],"steps":{"en":["Stand with your feet shoulder-width apart and knees slightly bent.","Hold a barbell with an overhand grip, palms facing down, and hands slightly wider than shoulder-width apart.","Bend forward at the hips, keeping your back straight and chest up, until your torso is almost parallel to the floor.","Pull the barbell towards your lower chest, squeezing your shoulder blades together.","Pause for a moment at the top, then slowly lower the barbell back to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai in piedi con i piedi alla larghezza delle spalle e le ginocchia leggermente piegate.","Tieni un bilanciere con una presa prona, i palmi rivolti verso il basso e le mani leggermente più larghe della larghezza delle spalle.","Piegati in avanti all'altezza dei fianchi, mantenendo la schiena dritta e il petto in alto, finché il busto non sarà quasi parallelo al pavimento.","Tirare il bilanciere verso la parte inferiore del torace, stringendo insieme le scapole.","Fermati per un momento in alto, quindi abbassa lentamente il bilanciere nella posizione iniziale.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"1256","name":"barbell reverse grip decline bench press","category":"chest","equipment":"barbell","target":"pectorals","secondary":["triceps","shoulders"],"steps":{"en":["Lie on a decline bench with your feet secured and your head lower than your hips.","Grasp the barbell with a reverse grip, slightly wider than shoulder-width apart.","Unrack the barbell and lower it slowly towards your chest, keeping your elbows tucked in.","Pause for a moment at the bottom, then push the barbell back up to the starting position.","Repeat for the desired number of repetitions."],"it":["Sdraiati su una panca declinata con i piedi fissati e la testa più in basso rispetto ai fianchi.","Afferrare il bilanciere con una presa inversa, leggermente più largo della larghezza delle spalle.","Togli il bilanciere e abbassalo lentamente verso il petto, mantenendo i gomiti piegati.","Fermati per un momento in basso, quindi riporta il bilanciere nella posizione iniziale.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"1257","name":"barbell reverse grip incline bench press","category":"chest","equipment":"barbell","target":"pectorals","secondary":["triceps","shoulders"],"steps":{"en":["Set up an incline bench at a 45-degree angle.","Lie down on the bench with your feet flat on the ground.","Grasp the barbell with a reverse grip, hands slightly wider than shoulder-width apart.","Unrack the barbell and lower it slowly towards your chest, keeping your elbows tucked in.","Pause for a moment when the barbell touches your chest.","Push the barbell back up to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."],"it":["Installa una panca inclinata con un angolo di 45 gradi.","Sdraiati sulla panca con i piedi appoggiati a terra.","Afferrare il bilanciere con una presa inversa, le mani leggermente più larghe della larghezza delle spalle.","Togli il bilanciere e abbassalo lentamente verso il petto, mantenendo i gomiti piegati.","Fai una pausa per un momento quando il bilanciere tocca il tuo petto.","Spingi nuovamente il bilanciere nella posizione iniziale, estendendo completamente le braccia.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"1317","name":"barbell reverse grip incline bench row","category":"back","equipment":"barbell","target":"upper back","secondary":["biceps","forearms"],"steps":{"en":["Set up an incline bench at a 45-degree angle.","Sit on the bench facing the backrest with your chest against it.","Grab the barbell with a reverse grip (palms facing down) and hands slightly wider than shoulder-width apart.","Keep your back straight and core engaged.","Pull the barbell towards your upper abdomen, squeezing your shoulder blades together.","Pause for a moment at the top of the movement.","Slowly lower the barbell back to the starting position.","Repeat for the desired number of repetitions."],"it":["Installa una panca inclinata con un angolo di 45 gradi.","Sedersi sulla panca di fronte allo schienale con il petto appoggiato ad esso.","Afferra il bilanciere con una presa inversa (palmi rivolti verso il basso) e le mani leggermente più larghe della larghezza delle spalle.","Tieni la schiena dritta e il core impegnato.","Tirare il bilanciere verso la parte superiore dell'addome, stringendo insieme le scapole.","Fermati un attimo nella parte superiore del movimento.","Abbassa lentamente il bilanciere nella posizione iniziale.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"1721","name":"barbell reverse grip skullcrusher","category":"upper arms","equipment":"barbell","target":"triceps","secondary":["forearms"],"steps":{"en":["Lie flat on a bench with your feet flat on the ground and your head at the end of the bench.","Hold the barbell with a reverse grip, palms facing towards your face, and your hands shoulder-width apart.","Extend your arms straight up over your chest, keeping your elbows in and your wrists straight.","Slowly lower the barbell towards your forehead by bending your elbows, keeping your upper arms stationary.","Pause for a moment at the bottom, then extend your arms back up to the starting position.","Repeat for the desired number of repetitions."],"it":["Sdraiati su una panca con i piedi appoggiati a terra e la testa all'estremità della panca.","Tieni il bilanciere con una presa inversa, i palmi rivolti verso il viso e le mani alla larghezza delle spalle.","Estendi le braccia verso l'alto sul petto, mantenendo i gomiti e i polsi dritti.","Abbassa lentamente il bilanciere verso la fronte piegando i gomiti e mantenendo ferma la parte superiore delle braccia.","Fai una pausa per un momento in basso, quindi allunga le braccia fino alla posizione iniziale.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0081","name":"barbell reverse preacher curl","category":"upper arms","equipment":"barbell","target":"biceps","secondary":["forearms"],"steps":{"en":["Sit on a preacher bench with your chest against the pad and your arms extended straight down, holding a barbell with an overhand grip.","Keeping your upper arms stationary, exhale and curl the barbell upward while contracting your biceps.","Continue to raise the barbell until your biceps are fully contracted and the barbell is at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly lower the barbell back to the starting position.","Repeat for the desired number of repetitions."],"it":["Siediti su una panca da predicatore con il petto contro il cuscino e le braccia distese verso il basso, tenendo un bilanciere con una presa prona.","Mantenendo ferma la parte superiore delle braccia, espira e piega il bilanciere verso l'alto contraendo i bicipiti.","Continua a sollevare il bilanciere finché i bicipiti non saranno completamente contratti e il bilanciere sarà all'altezza delle spalle.","Mantieni la posizione contratta per una breve pausa mentre contrai i bicipiti.","Inspira e abbassa lentamente il bilanciere nella posizione iniziale.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0082","name":"barbell reverse wrist curl","category":"lower arms","equipment":"barbell","target":"forearms","secondary":["biceps","brachialis"],"steps":{"en":["Sit on a bench with your feet flat on the ground and hold a barbell with an overhand grip, palms facing down.","Rest your forearms on your thighs, allowing your wrists to hang off the edge.","Slowly curl your wrists upward, bringing the barbell towards your body.","Pause for a moment at the top, then slowly lower the barbell back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Sedersi su una panca con i piedi appoggiati a terra e tenere un bilanciere con una presa prona, i palmi rivolti verso il basso.","Appoggia gli avambracci sulle cosce, lasciando che i polsi pendano dal bordo.","Piega lentamente i polsi verso l'alto, portando il bilanciere verso il tuo corpo.","Fermati per un momento in alto, quindi abbassa lentamente il bilanciere nella posizione iniziale.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0084","name":"barbell rollerout","category":"waist","equipment":"barbell","target":"abs","secondary":["lower back"],"steps":{"en":["Kneel on the floor and hold a barbell with both hands, shoulder-width apart.","Roll the barbell forward, extending your arms and keeping your core engaged.","Continue rolling forward until your body is fully extended and your arms are overhead.","Pause for a moment, then slowly roll the barbell back towards your knees, maintaining control.","Repeat for the desired number of repetitions."],"it":["Inginocchiarsi sul pavimento e tenere un bilanciere con entrambe le mani, alla larghezza delle spalle.","Fai rotolare il bilanciere in avanti, estendendo le braccia e mantenendo il core impegnato.","Continua a rotolare in avanti finché il corpo non è completamente esteso e le braccia sono sopra la testa.","Fai una pausa per un momento, quindi ruota lentamente il bilanciere verso le ginocchia, mantenendo il controllo.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0083","name":"barbell rollerout from bench","category":"waist","equipment":"barbell","target":"abs","secondary":["shoulders","triceps"],"steps":{"en":["Start by kneeling on the floor with a barbell placed on a bench in front of you.","Grasp the barbell with an overhand grip, slightly wider than shoulder-width apart.","Keeping your core engaged and your back straight, slowly roll the barbell forward, extending your arms in front of you.","Continue rolling the barbell forward until your body is fully extended and your arms are overhead.","Pause for a moment at the fully extended position, then slowly roll the barbell back towards your body, returning to the starting position.","Repeat for the desired number of repetitions."],"it":["Inizia in ginocchio sul pavimento con un bilanciere posizionato su una panca di fronte a te.","Afferrare il bilanciere con una presa prona, leggermente più larga della larghezza delle spalle.","Mantenendo il core impegnato e la schiena dritta, fai rotolare lentamente il bilanciere in avanti, estendendo le braccia davanti a te.","Continua a far rotolare il bilanciere in avanti finché il tuo corpo non è completamente esteso e le tue braccia sono sopra la testa.","Fermati per un momento nella posizione completamente estesa, quindi ruota lentamente il bilanciere verso il tuo corpo, tornando alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0085","name":"barbell romanian deadlift","category":"upper legs","equipment":"barbell","target":"glutes","secondary":["hamstrings","lower back"],"steps":{"en":["Stand with your feet shoulder-width apart and your toes pointing forward.","Hold the barbell with an overhand grip, hands slightly wider than shoulder-width apart.","Bend at the hips, keeping your back straight and your knees slightly bent.","Lower the barbell towards the ground, keeping it close to your body.","Feel the stretch in your hamstrings as you lower the barbell.","Once you feel a stretch in your hamstrings, push your hips forward and stand up straight.","Squeeze your glutes at the top of the movement.","Lower the barbell back down to the starting position and repeat for the desired number of repetitions."],"it":["Stai con i piedi alla larghezza delle spalle e le dita dei piedi rivolte in avanti.","Tieni il bilanciere con una presa prona, con le mani leggermente più larghe della larghezza delle spalle.","Piegati sui fianchi, mantenendo la schiena dritta e le ginocchia leggermente piegate.","Abbassa il bilanciere verso terra, tenendolo vicino al corpo.","Senti l'allungamento dei muscoli posteriori della coscia mentre abbassi il bilanciere.","Una volta che senti un allungamento nei muscoli posteriori della coscia, spingi i fianchi in avanti e stai dritto.","Contrai i glutei nella parte superiore del movimento.","Abbassare nuovamente il bilanciere nella posizione iniziale e ripetere per il numero di ripetizioni desiderato."]}},{"id":"0086","name":"barbell seated behind head military press","category":"shoulders","equipment":"barbell","target":"delts","secondary":["triceps","upper back"],"steps":{"en":["Sit on a bench with your back straight and feet flat on the ground.","Hold the barbell with an overhand grip, slightly wider than shoulder-width apart.","Lift the barbell off the rack and bring it down to shoulder level, behind your head.","Press the barbell upward until your arms are fully extended.","Lower the barbell back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Siediti su una panca con la schiena dritta e i piedi appoggiati a terra.","Tieni il bilanciere con una presa prona, leggermente più larga della larghezza delle spalle.","Solleva il bilanciere dal rack e abbassalo all'altezza delle spalle, dietro la testa.","Spingi il bilanciere verso l'alto finché le braccia non sono completamente distese.","Abbassare nuovamente il bilanciere nella posizione iniziale.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0087","name":"barbell seated bradford rocky press","category":"shoulders","equipment":"barbell","target":"delts","secondary":["triceps","upper back"],"steps":{"en":["Sit on a bench with your back straight and feet flat on the ground.","Hold the barbell with an overhand grip, slightly wider than shoulder-width apart.","Lift the barbell to shoulder height, keeping your elbows slightly bent and pointing forward.","Press the barbell overhead, fully extending your arms.","Lower the barbell back to shoulder height and repeat for the desired number of repetitions."],"it":["Siediti su una panca con la schiena dritta e i piedi appoggiati a terra.","Tieni il bilanciere con una presa prona, leggermente più larga della larghezza delle spalle.","Sollevare il bilanciere all'altezza delle spalle, mantenendo i gomiti leggermente piegati e rivolti in avanti.","Premi il bilanciere sopra la testa, estendendo completamente le braccia.","Abbassare il bilanciere all'altezza delle spalle e ripetere per il numero di ripetizioni desiderato."]}},{"id":"0088","name":"barbell seated calf raise","category":"lower legs","equipment":"barbell","target":"calves","secondary":["hamstrings","quadriceps"],"steps":{"en":["Sit on a bench with your feet flat on the floor and a barbell resting on your thighs.","Place the balls of your feet on a raised platform, such as a block or step.","Position the barbell across your thighs and hold it securely with your hands.","Keeping your back straight and your core engaged, lift your heels off the ground by extending your ankles.","Pause for a moment at the top, then slowly lower your heels back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Siediti su una panca con i piedi appoggiati sul pavimento e un bilanciere appoggiato sulle cosce.","Posiziona le punte dei piedi su una piattaforma rialzata, come un blocco o un gradino.","Posiziona il bilanciere sulle cosce e tienilo saldamente con le mani.","Tenendo la schiena dritta e il core impegnato, solleva i talloni da terra estendendo le caviglie.","Fai una pausa per un momento in alto, quindi abbassa lentamente i talloni nella posizione iniziale.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"1371","name":"barbell seated calf raise","category":"lower legs","equipment":"barbell","target":"calves","secondary":["hamstrings"],"steps":{"en":["Sit on a bench with your feet flat on the floor and a barbell resting on your thighs.","Place the balls of your feet on a raised platform, such as a block or step.","Lower your heels as far as possible, feeling a stretch in your calves.","Raise your heels as high as possible, contracting your calves.","Repeat for the desired number of repetitions."],"it":["Siediti su una panca con i piedi appoggiati sul pavimento e un bilanciere appoggiato sulle cosce.","Posiziona le punte dei piedi su una piattaforma rialzata, come un blocco o un gradino.","Abbassa i talloni il più possibile, avvertendo un allungamento nei polpacci.","Alza i talloni il più in alto possibile, contraendo i polpacci.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"1718","name":"barbell seated close grip behind neck triceps extension","category":"upper arms","equipment":"barbell","target":"triceps","secondary":["shoulders"],"steps":{"en":["Sit on a bench with your back straight and feet flat on the ground.","Hold the barbell with a close grip behind your neck, palms facing forward.","Keep your elbows close to your head and slowly lower the barbell towards the back of your head.","Pause for a moment, then extend your arms back up to the starting position.","Repeat for the desired number of repetitions."],"it":["Siediti su una panca con la schiena dritta e i piedi appoggiati a terra.","Tieni il bilanciere con una presa salda dietro il collo, con i palmi rivolti in avanti.","Tieni i gomiti vicini alla testa e abbassa lentamente il bilanciere verso la parte posteriore della testa.","Fai una pausa per un momento, quindi allunga le braccia fino alla posizione iniziale.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0089","name":"barbell seated close-grip concentration curl","category":"upper arms","equipment":"barbell","target":"biceps","secondary":["forearms"],"steps":{"en":["Sit on a bench with your feet flat on the floor and hold a barbell with an underhand grip, hands shoulder-width apart.","Rest your upper arms against your inner thighs, just above your knees, and let the barbell hang down in front of you.","Keeping your upper arms stationary, exhale and curl the barbell up towards your shoulders, contracting your biceps.","Hold the contracted position for a brief pause, then inhale and slowly lower the barbell back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Sedersi su una panca con i piedi appoggiati sul pavimento e tenere un bilanciere con una presa subdola, con le mani alla larghezza delle spalle.","Appoggia la parte superiore delle braccia contro l'interno delle cosce, appena sopra le ginocchia, e lascia che il bilanciere penda davanti a te.","Mantenendo ferma la parte superiore delle braccia, espira e porta il bilanciere verso le spalle, contraendo i bicipiti.","Mantieni la posizione contratta per una breve pausa, quindi inspira e abbassa lentamente il bilanciere nella posizione iniziale.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0090","name":"barbell seated good morning","category":"upper legs","equipment":"barbell","target":"glutes","secondary":["hamstrings","lower back"],"steps":{"en":["Sit on a bench with your feet flat on the ground and a barbell resting on your upper back.","Keep your back straight and your chest up.","Slowly hinge forward at the hips, lowering your torso towards the ground.","Pause for a moment at the bottom, then push through your heels to return to the starting position.","Repeat for the desired number of repetitions."],"it":["Siediti su una panca con i piedi piatti a terra e un bilanciere appoggiato sulla parte alta della schiena.","Tieni la schiena dritta e il petto sollevato.","Inclinati lentamente in avanti ai fianchi, abbassando il busto verso terra.","Fermati un attimo in fondo, poi spingi attraverso i talloni per tornare alla posizione di partenza.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0091","name":"barbell seated overhead press","category":"shoulders","equipment":"barbell","target":"delts","secondary":["triceps","upper back"],"steps":{"en":["Sit on a bench with your back straight and feet flat on the ground.","Hold the barbell with an overhand grip, slightly wider than shoulder-width apart.","Lift the barbell off the rack and bring it to shoulder level, with your elbows bent and palms facing forward.","Press the barbell overhead by extending your arms fully.","Pause for a moment at the top, then slowly lower the barbell back to shoulder level.","Repeat for the desired number of repetitions."],"it":["Siediti su una panchina con la schiena dritta e i piedi piatti a terra.","Tieni il bilanciere con una presa sopra la mano, leggermente più larga della larghezza delle spalle.","Solleva il bilanciere dal portapacchi e portalo all'altezza delle spalle, con i gomiti piegati e i palmi rivolti in avanti.","Premi il bilanciere sopra la testa estendendo completamente le braccia.","Fermati un attimo in cima, poi abbassa lentamente il bilanciere all'altezza delle spalle.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0092","name":"barbell seated overhead triceps extension","category":"upper arms","equipment":"barbell","target":"triceps","secondary":["shoulders"],"steps":{"en":["Sit on a bench with your back straight and feet flat on the ground.","Hold a barbell with an overhand grip, hands shoulder-width apart, and raise it overhead.","Lower the barbell behind your head by bending your elbows, keeping your upper arms close to your head.","Pause for a moment, then extend your arms to raise the barbell back to the starting position.","Repeat for the desired number of repetitions."],"it":["Siediti su una panchina con la schiena dritta e i piedi piatti a terra.","Tieni un bilanciere con una presa sopra la testa, mani alla larghezza delle spalle, e sollevalo sopra la testa.","Abbassa il bilanciere dietro la testa piegando i gomiti, tenendo le braccia superiori vicine alla testa.","Fermati un attimo, poi estendi le braccia per sollevare il bilanciere fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0094","name":"barbell seated twist","category":"waist","equipment":"barbell","target":"abs","secondary":["obliques","lower back"],"steps":{"en":["Sit on a flat bench with your feet flat on the ground and your knees bent.","Hold a barbell with both hands in front of your chest, keeping your elbows slightly bent.","Engage your core and slowly twist your torso to one side, keeping your back straight.","Pause for a moment at the end of the twist, then slowly rotate back to the starting position.","Repeat the twist to the other side.","Continue alternating sides for the desired number of repetitions."],"it":["Siediti su una panchina piatta con i piedi piatti a terra e le ginocchia piegate.","Tieni un bilanciere con entrambe le mani davanti al petto, tenendo i gomiti leggermente piegati.","Attiva il core e ruota lentamente il busto da un lato, mantenendo la schiena dritta.","Fermati un attimo alla fine della torsione, poi ruota lentamente tornando alla posizione iniziale.","Ripeti la torsione dall'altro lato.","Continua ad alternare i lati per il numero desiderato di ripetizioni."]}},{"id":"0095","name":"barbell shrug","category":"back","equipment":"barbell","target":"traps","secondary":["shoulders"],"steps":{"en":["Stand with your feet shoulder-width apart and hold a barbell in front of you with an overhand grip.","Keep your arms straight and your back straight throughout the exercise.","Lift your shoulders up towards your ears as high as possible, squeezing your traps at the top.","Hold for a moment, then slowly lower your shoulders back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai con i piedi alla larghezza delle spalle e tieni un bilanciere davanti a te con una presa sopra la testa.","Mantieni le braccia dritte e la schiena dritta durante tutto l'esercizio.","Alza le spalle verso le orecchie il più possibile, stringendo i trapezi in alto.","Tieni per un momento, poi abbassa lentamente le spalle fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0096","name":"barbell side bent v. 2","category":"waist","equipment":"barbell","target":"abs","secondary":["obliques","lower back"],"steps":{"en":["Stand with your feet shoulder-width apart and hold a barbell with both hands, palms facing down.","Keep your back straight and core engaged throughout the exercise.","Slowly bend your torso to the right side, lowering the barbell towards your right knee.","Pause for a moment, then return to the starting position.","Repeat the movement on the left side.","Continue alternating sides for the desired number of repetitions."],"it":["Stai con i piedi a larghezza delle spalle e tieni un bilanciere con entrambe le mani, palmi rivolti verso il basso.","Mantieni la schiena dritta e il core impegnato durante tutto l'esercizio.","Piega lentamente il busto verso il lato destro, abbassando il bilanciere verso il ginocchio destro.","Fermati un attimo, poi torna alla posizione iniziale.","Ripeti il movimento sul lato sinistro.","Continua ad alternare i lati per il numero desiderato di ripetizioni."]}},{"id":"0098","name":"barbell side split squat","category":"upper legs","equipment":"barbell","target":"quads","secondary":["glutes","hamstrings","calves"],"steps":{"en":["Stand with your feet wider than shoulder-width apart, toes pointing slightly outward.","Hold a barbell across your upper back, resting it on your traps.","Engage your core and keep your chest up as you lower your body down into a squat position, bending at the knees and hips.","As you lower, push your knees out to the sides and keep your weight on your heels.","Lower until your thighs are parallel to the ground, then push through your heels to return to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai in piedi con i piedi più larghi delle spalle, le dita leggermente rivolte verso l'esterno.","Tieni un bilanciere sulla parte alta della schiena, appoggiandolo sui trapezi.","Attiva il core e tieni il petto sollevato mentre abbassi il corpo in posizione accovacciata, piegando ginocchia e fianchi.","Mentre ti abbassi, spingi le ginocchia verso i lati e tieni il peso sui talloni.","Abbassa finché le cosce non sono parallele al suolo, poi spingi attraverso i talloni per tornare alla posizione di partenza.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0097","name":"barbell side split squat v. 2","category":"upper legs","equipment":"barbell","target":"quads","secondary":["glutes","hamstrings","calves"],"steps":{"en":["Stand with your feet wider than shoulder-width apart, toes pointing slightly outwards.","Hold a barbell across your upper back, resting it on your shoulders.","Take a big step to the side with your right foot, keeping your left foot planted.","Bend your right knee and lower your body down into a squat position, keeping your chest up and your back straight.","Push through your right heel to return to the starting position.","Repeat on the other side, stepping out with your left foot.","Continue alternating sides for the desired number of repetitions."],"it":["Stai in piedi con i piedi più larghi delle spalle, con le dita leggermente rivolte verso l'esterno.","Tieni un bilanciere sulla parte alta della schiena, appoggiandolo sulle spalle.","Fai un grande passo di lato con il piede destro, mantenendo il sinistro piantato.","Flette il ginocchio destro e abbassa il corpo in posizione accovacciata, mantenendo il petto sollevato e la schiena dritta.","Spingi attraverso il tallone destro per tornare alla posizione di partenza.","Ripeti dall'altro lato, facendo un passo avanti con il piede sinistro.","Continua ad alternare i lati per il numero desiderato di ripetizioni."]}},{"id":"1756","name":"barbell single leg deadlift","category":"upper legs","equipment":"barbell","target":"glutes","secondary":["hamstrings","lower back"],"steps":{"en":["Stand with your feet hip-width apart, holding a barbell in front of your thighs with an overhand grip.","Shift your weight onto your left foot and lift your right foot slightly off the ground.","Hinge forward at the hips, keeping your back straight and your right leg extended behind you for balance.","Lower the barbell towards the ground, keeping it close to your body and your left leg slightly bent.","Pause for a moment at the bottom, then engage your glutes and hamstrings to lift your torso back up to the starting position.","Repeat for the desired number of repetitions, then switch sides."],"it":["Stai con i piedi larghi i fianchi, tenendo un bilanciere davanti alle cosce con una presa sopra la testa.","Sposta il peso sul piede sinistro e solleva leggermente il piede destro da terra.","Piega in avanti ai fianchi, mantenendo la schiena dritta e la gamba destra estesa dietro di te per mantenere l'equilibrio.","Abbassa il bilanciere verso terra, tenendolo vicino al corpo e la gamba sinistra leggermente piegata.","Fermati un attimo in basso, poi attiva glutei e muscoli posteriori femorale per sollevare il busto fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni, poi cambia lato."]}},{"id":"0099","name":"barbell single leg split squat","category":"upper legs","equipment":"barbell","target":"quads","secondary":["glutes","hamstrings","calves"],"steps":{"en":["Stand with your feet shoulder-width apart, holding a barbell across your upper back.","Take a large step forward with one leg, keeping your torso upright.","Lower your body by bending your front knee and hip, while keeping your back leg straight.","Continue lowering until your front thigh is parallel to the ground.","Pause for a moment, then push through your front heel to return to the starting position.","Repeat for the desired number of repetitions, then switch legs."],"it":["Stai con i piedi divaricati alla larghezza delle spalle, tenendo una barra sulla parte alta della schiena.","Fai un grande passo avanti con una gamba, mantenendo il busto dritto.","Abbassa il corpo piegando il ginocchio anteriore e il fianco, mantenendo la gamba posteriore dritta.","Continua ad abbassare finché la coscia anteriore non è parallela al suolo.","Fermati un attimo, poi spingi attraverso il tallone anteriore per tornare alla posizione di partenza.","Ripeti per il numero desiderato di ripetizioni, poi cambia gamba."]}},{"id":"2799","name":"barbell sitted alternate leg raise","category":"waist","equipment":"barbell","target":"abs","secondary":["hip flexors"],"steps":{"en":["Sit on a bench with your back straight and hold a barbell across your thighs.","Keeping your legs straight, lift one leg up as high as possible while keeping the other leg on the ground.","Lower the raised leg back down and repeat with the other leg.","Continue alternating legs for the desired number of repetitions."],"it":["Siediti su una panca con la schiena dritta e tieni un bilanciere sopra le cosce.","Tieni le gambe dritte, solleva una gamba il più in alto possibile mentre tieni l'altra a terra.","Abbassa di nuovo la gamba sollevata e ripeti con l'altra gamba.","Continua ad alternare le gambe per il numero desiderato di ripetizioni."]}},{"id":"2800","name":"barbell sitted alternate leg raise (female)","category":"waist","equipment":"barbell","target":"abs","secondary":["hip flexors","quadriceps"],"steps":{"en":["Sit on a bench with your back straight and hold a barbell across your thighs.","Place your hands on the sides of the bench for support.","Keeping your legs straight, lift one leg up as high as possible while keeping it parallel to the ground.","Lower the leg back down and repeat with the other leg.","Continue alternating legs for the desired number of repetitions."],"it":["Siediti su una panca con la schiena dritta e tieni un bilanciere sopra le cosce.","Appoggia le mani ai lati della panca per sostenerti.","Tenendo le gambe dritte, solleva una gamba il più in alto possibile mantenendola parallela al suolo.","Abbassa di nuovo la gamba e ripeti con l'altra gamba.","Continua ad alternare le gambe per il numero desiderato di ripetizioni."]}},{"id":"0100","name":"barbell skier","category":"shoulders","equipment":"barbell","target":"delts","secondary":["triceps","core"],"steps":{"en":["Stand with your feet shoulder-width apart and hold a barbell in front of your thighs with an overhand grip.","Bend your knees slightly and hinge forward at the hips, keeping your back straight and chest up.","Simultaneously lift the barbell up towards your shoulders while jumping slightly off the ground.","As you reach the top of the movement, quickly reverse the motion and lower the barbell back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai con i piedi a larghezza delle spalle e tieni un bilanciere davanti alle cosce con una presa sopra la mano.","Flette leggermente le ginocchia e piega in avanti sui fianchi, mantenendo la schiena dritta e il petto sollevato.","Contemporaneamente solleva il bilanciere verso le spalle saltando leggermente da terra.","Quando raggiungi la parte alta del movimento, inverti rapidamente il movimento e abbassa il bilanciere fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0101","name":"barbell speed squat","category":"upper legs","equipment":"barbell","target":"glutes","secondary":["quadriceps","hamstrings","calves"],"steps":{"en":["Stand with your feet shoulder-width apart, toes slightly turned out.","Hold the barbell across your upper back, resting it on your traps or rear delts.","Engage your core and keep your chest up as you lower your hips back and down, as if sitting into a chair.","Lower until your thighs are parallel to the ground, or as low as you can comfortably go.","Drive through your heels to stand back up, squeezing your glutes at the top.","Repeat for the desired number of repetitions."],"it":["Stai in piedi con i piedi alla larghezza delle spalle, le dita leggermente rivolte verso l'esterno.","Tieni la barra sopra la parte superiore della schiena, appoggiandola sui trapezi o sui deltoidi posteriori.","Attiva il core e tieni il petto sollevato mentre abbassi i fianchi all'indietro e verso il basso, come se fossi seduto su una sedia.","Abbassa finché le cosce non sono parallele al suolo, o il più in basso che puoi andare comodamente.","Spingi attraverso i talloni per rialzarti, stringendo i glutei in alto.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"2810","name":"barbell split squat v. 2","category":"upper legs","equipment":"barbell","target":"quads","secondary":["glutes","hamstrings","calves"],"steps":{"en":["Start by standing with your feet shoulder-width apart, holding a barbell across your upper back.","Take a large step forward with your right foot, keeping your torso upright.","Lower your body by bending your knees and hips until your right thigh is parallel to the ground.","Pause for a moment, then push through your right heel to return to the starting position.","Repeat with your left leg forward for the desired number of repetitions."],"it":["Inizia stando in piedi con i piedi a larghezza delle spalle, tenendo una barra sulla parte superiore della schiena.","Fai un grande passo avanti con il piede destro, mantenendo il busto eretto.","Abbassa il corpo piegando ginocchia e anche finché la coscia destra non è parallela al suolo.","Fermati un attimo, poi spingi attraverso il tallone destro per tornare alla posizione di partenza.","Ripeti con la gamba sinistra in avanti per il numero desiderato di ripetizioni."]}},{"id":"0102","name":"barbell squat (on knees)","category":"upper legs","equipment":"barbell","target":"quads","secondary":["glutes","hamstrings","calves"],"steps":{"en":["Start by kneeling on the ground with your knees hip-width apart and your toes pointing forward.","Place a barbell across your shoulders, gripping it with an overhand grip and your hands slightly wider than shoulder-width apart.","Engage your core and keep your chest lifted as you slowly lower your body down by bending your knees, keeping your back straight.","Continue lowering until your thighs are parallel to the ground, or as low as you can comfortably go.","Pause for a moment at the bottom, then push through your heels to return to the starting position.","Repeat for the desired number of repetitions."],"it":["Inizia inginocchiandoti a terra con le ginocchia larghe all'altezza dei fianchi e le dita dei piedi rivolte in avanti.","Metti un bilanciere sulle spalle, stringendolo con una presa sopra la mano e con le mani leggermente più larghe della larghezza delle spalle.","Attiva il core e tieni il petto sollevato mentre abbassi lentamente il corpo piegando le ginocchia e mantenendo la schiena dritta.","Continua ad abbassare finché le cosce non sono parallele al suolo, o il più in basso che puoi comodamente.","Fermati un attimo in fondo, poi spingi attraverso i talloni per tornare alla posizione di partenza.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"2798","name":"barbell squat jump step rear lunge","category":"upper legs","equipment":"barbell","target":"quads","secondary":["glutes","hamstrings","calves"],"steps":{"en":["Start by standing with your feet shoulder-width apart, holding a barbell across your upper back.","Lower your body into a squat position by bending your knees and pushing your hips back.","Explode upwards, jumping off the ground as high as you can.","Land softly on your feet and immediately step back with one leg into a reverse lunge.","Lower your body down until your front thigh is parallel to the ground, keeping your back straight.","Push through your front heel to return to the starting position.","Repeat the jump and lunge sequence on the other leg.","Continue alternating legs for the desired number of repetitions."],"it":["Inizia stando in piedi con i piedi a larghezza delle spalle, tenendo una barra sulla parte superiore della schiena.","Abbassa il corpo in posizione accovacciata piegando le ginocchia e spingendo i fianchi all'indietro.","Esplodi verso l'alto, saltando da terra il più in alto possibile.","Atterra dolcemente sui piedi e subito indietro con una gamba in un affondo inverso.","Abbassa il corpo finché la coscia anteriore non è parallela al suolo, mantenendo la schiena dritta.","Spingi attraverso il tallone anteriore per tornare alla posizione di partenza.","Ripeti la sequenza di salto e affondo sull'altra gamba.","Continua ad alternare le gambe per il numero desiderato di ripetizioni."]}},{"id":"0103","name":"barbell standing ab rollerout","category":"waist","equipment":"barbell","target":"abs","secondary":["shoulders","lower back"],"steps":{"en":["Stand upright with your feet shoulder-width apart and hold the barbell with both hands in front of your thighs.","Engage your core and slowly roll the barbell down towards the ground, keeping your back straight and your arms extended.","Continue rolling the barbell forward until your body is fully extended and your hands are directly above your head.","Pause for a moment, then slowly roll the barbell back towards your thighs, maintaining control and keeping your core engaged.","Repeat for the desired number of repetitions."],"it":["Stai in piedi dritto con i piedi larghi le spalle e tieni il bilanciere con entrambe le mani davanti alle cosce.","Attiva il core e fai rotolare lentamente la barra verso terra, mantenendo la schiena dritta e le braccia estese.","Continua a far rotolare il bilanciere in avanti finché il corpo non è completamente esteso e le mani sono direttamente sopra la testa.","Fermati un attimo, poi fai ruotare lentamente il bilanciere verso le cosce, mantenendo il controllo e il core attivo.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0104","name":"barbell standing back wrist curl","category":"lower arms","equipment":"barbell","target":"forearms","secondary":["biceps","shoulders"],"steps":{"en":["Stand up straight with your feet shoulder-width apart and hold a barbell with an overhand grip.","Rest the barbell on the back of your hands with your palms facing down and your fingers pointing towards your body.","Keeping your upper arms stationary, exhale and curl your wrists upwards as far as possible.","Hold the contracted position for a brief pause, then inhale and slowly lower the barbell back to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai dritto con i piedi alla larghezza delle spalle e tieni un bilanciere con una presa sopra la mano.","Appoggia il bilanciere sul dorso delle mani con i palmi rivolti verso il basso e le dita puntate verso il corpo.","Mantenendo ferme le braccia superiori, espira e arriccia i polsi verso l'alto il più possibile.","Mantieni la posizione contratta per una breve pausa, poi inspira e abbassa lentamente il bilanciere fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0105","name":"barbell standing bradford press","category":"shoulders","equipment":"barbell","target":"delts","secondary":["triceps","upper back"],"steps":{"en":["Stand with your feet shoulder-width apart and hold the barbell in front of your shoulders with an overhand grip.","Press the barbell overhead, fully extending your arms.","Lower the barbell back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai con i piedi divaricati alla larghezza delle spalle e tieni il bilanciere davanti alle spalle con una presa sopra la mano.","Premi il bilanciere sopra la testa, estendendo completamente le braccia.","Abbassa il bilanciere fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"1372","name":"barbell standing calf raise","category":"lower legs","equipment":"barbell","target":"calves","secondary":["hamstrings","glutes"],"steps":{"en":["Stand with your feet shoulder-width apart and place a barbell across your upper back.","Raise your heels off the ground as high as possible, using only your toes.","Pause for a moment at the top, then slowly lower your heels back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai con i piedi a larghezza delle spalle e posiziona una barra sulla parte superiore della schiena.","Alza i talloni da terra il più in alto possibile, usando solo le dita dei piedi.","Fermati un attimo in cima, poi abbassa lentamente i talloni fino alla posizione di partenza.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0106","name":"barbell standing close grip curl","category":"upper arms","equipment":"barbell","target":"biceps","secondary":["forearms"],"steps":{"en":["Stand up straight with your feet shoulder-width apart and hold a barbell with an underhand grip, hands close together.","Keep your elbows close to your torso and your upper arms stationary throughout the movement.","Exhale as you curl the weights while contracting your biceps. Continue to raise the bar until your biceps are fully contracted and the bar is at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale as you slowly begin to bring the barbell back to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai dritto con i piedi alla larghezza delle spalle e tieni un bilanciere con una presa sottomano, mani vicine.","Tieni i gomiti vicini al busto e le braccia superiori ferme durante tutto il movimento.","Espira mentre piedi i pesi contraendo i bicipiti. Continua ad alzare la barra finché i bicipiti non sono completamente contratti e la barra non è all'altezza delle spalle.","Mantieni la posizione contratta per una breve pausa mentre stringi i bicipiti.","Inspira mentre inizi lentamente a riportare il bilanciere alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"1456","name":"barbell standing close grip military press","category":"shoulders","equipment":"barbell","target":"delts","secondary":["triceps","upper back"],"steps":{"en":["Stand with your feet shoulder-width apart and hold the barbell with an overhand grip, hands slightly closer than shoulder-width apart.","Lift the barbell to shoulder height, keeping your elbows close to your body.","Press the barbell overhead, extending your arms fully.","Lower the barbell back to shoulder height.","Repeat for the desired number of repetitions."],"it":["Stai con i piedi a larghezza delle spalle e tieni il bilanciere con una presa sopra la mano, le mani leggermente più vicine rispetto alla larghezza delle spalle.","Solleva il bilanciere all'altezza delle spalle, tenendo i gomiti vicini al corpo.","Premi il bilanciere sopra la testa, estendendo completamente le braccia.","Abbassa il bilanciere fino all'altezza delle spalle.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"2414","name":"barbell standing concentration curl","category":"upper arms","equipment":"barbell","target":"biceps","secondary":["forearms"],"steps":{"en":["Stand with your feet shoulder-width apart and hold a barbell in one hand, palm facing up.","Rest your opposite hand on your thigh for support.","Keeping your upper arm stationary, exhale and curl the weight up towards your shoulder.","Pause for a moment at the top, squeezing your biceps.","Inhale and slowly lower the weight back down to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"it":["Stai con i piedi alla larghezza delle spalle e tieni un bilanciere con una mano, palmo rivolto verso l'alto.","Appoggia la mano opposta sulla coscia per sostenerti.","Mantenendo fermo il braccio superiore, espira e arrotola il peso verso la spalla.","Fermati un attimo in cima, stringendo i bicipiti.","Inspira e abbassa lentamente il peso fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni, poi cambia braccio."]}},{"id":"0107","name":"barbell standing front raise over head","category":"shoulders","equipment":"barbell","target":"delts","secondary":["triceps","upper back"],"steps":{"en":["Stand with your feet shoulder-width apart, holding a barbell in front of your thighs with an overhand grip.","Keep your back straight and engage your core.","Slowly raise the barbell in front of you, keeping your arms straight and your palms facing down.","Continue lifting until the barbell is slightly above shoulder level.","Pause for a moment at the top, then slowly lower the barbell back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai con i piedi a larghezza delle spalle, tenendo una barra davanti alle cosce con una presa sopra la testa.","Tieni la schiena dritta e attiva il core.","Alza lentamente il bilanciere davanti a te, tenendo le braccia dritte e i palmi rivolti verso il basso.","Continua a sollevare fino a quando il bilanciere non è leggermente sopra il livello delle spalle.","Fermati un attimo in cima, poi abbassa lentamente il bilanciere fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0108","name":"barbell standing leg calf raise","category":"lower legs","equipment":"barbell","target":"calves","secondary":["hamstrings","glutes"],"steps":{"en":["Stand with your feet shoulder-width apart and place a barbell across your upper back.","Raise your heels off the ground as high as possible, using your calves.","Pause for a moment at the top, then slowly lower your heels back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai con i piedi a larghezza delle spalle e posiziona una barra sulla parte superiore della schiena.","Alza i talloni da terra il più in alto possibile, usando i polpacci.","Fermati un attimo in cima, poi abbassa lentamente i talloni fino alla posizione di partenza.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0109","name":"barbell standing overhead triceps extension","category":"upper arms","equipment":"barbell","target":"triceps","secondary":["shoulders"],"steps":{"en":["Stand with your feet shoulder-width apart and hold a barbell with an overhand grip.","Raise the barbell overhead, fully extending your arms.","Keeping your upper arms close to your head, slowly lower the barbell behind your head by bending your elbows.","Pause for a moment, then raise the barbell back to the starting position by extending your arms.","Repeat for the desired number of repetitions."],"it":["Stai con i piedi divaricati alla larghezza delle spalle e tieni un bilanciere con una presa sopra la testa.","Alza il bilanciere sopra la testa, estendendo completamente le braccia.","Tenendo le braccia superiori vicine alla testa, abbassa lentamente il bilanciere dietro la testa piegando i gomiti.","Fermati un attimo, poi riporta il bilanciere alla posizione iniziale estendendo le braccia.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0110","name":"barbell standing reverse grip curl","category":"upper arms","equipment":"barbell","target":"biceps","secondary":["forearms"],"steps":{"en":["Stand up straight with your feet shoulder-width apart and hold a barbell with an underhand grip, palms facing up.","Keep your elbows close to your torso and your upper arms stationary.","Exhale and curl the weights while contracting your biceps, bringing the barbell as close to your shoulders as possible.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly lower the barbell back to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai dritto con i piedi divaricati alla larghezza delle spalle e tieni un bilanciere con una presa sottomano, palmi rivolti verso l'alto.","Tieni i gomiti vicini al busto e le braccia superiori ferme.","Espira e arriccia i pesi mentre contrahi i bicipiti, portando il bilanciere il più vicino possibile alle spalle.","Mantieni la posizione contratta per una breve pausa mentre stringi i bicipiti.","Inspira e abbassa lentamente il bilanciere fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0111","name":"barbell standing rocking leg calf raise","category":"lower legs","equipment":"barbell","target":"calves","secondary":["hamstrings","quadriceps"],"steps":{"en":["Stand with your feet shoulder-width apart and hold a barbell across your upper back.","Raise your heels off the ground as high as possible, balancing on the balls of your feet.","Slowly lower your heels back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai in piedi con i piedi a larghezza delle spalle e tieni un bilanciere sulla parte superiore della schiena.","Alza i talloni da terra il più in alto possibile, bilanciandoti sulle punte dei piedi.","Abbassa lentamente i talloni fino alla posizione di partenza.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0112","name":"barbell standing twist","category":"waist","equipment":"barbell","target":"abs","secondary":["obliques","lower back"],"steps":{"en":["Stand with your feet shoulder-width apart and hold a barbell in front of your chest with both hands, palms facing down.","Engage your core and keep your back straight throughout the exercise.","Slowly twist your torso to the right, pivoting on your feet and hips, while keeping your lower body stable.","Pause for a moment at the end of the twist, then slowly return to the starting position.","Repeat the twist to the left side.","Continue alternating twists for the desired number of repetitions."],"it":["Stai con i piedi a larghezza delle spalle e tieni un bilanciere davanti al petto con entrambe le mani, palmi rivolti verso il basso.","Attiva il core e tieni la schiena dritta durante tutto l'esercizio.","Ruota lentamente il busto verso destra, ruotando su piedi e fianchi, mantenendo stabile la parte inferiore del corpo.","Fermati un attimo alla fine della torsione, poi torna lentamente alla posizione iniziale.","Ripeti la torsione verso sinistra.","Continua ad alternare le torsioni per il numero desiderato di ripetizioni."]}},{"id":"1629","name":"barbell standing wide grip biceps curl","category":"upper arms","equipment":"barbell","target":"biceps","secondary":["forearms"],"steps":{"en":["Stand with your feet shoulder-width apart and hold a barbell with an underhand grip, hands wider than shoulder-width apart.","Keep your back straight and your elbows close to your torso.","Exhale and curl the barbell up towards your shoulders, keeping your upper arms stationary.","Pause for a moment at the top, squeezing your biceps.","Inhale and slowly lower the barbell back to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."],"it":["Stai con i piedi a larghezza delle spalle e tieni un bilanciere con una presa sottomano, le mani più distanti della larghezza delle spalle.","Tieni la schiena dritta e i gomiti vicini al busto.","Espira e arrotola il bilanciere verso le spalle, mantenendo ferme le braccia superiori.","Fermati un attimo in cima, stringendo i bicipiti.","Inspira e abbassa lentamente il bilanciere fino alla posizione iniziale, estendendo completamente le braccia.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"1457","name":"barbell standing wide military press","category":"shoulders","equipment":"barbell","target":"delts","secondary":["triceps","upper back"],"steps":{"en":["Stand with your feet shoulder-width apart and hold the barbell with an overhand grip, slightly wider than shoulder-width.","Lift the barbell to shoulder height, keeping your elbows slightly in front of the bar.","Press the barbell overhead, extending your arms fully.","Lower the barbell back to shoulder height and repeat for the desired number of repetitions."],"it":["Stai con i piedi a larghezza delle spalle e tieni il bilanciere con una presa sopra la mano, leggermente più larga della larghezza delle spalle.","Solleva il bilanciere all'altezza della spalla, mantenendo i gomiti leggermente davanti alla barra.","Premi il bilanciere sopra la testa, estendendo completamente le braccia.","Abbassa il bilanciere all'altezza delle spalle e ripeti per il numero desiderato di ripetizioni."]}},{"id":"0113","name":"barbell standing wide-grip curl","category":"upper arms","equipment":"barbell","target":"biceps","secondary":["forearms","shoulders"],"steps":{"en":["Stand up straight with your feet shoulder-width apart and hold a barbell with an overhand grip, hands wider than shoulder-width apart.","Let the barbell hang at arm's length in front of your thighs, with your palms facing away from your body.","Keeping your upper arms stationary, exhale and curl the barbell upward by contracting your biceps.","Continue to raise the barbell until your biceps are fully contracted and the barbell is at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the barbell back to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai dritto con i piedi alla larghezza delle spalle e tieni un bilanciere con una presa sopra la mano, mani più larghe della larghezza delle spalle.","Lascia che il bilanciere penda a distanza di braccio davanti alle cosce, con i palmi rivolti lontano dal corpo.","Mantenendo ferme le braccia superiori, espira e arriccia il bilanciere verso l'alto contraendo i bicipiti.","Continua ad alzare il bilanciere finché i bicipiti non sono completamente contratti e il bilanciere non è all'altezza delle spalle.","Mantieni la posizione contratta per una breve pausa mentre stringi i bicipiti.","Inspira e inizia lentamente ad abbassare il bilanciere fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0114","name":"barbell step-up","category":"upper legs","equipment":"barbell","target":"glutes","secondary":["quadriceps","hamstrings","calves"],"steps":{"en":["Stand in front of a bench or step with a barbell resting on your upper back.","Place one foot on the bench or step, ensuring your entire foot is in contact with the surface.","Push through your heel and step up onto the bench or step, fully extending your hip and knee.","Pause briefly at the top, then lower yourself back down to the starting position.","Repeat with the opposite leg.","Continue alternating legs for the desired number of repetitions."],"it":["Mettiti davanti a una panca o metti un passo con un bilanciere appoggiato sulla parte superiore della schiena.","Appoggia un piede sulla panca o sul gradino, assicurandoti che tutto il piede sia a contatto con la superficie.","Spingi attraverso il tallone e sali sulla panca o sul gradino, estendendo completamente anche e ginocchio.","Fermati brevemente in cima, poi scendi di nuovo alla posizione di partenza.","Ripeti con la gamba opposta.","Continua ad alternare le gambe per il numero desiderato di ripetizioni."]}},{"id":"0115","name":"barbell stiff leg good morning","category":"upper legs","equipment":"barbell","target":"glutes","secondary":["hamstrings","lower back"],"steps":{"en":["Stand with your feet shoulder-width apart and your knees slightly bent.","Hold the barbell across your upper back, resting it on your traps.","Keeping your back straight, hinge forward at the hips, pushing your glutes back.","Lower your torso until it is parallel to the ground, feeling a stretch in your hamstrings.","Engage your glutes and hamstrings to return to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai in piedi con i piedi a larghezza delle spalle e le ginocchia leggermente piegate.","Tieni il bilanciere sopra la parte alta della schiena, appoggiandolo sui trapezi.","Tieni la schiena dritta, piega in avanti ai fianchi, spinge indietro i glutei.","Abbassa il busto finché non è parallelo al suolo, sentendo uno stiramento nei muscoli posteriori femorale.","Attiva glutei e muscoli femorale per tornare alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0116","name":"barbell straight leg deadlift","category":"upper legs","equipment":"barbell","target":"hamstrings","secondary":["glutes","lower back"],"steps":{"en":["Stand with your feet shoulder-width apart and your toes pointing forward.","Hold the barbell with an overhand grip, hands slightly wider than shoulder-width apart.","Bend at your hips and lower the barbell towards the ground, keeping your back straight and your knees slightly bent.","Lower the barbell until you feel a stretch in your hamstrings.","Engage your hamstrings and glutes to lift the barbell back up to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai in piedi con i piedi alla larghezza delle spalle e le dita rivolte in avanti.","Tieni il bilanciere con una presa sopra la mano, le mani leggermente più larghe della larghezza delle spalle.","Piega i fianchi e abbassa il bilanciere verso terra, mantenendo la schiena dritta e le ginocchia leggermente piegate.","Abbassa il bilanciere finché non senti uno stiramento nei muscoli posteriori femorale.","Attiva i muscoli femorale e i glutei per sollevare la barra fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0117","name":"barbell sumo deadlift","category":"upper legs","equipment":"barbell","target":"glutes","secondary":["hamstrings","quadriceps","lower back"],"steps":{"en":["Stand with your feet wider than shoulder-width apart, toes pointing outwards.","Place a barbell on the ground in front of you, centered between your feet.","Bend your knees and lower your hips, keeping your back straight and chest up, to grip the barbell with an overhand grip.","Engage your core and drive through your heels to lift the barbell off the ground, extending your hips and knees simultaneously.","As you lift, keep your chest up and back straight, and push your hips forward to fully engage your glutes.","Pause for a moment at the top, then slowly lower the barbell back down to the starting position, maintaining control throughout the movement.","Repeat for the desired number of repetitions."],"it":["Stai in piedi con i piedi più larghi della larghezza delle spalle, con le dita rivolte verso l'esterno.","Metti un bilanciere a terra davanti a te, centrato tra i piedi.","Flette le ginocchia e abbassa i fianchi, tenendo la schiena dritta e il petto sollevato, per afferrare il bilanciere con una presa sopra la mano.","Attiva il core e spingi attraverso i talloni per sollevare il bilanciere da terra, estendendo contemporaneamente anche e ginocchia.","Mentre solleva i sollievi, tieni il petto sollevato e la schiena dritta, e spingi i fianchi in avanti per attivare completamente i glutei.","Fermati un attimo in cima, poi abbassa lentamente il bilanciere fino alla posizione iniziale, mantenendo il controllo durante tutto il movimento.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"3305","name":"barbell thruster","category":"shoulders","equipment":"barbell","target":"delts","secondary":["quadriceps","glutes","hamstrings","core"],"steps":{"en":["Start by standing with your feet shoulder-width apart, holding a barbell at shoulder height with an overhand grip.","Lower into a squat position by bending your knees and pushing your hips back.","As you reach the bottom of the squat, explosively drive through your heels to stand up, simultaneously pressing the barbell overhead.","Lower the barbell back to shoulder height as you lower back into the squat position.","Repeat for the desired number of repetitions."],"it":["Inizia con i piedi a larghezza delle spalle, tenendo un bilanciere all'altezza delle spalle con una presa sopra la testa.","Abbassati in posizione squat piegando le ginocchia e spingendo indietro i fianchi.","Quando raggiungi il fondo dello squat, spingi esplosivamente attraverso i talloni per alzarti, premendo contemporaneamente la barra sopra la testa.","Abbassa il bilanciere all'altezza delle spalle mentre ti abbassi indietro in posizione squat.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0120","name":"barbell upright row","category":"shoulders","equipment":"barbell","target":"delts","secondary":["traps","biceps"],"steps":{"en":["Stand with your feet shoulder-width apart and hold a barbell with an overhand grip, hands slightly wider than shoulder-width apart.","Let the barbell hang in front of your thighs, arms fully extended.","Keeping your back straight and core engaged, exhale and lift the barbell straight up towards your chin, leading with your elbows.","Pause for a moment at the top, then inhale and slowly lower the barbell back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai con i piedi a larghezza delle spalle e tieni un bilanciere con una presa sopra la mano, le mani leggermente più larghe della larghezza delle spalle.","Lascia che il bilanciere pendi davanti alle cosce, braccia completamente distese.","Tenendo la schiena dritta e il core attivo, espira e solleva il bilanciere verso il mento, iniziando con i gomiti.","Fermati un attimo in cima, poi inspira e abbassa lentamente il bilanciere fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0119","name":"barbell upright row v. 2","category":"shoulders","equipment":"barbell","target":"delts","secondary":["traps","biceps"],"steps":{"en":["Stand with your feet shoulder-width apart and hold a barbell with an overhand grip, hands slightly wider than shoulder-width apart.","Let the barbell hang in front of your thighs, arms fully extended.","Keeping your back straight, exhale and lift the barbell straight up towards your chin, leading with your elbows.","Pause for a moment at the top, then inhale and slowly lower the barbell back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai con i piedi a larghezza delle spalle e tieni un bilanciere con una presa sopra la mano, le mani leggermente più larghe della larghezza delle spalle.","Lascia che il bilanciere pendi davanti alle cosce, braccia completamente distese.","Tieni la schiena dritta, espira e solleva il bilanciere verso il mento, iniziando con i gomiti.","Fermati un attimo in cima, poi inspira e abbassa lentamente il bilanciere fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0121","name":"barbell upright row v. 3","category":"shoulders","equipment":"barbell","target":"delts","secondary":["traps","biceps"],"steps":{"en":["Stand with your feet shoulder-width apart and hold a barbell with an overhand grip, hands slightly wider than shoulder-width apart.","Let the barbell hang in front of your thighs, arms fully extended.","Keeping your core engaged and back straight, exhale as you lift the barbell straight up towards your chin, leading with your elbows.","Pause for a moment at the top, then inhale as you slowly lower the barbell back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai con i piedi a larghezza delle spalle e tieni un bilanciere con una presa sopra la mano, le mani leggermente più larghe della larghezza delle spalle.","Lascia che il bilanciere pendi davanti alle cosce, braccia completamente distese.","Mantenendo il core impegnato e la schiena dritta, espira mentre sollevi il bilanciere verso il mento, iniziando con i gomiti.","Fermati un attimo in cima, poi inspira mentre abbassi lentamente il bilanciere fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0122","name":"barbell wide bench press","category":"chest","equipment":"barbell","target":"pectorals","secondary":["shoulders","triceps"],"steps":{"en":["Lie flat on a bench with your feet flat on the ground and your back pressed against the bench.","Grasp the barbell with a wide grip, slightly wider than shoulder-width apart.","Lift the barbell off the rack and hold it directly above your chest with your arms fully extended.","Lower the barbell slowly towards your chest, keeping your elbows slightly flared out.","Pause for a moment when the barbell touches your chest, then push it back up to the starting position.","Repeat for the desired number of repetitions."],"it":["Sdraiati disteso su una panca con i piedi piatti a terra e la schiena premuta contro la panca.","Afferra il bilanciere con una presa larga, leggermente più larga della larghezza delle spalle.","Solleva il bilanciere dal rack e tienilo direttamente sopra il petto con le braccia completamente distese.","Abbassa lentamente il bilanciere verso il petto, mantenendo i gomiti leggermente slargati.","Fermati un attimo quando il bilanciere tocca il petto, poi spingilo di nuovo verso l'alto alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"1258","name":"barbell wide reverse grip bench press","category":"chest","equipment":"barbell","target":"pectorals","secondary":["triceps","shoulders"],"steps":{"en":["Lie flat on a bench with your feet flat on the ground and your back pressed against the bench.","Grasp the barbell with a wide reverse grip, slightly wider than shoulder-width apart.","Lift the barbell off the rack and hold it directly above your chest with your arms fully extended.","Lower the barbell slowly towards your chest, keeping your elbows tucked in and your wrists straight.","Pause for a moment when the barbell touches your chest, then push it back up to the starting position.","Repeat for the desired number of repetitions."],"it":["Sdraiati disteso su una panca con i piedi piatti a terra e la schiena premuta contro la panca.","Afferra il bilanciere con una presa larga al contrario, leggermente più larga della larghezza delle spalle.","Solleva il bilanciere dal rack e tienilo direttamente sopra il petto con le braccia completamente distese.","Abbassa lentamente il bilanciere verso il petto, tenendo i gomiti raccolti e i polsi dritti.","Fermati un attimo quando il bilanciere tocca il petto, poi spingilo di nuovo verso l'alto alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0124","name":"barbell wide squat","category":"upper legs","equipment":"barbell","target":"quads","secondary":["glutes","hamstrings","calves"],"steps":{"en":["Stand with your feet wider than shoulder-width apart, toes pointing slightly outward.","Hold the barbell across your upper back, resting it on your traps or rear delts.","Engage your core and keep your chest up as you lower your body down into a squat, pushing your hips back and bending your knees.","Lower until your thighs are parallel to the ground, or as low as you can comfortably go.","Pause for a moment at the bottom, then push through your heels to return to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai in piedi con i piedi più larghi delle spalle, le dita leggermente rivolte verso l'esterno.","Tieni la barra sopra la parte superiore della schiena, appoggiandola sui trapezi o sui deltoidi posteriori.","Attiva il core e tieni il petto sollevato mentre abbassi il corpo in uno squat, spingendo indietro i fianchi e piegando le ginocchia.","Abbassa finché le cosce non sono parallele al suolo, o il più in basso che puoi andare comodamente.","Fermati un attimo in fondo, poi spingi attraverso i talloni per tornare alla posizione di partenza.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0123","name":"barbell wide-grip upright row","category":"shoulders","equipment":"barbell","target":"delts","secondary":["traps","biceps"],"steps":{"en":["Stand with your feet shoulder-width apart and hold a barbell with an overhand grip, hands wider than shoulder-width apart.","Let the barbell hang in front of your thighs, arms fully extended.","Keeping your back straight, exhale and lift the barbell straight up towards your chin, leading with your elbows.","Pause for a moment at the top, then inhale and slowly lower the barbell back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai con i piedi a larghezza delle spalle e tieni un bilanciere con una presa sopra la mano, le mani più larghe della larghezza delle spalle.","Lascia che il bilanciere pendi davanti alle cosce, braccia completamente distese.","Tieni la schiena dritta, espira e solleva il bilanciere verso il mento, iniziando con i gomiti.","Fermati un attimo in cima, poi inspira e abbassa lentamente il bilanciere fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0126","name":"barbell wrist curl","category":"lower arms","equipment":"barbell","target":"forearms","secondary":["biceps","brachialis"],"steps":{"en":["Sit on a bench with your feet flat on the ground and your forearms resting on your thighs, holding a barbell with an underhand grip.","Allow the barbell to roll down to your fingertips, keeping your wrists straight.","Slowly curl the barbell up towards your forearms by flexing your wrists.","Pause for a moment at the top, then slowly lower the barbell back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Siediti su una panca con i piedi piatti a terra e gli avambracci appoggiati sulle cosce, tenendo un bilanciere con una presa sottomano.","Lascia che la barra scenda fino alle punte delle dita, mantenendo i polsi dritti.","Arrotola lentamente il bilanciere verso gli avambracci flettendo i polsi.","Fermati un attimo in cima, poi abbassa lentamente il bilanciere fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0125","name":"barbell wrist curl v. 2","category":"lower arms","equipment":"barbell","target":"forearms","secondary":["biceps","brachialis"],"steps":{"en":["Sit on a bench with your feet flat on the ground and your knees bent.","Hold a barbell with an underhand grip, palms facing up, and your hands shoulder-width apart.","Rest your forearms on your thighs, allowing your wrists to hang off the edge.","Slowly curl your wrists upward, bringing the barbell towards your forearms.","Pause for a moment at the top, then slowly lower the barbell back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Siediti su una panchina con i piedi piatti a terra e le ginocchia piegate.","Tieni una barra con una presa sotto, palmi rivolti verso l'alto e mani a larghezza delle spalle.","Appoggia gli avambracci sulle cosce, lasciando che i polsi penzolano dal bordo.","Ripiega lentamente i polsi verso l'alto, portando il bilanciere verso gli avambracci.","Fermati un attimo in cima, poi abbassa lentamente il bilanciere fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0127","name":"barbell zercher squat","category":"upper legs","equipment":"barbell","target":"glutes","secondary":["quadriceps","hamstrings","calves","core"],"steps":{"en":["Stand with your feet shoulder-width apart and toes slightly turned out.","Hold the barbell in the crooks of your elbows, with your hands gripping the bar for stability.","Engage your core and keep your chest lifted as you lower your hips back and down into a squat position.","Keep your knees in line with your toes and your weight in your heels.","Pause for a moment at the bottom of the squat, then push through your heels to return to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai in piedi con i piedi alla larghezza delle spalle e le dita leggermente rivolte verso l'esterno.","Tieni il bilanciere nelle pieghe dei gomiti, con le mani che stringono il bilanciere per stabilità.","Attiva il core e tieni il petto sollevato mentre abbassi i fianchi all'indietro e in posizione squat.","Mantieni le ginocchia allineate con le dita dei piedi e il peso sui talloni.","Fermati un attimo in fondo allo squat, poi spingi attraverso i talloni per tornare alla posizione di partenza.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"3212","name":"basic toe touch (male)","category":"upper legs","equipment":"body weight","target":"glutes","secondary":["hamstrings","calves"],"steps":{"en":["Stand with your feet shoulder-width apart and your arms by your sides.","Bend forward at the waist, keeping your back straight and your knees slightly bent.","Reach down towards your toes with your hands, keeping your legs as straight as possible.","Pause for a moment at the bottom, then slowly return to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai in piedi con i piedi larghi alle spalle e le braccia lungo i fianchi.","Piegati in avanti in vita, tenendo la schiena dritta e le ginocchia leggermente piegate.","Allunga le mani verso le dita dei piedi, tenendo le gambe il più dritte possibile.","Fermati un attimo in fondo, poi torna lentamente alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"3360","name":"bear crawl","category":"cardio","equipment":"body weight","target":"cardiovascular system","secondary":["core","shoulders","triceps"],"steps":{"en":["Start on all fours with your hands directly under your shoulders and your knees directly under your hips.","Lift your knees slightly off the ground, keeping your back flat and your core engaged.","Move your right hand and left foot forward simultaneously, followed by your left hand and right foot.","Continue crawling forward, alternating your hand and foot movements.","Maintain a steady pace and keep your core tight throughout the exercise.","Continue for the desired distance or time."],"it":["Inizia a quattro zampe con le mani direttamente sotto le spalle e le ginocchia sotto i fianchi.","Alza leggermente le ginocchia da terra, mantenendo la schiena piatta e il core attivo.","Muovi in avanti contemporaneamente la mano destra e il piede sinistro, seguiti dalla mano sinistra e dal piede destro.","Continua a strisciare in avanti, alternando movimenti di mani e piedi.","Mantieni un ritmo costante e tieni il core teso durante tutto l'esercizio.","Continua per la distanza o il tempo desiderato."]}},{"id":"0129","name":"bench dip (knees bent)","category":"upper arms","equipment":"body weight","target":"triceps","secondary":["chest","shoulders"],"steps":{"en":["Sit on the edge of a bench or chair with your hands gripping the edge next to your hips.","Slide your butt off the bench and straighten your legs in front of you, keeping your heels on the ground.","Bend your elbows and lower your body towards the ground, keeping your back close to the bench.","Pause for a moment at the bottom, then push yourself back up to the starting position.","Repeat for the desired number of repetitions."],"it":["Siediti sul bordo di una panca o di una sedia con le mani che stringono il bordo accanto ai fianchi.","Fai scivolare il sedere fuori dalla panca e raddrizzare le gambe davanti a te, tenendo i talloni a terra.","Piega i gomiti e abbassa il corpo verso terra, tenendo la schiena vicina alla panca.","Fermati un attimo in fondo, poi risali fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"1399","name":"bench dip on floor","category":"upper arms","equipment":"body weight","target":"triceps","secondary":["chest","shoulders"],"steps":{"en":["Sit on the edge of a bench or chair with your hands gripping the edge, fingers pointing forward.","Slide your butt off the bench, supporting your weight with your hands.","Lower your body by bending your elbows until your upper arms are parallel to the floor.","Push yourself back up to the starting position by straightening your arms.","Repeat for the desired number of repetitions."],"it":["Siediti sul bordo di una panca o di una sedia con le mani che stringono il bordo e le dita puntate in avanti.","Fai scivolare il sedere giù dalla panca, sostenendo il peso con le mani.","Abbassa il corpo piegando i gomiti finché le braccia superiori non sono parallele al pavimento.","Spingi di nuovo verso la posizione iniziale raddrizzando le braccia.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0130","name":"bench hip extension","category":"upper legs","equipment":"body weight","target":"glutes","secondary":["hamstrings"],"steps":{"en":["Sit on a bench with your back against the bench and your feet flat on the ground.","Place your hands on the bench for support.","Engage your glutes and hamstrings, then lift your hips off the bench until your body forms a straight line from your knees to your shoulders.","Pause for a moment at the top, then slowly lower your hips back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Siediti su una panchina con la schiena appoggiata alla panca e i piedi piatti a terra.","Appoggia le mani sulla panca per sostenerti.","Attiva glutei e muscoli posteriori femorale, poi solleva i fianchi dalla panca finché il corpo non forma una linea retta dalle ginocchia alle spalle.","Fermati un attimo in cima, poi abbassa lentamente i fianchi fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"3019","name":"bench pull-ups","category":"back","equipment":"body weight","target":"lats","secondary":["biceps","forearms"],"steps":{"en":["Position yourself under a bar or a sturdy horizontal surface that is at chest height.","Grab the bar or surface with an overhand grip, slightly wider than shoulder-width apart.","Hang with your arms fully extended and your body straight.","Pull your chest towards the bar or surface by squeezing your shoulder blades together and bending your elbows.","Continue pulling until your chin is above the bar or surface.","Lower yourself back down to the starting position with control.","Repeat for the desired number of repetitions."],"it":["Posizionati sotto una barra o su una superficie orizzontale robusta all'altezza del petto.","Afferra il manubrio o la superficie con una presa sopra la mano, leggermente più larga della larghezza delle spalle.","Tieni le braccia completamente distese e il corpo dritto.","Tira il petto verso la barra o la superficie stringendo le scapole e piegando i gomiti.","Continua a tirare finché il mento non è sopra la barra o la superficie.","Abbassati di nuovo alla posizione di partenza con controllo.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"3639","name":"bent knee lying twist (male)","category":"upper legs","equipment":"body weight","target":"glutes","secondary":["obliques","hip flexors"],"steps":{"en":["Lie flat on your back with your knees bent and feet flat on the ground.","Extend your arms out to the sides, perpendicular to your body.","Keeping your knees together, slowly lower them to one side, aiming to touch the ground with your knees.","Pause for a moment, then engage your core and slowly lift your knees back to the starting position.","Repeat the movement to the other side.","Continue alternating sides for the desired number of repetitions."],"it":["Sdraiati sulla schiena con le ginocchia piegate e i piedi piatti a terra.","Allunga le braccia ai lati, perpendicolarmente al corpo.","Tenendo le ginocchia unite, abbassale lentamente da un lato, cercando di toccare il suolo con le ginocchia.","Fermati un attimo, poi attiva il core e solleva lentamente le ginocchia fino alla posizione iniziale.","Ripeti il movimento dall'altra parte.","Continua ad alternare i lati per il numero desiderato di ripetizioni."]}},{"id":"1770","name":"biceps leg concentration curl","category":"upper arms","equipment":"body weight","target":"biceps","secondary":["forearms"],"steps":{"en":["Sit on a bench with your legs spread apart and your feet flat on the ground.","Hold a dumbbell in one hand and place your elbow on the inside of your thigh, just above the knee.","With your palm facing up, curl the dumbbell towards your shoulder while keeping your upper arm stationary.","Squeeze your biceps at the top of the movement, then slowly lower the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"it":["Siediti su una panchina con le gambe divaricate e i piedi piatti a terra.","Tieni un manubrio in una mano e posiziona il gomito all'interno della coscia, appena sopra il ginocchio.","Con il palmo rivolto verso l'alto, piega il manubrio verso la spalla mantenendo fermo il braccio superiore.","Stringi i bicipiti all'inizio del movimento, poi abbassa lentamente il manubrio fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni, poi cambia braccio."]}},{"id":"0139","name":"biceps narrow pull-ups","category":"upper arms","equipment":"body weight","target":"biceps","secondary":["forearms","shoulders"],"steps":{"en":["Hang from a pull-up bar with your palms facing towards you and your hands shoulder-width apart.","Engage your core and pull yourself up towards the bar, focusing on using your biceps to lift your body.","Pause for a moment at the top, then slowly lower yourself back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Appenditi a una barra per trazioni con i palmi rivolti verso di te e le mani distanti alla larghezza delle spalle.","Impegna il core e tira verso la barra, concentrandoti sull'uso dei bicipiti per sollevare il corpo.","Fermati un attimo in cima, poi lentamente scendi di nuovo alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0140","name":"biceps pull-up","category":"upper arms","equipment":"body weight","target":"biceps","secondary":["forearms","shoulders"],"steps":{"en":["Hang from a pull-up bar with your palms facing away from you and your hands shoulder-width apart.","Engage your core and pull yourself up by bending your elbows, bringing your chest towards the bar.","Pause at the top of the movement, then slowly lower yourself back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Appenditi a una barra per trazioni con i palmi rivolti dall'altra parte e le mani a largo spalla.","Attiva il core e tira su piegando i gomiti, portando il petto verso la barra.","Fermati all'inizio del movimento, poi lentamente scendi di nuovo alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0137","name":"body-up","category":"upper arms","equipment":"body weight","target":"triceps","secondary":["chest","shoulders"],"steps":{"en":["Start by placing your hands on a raised surface, such as a bench or parallel bars, with your palms facing down and fingers pointing forward.","Extend your legs out in front of you, keeping your heels on the ground and your body straight.","Lower your body by bending your elbows, keeping them close to your sides, until your upper arms are parallel to the ground.","Pause for a moment, then push through your palms to straighten your arms and lift your body back up to the starting position.","Repeat for the desired number of repetitions."],"it":["Inizia posizionando le mani su una superficie rialzata, come una panca o barre parallele, con i palmi rivolti verso il basso e le dita puntate in avanti.","Allunga le gambe davanti a te, tenendo i talloni a terra e il corpo dritto.","Abbassa il corpo piegando i gomiti, tenendoli vicini ai fianchi, finché le braccia superiori non sono parallele al terreno.","Fermati un attimo, poi spingi attraverso i palmi per raddrizzare le braccia e sollevare di nuovo il corpo alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"3543","name":"bodyweight drop jump squat","category":"upper legs","equipment":"body weight","target":"glutes","secondary":["quadriceps","hamstrings","calves"],"steps":{"en":["Stand with your feet shoulder-width apart.","Lower your body into a squat position by bending your knees and pushing your hips back.","Jump up explosively, extending your hips, knees, and ankles.","While in mid-air, quickly bring your feet together.","Land softly on the balls of your feet and immediately drop back into a squat position.","Repeat for the desired number of repetitions."],"it":["Stai con i piedi a larghezza delle spalle.","Abbassa il corpo in posizione accovacciata piegando le ginocchia e spingendo i fianchi all'indietro.","Salta in modo esplosivo, estendendo anche fianchi, ginocchia e caviglie.","Mentre sei a mezz'aria, unisci rapidamente i piedi.","Atterra dolcemente sulle punte dei piedi e subito torna in posizione accovacciata.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"3544","name":"bodyweight incline side plank","category":"waist","equipment":"body weight","target":"abs","secondary":["obliques","shoulders"],"steps":{"en":["Start by lying on your side with your legs extended and stacked on top of each other.","Place your forearm on the ground directly below your shoulder, with your elbow bent at a 90-degree angle.","Engage your core and lift your hips off the ground, creating a straight line from your head to your feet.","Hold this position for the desired amount of time.","Lower your hips back down to the ground and repeat on the other side."],"it":["Inizia sdraiandoti su un fianco con le gambe distese e sovrapposte una sopra l'altra.","Appoggia l'avambraccio a terra direttamente sotto la spalla, con il gomito piegato a 90 gradi.","Attiva il core e solleva i fianchi da terra, creando una linea retta dalla testa ai piedi.","Mantieni questa posizione per il tempo desiderato.","Abbassa i fianchi di nuovo a terra e ripeti dall'altro lato."]}},{"id":"1771","name":"bodyweight kneeling triceps extension","category":"upper arms","equipment":"body weight","target":"triceps","secondary":["shoulders","chest"],"steps":{"en":["Kneel down on the ground with your knees hip-width apart.","Place your hands on the ground in front of you, shoulder-width apart, fingers pointing forward.","Extend your legs straight behind you, balancing on your toes and hands, forming a straight line from head to heels.","Bend your elbows and lower your upper body towards the ground, keeping your elbows close to your sides.","Pause for a moment at the bottom, then push through your hands to straighten your arms and return to the starting position.","Repeat for the desired number of repetitions."],"it":["Inginocchiati a terra con le ginocchia larghe ai fianchi.","Metti le mani a terra davanti a te, divaricate alla larghezza delle spalle, dita puntate in avanti.","Allunga le gambe dritte dietro di te, bilanciandoti sulle punte dei piedi e sulle mani, formando una linea retta dalla testa ai talloni.","Piega i gomiti e abbassa la parte superiore del corpo verso terra, tenendo i gomiti vicini ai fianchi.","Fermati un attimo in basso, poi spingi tra le mani per raddrizzare le braccia e tornare alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"1769","name":"bodyweight side lying biceps curl","category":"upper arms","equipment":"body weight","target":"biceps","secondary":["forearms"],"steps":{"en":["Lie on your side with your legs extended and your head supported by your arm.","Hold your upper arm against your side and bend your elbow to curl your forearm towards your shoulder.","Pause for a moment at the top, then slowly lower your forearm back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Sdraiati su un fianco con le gambe distese e la testa sostenuta dal braccio.","Tieni il braccio superiore contro il fianco e piega il gomito per piegare l'avambraccio verso la spalla.","Fermati un attimo in cima, poi abbassa lentamente l'avambraccio fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"3168","name":"bodyweight squatting row","category":"back","equipment":"body weight","target":"upper back","secondary":["biceps","shoulders"],"steps":{"en":["Stand with your feet shoulder-width apart, holding onto a sturdy object or suspension trainer with your arms extended.","Lower your body into a squat position, keeping your back straight and your knees behind your toes.","From the squat position, pull your body up towards the object or suspension trainer, squeezing your shoulder blades together.","Pause for a moment at the top, then slowly lower your body back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai in piedi con i piedi alla larghezza delle spalle, aggrappandoti a un oggetto robusto o a un allenatore con le braccia distese.","Abbassa il corpo in posizione squat, mantenendo la schiena dritta e le ginocchia dietro le dita dei piedi.","Dalla posizione accovacciata, tira il corpo verso l'oggetto o il soccorso di sospensione, stringendo le scapole insieme.","Fermati un attimo in cima, poi abbassa lentamente il corpo fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"3167","name":"bodyweight squatting row (with towel)","category":"back","equipment":"body weight","target":"upper back","secondary":["biceps","shoulders"],"steps":{"en":["Stand with your feet shoulder-width apart, holding a towel in front of you with your palms facing down.","Bend your knees and lower your body into a squat position, keeping your back straight and your chest up.","As you lower into the squat, simultaneously pull the towel towards your chest, squeezing your shoulder blades together.","Pause for a moment at the bottom of the squat, then slowly return to the starting position while extending your arms.","Repeat for the desired number of repetitions."],"it":["Stai con i piedi a larghezza delle spalle, tenendo un asciugamano davanti a te con i palmi rivolti verso il basso.","Flette le ginocchia e abbassa il corpo in posizione accovacciata, tenendo la schiena dritta e il petto sollevato.","Mentre ti abbassi nello squat, tira contemporaneamente l'asciugamano verso il petto, stringendo le scapole insieme.","Fermati un attimo in fondo allo squat, poi torna lentamente alla posizione iniziale mentre estendi le braccia.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"1373","name":"bodyweight standing calf raise","category":"lower legs","equipment":"body weight","target":"calves","secondary":["ankles","feet"],"steps":{"en":["Stand with your feet shoulder-width apart, toes pointing forward.","Place your hands on a wall or stable surface for balance.","Slowly raise your heels off the ground, lifting your body weight onto the balls of your feet.","Pause for a moment at the top, then slowly lower your heels back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai in piedi con i piedi alla larghezza delle spalle, le dita rivolte in avanti.","Appoggia le mani su un muro o una superficie stabile per mantenere l'equilibrio.","Alza lentamente i talloni da terra, sollevando il peso del corpo sulle punte dei piedi.","Fermati un attimo in cima, poi abbassa lentamente i talloni fino alla posizione di partenza.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"3156","name":"bodyweight standing close-grip one arm row","category":"back","equipment":"body weight","target":"upper back","secondary":["biceps","forearms"],"steps":{"en":["Stand with your feet shoulder-width apart, knees slightly bent, and hold a dumbbell in one hand with a neutral grip.","Bend forward at the hips, keeping your back straight and your core engaged.","Pull the dumbbell up towards your chest, keeping your elbow close to your body and squeezing your shoulder blades together.","Pause for a moment at the top, then slowly lower the dumbbell back down to the starting position.","Repeat for the desired number of repetitions, then switch sides."],"it":["Stai in piedi con i piedi alla larghezza delle spalle, le ginocchia leggermente piegate, e tieni un manubrio in una mano con una presa neutra.","Piegati in avanti sui fianchi, mantenendo la schiena dritta e il core attivo.","Tira il manubrio verso il petto, tenendo il gomito vicino al corpo e stringendo le scapole insieme.","Fermati un attimo in cima, poi abbassa lentamente il manubrio fino alla posizione di partenza.","Ripeti per il numero desiderato di ripetizioni, poi cambia lato."]}},{"id":"3158","name":"bodyweight standing close-grip row","category":"back","equipment":"body weight","target":"upper back","secondary":["biceps","forearms"],"steps":{"en":["Stand with your feet shoulder-width apart and knees slightly bent.","Bend forward at the waist, keeping your back straight and your core engaged.","Extend your arms straight in front of you, gripping the bar or handles with a close grip.","Pull the bar or handles towards your body, squeezing your shoulder blades together.","Pause for a moment at the top of the movement, then slowly release and return to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai in piedi con i piedi alla larghezza delle spalle e le ginocchia leggermente piegate.","Piegati in avanti in vita, mantenendo la schiena dritta e il core attivo.","Allunga le braccia dritte davanti a te, stringendo la barra o le maniglie con una presa stretta.","Tira il manubrio o i manici verso il corpo, stringendo le scapole insieme.","Fermati un attimo all'inizio del movimento, poi lascia andare lentamente e torna alla posizione di partenza.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"3162","name":"bodyweight standing one arm row","category":"back","equipment":"body weight","target":"upper back","secondary":["biceps","forearms"],"steps":{"en":["Stand with your feet shoulder-width apart, knees slightly bent, and hold a dumbbell in one hand.","Bend forward at the hips, keeping your back straight and your core engaged.","Let the dumbbell hang straight down in front of you, with your arm fully extended.","Pull the dumbbell up towards your chest, keeping your elbow close to your body.","Squeeze your shoulder blades together at the top of the movement.","Lower the dumbbell back down to the starting position.","Repeat for the desired number of repetitions, then switch sides."],"it":["Stai in piedi con i piedi all'altezza delle spalle, le ginocchia leggermente piegate, e tieni un manubrio in una mano.","Piegati in avanti sui fianchi, mantenendo la schiena dritta e il core attivo.","Lascia che il manubrio penda dritto davanti a te, con il braccio completamente esteso.","Tira il manubrio verso il petto, tenendo il gomito vicino al corpo.","Stringi le scapole insieme nella parte alta del movimento.","Abbassa il manubrio fino alla posizione di partenza.","Ripeti per il numero desiderato di ripetizioni, poi cambia lato."]}},{"id":"3161","name":"bodyweight standing one arm row (with towel)","category":"back","equipment":"body weight","target":"upper back","secondary":["biceps","forearms"],"steps":{"en":["Stand with your feet shoulder-width apart, knees slightly bent, and hold a towel with one hand.","Bend forward at the hips, keeping your back straight and your core engaged.","Pull the towel towards your chest, squeezing your shoulder blades together.","Pause for a moment at the top, then slowly lower the towel back to the starting position.","Repeat for the desired number of repetitions, then switch to the other arm."],"it":["Stai in piedi con i piedi larghi alle spalle, le ginocchia leggermente piegate, e tieni un asciugamano con una mano.","Piegati in avanti sui fianchi, mantenendo la schiena dritta e il core attivo.","Tira l'asciugamano verso il petto, stringendo le scapole insieme.","Fermati un attimo in cima, poi abbassa lentamente l'asciugamano fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni, poi passa all'altro braccio."]}},{"id":"3166","name":"bodyweight standing row","category":"back","equipment":"body weight","target":"upper back","secondary":["biceps","shoulders"],"steps":{"en":["Stand with your feet shoulder-width apart and knees slightly bent.","Grasp a bar or handles with an overhand grip, palms facing down.","Keep your back straight and core engaged.","Pull the bar or handles towards your body, squeezing your shoulder blades together.","Pause for a moment at the top of the movement.","Slowly release and extend your arms back to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai in piedi con i piedi alla larghezza delle spalle e le ginocchia leggermente piegate.","Afferra una barra o manici con una presa sopra la mano, palmi rivolti verso il basso.","Tieni la schiena dritta e il core attivo.","Tira il manubrio o i manici verso il corpo, stringendo le scapole insieme.","Fermati un attimo all'inizio del movimento.","Rilascia lentamente ed estendi le braccia fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"3165","name":"bodyweight standing row (with towel)","category":"back","equipment":"body weight","target":"upper back","secondary":["biceps","shoulders"],"steps":{"en":["Stand with your feet shoulder-width apart and hold a towel in front of you with both hands.","Bend your knees slightly and hinge forward at the hips, keeping your back straight.","Pull the towel towards your chest, squeezing your shoulder blades together.","Pause for a moment at the top, then slowly release the tension and return to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai con i piedi a largo livello di spalle e tieni un asciugamano davanti a te con entrambe le mani.","Piega leggermente le ginocchia e piega in avanti ai fianchi, mantenendo la schiena dritta.","Tira l'asciugamano verso il petto, stringendo le scapole insieme.","Fermati un attimo in cima, poi rilassa lentamente la tensione e torna alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0138","name":"bottoms-up","category":"waist","equipment":"body weight","target":"abs","secondary":["obliques","hip flexors"],"steps":{"en":["Lie flat on your back with your legs extended and your arms by your sides.","Bend your knees and bring them towards your chest, keeping your feet off the ground.","Engaging your abs, lift your hips off the ground, bringing your knees towards your head.","Pause for a moment at the top, then slowly lower your hips back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Sdraiati sulla schiena con le gambe distese e le braccia lungo i fianchi.","Piega le ginocchia e portale al petto, tenendo i piedi sollevati da terra.","Attiva gli addominali, solleva i fianchi da terra, avvicinando le ginocchia alla testa.","Fermati un attimo in cima, poi abbassa lentamente i fianchi fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"1374","name":"box jump down with one leg stabilization","category":"lower legs","equipment":"body weight","target":"calves","secondary":["quadriceps","hamstrings","glutes"],"steps":{"en":["Stand in front of a box or platform with your feet shoulder-width apart.","Bend your knees and jump onto the box, landing softly with one foot on the box and the other foot hanging off the edge.","Stabilize yourself on the box with the foot that is on it, while keeping the other foot off the ground.","Hold this position for a few seconds, engaging your calf muscles to maintain balance.","Slowly step down with the foot that is on the box, returning to the starting position.","Repeat the exercise with the other leg."],"it":["Mettiti davanti a una scatola o a una piattaforma con i piedi distanti alla larghezza delle spalle.","Piega le ginocchia e salta sulla scatola, atterrando dolcemente con un piede sulla scatola e l'altro che pendeva dal bordo.","Stabilizzati sulla scatola con il piede che è sopra, mantenendo l'altro piede sollevato da terra.","Mantieni questa posizione per qualche secondo, attivando i muscoli del polpaccio per mantenere l'equilibrio.","Scendi lentamente con il piede che è sulla scatola, tornando alla posizione iniziale.","Ripeti l'esercizio con l'altra gamba."]}},{"id":"2466","name":"bridge - mountain climber (cross body)","category":"waist","equipment":"body weight","target":"abs","secondary":["glutes","quadriceps","hamstrings","shoulders","triceps"],"steps":{"en":["Start in a high plank position with your hands directly under your shoulders and your body in a straight line.","Engage your core and lift your right foot off the ground, bringing your right knee towards your left elbow.","Return your right foot to the starting position and repeat the movement with your left foot towards your right elbow.","Continue alternating sides, moving at a controlled pace.","Keep your hips level and avoid lifting your hips too high or sagging them too low.","Maintain a steady breathing pattern throughout the exercise.","Repeat for the desired number of repetitions."],"it":["Inizia in posizione di plank alta con le mani direttamente sotto le spalle e il corpo in linea retta.","Attiva il core e solleva il piede destro da terra, avvicinando il ginocchio destro al gomito sinistro.","Riporta il piede destro nella posizione iniziale e ripeti il movimento con il piede sinistro verso il gomito destro.","Continua ad alternare i lati, muovendoti a un ritmo controllato.","Mantieni i fianchi in linea e evita di sollevarli troppo in alto o di abbassarli troppo.","Mantieni un ritmo di respirazione regolare durante tutto l'esercizio.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"1160","name":"burpee","category":"cardio","equipment":"body weight","target":"cardiovascular system","secondary":["quadriceps","hamstrings","calves","shoulders","chest"],"steps":{"en":["Start in a standing position with your feet shoulder-width apart.","Lower your body into a squat position by bending your knees and placing your hands on the floor in front of you.","Kick your feet back into a push-up position.","Perform a push-up, keeping your body in a straight line.","Jump your feet back into the squat position.","Jump up explosively, reaching your arms overhead.","Land softly and immediately lower back into a squat position to begin the next repetition."],"it":["Inizia in posizione eretta, con i piedi alla larghezza delle spalle.","Abbassa il corpo in posizione accovacciata piegando le ginocchia e appoggiando le mani sul pavimento davanti a te.","Rimetti i piedi in posizione di piegamenti.","Fai una flessione, mantenendo il corpo in linea retta.","Rimetti i piedi in posizione squat.","Salta su esplosivamente, allungando le braccia sopra la testa.","Atterra dolcemente e poi si abbassa subito in posizione accovacciato per iniziare la prossima ripetizione."]}},{"id":"0870","name":"butt-ups","category":"waist","equipment":"body weight","target":"abs","secondary":["hip flexors","lower back"],"steps":{"en":["Lie flat on your back with your knees bent and feet flat on the ground.","Place your hands by your sides, palms facing down.","Engaging your abs, lift your legs off the ground, bringing your knees towards your chest.","At the top of the movement, squeeze your abs and pause for a moment.","Slowly lower your legs back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Sdraiati sulla schiena con le ginocchia piegate e i piedi piatti a terra.","Metti le mani lungo i fianchi, palmi rivolti verso il basso.","Attivando gli addominali, solleva le gambe da terra, portando le ginocchia verso il petto.","All'inizio del movimento, stringi gli addominali e fermati un attimo.","Abbassa lentamente le gambe fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"1494","name":"butterfly yoga pose","category":"upper legs","equipment":"body weight","target":"adductors","secondary":["hamstrings","groin"],"steps":{"en":["Sit on the floor with your legs extended in front of you.","Bend your knees and bring the soles of your feet together, allowing your knees to fall out to the sides.","Hold onto your ankles or feet with your hands.","Sit up tall and lengthen your spine.","Gently press your knees down towards the floor, feeling a stretch in your inner thighs.","Hold this position for a few breaths.","To release, slowly bring your knees back up and extend your legs."],"it":["Siediti sul pavimento con le gambe distese davanti a te.","Piega le ginocchia e unisci le piante dei piedi, permettendo alle ginocchia di cadere ai lati.","Tieni le caviglie o i piedi con le mani.","Siediti dritto e allunga la colonna vertebrale.","Premi delicatamente le ginocchia verso il pavimento, sentendo uno stiramento nelle cosce interne.","Mantieni questa posizione per qualche respiro.","Per rilassarti, solleva lentamente le ginocchia ed allunga le gambe."]}},{"id":"1407","name":"calf push stretch with hands against wall","category":"lower legs","equipment":"body weight","target":"calves","secondary":["hamstrings"],"steps":{"en":["Stand facing a wall with your feet hip-width apart.","Place your hands against the wall at shoulder height.","Step back with one foot, keeping your heel on the ground and your leg straight.","Bend your front knee slightly and lean forward, feeling a stretch in your calf.","Hold the stretch for 20-30 seconds.","Switch legs and repeat the stretch."],"it":["Stai rivolto verso un muro con i piedi alla larghezza dei fianchi.","Appoggia le mani al muro all'altezza delle spalle.","Fai un passo indietro con un piede, tenendo il tallone a terra e la gamba dritta.","Piega leggermente il ginocchio anteriore e inclinati in avanti, sentendo uno stiramento al polpaccio.","Mantieni lo stretch per 20-30 secondi.","Cambia gamba e ripeti lo stretching."]}},{"id":"1377","name":"calf stretch with hands against wall","category":"lower legs","equipment":"body weight","target":"calves","secondary":["hamstrings"],"steps":{"en":["Stand facing a wall with your feet hip-width apart.","Place your hands against the wall at shoulder height.","Step your right foot back, keeping your heel on the ground and your leg straight.","Bend your left knee and lean forward, keeping your back leg straight and your heel on the ground.","Hold the stretch for 20-30 seconds.","Switch legs and repeat the stretch."],"it":["Stai rivolto verso un muro con i piedi alla larghezza dei fianchi.","Appoggia le mani al muro all'altezza delle spalle.","Fai un passo indietro con il piede destro, mantenendo il tallone a terra e la gamba dritta.","Piega il ginocchio sinistro e inclinati in avanti, tenendo la gamba posteriore dritta e il tallone a terra.","Mantieni lo stretch per 20-30 secondi.","Cambia gamba e ripeti lo stretching."]}},{"id":"0248","name":"cambered bar lying row","category":"back","equipment":"barbell","target":"upper back","secondary":["biceps","forearms"],"steps":{"en":["Set up a barbell on the floor and lie face down on a bench with your chest just off the edge.","Reach down and grab the barbell with an overhand grip, slightly wider than shoulder-width apart.","With your legs straight and feet on the ground, lift the barbell off the floor by extending your arms.","Pull the barbell towards your chest, squeezing your shoulder blades together.","Lower the barbell back down to the starting position and repeat for the desired number of repetitions."],"it":["Appoggia un bilanciere sul pavimento e sdraiati a faccia in giù su una panca con il petto appena fuori dal bordo.","Allunga la mano e afferra il bilanciere con una presa sopra la mano, leggermente più larga della larghezza delle spalle.","Con le gambe dritte e i piedi a terra, solleva il bilanciere da terra estendendo le braccia.","Tira il bilanciere verso il petto, stringendo le scapole insieme.","Abbassa il bilanciere fino alla posizione iniziale e ripeti per il numero desiderato di ripetizioni."]}},{"id":"2963","name":"captains chair straight leg raise","category":"waist","equipment":"body weight","target":"abs","secondary":["hip flexors"],"steps":{"en":["Sit on the captain's chair with your back against the backrest and your forearms resting on the arm pads.","Keep your upper body stable and your back straight.","Engage your abs and lift your legs up in front of you, keeping them straight.","Continue lifting until your legs are parallel to the ground or as high as you can comfortably go.","Pause for a moment at the top, then slowly lower your legs back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Siediti sulla sedia del capitano con la schiena appoggiata allo schienale e gli avambracci appoggiati sui bracciali.","Mantieni la parte superiore del corpo stabile e la schiena dritta.","Attiva gli addominali e solleva le gambe davanti a te, tenendole dritte.","Continua a sollevare soli finché le gambe non sono parallele al suolo o il più in alto che puoi comodamente.","Fermati un attimo in cima, poi abbassa lentamente le gambe fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"1548","name":"chair leg extended stretch","category":"upper legs","equipment":"body weight","target":"quads","secondary":["hamstrings","calves"],"steps":{"en":["Sit on the edge of a chair with your back straight and feet flat on the ground.","Extend one leg straight out in front of you, keeping your heel on the ground.","Lean forward slightly, feeling a stretch in your quadriceps.","Hold this position for 20-30 seconds.","Switch legs and repeat the stretch."],"it":["Siediti sul bordo di una sedia con la schiena dritta e i piedi piatti a terra.","Estendi una gamba dritta davanti a te, tenendo il tallone a terra.","Piegati leggermente in avanti, sentendo uno stiramento nei quadricipiti.","Mantieni questa posizione per 20-30 secondi.","Cambia gamba e ripeti lo stretching."]}},{"id":"1271","name":"chest and front of shoulder stretch","category":"chest","equipment":"body weight","target":"pectorals","secondary":["deltoids"],"steps":{"en":["Stand tall with your feet shoulder-width apart.","Extend your arms straight out in front of you at shoulder height.","Cross your arms in front of your body, with your right arm on top of your left arm.","Interlace your fingers and press your palms together.","Gently squeeze your shoulder blades together and push your hands forward, feeling a stretch in your chest and front of your shoulders.","Hold the stretch for 20-30 seconds, then release.","Repeat for the desired number of repetitions."],"it":["Stai dritto con i piedi a larghezza delle spalle.","Allunga le braccia dritte davanti a te all'altezza delle spalle.","Incrocia le braccia davanti al corpo, con il braccio destro sopra quello sinistro.","Intreccia le dita e premi i palmi insieme.","Stringi delicatamente le scapole e spingi le mani in avanti, sentendo uno stiramento al petto e davanti alle spalle.","Mantieni lo stretching per 20-30 secondi, poi rilascia.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0251","name":"chest dip","category":"chest","equipment":"body weight","target":"pectorals","secondary":["triceps","shoulders"],"steps":{"en":["Position yourself on parallel bars with your arms fully extended and your body straight.","Lower your body by bending your elbows until your shoulders are below your elbows.","Push yourself back up to the starting position by straightening your arms.","Repeat for the desired number of repetitions."],"it":["Posizionati sulle barre parallele con le braccia completamente estese e il corpo dritto.","Abbassa il corpo piegando i gomiti finché le spalle non saranno sotto i gomiti.","Spingi di nuovo verso la posizione iniziale raddrizzando le braccia.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"1430","name":"chest dip (on dip-pull-up cage)","category":"chest","equipment":"body weight","target":"pectorals","secondary":["triceps","shoulders"],"steps":{"en":["Adjust the dip bars to a height that allows you to comfortably grip them.","Stand between the bars and place your hands on each bar, slightly wider than shoulder-width apart.","Jump up and straighten your arms, supporting your body weight on the bars.","Bend your knees and cross your ankles behind you.","Lower your body by bending your elbows, keeping your chest up and your shoulders down.","Continue lowering until your shoulders are below your elbows or until you feel a stretch in your chest.","Push through your palms and extend your elbows to raise your body back up to the starting position.","Repeat for the desired number of repetitions."],"it":["Regola le barre di immersione a un'altezza che ti permetta di tenerle comodamente.","Mettiti tra le barre e metti le mani su ciascuna barra, leggermente più larghe della larghezza delle spalle.","Salta su e raddrizza le braccia, sostenendo il peso del corpo sulle barre.","Piega le ginocchia e incrocia le caviglie dietro di te.","Abbassa il corpo piegando i gomiti, tenendo il petto sollevato e le spalle basse.","Continua ad abbassare finché le spalle non sono sotto i gomiti o finché non senti un allungamento al petto.","Spingi attraverso i palmi e allunga i gomiti per sollevare il corpo fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"2462","name":"chest dip on straight bar","category":"chest","equipment":"body weight","target":"pectorals","secondary":["triceps","shoulders"],"steps":{"en":["Grab the parallel bars with your palms facing down and your arms fully extended.","Bend your knees and cross your ankles.","Lower your body by bending your arms until your shoulders are below your elbows.","Push yourself back up to the starting position by straightening your arms.","Repeat for the desired number of repetitions."],"it":["Prendi le barre parallele con i palmi rivolti verso il basso e le braccia completamente distese.","Piega le ginocchia e incrocia le caviglie.","Abbassa il corpo piegando le braccia finché le spalle non saranno sotto i gomiti.","Spingi di nuovo verso la posizione iniziale raddrizzando le braccia.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"1272","name":"chest stretch with exercise ball","category":"chest","equipment":"stability ball","target":"pectorals","secondary":["shoulders","triceps"],"steps":{"en":["Sit on the stability ball with your feet flat on the ground and your back straight.","Hold the exercise ball with both hands and extend your arms straight out in front of you.","Slowly bring the exercise ball towards your chest, feeling a stretch in your chest muscles.","Hold the stretch for a few seconds, then slowly return to the starting position.","Repeat for the desired number of repetitions."],"it":["Siediti sulla palla di stabilità con i piedi piatti a terra e la schiena dritta.","Tieni la palla da esercizio con entrambe le mani e estendi le braccia dritte davanti a te.","Porta lentamente la palla da esercizio verso il petto, sentendo uno stiramento nei muscoli del petto.","Mantieni lo stretching per qualche secondo, poi torna lentamente alla posizione di partenza.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"3216","name":"chest tap push-up (male)","category":"chest","equipment":"body weight","target":"pectorals","secondary":["triceps","shoulders"],"steps":{"en":["Start in a high plank position with your hands slightly wider than shoulder-width apart and your body in a straight line.","Lower your body towards the ground by bending your elbows, keeping them close to your sides.","As you lower yourself, tap your chest with your right hand.","Push yourself back up to the starting position.","Repeat the movement, this time tapping your chest with your left hand.","Continue alternating sides for the desired number of repetitions."],"it":["Inizia in posizione di plank alta, con le mani leggermente più larghe della larghezza delle spalle e il corpo in linea retta.","Abbassa il corpo verso il suolo piegando i gomiti, tenendoli vicini ai fianchi.","Mentre ti abbassi, tocca il petto con la mano destra.","Spingi di nuovo verso la posizione di partenza.","Ripeti il movimento, questa volta toccando il petto con la mano sinistra.","Continua ad alternare i lati per il numero desiderato di ripetizioni."]}},{"id":"1326","name":"chin-up","category":"back","equipment":"body weight","target":"lats","secondary":["biceps","forearms"],"steps":{"en":["Hang from a pull-up bar with your palms facing towards you and your hands shoulder-width apart.","Engage your core and pull your body up towards the bar, leading with your chest.","Continue pulling until your chin is above the bar.","Pause for a moment at the top, then slowly lower your body back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Appenditi a una barra per trazioni con i palmi rivolti verso di te e le mani distanti alla larghezza delle spalle.","Attiva il core e tira il corpo verso la barra, iniziando con il petto.","Continua a tirare finché il mento non è sopra il bilanciere.","Fermati un attimo in cima, poi abbassa lentamente il corpo fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0253","name":"chin-ups (narrow parallel grip)","category":"back","equipment":"body weight","target":"upper back","secondary":["biceps","forearms"],"steps":{"en":["Hang from a pull-up bar with a narrow parallel grip, palms facing towards you.","Engage your back muscles and pull your body up towards the bar, keeping your elbows close to your body.","Continue pulling until your chin is above the bar.","Pause for a moment at the top, then slowly lower your body back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Appenditi a una barra per trazioni con una presa stretta e parallela, palmi rivolti verso di te.","Attiva i muscoli della schiena e tira il corpo verso la barra, tenendo i gomiti vicini al corpo.","Continua a tirare finché il mento non è sopra il bilanciere.","Fermati un attimo in cima, poi abbassa lentamente il corpo fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0257","name":"circles knee stretch","category":"lower legs","equipment":"body weight","target":"calves","secondary":["hamstrings","quadriceps"],"steps":{"en":["Stand with your feet shoulder-width apart and your hands on your hips.","Bend your knees slightly and lift your heels off the ground, balancing on the balls of your feet.","Keeping your knees bent, rotate your knees in a circular motion, first clockwise and then counterclockwise.","Perform the movement for the desired number of repetitions."],"it":["Stai in piedi con i piedi alla larghezza delle spalle e le mani sui fianchi.","Flette leggermente le ginocchia e solleva i talloni da terra, bilanciandoti sulle punte dei piedi.","Tenendo le ginocchia piegate, ruotate le ginocchia in un movimento circolare, prima in senso orario e poi in senso antiorario.","Esegui il movimento per il numero desiderato di ripetizioni."]}},{"id":"1273","name":"clap push up","category":"chest","equipment":"body weight","target":"pectorals","secondary":["triceps","shoulders"],"steps":{"en":["Start in a high plank position with your hands slightly wider than shoulder-width apart.","Lower your body towards the ground by bending your elbows, keeping your core engaged.","Push through your palms explosively to propel your body off the ground.","While in mid-air, clap your hands together before landing back in the starting position.","Repeat for the desired number of repetitions."],"it":["Inizia in posizione di tavola alta con le mani leggermente più larghe della larghezza delle spalle.","Abbassa il corpo verso il suolo piegando i gomiti, mantenendo il core attivo.","Spingi attraverso i palmi esplosivi per sollevare il corpo da terra.","Mentre sei a mezz'aria, batti le mani insieme prima di riatterrare nella posizione di partenza.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0258","name":"clock push-up","category":"chest","equipment":"body weight","target":"pectorals","secondary":["triceps","shoulders","core"],"steps":{"en":["Start in a high plank position with your hands directly under your shoulders and your body in a straight line.","Lower your body towards the ground by bending your elbows, keeping them close to your sides.","As you lower, rotate your body to the left, extending your left arm straight out to the side.","Push back up to the starting position, while rotating your body to the center.","Repeat the push-up, this time rotating your body to the right and extending your right arm out to the side.","Continue alternating sides with each repetition."],"it":["Inizia in posizione di plank alta con le mani direttamente sotto le spalle e il corpo in linea retta.","Abbassa il corpo verso il suolo piegando i gomiti, tenendoli vicini ai fianchi.","Mentre ti abbassi, ruota il corpo verso sinistra, estendendo il braccio sinistro dritto di lato.","Spingi di nuovo verso l'alto fino alla posizione iniziale, ruotando il corpo verso il centro.","Ripeti il piegamenti, questa volta ruotando il corpo verso destra e estendendo il braccio destro di lato.","Continua ad alternare i lati ad ogni ripetizione."]}},{"id":"1327","name":"close grip chin-up","category":"back","equipment":"body weight","target":"lats","secondary":["biceps","forearms"],"steps":{"en":["Grab the pull-up bar with your palms facing towards you and your hands shoulder-width apart.","Hang from the bar with your arms fully extended and your feet off the ground.","Engage your back muscles and pull your body up towards the bar, keeping your elbows close to your body.","Continue pulling until your chin is above the bar.","Pause for a moment at the top, then slowly lower your body back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Prendi la barra per le trazioni con i palmi rivolti verso di te e le mani alla larghezza delle spalle.","Appenditi al bilanciere con le braccia completamente distese e i piedi sollevati da terra.","Attiva i muscoli della schiena e tira il corpo verso la barra, tenendo i gomiti vicini al corpo.","Continua a tirare finché il mento non è sopra il bilanciere.","Fermati un attimo in cima, poi abbassa lentamente il corpo fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0259","name":"close-grip push-up","category":"upper arms","equipment":"body weight","target":"triceps","secondary":["chest","shoulders"],"steps":{"en":["Start in a high plank position with your hands placed close together, directly under your shoulders.","Engage your core and lower your body towards the ground, keeping your elbows close to your sides.","Push through your palms to extend your arms and return to the starting position.","Repeat for the desired number of repetitions."],"it":["Inizia in posizione di tavola alta con le mani vicine, direttamente sotto le spalle.","Attiva il core e abbassa il corpo verso terra, tenendo i gomiti vicini ai fianchi.","Spingi attraverso i palmi per estendere le braccia e tornare alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"2398","name":"close-grip push-up (on knees)","category":"upper arms","equipment":"body weight","target":"triceps","secondary":["chest","shoulders"],"steps":{"en":["Start by getting on your hands and knees, with your hands shoulder-width apart and your knees hip-width apart.","Lower your upper body towards the ground by bending your elbows, keeping them close to your sides.","Pause for a moment when your chest is just above the ground.","Push through your palms to straighten your arms and return to the starting position.","Repeat for the desired number of repetitions."],"it":["Inizia mettendosi a quattro zampe, con le mani larghe alle spalle e le ginocchia larghe ai fianchi.","Abbassa la parte superiore del corpo verso terra piegando i gomiti, tenendoli vicini ai fianchi.","Fermati un attimo quando il petto è appena sopra il suolo.","Spingi attraverso i palmi per raddrizzare le braccia e tornare alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0260","name":"cocoons","category":"waist","equipment":"body weight","target":"abs","secondary":["hip flexors","lower back"],"steps":{"en":["Lie flat on your back with your knees bent and feet flat on the ground.","Place your hands behind your head with your elbows pointing outwards.","Engaging your abs, slowly lift your upper body off the ground, curling forward until your torso is at a 45-degree angle.","Pause for a moment at the top, then slowly lower your upper body back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Sdraiati sulla schiena con le ginocchia piegate e i piedi piatti a terra.","Metti le mani dietro la testa con i gomiti rivolti verso l'esterno.","Attivando gli addominali, solleva lentamente la parte superiore del corpo da terra, piegandola in avanti finché il busto non è a un angolo di 45 gradi.","Fermati un attimo in cima, poi abbassa lentamente la parte superiore del corpo fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"1468","name":"crab twist toe touch","category":"waist","equipment":"body weight","target":"abs","secondary":["obliques","hip flexors"],"steps":{"en":["Start by sitting on the ground with your knees bent and feet flat on the floor.","Place your hands behind you, fingers pointing towards your feet, and lift your hips off the ground.","Extend one leg straight out in front of you while simultaneously reaching your opposite hand towards your toes.","Return to the starting position and repeat on the other side.","Continue alternating sides for the desired number of repetitions."],"it":["Inizia seduto a terra con le ginocchia piegate e i piedi appoggiati sul pavimento.","Metti le mani dietro di te, le dita puntate verso i piedi, e solleva i fianchi da terra.","Allunga una gamba dritta davanti a te mentre contemporaneamente allunghi la mano opposta verso le dita dei piedi.","Torna alla posizione di partenza e ripeti dall'altra parte.","Continua ad alternare i lati per il numero desiderato di ripetizioni."]}},{"id":"0262","name":"cross body crunch","category":"waist","equipment":"body weight","target":"abs","secondary":["obliques"],"steps":{"en":["Lie flat on your back with your knees bent and feet flat on the ground.","Place your hands behind your head with your elbows pointing outwards.","Engaging your abs, lift your upper body off the ground and twist to bring your right elbow towards your left knee.","Pause for a moment at the top, then slowly lower your upper body back down to the starting position.","Repeat on the other side, bringing your left elbow towards your right knee.","Repeat for the desired number of repetitions."],"it":["Sdraiati sulla schiena con le ginocchia piegate e i piedi piatti a terra.","Metti le mani dietro la testa con i gomiti rivolti verso l'esterno.","Attivando gli addominali, solleva la parte superiore del corpo da terra e ruota per avvicinare il gomito destro al ginocchio sinistro.","Fermati un attimo in cima, poi abbassa lentamente la parte superiore del corpo fino alla posizione iniziale.","Ripeti dall'altro lato, avvicinando il gomito sinistro al ginocchio destro.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0267","name":"crunch (hands overhead)","category":"waist","equipment":"body weight","target":"abs","secondary":["hip flexors"],"steps":{"en":["Lie flat on your back with your knees bent and feet flat on the ground.","Extend your arms straight above your head.","Engaging your abs, lift your upper body off the ground, curling forward towards your knees.","Pause for a moment at the top, then slowly lower your upper body back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Sdraiati sulla schiena con le ginocchia piegate e i piedi piatti a terra.","Allunga le braccia dritte sopra la testa.","Attivando gli addominali, solleva la parte superiore del corpo da terra, piegandola in avanti verso le ginocchia.","Fermati un attimo in cima, poi abbassa lentamente la parte superiore del corpo fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0271","name":"crunch (on stability ball)","category":"waist","equipment":"stability ball","target":"abs","secondary":["hip flexors"],"steps":{"en":["Sit on the stability ball with your feet flat on the ground and your knees bent at a 90-degree angle.","Lie back on the ball until your lower back is supported and your upper body is parallel to the floor.","Place your hands behind your head or across your chest.","Engage your abs and lift your upper body towards your knees, curling your torso forward.","Pause for a moment at the top of the movement, then slowly lower your upper body back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Siediti sulla palla di stabilità con i piedi piatti a terra e le ginocchia piegate a 90 gradi.","Sdraiati sulla palla finché la parte bassa della schiena non è sostenuta e la parte superiore del corpo è parallela al pavimento.","Metti le mani dietro la testa o sul petto.","Attiva gli addominali e solleva la parte superiore del corpo verso le ginocchia, piegando il busto in avanti.","Fermati un attimo all'inizio del movimento, poi abbassa lentamente la parte superiore del corpo fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0272","name":"crunch (on stability ball, arms straight)","category":"waist","equipment":"stability ball","target":"abs","secondary":["hip flexors"],"steps":{"en":["Sit on the stability ball with your feet flat on the ground and your knees bent at a 90-degree angle.","Lie back on the ball until your lower back is supported and your upper body is parallel to the floor.","Place your hands behind your head or cross them over your chest.","Engage your abs and lift your upper body off the ball, curling your shoulders towards your hips.","Pause for a moment at the top, then slowly lower your upper body back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Siediti sulla palla di stabilità con i piedi piatti a terra e le ginocchia piegate a 90 gradi.","Sdraiati sulla palla finché la parte bassa della schiena non è sostenuta e la parte superiore del corpo è parallela al pavimento.","Metti le mani dietro la testa o incrociale sul petto.","Attiva gli addominali e solleva la parte superiore del corpo dalla palla, piegando le spalle verso i fianchi.","Fermati un attimo in cima, poi abbassa lentamente la parte superiore del corpo fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0274","name":"crunch floor","category":"waist","equipment":"body weight","target":"abs","secondary":["hip flexors"],"steps":{"en":["Lie flat on your back with your knees bent and feet flat on the ground.","Place your hands behind your head with your elbows pointing outwards.","Engage your abs and lift your shoulders off the ground, curling forward towards your knees.","Pause for a moment at the top, then slowly lower your shoulders back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Sdraiati sulla schiena con le ginocchia piegate e i piedi piatti a terra.","Metti le mani dietro la testa con i gomiti rivolti verso l'esterno.","Attiva gli addominali e solleva le spalle da terra, piegandosi in avanti verso le ginocchia.","Fermati un attimo in cima, poi abbassa lentamente le spalle fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"3016","name":"curl-up","category":"waist","equipment":"body weight","target":"abs","secondary":["hip flexors"],"steps":{"en":["Lie flat on your back with your knees bent and feet flat on the ground.","Place your hands behind your head with your elbows pointing outwards.","Engaging your abs, slowly lift your upper body off the ground, curling forward until your torso is at a 45-degree angle.","Pause for a moment at the top, then slowly lower your upper body back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Sdraiati sulla schiena con le ginocchia piegate e i piedi piatti a terra.","Metti le mani dietro la testa con i gomiti rivolti verso l'esterno.","Attivando gli addominali, solleva lentamente la parte superiore del corpo da terra, piegandola in avanti finché il busto non è a un angolo di 45 gradi.","Fermati un attimo in cima, poi abbassa lentamente la parte superiore del corpo fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"3769","name":"curtsey squat","category":"upper legs","equipment":"body weight","target":"glutes","secondary":["quadriceps","hamstrings","calves"],"steps":{"en":["Stand with your feet shoulder-width apart.","Take a step diagonally behind and across your body with your right foot, crossing it behind your left leg.","Bend both knees as if you were curtsying, lowering your body towards the ground.","Keep your torso upright and your weight on your front foot.","Push through your front foot to return to the starting position.","Repeat on the other side, stepping diagonally behind and across your body with your left foot."],"it":["Stai con i piedi a larghezza delle spalle.","Fai un passo diagonalmente dietro e attraverso il corpo con il piede destro, incrociandolo dietro la gamba sinistra.","Piega entrambe le ginocchia come se stessi facendo un inchino, abbassando il corpo verso terra.","Mantieni il busto eretto e il peso sul piede anteriore.","Spingi con il piede anteriore per tornare alla posizione di partenza.","Ripeti dall'altro lato, camminando diagonalmente dietro e attraverso il corpo con il piede sinistro."]}},{"id":"0276","name":"dead bug","category":"waist","equipment":"body weight","target":"abs","secondary":["hip flexors","lower back"],"steps":{"en":["Lie flat on your back with your arms extended towards the ceiling.","Bend your knees and lift your legs off the ground, creating a 90-degree angle at your hips and knees.","Engage your core and lower back to press your lower back into the ground.","Slowly lower your right arm and left leg towards the ground, keeping them straight and hovering just above the floor.","Pause for a moment, then return to the starting position.","Repeat the movement with your left arm and right leg.","Continue alternating sides for the desired number of repetitions."],"it":["Sdraiati sulla schiena con le braccia tese verso il soffitto.","Piega le ginocchia e solleva le gambe da terra, creando un angolo di 90 gradi tra fianchi e ginocchia.","Attiva il core e la parte bassa della schiena per premere la parte bassa della schiena contro il terreno.","Abbassa lentamente il braccio destro e la gamba sinistra verso terra, mantenendoli dritti e sospesi appena sopra il pavimento.","Fermati un attimo, poi torna alla posizione iniziale.","Ripeti il movimento con il braccio sinistro e la gamba destra.","Continua ad alternare i lati per il numero desiderato di ripetizioni."]}},{"id":"0277","name":"decline crunch","category":"waist","equipment":"body weight","target":"abs","secondary":["hip flexors"],"steps":{"en":["Lie on a decline bench with your feet secured and your knees bent at a 90-degree angle.","Place your hands behind your head or across your chest.","Engage your abs and lift your upper body towards your knees, curling your torso.","Pause for a moment at the top, then slowly lower your upper body back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Sdraiati su una panca di discesa con i piedi ben assicurati e le ginocchia piegate a 90 gradi.","Metti le mani dietro la testa o sul petto.","Attiva gli addominali e solleva la parte superiore del corpo verso le ginocchia, curvando il busto.","Fermati un attimo in cima, poi abbassa lentamente la parte superiore del corpo fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0279","name":"decline push-up","category":"chest","equipment":"body weight","target":"pectorals","secondary":["triceps","shoulders"],"steps":{"en":["Place your hands on the ground slightly wider than shoulder-width apart, with your feet elevated on a stable surface.","Keep your body in a straight line from head to toe, engaging your core muscles.","Lower your chest towards the ground by bending your elbows, keeping them close to your body.","Push through your palms to extend your arms and return to the starting position.","Repeat for the desired number of repetitions."],"it":["Appoggia le mani a terra, leggermente più larghe della larghezza delle spalle, con i piedi sollevati su una superficie stabile.","Mantieni il corpo in linea retta dalla testa ai piedi, attivando i muscoli del core.","Abbassa il petto verso il suolo piegando i gomiti, tenendoli vicini al corpo.","Spingi attraverso i palmi per estendere le braccia e tornare alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0282","name":"decline sit-up","category":"waist","equipment":"body weight","target":"abs","secondary":["hip flexors","lower back"],"steps":{"en":["Lie on a decline bench with your feet secured and your knees bent.","Place your hands behind your head or across your chest.","Engage your abs and lift your upper body off the bench, curling forward towards your knees.","Pause for a moment at the top, then slowly lower your upper body back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Sdraiati su una panca inclinata con i piedi ben assicurati e le ginocchia piegate.","Metti le mani dietro la testa o sul petto.","Attiva gli addominali e solleva la parte superiore del corpo dalla panca, piegandosi in avanti verso le ginocchia.","Fermati un attimo in cima, poi abbassa lentamente la parte superiore del corpo fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"1274","name":"deep push up","category":"chest","equipment":"dumbbell","target":"pectorals","secondary":["triceps","shoulders"],"steps":{"en":["Start in a high plank position with your hands slightly wider than shoulder-width apart and your body in a straight line.","Lower your chest towards the ground by bending your elbows, keeping them close to your body.","Push through your palms to extend your arms and return to the starting position.","Repeat for the desired number of repetitions."],"it":["Inizia in posizione di plank alta, con le mani leggermente più larghe della larghezza delle spalle e il corpo in linea retta.","Abbassa il petto verso il suolo piegando i gomiti, tenendoli vicini al corpo.","Spingi attraverso i palmi per estendere le braccia e tornare alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0283","name":"diamond push-up","category":"upper arms","equipment":"body weight","target":"triceps","secondary":["chest","shoulders"],"steps":{"en":["Start in a high plank position with your hands close together, forming a diamond shape with your thumbs and index fingers.","Keep your body in a straight line from head to toe, engaging your core and glutes.","Lower your chest towards the diamond shape formed by your hands, keeping your elbows close to your body.","Pause for a moment at the bottom, then push yourself back up to the starting position.","Repeat for the desired number of repetitions."],"it":["Inizia in posizione di tavola alta con le mani vicine, formando una forma di diamante con pollici e indici.","Mantieni il corpo in linea retta dalla testa ai piedi, attivando core e glutei.","Abbassa il petto verso la forma a diamante formata dalle mani, tenendo i gomiti vicini al corpo.","Fermati un attimo in fondo, poi risali fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0284","name":"donkey calf raise","category":"lower legs","equipment":"body weight","target":"calves","secondary":["hamstrings","glutes"],"steps":{"en":["Stand with your toes on an elevated surface, such as a step or block.","Place your hands on a stable support, such as a wall or railing, for balance.","Raise your heels as high as possible, lifting your body weight onto the balls of your feet.","Pause for a moment at the top, then slowly lower your heels back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai con le dita dei piedi su una superficie rialzata, come un gradino o un blocco.","Appoggia le mani su un supporto stabile, come un muro o una ringhiera, per mantenere l'equilibrio.","Alza i talloni il più in alto possibile, sollevando il peso del corpo sulle punte dei piedi.","Fermati un attimo in cima, poi abbassa lentamente i talloni fino alla posizione di partenza.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"1275","name":"drop push up","category":"chest","equipment":"body weight","target":"pectorals","secondary":["triceps","shoulders"],"steps":{"en":["Start in a high plank position with your hands slightly wider than shoulder-width apart.","Lower your chest towards the ground, keeping your elbows close to your body.","Once your chest is just above the ground, quickly drop your knees to the ground.","Push yourself back up to the starting position by extending your arms.","Repeat for the desired number of repetitions."],"it":["Inizia in posizione di tavola alta con le mani leggermente più larghe della larghezza delle spalle.","Abbassa il petto verso terra, tenendo i gomiti vicini al corpo.","Quando il petto è appena sopra il suolo, abbassa rapidamente le ginocchia a terra.","Rialzati alla posizione iniziale estendendo le braccia.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0285","name":"dumbbell alternate biceps curl","category":"upper arms","equipment":"dumbbell","target":"biceps","secondary":["forearms"],"steps":{"en":["Stand up straight with a dumbbell in each hand, palms facing forward and arms fully extended.","Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions, alternating arms."],"it":["Stai dritto con un manubrio in ogni mano, palmi rivolti in avanti e braccia completamente estese.","Mantenendo ferme le braccia superiori, espira e arriccia i pesi mentre contrahi i bicipiti.","Continua ad alzare i manubri finché i bicipiti non sono completamente contratti e i manubri non sono all'altezza delle spalle.","Mantieni la posizione contratta per una breve pausa mentre stringi i bicipiti.","Inspira e inizia lentamente ad abbassare i manubri fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni, alternando le braccia."]}},{"id":"2403","name":"dumbbell alternate biceps curl (with arm blaster)","category":"upper arms","equipment":"dumbbell","target":"biceps","secondary":["forearms"],"steps":{"en":["Stand up straight with your feet shoulder-width apart and hold a dumbbell in each hand, palms facing forward.","Place the arm blaster on your upper arms, ensuring a secure fit.","Keeping your upper arms stationary, exhale and curl one dumbbell up towards your shoulder while contracting your biceps.","Continue to raise the dumbbell until your biceps are fully contracted and the dumbbell is at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly lower the dumbbell back to the starting position.","Repeat the movement with the opposite arm.","Continue alternating arms for the desired number of repetitions."],"it":["Stai dritto con i piedi alla larghezza delle spalle e tieni un manubrio in ciascuna mano, palmi rivolti in avanti.","Posiziona il braccio blaster sulle braccia superiori, assicurandoti una calzata sicura.","Mantenendo ferme le braccia superiori, espira e arriccia un manubrio verso la spalla mentre contrahi i bicipiti.","Continua ad alzare il manubrio finché i bicipiti non sono completamente contratti e il manubrio non è all'altezza delle spalle.","Mantieni la posizione contratta per una breve pausa mentre stringi i bicipiti.","Inspira e abbassa lentamente il manubrio alla posizione iniziale.","Ripeti il movimento con il braccio opposto.","Continuare ad alternare le braccia per il numero desiderato di ripetizioni."]}},{"id":"1646","name":"dumbbell alternate hammer preacher curl","category":"upper arms","equipment":"dumbbell","target":"biceps","secondary":["forearms"],"steps":{"en":["Sit on a preacher bench with a dumbbell in each hand, palms facing your torso and arms fully extended.","Keep your upper arms stationary and exhale as you curl the weights while contracting your biceps.","Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the recommended amount of repetitions."],"it":["Siediti su una panca da predicatore con un manubrio in ogni mano, i palmi rivolti verso il busto e le braccia completamente distese.","Mantieni ferme le braccia superiori ed espira mentre piedi i pesi contraendo i bicipiti.","Continua ad alzare i manubri finché i bicipiti non sono completamente contratti e i manubri non sono all'altezza delle spalle.","Mantieni la posizione contratta per una breve pausa mentre stringi i bicipiti.","Inspira e inizia lentamente ad abbassare i manubri fino alla posizione iniziale.","Ripeti per il numero consigliato di ripetizioni."]}},{"id":"1647","name":"dumbbell alternate preacher curl","category":"upper arms","equipment":"dumbbell","target":"biceps","secondary":["forearms"],"steps":{"en":["Sit on a preacher bench with a dumbbell in each hand, palms facing up.","Rest your upper arms on the pad of the preacher bench, allowing your arms to fully extend.","Keeping your upper arms stationary, exhale and curl the dumbbell in your right hand as you contract your biceps.","Continue to curl the dumbbell until your biceps are fully contracted and the dumbbell is at shoulder level.","Pause for a moment, then inhale and slowly lower the dumbbell back to the starting position.","Repeat the movement with your left arm.","Continue alternating arms for the desired number of repetitions."],"it":["Seduta su una panca da predicatore con un manubrio in ogni mano, i palmi rivolti verso l'alto.","Appoggia le braccia superiori sul cuscinetto della panca del predicatore, permettendo alle braccia di estendersi completamente.","Mantenendo ferme le braccia superiori, espira e arriccia il manubrio nella mano destra mentre contrai i bicipiti.","Continua a piegare il manubrio finché i bicipiti non sono completamente contratti e il manubrio non è all'altezza delle spalle.","Fermati un attimo, poi inspira e abbassa lentamente il manubrio alla posizione iniziale.","Ripeti il movimento con il braccio sinistro.","Continuare ad alternare le braccia per il numero desiderato di ripetizioni."]}},{"id":"1648","name":"dumbbell alternate seated hammer curl","category":"upper arms","equipment":"dumbbell","target":"biceps","secondary":["forearms"],"steps":{"en":["Sit on a bench with a dumbbell in each hand, palms facing your torso and arms extended down.","Keep your back straight and your elbows close to your torso.","Exhale and curl the dumbbell in your right hand towards your shoulder, keeping your upper arm stationary.","Continue to raise the dumbbell until your biceps are fully contracted and the dumbbell is at shoulder level.","Pause for a brief moment, then inhale and slowly lower the dumbbell back to the starting position.","Repeat the movement with your left arm.","Continue alternating arms for the desired number of repetitions."],"it":["Siediti su una panchina con un manubrio in ogni mano, i palmi rivolti verso il busto e le braccia distese verso il basso.","Tieni la schiena dritta e i gomiti vicini al busto.","Espira e arrotola il manubrio della mano destra verso la spalla, mantenendo fermo il braccio superiore.","Continua ad alzare il manubrio finché i bicipiti non sono completamente contratti e il manubrio non è all'altezza delle spalle.","Fermati un attimo, poi inspira e abbassa lentamente il manubrio fino alla posizione iniziale.","Ripeti il movimento con il braccio sinistro.","Continuare ad alternare le braccia per il numero desiderato di ripetizioni."]}},{"id":"0286","name":"dumbbell alternate side press","category":"shoulders","equipment":"dumbbell","target":"delts","secondary":["triceps","core"],"steps":{"en":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand at shoulder height.","Press one dumbbell overhead while keeping the other dumbbell at shoulder height.","Lower the pressed dumbbell back to shoulder height while pressing the other dumbbell overhead.","Continue alternating sides for the desired number of repetitions."],"it":["Stai con i piedi a larghezza delle spalle, tenendo un manubrio in ogni mano all'altezza delle spalle.","Premi un manubrio sopra la testa mantenendo l'altro all'altezza delle spalle.","Abbassa il manubrio premuto all'altezza delle spalle mentre premi l'altro manubrio sopra la testa.","Continua ad alternare i lati per il numero desiderato di ripetizioni."]}},{"id":"1649","name":"dumbbell alternating bicep curl with leg raised on exercise ball","category":"upper arms","equipment":"dumbbell","target":"biceps","secondary":["forearms","shoulders"],"steps":{"en":["Stand with your feet shoulder-width apart and hold a dumbbell in each hand, palms facing forward.","Place an exercise ball behind you and position one foot on top of it, keeping your balance.","With your arms fully extended and elbows close to your sides, curl one dumbbell towards your shoulder while keeping your upper arm stationary.","Lower the dumbbell back down to the starting position and repeat with the other arm.","Continue alternating arms for the desired number of repetitions."],"it":["Stai con i piedi a larghezza delle spalle e tieni un manubrio in ogni mano, palmi rivolti in avanti.","Metti una palla da ginnastica dietro di te e posiziona un piede sopra di essa, mantenendo l'equilibrio.","Con le braccia completamente estese e i gomiti vicini ai fianchi, piega un manubrio verso la spalla mantenendo fermo la parte superiore del braccio.","Abbassa il manubrio fino alla posizione iniziale e ripeti con l'altro braccio.","Continuare ad alternare le braccia per il numero desiderato di ripetizioni."]}},{"id":"1650","name":"dumbbell alternating seated bicep curl on exercise ball","category":"upper arms","equipment":"dumbbell","target":"biceps","secondary":["forearms"],"steps":{"en":["Sit on an exercise ball with your feet flat on the ground and your back straight.","Hold a dumbbell in each hand with your palms facing forward and your arms fully extended.","Keeping your upper arms stationary, exhale and curl one dumbbell while rotating your forearm until your palm is facing your shoulder.","Inhale and slowly lower the dumbbell back to the starting position.","Repeat the curl with the other arm.","Continue alternating curls for the desired number of repetitions."],"it":["Siediti su una palla da ginnastica con i piedi piatti a terra e la schiena dritta.","Tieni un manubrio in ogni mano con i palmi rivolti in avanti e le braccia completamente estese.","Mantenendo ferme le braccia superiori, espira e arriccia un manubrio mentre ruoti l'avambraccio finché il palmo non è rivolto verso la spalla.","Inspira e abbassa lentamente il manubrio alla posizione iniziale.","Ripeti il curl con l'altro braccio.","Continua a alternare i ricci per il numero desiderato di ripetizioni."]}},{"id":"2137","name":"dumbbell arnold press","category":"shoulders","equipment":"dumbbell","target":"delts","secondary":["triceps","upper chest"],"steps":{"en":["Sit on a bench with back support and hold a dumbbell in each hand at shoulder level, palms facing your body and elbows bent.","Press the dumbbells upward until your arms are fully extended and your palms are facing forward.","Rotate your wrists as you lift, so that your palms are facing forward at the top of the movement.","Pause for a moment at the top, then slowly lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"it":["Siediti su una panca con supporto per la schiena e tieni un manubrio in ciascuna mano all'altezza delle spalle, con i palmi rivolti verso il corpo e i gomiti piegati.","Premi i manubri verso l'alto finché le braccia non sono completamente estese e i palmi sono rivolti in avanti.","Ruota i polsi mentre sollevi, in modo che i palmi siano rivolti in avanti all'inizio del movimento.","Fermati un attimo in cima, poi abbassa lentamente i manubri alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0287","name":"dumbbell arnold press v. 2","category":"shoulders","equipment":"dumbbell","target":"delts","secondary":["triceps","upper chest"],"steps":{"en":["Sit on a bench with back support and hold a dumbbell in each hand at shoulder level, palms facing your body and elbows bent.","Press the dumbbells upward until your arms are fully extended and your palms are facing forward.","Rotate your wrists as you lift, so that your palms end up facing forward at the top of the movement.","Pause for a moment at the top, then slowly lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"it":["Siediti su una panca con supporto per la schiena e tieni un manubrio in ciascuna mano all'altezza delle spalle, con i palmi rivolti verso il corpo e i gomiti piegati.","Premi i manubri verso l'alto finché le braccia non sono completamente estese e i palmi sono rivolti in avanti.","Ruota i polsi mentre sollevi, così che i palmi finiscano rivolti in avanti nella parte superiore del movimento.","Fermati un attimo in cima, poi abbassa lentamente i manubri alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0288","name":"dumbbell around pullover","category":"chest","equipment":"dumbbell","target":"pectorals","secondary":["triceps","latissimus dorsi"],"steps":{"en":["Lie flat on a bench with your head at one end and your feet firmly on the ground.","Hold a dumbbell with both hands and extend your arms straight above your chest.","Keeping your arms straight, slowly lower the dumbbell behind your head in an arc motion.","Pause for a moment at the bottom, then raise the dumbbell back to the starting position.","Repeat for the desired number of repetitions."],"it":["Sdraiati su una panchina con la testa a un'estremità e i piedi ben saldi a terra.","Tieni un manubrio con entrambe le mani e estendi le braccia dritte sopra il petto.","Tenendo le braccia dritte, abbassa lentamente il manubrio dietro la testa in un movimento ad arco.","Fermati un attimo in fondo, poi rialza il manubrio alla posizione di partenza.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0289","name":"dumbbell bench press","category":"chest","equipment":"dumbbell","target":"pectorals","secondary":["triceps","shoulders"],"steps":{"en":["Lie flat on a bench with your feet flat on the ground and your back pressed against the bench.","Hold a dumbbell in each hand, with your palms facing forward and your arms extended above your chest.","Lower the dumbbells slowly to the sides of your chest, keeping your elbows at a 90-degree angle.","Pause for a moment, then push the dumbbells back up to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."],"it":["Sdraiati disteso su una panca con i piedi piatti a terra e la schiena premuta contro la panca.","Tieni un manubrio in ogni mano, con i palmi rivolti in avanti e le braccia estese sopra il petto.","Abbassa lentamente i manubri ai lati del petto, mantenendo i gomiti a 90 gradi.","Fermati un attimo, poi spingi i manubri di nuovo alla posizione iniziale, estendendo completamente le braccia.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0290","name":"dumbbell bench seated press","category":"shoulders","equipment":"dumbbell","target":"delts","secondary":["triceps","chest"],"steps":{"en":["Sit on a bench with a dumbbell in each hand, resting on your thighs.","Lean back and position the dumbbells to the sides of your chest, palms facing forward.","Press the dumbbells upward until your arms are fully extended.","Pause for a moment at the top, then slowly lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"it":["Siediti su una panchina con un manubrio in ogni mano, appoggiato sulle cosce.","Appoggiati all'indietro e posiziona i manubri ai lati del petto, palmi rivolti in avanti.","Premi i manubri verso l'alto finché le braccia non sono completamente estese.","Fermati un attimo in cima, poi abbassa lentamente i manubri alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0291","name":"dumbbell bench squat","category":"upper legs","equipment":"dumbbell","target":"glutes","secondary":["quadriceps","hamstrings","calves"],"steps":{"en":["Place a dumbbell on the ground in front of a bench.","Stand facing away from the bench with your feet shoulder-width apart.","Bend at the knees and hips to lower yourself down towards the bench, keeping your chest up and back straight.","Once your glutes touch the bench, push through your heels to stand back up to the starting position.","Repeat for the desired number of repetitions."],"it":["Metti un manubrio a terra davanti a una panchina.","Stai rivolto dall'altra parte della panca con i piedi a larghezza delle spalle.","Fleetta ginocchia e fianchi per abbassarti verso la panca, tenendo il petto alzato e la schiena dritta.","Quando i glutei toccano la panca, spingi attraverso i talloni per rialzarti fino alla posizione di partenza.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0293","name":"dumbbell bent over row","category":"back","equipment":"dumbbell","target":"upper back","secondary":["biceps","forearms"],"steps":{"en":["Stand with your feet shoulder-width apart, knees slightly bent, and hold a dumbbell in each hand with your palms facing your body.","Bend forward at the hips, keeping your back straight and your core engaged.","Let your arms hang straight down towards the floor, with your elbows slightly bent.","Pull the dumbbells up towards your chest, squeezing your shoulder blades together.","Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai con i piedi a larghezza delle spalle, le ginocchia leggermente piegate, e tieni un manubrio in ciascuna mano con i palmi rivolti verso il corpo.","Piegati in avanti sui fianchi, mantenendo la schiena dritta e il core attivo.","Lascia che le braccia pendano dritte verso il pavimento, con i gomiti leggermente piegati.","Tira i manubri verso il petto, stringendo le scapole insieme.","Fermati un attimo in cima, poi abbassa lentamente i manubri fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"1651","name":"dumbbell bicep curl lunge with bowling motion","category":"upper arms","equipment":"dumbbell","target":"biceps","secondary":["forearms","shoulders"],"steps":{"en":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand with your palms facing forward.","Take a step forward with your right foot, bending your right knee and lowering your body into a lunge position.","As you lunge forward, curl the dumbbells up towards your shoulders, keeping your elbows close to your body.","At the bottom of the lunge, rotate your torso to the right, as if you were bowling a ball.","Reverse the motion, stepping back with your right foot and returning to the starting position while lowering the dumbbells back down.","Repeat the lunge and curl motion, this time rotating your torso to the left.","Continue alternating sides for the desired number of repetitions."],"it":["Stai in piedi con i piedi alla larghezza delle spalle, tenendo un manubrio in ciascuna mano con i palmi rivolti in avanti.","Fai un passo avanti con il piede destro, piegando il ginocchio destro e abbassando il corpo in posizione di affondamento.","Mentre ti lanci in avanti, arrotola i manubri verso le spalle, tenendo i gomiti vicini al corpo.","In fondo all'affondo, ruota il busto verso destra, come se stessi lanciando una palla.","Inverti il movimento, facendo un passo indietro con il piede destro e tornando alla posizione iniziale mentre abbassi di nuovo i manubri.","Ripeti il movimento di affondo e curvatura, questa volta ruotando il busto verso sinistra.","Continua ad alternare i lati per il numero desiderato di ripetizioni."]}},{"id":"1652","name":"dumbbell bicep curl on exercise ball with leg raised","category":"upper arms","equipment":"dumbbell","target":"biceps","secondary":["forearms","shoulders"],"steps":{"en":["Sit on an exercise ball with your feet flat on the ground and your back straight.","Hold a dumbbell in each hand with your palms facing forward and your arms fully extended.","Slowly curl the dumbbells towards your shoulders, keeping your elbows close to your sides.","Pause for a moment at the top of the movement, then slowly lower the dumbbells back to the starting position.","While performing the bicep curl, raise one leg off the ground and hold it in the air for the duration of the exercise.","Repeat for the desired number of repetitions, then switch legs and repeat."],"it":["Siediti su una palla da ginnastica con i piedi piatti a terra e la schiena dritta.","Tieni un manubrio in ogni mano con i palmi rivolti in avanti e le braccia completamente estese.","Arrotola lentamente i manubri verso le spalle, tenendo i gomiti vicini ai fianchi.","Fermati un attimo all'inizio del movimento, poi abbassa lentamente i manubri alla posizione iniziale.","Durante l'esecuzione del curl per il bicipite, solleva una gamba da terra e tienilo in aria per tutta la durata dell'esercizio.","Ripeti per il numero desiderato di ripetizioni, poi cambia gamba e ripeti."]}},{"id":"1653","name":"dumbbell bicep curl with stork stance","category":"upper arms","equipment":"dumbbell","target":"biceps","secondary":["forearms"],"steps":{"en":["Stand with your feet shoulder-width apart and hold a dumbbell in each hand, palms facing forward.","Extend one leg behind you, balancing on the toes of that foot.","Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions, then switch legs and repeat."],"it":["Stai con i piedi a larghezza delle spalle e tieni un manubrio in ogni mano, palmi rivolti in avanti.","Allunga una gamba dietro di te, bilanciandoti sulle punte di quel piede.","Mantenendo ferme le braccia superiori, espira e arriccia i pesi mentre contrahi i bicipiti.","Continua ad alzare i pesi finché i bicipiti non sono completamente contratti e i manubri non sono all'altezza delle spalle.","Mantieni la posizione contratta per una breve pausa mentre stringi i bicipiti.","Inspira e inizia lentamente ad abbassare i manubri fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni, poi cambia gamba e ripeti."]}},{"id":"0294","name":"dumbbell biceps curl","category":"upper arms","equipment":"dumbbell","target":"biceps","secondary":["forearms"],"steps":{"en":["Stand up straight with a dumbbell in each hand, palms facing forward and arms fully extended.","Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai dritto con un manubrio in ogni mano, palmi rivolti in avanti e braccia completamente estese.","Mantenendo ferme le braccia superiori, espira e arriccia i pesi mentre contrahi i bicipiti.","Continua ad alzare i pesi finché i bicipiti non sono completamente contratti e i manubri non sono all'altezza delle spalle.","Mantieni la posizione contratta per una breve pausa mentre stringi i bicipiti.","Inspira e inizia lentamente ad abbassare i manubri fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"2401","name":"dumbbell biceps curl (with arm blaster)","category":"upper arms","equipment":"dumbbell","target":"biceps","secondary":["forearms"],"steps":{"en":["Stand up straight with a dumbbell in each hand, palms facing forward.","Keep your elbows close to your torso and your upper arms stationary.","Exhale and curl the weights while contracting your biceps.","Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai dritto con un manubrio in ciascuna mano, palmi rivolti in avanti.","Tieni i gomiti vicini al busto e le braccia superiori ferme.","Espira e arriccia i pesi mentre contrahi i bicipiti.","Continua ad alzare i pesi finché i bicipiti non sono completamente contratti e i manubri non sono all'altezza delle spalle.","Mantieni la posizione contratta per una breve pausa mentre stringi i bicipiti.","Inspira e inizia lentamente ad abbassare i manubri fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"1654","name":"dumbbell biceps curl reverse","category":"upper arms","equipment":"dumbbell","target":"biceps","secondary":["forearms"],"steps":{"en":["Stand up straight with a dumbbell in each hand, palms facing down and arms fully extended.","Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai dritto con un manubrio in ogni mano, palmi rivolti verso il basso e braccia completamente distese.","Mantenendo ferme le braccia superiori, espira e arriccia i pesi mentre contrahi i bicipiti.","Continua ad alzare i manubri finché i bicipiti non sono completamente contratti e i manubri non sono all'altezza delle spalle.","Mantieni la posizione contratta per una breve pausa mentre stringi i bicipiti.","Inspira e inizia lentamente ad abbassare i manubri fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"1655","name":"dumbbell biceps curl squat","category":"upper arms","equipment":"dumbbell","target":"biceps","secondary":["forearms"],"steps":{"en":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand with your palms facing forward.","Keeping your back straight and your elbows close to your sides, exhale and curl the dumbbells up towards your shoulders.","Pause for a moment at the top, squeezing your biceps.","Inhale and slowly lower the dumbbells back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai in piedi con i piedi alla larghezza delle spalle, tenendo un manubrio in ciascuna mano con i palmi rivolti in avanti.","Tenendo la schiena dritta e i gomiti ai lati, espira e arrotola i manubri verso le spalle.","Fermati un attimo in cima, stringendo i bicipiti.","Inspira e abbassa lentamente i manubri fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"1656","name":"dumbbell biceps curl v sit on bosu ball","category":"upper arms","equipment":"dumbbell","target":"biceps","secondary":["forearms","shoulders"],"steps":{"en":["Sit on a bosu ball with your feet flat on the ground and your knees bent at a 90-degree angle.","Hold a dumbbell in each hand with your palms facing forward and your arms fully extended down by your sides.","Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"it":["Siediti su una palla bosu con i piedi piatti a terra e le ginocchia piegate a 90 gradi.","Tieni un manubrio in ogni mano con i palmi rivolti in avanti e le braccia completamente estese lungo i fianchi.","Mantenendo ferme le braccia superiori, espira e arriccia i pesi mentre contrahi i bicipiti.","Continua ad alzare i manubri finché i bicipiti non sono completamente contratti e i manubri non sono all'altezza delle spalle.","Mantieni la posizione contratta per una breve pausa mentre stringi i bicipiti.","Inspira e inizia lentamente ad abbassare i manubri fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"1201","name":"dumbbell burpee","category":"cardio","equipment":"dumbbell","target":"cardiovascular system","secondary":["quadriceps","hamstrings","calves","shoulders","triceps","core"],"steps":{"en":["Start in a standing position with your feet shoulder-width apart and a dumbbell in each hand.","Lower your body into a squat position, placing the dumbbells on the ground in front of you.","Kick your feet back into a push-up position, keeping your body in a straight line.","Perform a push-up, bending your elbows and lowering your chest towards the ground.","Jump your feet back towards your hands, landing in a squat position.","Stand up explosively, lifting the dumbbells off the ground and bringing them to your shoulders.","Press the dumbbells overhead, fully extending your arms.","Lower the dumbbells back to your shoulders and repeat the entire sequence for the desired number of repetitions."],"it":["Inizia in posizione in piedi, con i piedi alla larghezza delle spalle e un manubrio in ogni mano.","Abbassa il corpo in posizione accovacciata, posizionando i manubri a terra davanti a te.","Calcia i piedi indietro in posizione push-up, mantenendo il corpo in linea retta.","Fai una flessione, piegando i gomiti e abbassando il petto verso terra.","Salta indietro verso le mani, atterrando in posizione squat.","Alzati in modo esplosivo, sollevando i manubri da terra e portandoli alle spalle.","Premi i manubri sopra la testa, estendendo completamente le braccia.","Abbassa i manubri sulle spalle e ripeti l'intera sequenza per il numero desiderato di ripetizioni."]}},{"id":"0295","name":"dumbbell clean","category":"upper legs","equipment":"dumbbell","target":"glutes","secondary":["hamstrings","quadriceps","calves"],"steps":{"en":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand with an overhand grip.","Bend your knees and lower your hips into a squat position, keeping your back straight and chest up.","Explosively extend your hips and knees, driving through your heels to jump off the ground.","As you jump, shrug your shoulders and pull the dumbbells up towards your shoulders, keeping them close to your body.","Catch the dumbbells at shoulder height, with your elbows pointing forward and your palms facing up.","Lower the dumbbells back down to the starting position by reversing the movement.","Repeat for the desired number of repetitions."],"it":["Stai con i piedi a larghezza delle spalle, tenendo un manubrio in ogni mano con una presa sopra la testa.","Piega le ginocchia e abbassa i fianchi in posizione squat, mantenendo la schiena dritta e il petto sollevato.","Allunga esplosivamente anche e ginocchia, passando attraverso i talloni per saltare da terra.","Mentre salti, scrolla le spalle e tira su i manubri verso le spalle, tenendoli vicini al corpo.","Afferra i manubri all'altezza delle spalle, con i gomiti rivolti in avanti e i palmi verso l'alto.","Abbassa i manubri fino alla posizione iniziale invertendo il movimento.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"1731","name":"dumbbell close grip press","category":"upper arms","equipment":"dumbbell","target":"triceps","secondary":["chest","shoulders"],"steps":{"en":["Sit on a flat bench with a dumbbell in each hand, resting on your thighs.","Using your thighs to help raise the dumbbells, lift the dumbbells one at a time so that you can hold them in front of you at shoulder width.","Once at shoulder width, rotate your wrists forward so that the palms of your hands are facing away from you. This will be your starting position.","As you breathe in, slowly lower the dumbbells to your side until they are about level with your chest.","As you exhale, use your triceps to lift the dumbbells back to the starting position. Make sure to use only your triceps and do not use your forearms or biceps to help lift the dumbbells.","After a second pause at the contracted position, repeat the movement for the prescribed amount of repetitions."],"it":["Siediti su una panca piatta con un manubrio in ogni mano, appoggiato sulle cosce.","Usando le cosce per aiutare a sollevare i manubri, solleva i manubri uno alla volta così da poterli tenere davanti a te alla larghezza delle spalle.","Una volta a larghezza delle spalle, ruota i polsi in avanti in modo che i palmi delle mani siano rivolti lontano. Questa sarà la tua posizione di partenza.","Mentre inspiri, abbassa lentamente i manubri ai lati finché non saranno all'altezza del petto.","Mentre espiri, usa i tricipiti per sollevare i manubri fino alla posizione iniziale. Assicurati di usare solo i tricipiti e non usare gli avambracci o i bicipiti per aiutare a sollevare i manubri.","Dopo una seconda pausa nella posizione contratta, ripetere il movimento per il numero prescrito di ripetizioni."]}},{"id":"0296","name":"dumbbell close-grip press","category":"upper arms","equipment":"dumbbell","target":"triceps","secondary":["chest","shoulders"],"steps":{"en":["Sit on a flat bench with a dumbbell in each hand, resting on your thighs.","Using your thighs to help raise the dumbbells, lift the dumbbells one at a time so that you can hold them in front of you at shoulder width.","Once at shoulder width, rotate your wrists forward so that the palms of your hands are facing away from you. This will be your starting position.","As you breathe in, slowly lower the dumbbells to your side until they are about level with your chest.","As you exhale, use your triceps to lift the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"it":["Siediti su una panca piatta con un manubrio in ogni mano, appoggiato sulle cosce.","Usando le cosce per aiutare a sollevare i manubri, solleva i manubri uno alla volta così da poterli tenere davanti a te alla larghezza delle spalle.","Una volta a larghezza delle spalle, ruota i polsi in avanti in modo che i palmi delle mani siano rivolti lontano. Questa sarà la tua posizione di partenza.","Mentre inspiri, abbassa lentamente i manubri ai lati finché non saranno all'altezza del petto.","Mentre espiri, usa i tricipiti per sollevare i manubri fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0297","name":"dumbbell concentration curl","category":"upper arms","equipment":"dumbbell","target":"biceps","secondary":["forearms"],"steps":{"en":["Sit on a bench with your legs spread apart and a dumbbell in one hand, resting your elbow on the inside of your thigh.","Fully extend your arm and hold the dumbbell with an underhand grip.","Keeping your upper arm stationary, exhale and curl the weight up towards your shoulder while contracting your biceps.","Continue to raise the dumbbell until your biceps are fully contracted and the dumbbell is at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly lower the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"it":["Siediti su una panchina con le gambe divaricate e un manubrio in una mano, appoggiando il gomito all'interno della coscia.","Estendi completamente il braccio e tieni il manubrio con una presa sottomano.","Mantenendo fermo il braccio superiore, espira e arrotola il peso verso la spalla mentre contrahi i bicipiti.","Continua ad alzare il manubrio finché i bicipiti non sono completamente contratti e il manubrio non è all'altezza delle spalle.","Mantieni la posizione contratta per una breve pausa mentre stringi i bicipiti.","Inspira e abbassa lentamente il manubrio alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni, poi cambia braccio."]}},{"id":"3635","name":"dumbbell contralateral forward lunge","category":"upper legs","equipment":"dumbbell","target":"glutes","secondary":["quadriceps","hamstrings","calves"],"steps":{"en":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand.","Take a step forward with your right foot, keeping your back straight and core engaged.","Lower your body by bending both knees until your right thigh is parallel to the ground.","Push through your right heel to return to the starting position.","Repeat with your left leg.","Alternate legs for the desired number of repetitions."],"it":["Stai con i piedi a larghezza delle spalle, tenendo un manubrio in ciascuna mano.","Fai un passo avanti con il piede destro, mantenendo la schiena dritta e il core attivo.","Abbassa il corpo piegando entrambe le ginocchia finché la coscia destra non è parallela al terreno.","Spingi attraverso il tallone destro per tornare alla posizione di partenza.","Ripeti con la gamba sinistra.","Alterna le gambe per il numero desiderato di ripetizioni."]}},{"id":"0298","name":"dumbbell cross body hammer curl","category":"upper arms","equipment":"dumbbell","target":"biceps","secondary":["forearms"],"steps":{"en":["Stand up straight with a dumbbell in each hand, palms facing your body.","Keep your elbows close to your torso and your upper arms stationary.","Exhale and curl the weights while contracting your biceps, bringing the dumbbells across your body towards your opposite shoulder.","Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai dritto con un manubrio in ogni mano, palmi rivolti verso il corpo.","Tieni i gomiti vicini al busto e le braccia superiori ferme.","Espira e arrotola i pesi mentre contrahi i bicipiti, portando i manubri sul corpo verso la spalla opposta.","Continua ad alzare i manubri finché i bicipiti non sono completamente contratti e i manubri non sono all'altezza delle spalle.","Mantieni la posizione contratta per una breve pausa mentre stringi i bicipiti.","Inspira e inizia lentamente ad abbassare i manubri fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"1657","name":"dumbbell cross body hammer curl v. 2","category":"upper arms","equipment":"dumbbell","target":"biceps","secondary":["forearms"],"steps":{"en":["Stand up straight with a dumbbell in each hand, palms facing your body.","Keep your elbows close to your torso and your upper arms stationary.","Exhale and curl the weights while contracting your biceps, bringing the dumbbells as close to your opposite shoulder as possible.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai dritto con un manubrio in ogni mano, palmi rivolti verso il corpo.","Tieni i gomiti vicini al busto e le braccia superiori ferme.","Espira e arriccia i pesi mentre contrahi i bicipiti, avvicinando i manubri il più possibile alla spalla opposta.","Mantieni la posizione contratta per una breve pausa mentre stringi i bicipiti.","Inspira e inizia lentamente ad abbassare i manubri fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0299","name":"dumbbell cuban press","category":"shoulders","equipment":"dumbbell","target":"delts","secondary":["triceps","upper back"],"steps":{"en":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand at shoulder height with your palms facing down.","Keeping your core engaged and your elbows slightly bent, press the dumbbells up and overhead until your arms are fully extended.","Rotate your wrists so that your palms are facing forward.","Slowly lower the dumbbells back to the starting position, rotating your wrists back to the starting position as you do so.","Repeat for the desired number of repetitions."],"it":["Stai con i piedi a larghezza delle spalle, tenendo un manubrio in ogni mano all'altezza delle spalle con i palmi rivolti verso il basso.","Mantenendo il core impegnato e i gomiti leggermente piegati, premi i manubri verso l'alto e sopra la testa finché le braccia non sono completamente estese.","Ruota i polsi in modo che i palmi siano rivolti in avanti.","Abbassa lentamente i manubri fino alla posizione iniziale, ruotando i polsi di nuovo alla posizione iniziale mentre lo fai.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"2136","name":"dumbbell cuban press v. 2","category":"shoulders","equipment":"dumbbell","target":"delts","secondary":["triceps","upper back"],"steps":{"en":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand at shoulder height with your palms facing down.","Keeping your core engaged and your back straight, press the dumbbells straight up overhead until your arms are fully extended.","Rotate your wrists so that your palms are facing forward.","Lower the dumbbells back down to shoulder height, rotating your wrists back to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai con i piedi a larghezza delle spalle, tenendo un manubrio in ogni mano all'altezza delle spalle con i palmi rivolti verso il basso.","Tenendo il core impegnato e la schiena dritta, premi i manubri dritti sopra la testa finché le braccia non sono completamente estese.","Ruota i polsi in modo che i palmi siano rivolti in avanti.","Abbassa i manubri fino all'altezza delle spalle, ruotando i polsi di nuovo alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0300","name":"dumbbell deadlift","category":"upper legs","equipment":"dumbbell","target":"glutes","secondary":["hamstrings","lower back"],"steps":{"en":["Stand with your feet shoulder-width apart, toes pointing forward.","Hold a dumbbell in each hand, palms facing your body, arms extended downwards.","Bend at your hips and knees, lowering the dumbbells towards the ground while keeping your back straight.","Push through your heels and extend your hips and knees, lifting the dumbbells back up to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai in piedi con i piedi alla larghezza delle spalle, le dita rivolte in avanti.","Tieni un manubrio in ogni mano, palmi rivolti verso il corpo, braccia distese verso il basso.","Piega fianchi e ginocchia, abbassando i manubri verso terra mantenendo la schiena dritta.","Spingi attraverso i talloni ed allunga anche e ginocchia, rialzando i manubri alla posizione di partenza.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0301","name":"dumbbell decline bench press","category":"chest","equipment":"dumbbell","target":"pectorals","secondary":["triceps","shoulders"],"steps":{"en":["Lie down on a decline bench with your feet secured and your head lower than your hips.","Hold a dumbbell in each hand and extend your arms straight up above your chest, palms facing forward.","Lower the dumbbells slowly to the sides of your chest, keeping your elbows at a 90-degree angle.","Push the dumbbells back up to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."],"it":["Sdraiati su una panca con i piedi ben assicurati e la testa più bassa dei fianchi.","Tieni un manubrio in ciascuna mano e allunga le braccia dritte sopra il petto, palmi rivolti in avanti.","Abbassa lentamente i manubri ai lati del petto, mantenendo i gomiti a 90 gradi.","Spingi i manubri di nuovo alla posizione iniziale, estendendo completamente le braccia.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0302","name":"dumbbell decline fly","category":"chest","equipment":"dumbbell","target":"pectorals","secondary":["shoulders"],"steps":{"en":["Lie on a decline bench with your feet secured and your head lower than your hips.","Hold a dumbbell in each hand with your palms facing each other and your arms extended above your chest.","Lower the dumbbells out to the sides in a wide arc until you feel a stretch in your chest.","Pause for a moment, then squeeze your chest muscles to bring the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"it":["Sdraiati su una panca inclinata con i piedi ben saldati e la testa più bassa dei fianchi.","Tieni un manubrio in ogni mano con i palmi rivolti l'uno verso l'altro e le braccia estese sopra il petto.","Abbassa i manubri ai lati in un ampio arco finché non senti uno stiramento al petto.","Fermati un attimo, poi stringi i muscoli del petto per riportare i manubri alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0303","name":"dumbbell decline hammer press","category":"chest","equipment":"dumbbell","target":"pectorals","secondary":["triceps","shoulders"],"steps":{"en":["Lie on a decline bench with your feet secured and your head lower than your hips.","Hold a dumbbell in each hand with your palms facing each other and your arms extended above your chest.","Lower the dumbbells to the sides of your chest, keeping your elbows slightly bent.","Press the dumbbells back up to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."],"it":["Sdraiati su una panca inclinata con i piedi ben saldati e la testa più bassa dei fianchi.","Tieni un manubrio in ogni mano con i palmi rivolti l'uno verso l'altro e le braccia estese sopra il petto.","Abbassa i manubri ai lati del petto, tenendo i gomiti leggermente piegati.","Riporta i manubri alla posizione iniziale, estendendo completamente le braccia.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"1276","name":"dumbbell decline one arm fly","category":"chest","equipment":"dumbbell","target":"pectorals","secondary":["shoulders"],"steps":{"en":["Lie down on a decline bench with a dumbbell in one hand, resting it on your thigh.","Using your thigh to help raise the dumbbell, lift it up to shoulder width with your palm facing your torso.","Rotate your wrist so that the palm of your hand is facing forward.","As you breathe in, lower the dumbbell slowly to the side until you feel a stretch in your chest.","Exhale and use your chest muscles to bring the dumbbell back up to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"it":["Sdraiati su una panchina inclinata con un manubrio in una mano, appoggiandolo sulla coscia.","Usando la coscia per aiutare a sollevare il manubrio, sollevalo alla larghezza delle spalle con il palmo rivolto verso il busto.","Ruota il polso in modo che il palmo della mano sia rivolto in avanti.","Mentre inspiri, abbassa lentamente il manubrio di lato finché non senti uno stiramento al petto.","Espira e usa i muscoli del petto per riportare il manubrio alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni, poi cambia braccio."]}},{"id":"1617","name":"dumbbell decline one arm hammer press","category":"upper arms","equipment":"dumbbell","target":"triceps","secondary":["chest","shoulders"],"steps":{"en":["Lie on a decline bench with a dumbbell in one hand, resting on your chest.","Extend your arm straight up, keeping your elbow slightly bent.","Lower the dumbbell down towards your shoulder, keeping your elbow close to your body.","Press the dumbbell back up to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"it":["Sdraiati su una panchina con un manubrio in una mano, appoggiato sul petto.","Allunga il braccio dritto, tenendo il gomito leggermente piegato.","Abbassa il manubrio verso la spalla, tenendo il gomito vicino al corpo.","Riporta il manubrio alla posizione di partenza.","Ripeti per il numero desiderato di ripetizioni, poi cambia braccio."]}},{"id":"0305","name":"dumbbell decline shrug","category":"back","equipment":"dumbbell","target":"traps","secondary":["shoulders","rhomboids"],"steps":{"en":["Set up a decline bench at a 45-degree angle.","Lie face down on the bench with your chest and stomach resting against it.","Hold a dumbbell in each hand with your arms fully extended towards the floor.","Keeping your arms straight, raise your shoulders towards your ears as high as possible.","Hold the contraction for a moment, then slowly lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"it":["Installare una panca di declino con un angolo di 45 gradi.","Sdraiati a faccia in giù sulla panchina con petto e pancia appoggiati contro di essa.","Tieni un manubrio in ogni mano con le braccia completamente distese verso il pavimento.","Tieni le braccia dritte, alza le spalle verso le orecchie il più possibile.","Tieni la contrazione per un momento, poi abbassa lentamente i manubri fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0304","name":"dumbbell decline shrug v. 2","category":"back","equipment":"dumbbell","target":"traps","secondary":["shoulders","rhomboids"],"steps":{"en":["Set up a decline bench at a 45-degree angle.","Lie face down on the bench with your chest and stomach resting on it.","Hold a dumbbell in each hand with your palms facing each other and your arms fully extended.","Keeping your arms straight, raise your shoulders as high as possible while squeezing your shoulder blades together.","Hold the contraction for a brief pause, then lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"it":["Installare una panca di declino con un angolo di 45 gradi.","Sdraiati a faccia in giù sulla panchina con petto e pancia appoggiati sopra.","Tieni un manubrio in ogni mano con i palmi rivolti l'uno verso l'altro e le braccia completamente estese.","Tieni le braccia dritte, alza le spalle il più possibile stringendo le scapole insieme.","Tieni la contrazione per una breve pausa, poi abbassa i manubri alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0306","name":"dumbbell decline triceps extension","category":"upper arms","equipment":"dumbbell","target":"triceps","secondary":["shoulders"],"steps":{"en":["Lie on a decline bench with your head lower than your feet and hold a dumbbell in each hand, palms facing each other.","Extend your arms fully, keeping your elbows close to your head.","Lower the dumbbells slowly behind your head, bending your elbows.","Pause for a moment, then raise the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"it":["Sdraiati su una panca inclinata con la testa più bassa dei piedi e tieni un manubrio in ciascuna mano, palmi rivolti l'uno verso l'altro.","Allunga completamente le braccia, tenendo i gomiti vicini alla testa.","Abbassa lentamente i manubri dietro la testa, piegando i gomiti.","Fermati un attimo, poi riporta i manubri alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0307","name":"dumbbell decline twist fly","category":"chest","equipment":"dumbbell","target":"pectorals","secondary":["shoulders","triceps"],"steps":{"en":["Lie down on a decline bench with your head lower than your hips.","Hold a dumbbell in each hand with your palms facing each other and your arms extended straight up over your chest.","Lower the dumbbells out to the sides in a wide arc until you feel a stretch in your chest.","As you lower the dumbbells, twist your wrists so that your palms face forward at the bottom of the movement.","Reverse the motion and bring the dumbbells back up to the starting position, squeezing your chest muscles at the top.","Repeat for the desired number of repetitions."],"it":["Sdraiati su una panca con la testa più bassa dei fianchi.","Tieni un manubrio in ogni mano con i palmi rivolti l'uno verso l'altro e le braccia alzate sopra il petto.","Abbassa i manubri ai lati in un ampio arco finché non senti uno stiramento al petto.","Mentre abbassi i manubri, ruota i polsi in modo che i palmi siano rivolti in avanti alla base del movimento.","Inverti il movimento e riporta i manubri alla posizione iniziale, stringendo i muscoli del petto in alto.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"1437","name":"dumbbell finger curls","category":"lower arms","equipment":"dumbbell","target":"forearms","secondary":["wrist flexors","wrist extensors"],"steps":{"en":["Sit on a bench or chair with your feet flat on the ground and your back straight.","Hold a dumbbell in one hand with an underhand grip, resting your forearm on your thigh, palm facing up.","Allow the dumbbell to roll down to your fingertips, then curl it back up by flexing your fingers.","Repeat for the desired number of repetitions, then switch to the other hand."],"it":["Siediti su una panca o una sedia con i piedi piatti a terra e la schiena dritta.","Tieni un manubrio in una mano con una presa sotto, appoggiando l'avambraccio sulla coscia, il palmo rivolto verso l'alto.","Lascia che il manubrio scorra verso le punte delle dita, poi ripiegalo flettendo le dita.","Ripeti per il numero desiderato di ripetizioni, poi passa all'altra mano."]}},{"id":"0308","name":"dumbbell fly","category":"chest","equipment":"dumbbell","target":"pectorals","secondary":["shoulders"],"steps":{"en":["Lie flat on a bench with a dumbbell in each hand, palms facing each other.","Extend your arms straight up over your chest, with a slight bend in your elbows.","Keeping a slight bend in your elbows, lower your arms out to the sides in a wide arc until you feel a stretch in your chest.","Pause for a moment, then reverse the movement and bring the dumbbells back up to the starting position.","Repeat for the desired number of repetitions."],"it":["Sdraiati disteso su una panchina con un manubrio in ogni mano, i palmi uno verso l'altro.","Allunga le braccia dritte sopra il petto, con una leggera piega dei gomiti.","Mantenendo una leggera piega dei gomiti, abbassa le braccia ai lati in un ampio arco finché non senti uno stiramento al petto.","Fermati un attimo, poi inverti il movimento e riporta i manubri alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"1277","name":"dumbbell fly on exercise ball","category":"chest","equipment":"dumbbell","target":"pectorals","secondary":["shoulders","triceps"],"steps":{"en":["Sit on an exercise ball and hold a dumbbell in each hand.","Walk your feet forward and roll your body down until your head, neck, and upper back are supported by the ball.","Extend your arms straight up above your chest, palms facing each other.","Bend your elbows slightly and lower your arms out to the sides in a wide arc until you feel a stretch in your chest.","Pause for a moment, then reverse the movement and squeeze your chest muscles as you bring the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"it":["Siediti su una palla da ginnastica e tieni un manubrio in ogni mano.","Fai avanti i piedi e fai girare il corpo verso il basso finché testa, collo e parte superiore della schiena non sono sostenuti dalla palla.","Allunga le braccia dritte sopra il petto, palmi rivolti l'uno verso l'altro.","Piega leggermente i gomiti e abbassa le braccia ai lati in un ampio arco finché non senti uno stiramento al petto.","Fermati un attimo, poi inverti il movimento e stringi i muscoli del petto mentre riporti i manubri alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"1732","name":"dumbbell forward lunge triceps extension","category":"upper arms","equipment":"dumbbell","target":"triceps","secondary":["shoulders","core"],"steps":{"en":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand.","Take a step forward with your right foot, lowering your body into a lunge position.","Keep your back straight and your chest up.","Extend your arms straight overhead, keeping your elbows close to your ears.","Lower the dumbbells behind your head by bending your elbows.","Pause for a moment, then straighten your arms to return to the starting position.","Repeat the movement for the desired number of repetitions, then switch legs and repeat."],"it":["Stai con i piedi a larghezza delle spalle, tenendo un manubrio in ciascuna mano.","Fai un passo avanti con il piede destro, abbassando il corpo in posizione di affondamento.","Tieni la schiena dritta e il petto sollevato.","Allunga le braccia dritte sopra la testa, tenendo i gomiti vicino alle orecchie.","Abbassa i manubri dietro la testa piegando i gomiti.","Fermati un attimo, poi raddrizza le braccia per tornare alla posizione iniziale.","Ripeti il movimento per il numero desiderato di ripetizioni, poi cambia gamba e ripeti."]}},{"id":"0310","name":"dumbbell front raise","category":"shoulders","equipment":"dumbbell","target":"delts","secondary":["biceps","trapezius"],"steps":{"en":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand with your palms facing your thighs.","Keeping your arms straight, exhale and lift the dumbbells in front of you until they are at shoulder level.","Pause for a moment at the top, then inhale and slowly lower the dumbbells back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai con i piedi a larghezza delle spalle, tenendo un manubrio in ogni mano con i palmi rivolti verso le cosce.","Tieni le braccia dritte, espira e solleva i manubri davanti a te finché non sono all'altezza delle spalle.","Fermati un attimo in cima, poi inspira e abbassa lentamente i manubri fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0309","name":"dumbbell front raise v. 2","category":"shoulders","equipment":"dumbbell","target":"delts","secondary":["trapezius","biceps"],"steps":{"en":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand with your palms facing your thighs.","Keep your back straight and engage your core.","Slowly lift the dumbbells in front of you, with your arms straight, until they are at shoulder level.","Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai con i piedi a larghezza delle spalle, tenendo un manubrio in ogni mano con i palmi rivolti verso le cosce.","Tieni la schiena dritta e attiva il core.","Solleva lentamente i manubri davanti a te, con le braccia dritte, finché non saranno all'altezza delle spalle.","Fermati un attimo in cima, poi abbassa lentamente i manubri fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0311","name":"dumbbell full can lateral raise","category":"shoulders","equipment":"dumbbell","target":"delts","secondary":["traps","rotator cuff"],"steps":{"en":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand with your palms facing your body.","Keep your back straight and engage your core.","Raise your arms out to the sides, keeping a slight bend in your elbows, until they are parallel to the ground.","Pause for a moment at the top, then slowly lower your arms back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai con i piedi a larghezza delle spalle, tenendo un manubrio in ogni mano con i palmi rivolti verso il corpo.","Tieni la schiena dritta e attiva il core.","Alza le braccia ai lati, mantenendo una leggera piega dei gomiti, finché non sono paralleli al suolo.","Fermati un attimo in cima, poi abbassa lentamente le braccia fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"1760","name":"dumbbell goblet squat","category":"upper legs","equipment":"dumbbell","target":"quads","secondary":["glutes","hamstrings","calves"],"steps":{"en":["Stand with your feet shoulder-width apart, holding a dumbbell vertically against your chest with both hands.","Keeping your chest up and core engaged, lower your body down into a squat position by pushing your hips back and bending your knees.","Continue lowering until your thighs are parallel to the ground, or as low as you can comfortably go.","Pause for a moment at the bottom, then push through your heels to return to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai con i piedi a larghezza delle spalle, tenendo un manubrio verticalmente contro il petto con entrambe le mani.","Mantenendo il petto sollevato e il core attivo, abbassa il corpo in posizione squat spingendo indietro i fianchi e piegando le ginocchia.","Continua ad abbassare finché le cosce non sono parallele al suolo, o il più in basso che puoi comodamente.","Fermati un attimo in fondo, poi spingi attraverso i talloni per tornare alla posizione di partenza.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0313","name":"dumbbell hammer curl","category":"upper arms","equipment":"dumbbell","target":"biceps","secondary":["forearms"],"steps":{"en":["Stand up straight with a dumbbell in each hand, palms facing your torso.","Keep your elbows close to your torso and rotate the palms of your hands until they are facing forward.","This will be your starting position.","Now, keeping the upper arms stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Then, inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the recommended amount of repetitions."],"it":["Stai dritto con un manubrio in ogni mano, i palmi rivolti verso il busto.","Tieni i gomiti vicini al busto e ruota i palmi delle mani finché non sono rivolti in avanti.","Questa sarà la tua posizione di partenza.","Ora, mantenendo ferme le braccia superiori, espira e arriccia i pesi mentre contrahi i bicipiti.","Continua ad alzare i pesi finché i bicipiti non sono completamente contratti e i manubri non sono all'altezza delle spalle.","Mantieni la posizione contratta per una breve pausa mentre stringi i bicipiti.","Poi, inspira e inizia lentamente ad abbassare i manubri fino alla posizione iniziale.","Ripeti per il numero consigliato di ripetizioni."]}},{"id":"1659","name":"dumbbell hammer curl on exercise ball","category":"upper arms","equipment":"dumbbell","target":"biceps","secondary":["forearms"],"steps":{"en":["Sit on an exercise ball with your feet flat on the ground and your back straight.","Hold a dumbbell in each hand with your palms facing your body and your arms fully extended.","Keeping your upper arms stationary, exhale and curl the dumbbells while contracting your biceps.","Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"it":["Siediti su una palla da ginnastica con i piedi piatti a terra e la schiena dritta.","Tieni un manubrio in ogni mano con i palmi rivolti verso il corpo e le braccia completamente estese.","Mantenendo ferme le braccia superiori, espira e arriccia i manubri mentre contrahi i bicipiti.","Continua ad alzare i manubri finché i bicipiti non sono completamente contratti e i manubri non sono all'altezza delle spalle.","Mantieni la posizione contratta per una breve pausa mentre stringi i bicipiti.","Inspira e inizia lentamente ad abbassare i manubri fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0312","name":"dumbbell hammer curl v. 2","category":"upper arms","equipment":"dumbbell","target":"biceps","secondary":["forearms"],"steps":{"en":["Stand up straight with a dumbbell in each hand, palms facing your torso.","Keep your elbows close to your torso and rotate the palms of your hands until they are facing forward.","This will be your starting position.","Now, keeping the upper arms stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Then, inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the recommended amount of repetitions."],"it":["Stai dritto con un manubrio in ogni mano, i palmi rivolti verso il busto.","Tieni i gomiti vicini al busto e ruota i palmi delle mani finché non sono rivolti in avanti.","Questa sarà la tua posizione di partenza.","Ora, mantenendo ferme le braccia superiori, espira e arriccia i pesi mentre contrahi i bicipiti.","Continua ad alzare i pesi finché i bicipiti non sono completamente contratti e i manubri non sono all'altezza delle spalle.","Mantieni la posizione contratta per una breve pausa mentre stringi i bicipiti.","Poi, inspira e inizia lentamente ad abbassare i manubri fino alla posizione iniziale.","Ripeti per il numero consigliato di ripetizioni."]}},{"id":"2402","name":"dumbbell hammer curls (with arm blaster)","category":"upper arms","equipment":"dumbbell","target":"biceps","secondary":["forearms"],"steps":{"en":["Stand up straight with a dumbbell in each hand, palms facing your torso.","Keep your elbows close to your torso and rotate the palms of your hands until they are facing forward.","This will be your starting position.","Now, while holding your upper arm stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Then, inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the recommended amount of repetitions."],"it":["Stai dritto con un manubrio in ogni mano, i palmi rivolti verso il busto.","Tieni i gomiti vicini al busto e ruota i palmi delle mani finché non sono rivolti in avanti.","Questa sarà la tua posizione di partenza.","Ora, mentre tieni fermo la parte superiore del braccio, espira e arriccia i pesi mentre contrai i bicipiti.","Continua ad alzare i pesi finché i bicipiti non sono completamente contratti e i manubri non sono all'altezza delle spalle.","Mantieni la posizione contratta per una breve pausa mentre stringi i bicipiti.","Poi, inspira e inizia lentamente ad abbassare i manubri fino alla posizione iniziale.","Ripeti per il numero consigliato di ripetizioni."]}},{"id":"1664","name":"dumbbell high curl","category":"upper arms","equipment":"dumbbell","target":"biceps","secondary":["forearms"],"steps":{"en":["Stand up straight with a dumbbell in each hand, palms facing forward.","Keep your upper arms stationary and curl the dumbbells as high as possible while contracting your biceps.","Pause for a moment at the top, then slowly lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai dritto con un manubrio in ciascuna mano, palmi rivolti in avanti.","Mantieni ferme le braccia superiori e arriccia i manubri il più in alto possibile mentre contraggiamo i bicipiti.","Fermati un attimo in cima, poi abbassa lentamente i manubri alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"3545","name":"dumbbell incline alternate press","category":"chest","equipment":"dumbbell","target":"pectorals","secondary":["shoulders","triceps"],"steps":{"en":["Sit on an incline bench with a dumbbell in each hand, resting on your thighs.","Lean back on the bench and use your thighs to help raise the dumbbells to shoulder height, palms facing forward.","Once at shoulder height, rotate your wrists so that the palms of your hands are facing forward.","Push the dumbbells up with your chest and shoulders, extending your arms fully.","Lower the dumbbells back down to the starting position, keeping your elbows slightly bent.","Repeat for the desired number of repetitions, alternating arms."],"it":["Siediti su una panca inclinata con un manubrio in ogni mano, appoggiato sulle cosce.","Appoggiati all'indietro sulla panca e usa le cosce per aiutare a sollevare i manubri all'altezza delle spalle, palmi rivolti in avanti.","Una volta all'altezza delle spalle, ruota i polsi in modo che i palmi delle mani siano rivolti in avanti.","Spingi i manubri con petto e spalle, estendendo completamente le braccia.","Abbassa i manubri fino alla posizione iniziale, mantenendo i gomiti leggermente piegati.","Ripeti per il numero desiderato di ripetizioni, alternando le braccia."]}},{"id":"0314","name":"dumbbell incline bench press","category":"chest","equipment":"dumbbell","target":"pectorals","secondary":["shoulders","triceps"],"steps":{"en":["Set up an incline bench at a 45-degree angle.","Sit on the bench with your feet flat on the ground and your back pressed firmly against the bench.","Hold a dumbbell in each hand, palms facing forward, and lift them to shoulder height.","Slowly lower the dumbbells to the sides of your chest, keeping your elbows at a 90-degree angle.","Push the dumbbells back up to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."],"it":["Installa una panca inclinata con un angolo di 45 gradi.","Siediti sulla panca con i piedi piatti a terra e la schiena premuta saldamente contro la panca.","Tieni un manubrio in ogni mano, palmi rivolti in avanti, e sollevali all'altezza delle spalle.","Abbassa lentamente i manubri ai lati del petto, mantenendo i gomiti a 90 gradi.","Spingi i manubri di nuovo alla posizione iniziale, estendendo completamente le braccia.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0315","name":"dumbbell incline biceps curl","category":"upper arms","equipment":"dumbbell","target":"biceps","secondary":["forearms"],"steps":{"en":["Sit on an incline bench with a dumbbell in each hand, palms facing forward, and arms fully extended.","Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"it":["Siediti su una panchina inclinata con un manubrio in ciascuna mano, i palmi rivolti in avanti e le braccia completamente distese.","Mantenendo ferme le braccia superiori, espira e arriccia i pesi mentre contrahi i bicipiti.","Continua ad alzare i manubri finché i bicipiti non sono completamente contratti e i manubri non sono all'altezza delle spalle.","Mantieni la posizione contratta per una breve pausa mentre stringi i bicipiti.","Inspira e inizia lentamente ad abbassare i manubri fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0316","name":"dumbbell incline breeding","category":"chest","equipment":"dumbbell","target":"pectorals","secondary":["shoulders","triceps"],"steps":{"en":["Set up an incline bench at a 45-degree angle.","Sit on the bench with your back against the pad and feet flat on the ground.","Hold a dumbbell in each hand with an overhand grip, palms facing forward.","Start with your arms fully extended, perpendicular to the ground.","Lower the dumbbells slowly to the sides of your chest, keeping your elbows at a 90-degree angle.","Pause for a moment at the bottom, then push the dumbbells back up to the starting position.","Repeat for the desired number of repetitions."],"it":["Installa una panca inclinata con un angolo di 45 gradi.","Siediti sulla panca con la schiena appoggiata al pad e i piedi piatti a terra.","Tieni un manubrio in ciascuna mano con una presa sopra la mano, palmi rivolti in avanti.","Inizia con le braccia completamente distese, perpendicolari al suolo.","Abbassa lentamente i manubri ai lati del petto, mantenendo i gomiti a 90 gradi.","Fermati un attimo in fondo, poi spingi di nuovo i manubri fino alla posizione di partenza.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0318","name":"dumbbell incline curl","category":"upper arms","equipment":"dumbbell","target":"biceps","secondary":["forearms"],"steps":{"en":["Set an incline bench to a 45-degree angle and sit on it with a dumbbell in each hand, palms facing forward.","Rest your upper arms on the incline bench and let your elbows hang down, fully extending your arms.","Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"it":["Imposta una panca inclinata a 45 gradi e siediti sopra con un manubrio in ogni mano, palmi rivolti in avanti.","Appoggia le braccia superiori sulla panca inclinata e lascia che i gomiti pendano verso il basso, estendendo completamente le braccia.","Mantenendo ferme le braccia superiori, espira e arriccia i pesi mentre contrahi i bicipiti.","Continua ad alzare i manubri finché i bicipiti non sono completamente contratti e i manubri non sono all'altezza delle spalle.","Mantieni la posizione contratta per una breve pausa mentre stringi i bicipiti.","Inspira e inizia lentamente ad abbassare i manubri fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0317","name":"dumbbell incline curl v. 2","category":"upper arms","equipment":"dumbbell","target":"biceps","secondary":["forearms"],"steps":{"en":["Sit on an incline bench with a dumbbell in each hand, palms facing forward and arms fully extended.","Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"it":["Siediti su una panchina inclinata con un manubrio in ogni mano, palmi rivolti in avanti e braccia completamente distese.","Mantenendo ferme le braccia superiori, espira e arriccia i pesi mentre contrahi i bicipiti.","Continua ad alzare i manubri finché i bicipiti non sono completamente contratti e i manubri non sono all'altezza delle spalle.","Mantieni la posizione contratta per una breve pausa mentre stringi i bicipiti.","Inspira e inizia lentamente ad abbassare i manubri fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0319","name":"dumbbell incline fly","category":"chest","equipment":"dumbbell","target":"pectorals","secondary":["shoulders"],"steps":{"en":["Set an incline bench to a 45-degree angle.","Sit on the bench with a dumbbell in each hand, palms facing each other.","Lie back on the bench and press the dumbbells up to the starting position, directly above your chest.","Lower the dumbbells out to the sides in a wide arc until you feel a stretch in your chest.","Pause for a moment, then squeeze your chest muscles to bring the dumbbells back up to the starting position.","Repeat for the desired number of repetitions."],"it":["Imposta una panca inclinata a 45 gradi.","Seduta sulla panchina con un manubrio in ogni mano, i palmi rivolti l'uno verso l'altro.","Sdraiati sulla panca e spingi i manubri fino alla posizione iniziale, direttamente sopra il petto.","Abbassa i manubri ai lati in un ampio arco finché non senti uno stiramento al petto.","Fermati un attimo, poi stringi i muscoli del petto per riportare i manubri alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"1278","name":"dumbbell incline fly on exercise ball","category":"chest","equipment":"dumbbell","target":"pectorals","secondary":["shoulders"],"steps":{"en":["Set up an incline bench at a 45-degree angle.","Sit on an exercise ball and roll forward until your upper back is resting on the incline bench.","Hold a dumbbell in each hand with your palms facing each other and your arms extended above your chest.","Lower the dumbbells out to the sides in a wide arc until you feel a stretch in your chest.","Pause for a moment, then squeeze your chest muscles to bring the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"it":["Installa una panca inclinata con un angolo di 45 gradi.","Siediti su una palla da ginnastica e rotola in avanti finché la parte superiore della schiena non si appoggia sulla panca inclinata.","Tieni un manubrio in ogni mano con i palmi rivolti l'uno verso l'altro e le braccia estese sopra il petto.","Abbassa i manubri ai lati in un ampio arco finché non senti uno stiramento al petto.","Fermati un attimo, poi stringi i muscoli del petto per riportare i manubri alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0320","name":"dumbbell incline hammer curl","category":"upper arms","equipment":"dumbbell","target":"biceps","secondary":["forearms"],"steps":{"en":["Sit on an incline bench with a dumbbell in each hand, palms facing your torso and arms fully extended.","Keep your back against the bench and your feet flat on the floor.","While keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"it":["Siediti su una panca inclinata con un manubrio in ogni mano, i palmi rivolti verso il busto e le braccia completamente distese.","Tieni la schiena appoggiata alla panca e i piedi piatti sul pavimento.","Mantenendo ferme le braccia superiori, espira e arriccia i pesi mentre contrai i bicipiti.","Continua ad alzare i pesi finché i bicipiti non sono completamente contratti e i manubri non sono all'altezza delle spalle.","Mantieni la posizione contratta per una breve pausa mentre stringi i bicipiti.","Inspira e inizia lentamente ad abbassare i manubri fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0321","name":"dumbbell incline hammer press","category":"chest","equipment":"dumbbell","target":"pectorals","secondary":["shoulders","triceps"],"steps":{"en":["Set an incline bench to a 45-degree angle and sit on it with a dumbbell in each hand, resting on your thighs.","Lie back on the bench and position the dumbbells at shoulder level with your palms facing each other.","Press the dumbbells up and away from your body until your arms are fully extended.","Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Imposta una panca inclinata a 45 gradi e siediti sopra con un manubrio in ogni mano, appoggiandola sulle cosce.","Sdraiati sulla panca e posiziona i manubri all'altezza delle spalle con i palmi rivolti l'uno verso l'altro.","Spingi i manubri verso l'alto e lontani dal corpo finché le braccia non sono completamente estese.","Fermati un attimo in cima, poi abbassa lentamente i manubri fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"1618","name":"dumbbell incline hammer press on exercise ball","category":"upper arms","equipment":"dumbbell","target":"triceps","secondary":["chest","shoulders"],"steps":{"en":["Sit on an exercise ball with a dumbbell in each hand, palms facing each other.","Walk your feet forward and roll your body down the ball until your head, neck, and upper back are supported on the ball.","Hold the dumbbells at shoulder level, elbows bent and pointing out to the sides.","Press the dumbbells up and slightly inward, keeping your palms facing each other.","Extend your arms fully, squeezing your triceps at the top of the movement.","Slowly lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"it":["Siediti su una palla da ginnastica con un manubrio in ogni mano, i palmi rivolti uno verso l'altro.","Fai avanti i piedi e fai rotolare il corpo lungo la palla finché testa, collo e parte superiore della schiena non sono sostenuti sulla palla.","Tieni i manubri all'altezza delle spalle, gomiti piegati e rivolti ai lati.","Premi i manubri verso l'alto e leggermente verso l'interno, mantenendo i palmi uno verso l'altro.","Allunga completamente le braccia, stringendo i tricipiti nella parte alta del movimento.","Abbassa lentamente i manubri fino alla posizione di partenza.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0322","name":"dumbbell incline inner biceps curl","category":"upper arms","equipment":"dumbbell","target":"biceps","secondary":["forearms"],"steps":{"en":["Sit on an incline bench with a dumbbell in each hand, palms facing each other.","Rest your upper arms on the bench, allowing your elbows to hang down and your palms to face forward.","Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"it":["Siediti su una panchina inclinata con un manubrio in ogni mano, i palmi rivolti l'uno verso l'altro.","Appoggia le braccia superiori sulla panca, lasciando che i gomiti pendano e i palmi rivolti in avanti.","Mantenendo ferme le braccia superiori, espira e arriccia i pesi mentre contrahi i bicipiti.","Continua ad alzare i manubri finché i bicipiti non sono completamente contratti e i manubri non sono all'altezza delle spalle.","Mantieni la posizione contratta per una breve pausa mentre stringi i bicipiti.","Inspira e inizia lentamente ad abbassare i manubri fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"1279","name":"dumbbell incline one arm fly","category":"chest","equipment":"dumbbell","target":"pectorals","secondary":["deltoids","triceps"],"steps":{"en":["Adjust the incline bench to a 30-45 degree angle.","Sit on the bench with a dumbbell in one hand, resting it on your thigh.","Lie back on the bench, keeping your feet flat on the ground.","Hold the dumbbell with your arm extended straight up over your chest.","Lower the dumbbell out to the side in a wide arc, keeping a slight bend in your elbow.","Pause when your arm is parallel to the ground, then reverse the motion to bring the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"it":["Regola la panca inclinata a un angolo di 30-45 gradi.","Siediti sulla panchina con un manubrio in una mano, appoggiandolo sulla coscia.","Sdraiati sulla panca, tenendo i piedi piatti a terra.","Tieni il manubrio con il braccio teso sopra il petto.","Abbassa il manubrio di lato in un ampio arco, mantenendo una leggera piega del gomito.","Fermati quando il braccio è parallelo al suolo, poi inverti il movimento per riportare il manubrio alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni, poi cambia braccio."]}},{"id":"1280","name":"dumbbell incline one arm fly on exercise ball","category":"chest","equipment":"dumbbell","target":"pectorals","secondary":["shoulders"],"steps":{"en":["Sit on an exercise ball with a dumbbell in one hand.","Walk your feet forward and roll your body down until your head, neck, and upper back are supported on the ball.","Hold the dumbbell with your arm extended straight up over your chest, palm facing inwards.","Slowly lower the dumbbell out to the side, keeping a slight bend in your elbow.","Pause for a moment when your arm is parallel to the ground.","Engage your chest muscles to bring the dumbbell back up to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"it":["Siediti su una palla da ginnastica con un manubrio in una mano.","Fai avanzare i piedi e fai girare il corpo verso il basso finché testa, collo e parte superiore della schiena non sono sostenuti sulla palla.","Tieni il manubrio con il braccio teso sopra il petto, il palmo rivolto verso l'interno.","Abbassa lentamente il manubrio di lato, mantenendo una leggera piega del gomito.","Fermati un attimo quando il braccio è parallelo al suolo.","Attiva i muscoli del petto per riportare il manubrio alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni, poi cambia braccio."]}},{"id":"1619","name":"dumbbell incline one arm hammer press","category":"upper arms","equipment":"dumbbell","target":"triceps","secondary":["shoulders","chest"],"steps":{"en":["Sit on an incline bench with a dumbbell in one hand, resting on your thigh.","Lean back on the bench and use your thigh to help raise the dumbbell to shoulder height.","Rotate your wrist so that your palm is facing inward, towards your body.","Press the dumbbell up and away from your body, extending your arm fully.","Pause for a moment at the top, then slowly lower the dumbbell back down to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"it":["Siediti su una panchina inclinata con un manubrio in una mano, appoggiato sulla coscia.","Appoggiati all'indietro sulla panca e usa la coscia per aiutare a sollevare il manubrio all'altezza delle spalle.","Ruota il polso in modo che il palmo sia rivolto verso l'interno, verso il corpo.","Spingi il manubrio verso l'alto e lontano dal corpo, estendendo completamente il braccio.","Fermati un attimo in cima, poi abbassa lentamente il manubrio fino alla posizione di partenza.","Ripeti per il numero desiderato di ripetizioni, poi cambia braccio."]}},{"id":"1620","name":"dumbbell incline one arm hammer press on exercise ball","category":"upper arms","equipment":"dumbbell","target":"triceps","secondary":["shoulders","chest"],"steps":{"en":["Sit on an exercise ball with a dumbbell in one hand.","Walk your feet forward and roll your body down until your head, neck, and upper back are supported on the ball.","Hold the dumbbell with your palm facing inward and your elbow bent at a 90-degree angle.","Press the dumbbell up towards the ceiling, straightening your arm.","Lower the dumbbell back down to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"it":["Siediti su una palla da ginnastica con un manubrio in una mano.","Fai avanzare i piedi e fai girare il corpo verso il basso finché testa, collo e parte superiore della schiena non sono sostenuti sulla palla.","Tieni il manubrio con il palmo rivolto verso l'interno e il gomito piegato a un angolo di 90 gradi.","Spingi il manubrio verso il soffitto, raddrizzando il braccio.","Abbassa il manubrio fino alla posizione di partenza.","Ripeti per il numero desiderato di ripetizioni, poi cambia braccio."]}},{"id":"0323","name":"dumbbell incline one arm lateral raise","category":"shoulders","equipment":"dumbbell","target":"delts","secondary":["trapezius","triceps"],"steps":{"en":["Sit on an incline bench with a dumbbell in one hand, resting it on your thigh.","Lean forward and position your upper arm against the inside of your thigh.","Raise the dumbbell to the side, keeping your arm slightly bent and your palm facing down.","Continue lifting until your arm is parallel to the floor.","Pause for a moment at the top, then slowly lower the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch to the other arm."],"it":["Siediti su una panca inclinata con un manubrio in una mano, appoggiandolo sulla coscia.","Piegati in avanti e posiziona il braccio superiore contro l'interno della coscia.","Alza il manubrio di lato, tenendo il braccio leggermente piegato e il palmo rivolto verso il basso.","Continua a sollevare sollevando finché il braccio non è parallelo al pavimento.","Fermati un attimo in cima, poi abbassa lentamente il manubrio alla posizione di partenza.","Ripeti per il numero desiderato di ripetizioni, poi passa all'altro braccio."]}},{"id":"1281","name":"dumbbell incline one arm press","category":"chest","equipment":"dumbbell","target":"pectorals","secondary":["shoulders","triceps"],"steps":{"en":["Sit on an incline bench with a dumbbell in one hand, resting on your thigh.","Lie back on the bench and position the dumbbell at shoulder level, palm facing forward.","Press the dumbbell upward and slightly inward, extending your arm fully.","Pause for a moment at the top, then slowly lower the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch to the other arm."],"it":["Siediti su una panchina inclinata con un manubrio in una mano, appoggiato sulla coscia.","Sdraiati sulla panca e posiziona il manubrio all'altezza delle spalle, palmo rivolto in avanti.","Premi il manubrio verso l'alto e leggermente verso l'interno, estendendo completamente il braccio.","Fermati un attimo in cima, poi abbassa lentamente il manubrio alla posizione di partenza.","Ripeti per il numero desiderato di ripetizioni, poi passa all'altro braccio."]}},{"id":"1282","name":"dumbbell incline one arm press on exercise ball","category":"chest","equipment":"dumbbell","target":"pectorals","secondary":["shoulders","triceps"],"steps":{"en":["Sit on an exercise ball with a dumbbell in one hand, feet flat on the ground.","Slowly walk your feet forward, rolling the ball until your head, neck, and upper back are supported on the ball.","Hold the dumbbell at shoulder height with your palm facing forward.","Press the dumbbell upward until your arm is fully extended.","Pause for a moment at the top, then slowly lower the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch to the other arm."],"it":["Siediti su una palla da ginnastica con un manubrio in una mano, i piedi piatti a terra.","Muovi lentamente i piedi in avanti, facendo rotolare la palla finché testa, collo e parte superiore della schiena non sono sostenuti sulla palla.","Tieni il manubrio all'altezza delle spalle con il palmo rivolto in avanti.","Premi il manubrio verso l'alto finché il braccio non è completamente esteso.","Fermati un attimo in cima, poi abbassa lentamente il manubrio alla posizione di partenza.","Ripeti per il numero desiderato di ripetizioni, poi passa all'altro braccio."]}},{"id":"0324","name":"dumbbell incline palm-in press","category":"chest","equipment":"dumbbell","target":"pectorals","secondary":["shoulders","triceps"],"steps":{"en":["Set up an incline bench at a 45-degree angle.","Sit on the bench with a dumbbell in each hand, palms facing each other.","Plant your feet firmly on the ground and keep your back straight against the bench.","Start with the dumbbells at shoulder level, elbows bent and palms facing each other.","Press the dumbbells up and away from your body, extending your arms fully.","Pause for a moment at the top, then slowly lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"it":["Installa una panca inclinata con un angolo di 45 gradi.","Seduta sulla panchina con un manubrio in ogni mano, i palmi rivolti l'uno verso l'altro.","Pianta i piedi saldamente a terra e tieni la schiena dritta contro la panca.","Inizia con i manubri all'altezza delle spalle, gomiti piegati e palmi rivolti uno verso l'altro.","Spingi i manubri verso l'alto e lontano dal corpo, estendendo completamente le braccia.","Fermati un attimo in cima, poi abbassa lentamente i manubri alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"1283","name":"dumbbell incline press on exercise ball","category":"chest","equipment":"dumbbell","target":"pectorals","secondary":["shoulders","triceps"],"steps":{"en":["Sit on an exercise ball with a dumbbell in each hand, palms facing forward.","Slowly walk your feet forward, rolling your body down the ball until your head, neck, and upper back are supported on the ball.","Hold the dumbbells at shoulder level, elbows bent and pointing out to the sides.","Press the dumbbells upward, extending your arms fully.","Pause for a moment at the top, then slowly lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"it":["Siediti su una palla da ginnastica con un manubrio in ogni mano, i palmi rivolti in avanti.","Muovi lentamente i piedi in avanti, facendo rotolare il corpo lungo la palla finché testa, collo e parte superiore della schiena non sono sostenuti sulla palla.","Tieni i manubri all'altezza delle spalle, gomiti piegati e rivolti ai lati.","Premi i manubri verso l'alto, estendendo completamente le braccia.","Fermati un attimo in cima, poi abbassa lentamente i manubri alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0325","name":"dumbbell incline raise","category":"shoulders","equipment":"dumbbell","target":"delts","secondary":["trapezius","triceps"],"steps":{"en":["Sit on an incline bench with a dumbbell in each hand, resting on your thighs.","Lean back on the bench and raise the dumbbells to shoulder height, palms facing forward.","Keeping your back against the bench, exhale and raise the dumbbells above your head, fully extending your arms.","Pause for a moment at the top, then inhale and slowly lower the dumbbells back to shoulder height.","Repeat for the desired number of repetitions."],"it":["Siediti su una panca inclinata con un manubrio in ogni mano, appoggiato sulle cosce.","Appoggiati indietro alla panchina e alza i manubri all'altezza delle spalle, palmi rivolti in avanti.","Tenendo la schiena appoggiata alla panca, espira e alza i manubri sopra la testa, estendendo completamente le braccia.","Fermati un attimo in cima, poi inspira e abbassa lentamente i manubri all'altezza delle spalle.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0326","name":"dumbbell incline rear lateral raise","category":"shoulders","equipment":"dumbbell","target":"delts","secondary":["traps","rhomboids"],"steps":{"en":["Set up an incline bench at a 45-degree angle.","Sit on the bench with your chest against the backrest and hold a dumbbell in each hand.","Extend your arms straight down with your palms facing each other.","Keeping a slight bend in your elbows, raise your arms out to the sides until they are parallel to the ground.","Pause for a moment at the top, then slowly lower your arms back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Installa una panca inclinata con un angolo di 45 gradi.","Siediti sulla panca con il petto appoggiato allo schienale e tieni un manubrio in ogni mano.","Allunga le braccia dritte verso il basso con i palmi rivolti l'uno verso l'altro.","Mantenendo una leggera piega dei gomiti, alza le braccia ai lati finché non sono parallele al suolo.","Fermati un attimo in cima, poi abbassa lentamente le braccia fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0327","name":"dumbbell incline row","category":"back","equipment":"dumbbell","target":"upper back","secondary":["biceps","shoulders"],"steps":{"en":["Set up an incline bench at a 45-degree angle.","Grab a dumbbell in each hand and sit on the bench with your chest against the incline.","Extend your arms fully, allowing the dumbbells to hang straight down from your shoulders.","Pull the dumbbells up towards your chest, squeezing your shoulder blades together.","Pause for a moment at the top, then slowly lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"it":["Installa una panca inclinata con un angolo di 45 gradi.","Prendi un manubrio in ogni mano e siediti sulla panca con il petto appoggiato all'inclinazione.","Allunga completamente le braccia, lasciando che i manubri pendano dritti dalle spalle.","Tira i manubri verso il petto, stringendo le scapole insieme.","Fermati un attimo in cima, poi abbassa lentamente i manubri alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0328","name":"dumbbell incline shoulder raise","category":"chest","equipment":"dumbbell","target":"serratus anterior","secondary":["deltoids","trapezius"],"steps":{"en":["Set an incline bench to a 45-degree angle and sit on it with a dumbbell in each hand, palms facing down.","Rest the dumbbells on your thighs and lean back onto the bench.","Use your thighs to help raise the dumbbells to shoulder height, then rotate your wrists so that your palms are facing forward.","Exhale and slowly raise the dumbbells above your head, keeping a slight bend in your elbows.","Pause for a moment at the top, then inhale and slowly lower the dumbbells back to shoulder height.","Repeat for the desired number of repetitions."],"it":["Imposta una panca inclinata a 45 gradi e siediti sopra con un manubrio in ciascuna mano, i palmi rivolti verso il basso.","Appoggia i manubri sulle cosce e appoggiati allo schienale della panca.","Usa le cosce per aiutare a sollevare i manubri all'altezza delle spalle, poi ruota i polsi in modo che i palmi siano rivolti in avanti.","Espira e solleva lentamente i manubri sopra la testa, mantenendo una leggera piega dei gomiti.","Fermati un attimo in cima, poi inspira e abbassa lentamente i manubri all'altezza delle spalle.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0329","name":"dumbbell incline shrug","category":"back","equipment":"dumbbell","target":"traps","secondary":["shoulders"],"steps":{"en":["Set an incline bench to a 45-degree angle and sit on it with a dumbbell in each hand.","Place your feet flat on the ground and let your arms hang straight down with your palms facing your body.","Keeping your arms straight, shrug your shoulders up towards your ears as high as possible.","Hold the contraction for a moment, then slowly lower your shoulders back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Imposta una panca inclinata a 45 gradi e siediti con un manubrio in ogni mano.","Metti i piedi piatti a terra e lascia che le braccia pendano dritte verso il basso con i palmi rivolti verso il corpo.","Tieni le braccia dritte, alza le spalle verso le orecchie il più possibile.","Mantieni la contrazione per un momento, poi abbassa lentamente le spalle fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"3542","name":"dumbbell incline t-raise","category":"shoulders","equipment":"dumbbell","target":"delts","secondary":["traps","rhomboids"],"steps":{"en":["Set an incline bench to a 45-degree angle and sit on it with a dumbbell in each hand, palms facing inwards.","Lean forward and let your arms hang straight down, perpendicular to the floor.","Keeping your arms straight, raise them out to the sides until they are parallel to the floor, forming a 'T' shape with your body.","Pause for a moment at the top, then slowly lower your arms back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Imposta una panca inclinata a 45 gradi e siediti sopra con un manubrio in ciascuna mano, palmi rivolti verso l'interno.","Piegati in avanti e lascia che le braccia pendano dritte verso il basso, perpendicolari al pavimento.","Tenendo le braccia dritte, alzale ai lati finché non sono parallele al pavimento, formando una forma a 'T' con il corpo.","Fermati un attimo in cima, poi abbassa lentamente le braccia fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0330","name":"dumbbell incline triceps extension","category":"upper arms","equipment":"dumbbell","target":"triceps","secondary":["shoulders"],"steps":{"en":["Sit on an incline bench with a dumbbell in each hand, palms facing inwards.","Extend your arms fully overhead, keeping your elbows close to your head.","Lower the dumbbells behind your head by bending your elbows, keeping your upper arms stationary.","Pause for a moment, then raise the dumbbells back to the starting position by extending your arms.","Repeat for the desired number of repetitions."],"it":["Siediti su una panchina inclinata con un manubrio in ogni mano, i palmi rivolti verso l'interno.","Allunga completamente le braccia sopra la testa, tenendo i gomiti vicini alla testa.","Abbassa i manubri dietro la testa piegando i gomiti, mantenendo ferme le braccia superiori.","Fermati un attimo, poi riporta i manubri alla posizione iniziale estendendo le braccia.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0331","name":"dumbbell incline twisted flyes","category":"chest","equipment":"dumbbell","target":"pectorals","secondary":["shoulders","triceps"],"steps":{"en":["Set an incline bench to a 45-degree angle and sit on it with a dumbbell in each hand, palms facing each other.","Lie back on the bench and press the dumbbells up to the starting position, directly above your chest, with your arms extended.","Lower the dumbbells out to the sides in a wide arc until you feel a stretch in your chest.","As you lower the dumbbells, rotate your wrists so that your palms face forward at the bottom of the movement.","Reverse the motion and bring the dumbbells back up to the starting position, squeezing your chest muscles together at the top.","Repeat for the desired number of repetitions."],"it":["Imposta una panca inclinata a 45 gradi e siediti sopra con un manubrio in ogni mano, palmi rivolti l'uno verso l'altro.","Sdraiati sulla panca e spingi i manubri fino alla posizione iniziale, direttamente sopra il petto, con le braccia distese.","Abbassa i manubri ai lati in un ampio arco finché non senti uno stiramento al petto.","Mentre abbassi i manubri, ruota i polsi in modo che i palmi siano rivolti in avanti alla base del movimento.","Inverti il movimento e riporta i manubri nella posizione iniziale, stringendo i muscoli del petto in alto.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"1733","name":"dumbbell incline two arm extension","category":"upper arms","equipment":"dumbbell","target":"triceps","secondary":["shoulders"],"steps":{"en":["Sit on an incline bench with a dumbbell in each hand, resting on your thighs.","Slowly lie back on the bench, keeping the dumbbells close to your chest.","Once you are fully lying down, extend your arms straight up towards the ceiling, keeping your elbows slightly bent.","Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Siediti su una panca inclinata con un manubrio in ogni mano, appoggiato sulle cosce.","Sdraiati lentamente sulla panca, tenendo i manubri stretti al petto.","Una volta completamente sdraiato, estendi le braccia dritte verso il soffitto, mantenendo i gomiti leggermente piegati.","Fermati un attimo in cima, poi abbassa lentamente i manubri fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"3541","name":"dumbbell incline y-raise","category":"back","equipment":"dumbbell","target":"upper back","secondary":["shoulders","rear deltoids"],"steps":{"en":["Set an incline bench to a 45-degree angle and sit on it with a dumbbell in each hand, palms facing inwards.","Lean forward slightly and let your arms hang straight down, keeping a slight bend in your elbows.","Raise your arms out to the sides and up in a Y shape until they are parallel to the ground.","Pause for a moment at the top, then slowly lower your arms back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Imposta una panca inclinata a 45 gradi e siediti sopra con un manubrio in ciascuna mano, palmi rivolti verso l'interno.","Inclinati leggermente in avanti e lascia che le braccia pendano dritte verso il basso, mantenendo una leggera piega dei gomiti.","Alza le braccia ai lati e verso l'alto a forma di Y finché non sono parallele al suolo.","Fermati un attimo in cima, poi abbassa lentamente le braccia fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0332","name":"dumbbell iron cross","category":"shoulders","equipment":"dumbbell","target":"delts","secondary":["triceps","chest"],"steps":{"en":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand at your sides.","Raise your arms out to the sides until they are parallel to the ground, forming a T shape with your body.","Pause for a moment, then slowly lower your arms back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai con i piedi a larghezza delle spalle, tenendo un manubrio in ogni mano ai lati.","Alza le braccia ai lati finché non sono parallele al suolo, formando una forma a T con il corpo.","Fermati un attimo, poi abbassa lentamente le braccia fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0333","name":"dumbbell kickback","category":"upper arms","equipment":"dumbbell","target":"triceps","secondary":["shoulders"],"steps":{"en":["Stand with your feet shoulder-width apart and hold a dumbbell in each hand.","Bend your knees slightly and hinge forward at the hips, keeping your back straight.","Bring your upper arms close to your sides, with your elbows bent at a 90-degree angle.","Extend your arms straight back, squeezing your triceps at the top of the movement.","Pause for a moment, then slowly lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai con i piedi distanti alla larghezza delle spalle e tieni un manubrio in ciascuna mano.","Piega leggermente le ginocchia e piega in avanti ai fianchi, mantenendo la schiena dritta.","Avvicina le braccia superiori ai fianchi, con i gomiti piegati a 90 gradi.","Allunga le braccia dritte, stringendo i tricipiti nella parte superiore del movimento.","Fermati un attimo, poi abbassa lentamente i manubri alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"1734","name":"dumbbell kickbacks on exercise ball","category":"upper arms","equipment":"dumbbell","target":"triceps","secondary":["shoulders","back"],"steps":{"en":["Sit on an exercise ball with your feet flat on the ground and your back straight.","Hold a dumbbell in each hand with your palms facing inwards and your arms bent at a 90-degree angle.","Extend your arms straight back, squeezing your triceps at the top of the movement.","Pause for a moment, then slowly lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"it":["Siediti su una palla da ginnastica con i piedi piatti a terra e la schiena dritta.","Tieni un manubrio in ogni mano con i palmi rivolti verso l'interno e le braccia piegate a 90 gradi.","Allunga le braccia dritte, stringendo i tricipiti nella parte superiore del movimento.","Fermati un attimo, poi abbassa lentamente i manubri alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"1660","name":"dumbbell kneeling bicep curl exercise ball","category":"upper arms","equipment":"dumbbell","target":"biceps","secondary":["forearms"],"steps":{"en":["Kneel on the floor with an exercise ball in front of you.","Place your elbows on top of the exercise ball, holding a dumbbell in each hand with your palms facing up.","Keeping your upper arms stationary, exhale and curl the dumbbells while contracting your biceps.","Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"it":["Inginocchiati sul pavimento con una palla da ginnastica davanti a te.","Appoggia i gomiti sopra la palla da esercizio, tenendo un manubrio in ogni mano con i palmi rivolti verso l'alto.","Mantenendo ferme le braccia superiori, espira e arriccia i manubri mentre contrahi i bicipiti.","Continua ad alzare i manubri finché i bicipiti non sono completamente contratti e i manubri non sono all'altezza delle spalle.","Mantieni la posizione contratta per una breve pausa mentre stringi i bicipiti.","Inspira e inizia lentamente ad abbassare i manubri fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0334","name":"dumbbell lateral raise","category":"shoulders","equipment":"dumbbell","target":"delts","secondary":["traps"],"steps":{"en":["Stand with your feet shoulder-width apart and hold a dumbbell in each hand, palms facing your body.","Keep your back straight and engage your core.","Raise your arms out to the sides until they are parallel to the floor, keeping a slight bend in your elbows.","Pause for a moment at the top, then slowly lower your arms back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai in piedi con i piedi alla larghezza delle spalle e tieni un manubrio in ogni mano, palmi rivolti verso il corpo.","Tieni la schiena dritta e attiva il core.","Alza le braccia ai lati finché non sono parallele al pavimento, mantenendo una leggera piega dei gomiti.","Fermati un attimo in cima, poi abbassa lentamente le braccia fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0335","name":"dumbbell lateral to front raise","category":"shoulders","equipment":"dumbbell","target":"delts","secondary":["trapezius","biceps"],"steps":{"en":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand with your palms facing your body.","Keep your back straight and engage your core.","Raise your arms out to the sides until they are parallel to the ground, keeping a slight bend in your elbows.","Pause for a moment at the top, then slowly lower your arms back down to the starting position.","Next, raise your arms in front of you until they are parallel to the ground, again keeping a slight bend in your elbows.","Pause for a moment at the top, then slowly lower your arms back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai con i piedi a larghezza delle spalle, tenendo un manubrio in ogni mano con i palmi rivolti verso il corpo.","Tieni la schiena dritta e attiva il core.","Alza le braccia ai lati finché non sono parallele al suolo, mantenendo una leggera piega dei gomiti.","Fermati un attimo in cima, poi abbassa lentamente le braccia fino alla posizione iniziale.","Poi, alza le braccia davanti a te finché non sono parallele al suolo, mantenendo ancora una leggera piega dei gomiti.","Fermati un attimo in cima, poi abbassa lentamente le braccia fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0336","name":"dumbbell lunge","category":"upper legs","equipment":"dumbbell","target":"glutes","secondary":["quadriceps","hamstrings","calves"],"steps":{"en":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand.","Take a step forward with your right foot, lowering your body into a lunge position.","Keep your back straight and your chest up as you lower your body.","Push through your right heel to return to the starting position.","Repeat with your left leg.","Alternate legs for the desired number of repetitions."],"it":["Stai con i piedi a larghezza delle spalle, tenendo un manubrio in ciascuna mano.","Fai un passo avanti con il piede destro, abbassando il corpo in posizione di affondamento.","Tieni la schiena dritta e il petto sollevato mentre abbassi il corpo.","Spingi attraverso il tallone destro per tornare alla posizione di partenza.","Ripeti con la gamba sinistra.","Alterna le gambe per il numero desiderato di ripetizioni."]}},{"id":"1658","name":"dumbbell lunge with bicep curl","category":"upper arms","equipment":"dumbbell","target":"biceps","secondary":["quadriceps","hamstrings"],"steps":{"en":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand with your palms facing forward.","Take a step forward with your right foot, lowering your body into a lunge position. Your right knee should be bent at a 90-degree angle and your left knee should be hovering just above the ground.","As you lunge forward, simultaneously curl the dumbbells towards your shoulders, keeping your elbows close to your body.","Pause for a moment at the bottom of the lunge, then push through your right heel to return to the starting position, lowering the dumbbells back down to your sides.","Repeat the lunge and bicep curl on the opposite side, stepping forward with your left foot.","Continue alternating sides for the desired number of repetitions."],"it":["Stai in piedi con i piedi alla larghezza delle spalle, tenendo un manubrio in ciascuna mano con i palmi rivolti in avanti.","Fai un passo avanti con il piede destro, abbassando il corpo in posizione di affondamento. Il ginocchio destro dovrebbe essere piegato a 90 gradi e il ginocchio sinistro dovrebbe essere sospeso appena sopra il suolo.","Mentre ti lanci in avanti, arrotola contemporaneamente i manubri verso le spalle, tenendo i gomiti vicini al corpo.","Fermati un attimo in fondo all'affondo, poi spingi attraverso il tallone destro per tornare alla posizione iniziale, abbassando i manubri ai lati.","Ripeti l'affondo e il bicipite curl sul lato opposto, avanzando con il piede sinistro.","Continua ad alternare i lati per il numero desiderato di ripetizioni."]}},{"id":"0337","name":"dumbbell lying extension (across face)","category":"upper arms","equipment":"dumbbell","target":"triceps","secondary":["shoulders"],"steps":{"en":["Lie flat on a bench with your feet flat on the ground and your head at the end of the bench.","Hold a dumbbell with both hands and extend your arms straight up above your chest, palms facing each other.","Keeping your upper arms stationary, slowly lower the dumbbell in an arc behind your head until your forearms are parallel to the ground.","Pause for a moment, then contract your triceps to bring the dumbbell back to the starting position.","Repeat for the desired number of repetitions."],"it":["Sdraiati disteso su una panca con i piedi a terra e la testa alla fine della panca.","Tieni un manubrio con entrambe le mani e allunga le braccia dritte sopra il petto, palmi rivolti l'uno verso l'altro.","Mantenendo ferme le braccia superiori, abbassa lentamente il manubrio in un arco dietro la testa finché gli avambracci non sono paralleli al suolo.","Fermati un attimo, poi contrai i tricipiti per riportare il manubrio alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"1729","name":"dumbbell lying alternate extension","category":"upper arms","equipment":"dumbbell","target":"triceps","secondary":["shoulders"],"steps":{"en":["Lie flat on a bench with a dumbbell in each hand, palms facing each other.","Extend your arms straight up over your chest, keeping a slight bend in your elbows.","Lower one dumbbell down towards your head, bending at the elbow, while keeping the other arm extended.","Pause for a moment at the bottom, then raise the dumbbell back up to the starting position.","Repeat with the other arm, alternating sides for the desired number of repetitions."],"it":["Sdraiati disteso su una panchina con un manubrio in ogni mano, i palmi uno verso l'altro.","Allunga le braccia dritte sopra il petto, mantenendo una leggera piega dei gomiti.","Abbassa un manubrio verso la testa, piegandosi al gomito, mentre tieni l'altro braccio esteso.","Fermati un attimo in fondo, poi rialza il manubrio fino alla posizione di partenza.","Ripeti con l'altro braccio, alternando i lati per il numero desiderato di ripetizioni."]}},{"id":"0338","name":"dumbbell lying elbow press","category":"upper arms","equipment":"dumbbell","target":"triceps","secondary":["chest","shoulders"],"steps":{"en":["Lie flat on a bench with a dumbbell in each hand, palms facing each other and arms extended straight up over your chest.","Lower the dumbbells towards your shoulders by bending your elbows, keeping your upper arms stationary.","Pause for a moment at the bottom, then press the dumbbells back up to the starting position by extending your elbows.","Repeat for the desired number of repetitions."],"it":["Sdraiati su una panca con un manubrio in ogni mano, palmi rivolti e braccia allungate dritte sopra il petto.","Abbassa i manubri verso le spalle piegando i gomiti, mantenendo ferme le braccia superiori.","Fermati un attimo in basso, poi riporta i manubri alla posizione iniziale estendendo i gomiti.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0863","name":"dumbbell lying external shoulder rotation","category":"shoulders","equipment":"dumbbell","target":"delts","secondary":["rotator cuff","triceps"],"steps":{"en":["Lie on your side on a flat bench with your upper arm against your side and your elbow bent 90 degrees.","Hold a dumbbell in your hand with your palm facing down.","Keeping your upper arm against your side, slowly rotate your forearm upward as far as possible.","Pause for a moment at the top, then slowly lower your forearm back down to the starting position.","Repeat for the desired number of repetitions, then switch sides."],"it":["Sdraiati su un fianco su una panca piatta con il braccio superiore contro il fianco e il gomito piegato di 90 gradi.","Tieni un manubrio in mano con il palmo rivolto verso il basso.","Tenendo il braccio superiore contro il fianco, ruota lentamente l'avambraccio verso l'alto il più possibile.","Fermati un attimo in cima, poi abbassa lentamente l'avambraccio fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni, poi cambia lato."]}},{"id":"0339","name":"dumbbell lying femoral","category":"upper legs","equipment":"dumbbell","target":"hamstrings","secondary":["glutes"],"steps":{"en":["Lie flat on your back with your legs extended and a dumbbell resting on your lower abdomen.","Bend your knees and bring the dumbbell towards your glutes, keeping your feet flat on the ground.","Pause for a moment at the top, then slowly lower the dumbbell back to the starting position.","Repeat for the desired number of repetitions."],"it":["Sdraiati sulla schiena con le gambe distese e un manubrio appoggiato sul basso ventre.","Piega le ginocchia e porta il manubrio verso i glutei, mantenendo i piedi piatti a terra.","Fermati un attimo in cima, poi abbassa lentamente il manubrio alla posizione di partenza.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0340","name":"dumbbell lying hammer press","category":"chest","equipment":"dumbbell","target":"pectorals","secondary":["triceps","shoulders"],"steps":{"en":["Lie flat on a bench with a dumbbell in each hand, palms facing each other and arms extended straight up.","Lower the dumbbells to the sides of your chest, keeping your elbows at a 90-degree angle.","Press the dumbbells back up to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."],"it":["Sdraiati su una panca con un manubrio in ogni mano, palmi rivolti e braccia allungate verso l'alto.","Abbassa i manubri ai lati del petto, mantenendo i gomiti a un angolo di 90 gradi.","Riporta i manubri alla posizione iniziale, estendendo completamente le braccia.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"2470","name":"dumbbell lying on floor rear delt raise","category":"shoulders","equipment":"dumbbell","target":"delts","secondary":["trapezius","rhomboids"],"steps":{"en":["Lie face down on the floor with a dumbbell in each hand, palms facing each other.","Extend your arms straight out in front of you, keeping a slight bend in your elbows.","Engaging your shoulder muscles, lift your arms up and out to the sides, squeezing your shoulder blades together.","Pause for a moment at the top, then slowly lower your arms back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Sdraiati a faccia in giù sul pavimento con un manubrio in ciascuna mano, i palmi rivolti l'uno verso l'altro.","Allunga le braccia dritte davanti a te, mantenendo una leggera piega dei gomiti.","Attivando i muscoli delle spalle, solleva le braccia e allunga i lati, stringendo le scapole insieme.","Fermati un attimo in cima, poi abbassa lentamente le braccia fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0341","name":"dumbbell lying one arm deltoid rear","category":"shoulders","equipment":"dumbbell","target":"delts","secondary":["trapezius","rhomboids"],"steps":{"en":["Lie face down on a flat bench with a dumbbell in one hand, palm facing inwards.","Extend your arm straight down towards the floor, keeping it close to your body.","Raise your arm up and back, squeezing your shoulder blade towards your spine.","Pause for a moment at the top, then slowly lower your arm back down to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"it":["Sdraiati a faccia in giù su una panca piatta con un manubrio in una mano, il palmo rivolto verso l'interno.","Allunga il braccio verso il basso verso il pavimento, tenendolo vicino al corpo.","Alza il braccio verso l'indietro, stringendo la scapola verso la colonna vertebrale.","Fermati un attimo in cima, poi abbassa lentamente il braccio fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni, poi cambia braccio."]}},{"id":"0343","name":"dumbbell lying one arm press","category":"chest","equipment":"dumbbell","target":"pectorals","secondary":["triceps","shoulders"],"steps":{"en":["Lie flat on a bench with a dumbbell in one hand and your feet flat on the ground.","Hold the dumbbell at shoulder level with your palm facing forward.","Press the dumbbell upward until your arm is fully extended.","Pause for a moment at the top, then slowly lower the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch to the other arm."],"it":["Sdraiati su una panchina con un manubrio in una mano e i piedi appoggiati a terra.","Tieni il manubrio all'altezza delle spalle con il palmo rivolto in avanti.","Premi il manubrio verso l'alto finché il braccio non è completamente esteso.","Fermati un attimo in cima, poi abbassa lentamente il manubrio alla posizione di partenza.","Ripeti per il numero desiderato di ripetizioni, poi passa all'altro braccio."]}},{"id":"0342","name":"dumbbell lying one arm press v. 2","category":"chest","equipment":"dumbbell","target":"pectorals","secondary":["triceps","shoulders"],"steps":{"en":["Lie flat on a bench with your back supported and feet flat on the ground.","Hold a dumbbell in one hand with your palm facing towards your feet.","Extend your arm straight up towards the ceiling, keeping your elbow slightly bent.","Slowly lower the dumbbell down towards your chest, keeping your elbow close to your body.","Pause for a moment at the bottom, then push the dumbbell back up to the starting position.","Repeat for the desired number of repetitions, then switch to the other arm."],"it":["Sdraiati disteso su una panca con la schiena appoggiata e i piedi appoggiati a terra.","Tieni un manubrio in una mano con il palmo rivolto verso i piedi.","Allunga il braccio verso il soffitto, tenendo il gomito leggermente piegato.","Abbassa lentamente il manubrio verso il petto, tenendo il gomito vicino al corpo.","Fermati un attimo in fondo, poi riporta il manubrio alla posizione di partenza.","Ripeti per il numero desiderato di ripetizioni, poi passa all'altro braccio."]}},{"id":"0344","name":"dumbbell lying one arm pronated triceps extension","category":"upper arms","equipment":"dumbbell","target":"triceps","secondary":["shoulders"],"steps":{"en":["Lie flat on a bench with your back and head supported, and your feet flat on the ground.","Hold a dumbbell in one hand with your palm facing down, and extend your arm straight up above your shoulder.","Keeping your upper arm stationary, slowly lower the dumbbell behind your head by bending your elbow.","Pause for a moment at the bottom, then extend your arm back up to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"it":["Sdraiati disteso su una panca con la schiena e la testa sostenute, e i piedi piatti a terra.","Tieni un manubrio in una mano con il palmo rivolto verso il basso e allunga il braccio dritto sopra la spalla.","Mantenendo fermo il braccio superiore, abbassa lentamente il manubrio dietro la testa piegando il gomito.","Fermati un attimo in basso, poi rialza il braccio fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni, poi cambia braccio."]}},{"id":"0345","name":"dumbbell lying one arm rear lateral raise","category":"shoulders","equipment":"dumbbell","target":"delts","secondary":["traps","rhomboids"],"steps":{"en":["Lie face down on a flat bench with a dumbbell in one hand, hanging towards the floor.","Keep your arm straight and lift the dumbbell out to the side, away from your body.","Pause for a moment at the top, then slowly lower the dumbbell back down to the starting position.","Repeat for the desired number of repetitions, then switch to the other arm."],"it":["Sdraiati a faccia in giù su una panchina piatta con un manubrio in una mano, penzolante verso il pavimento.","Tieni il braccio teso e solleva il manubrio di lato, lontano dal corpo.","Fermati un attimo in cima, poi abbassa lentamente il manubrio fino alla posizione di partenza.","Ripeti per il numero desiderato di ripetizioni, poi passa all'altro braccio."]}},{"id":"0346","name":"dumbbell lying one arm supinated triceps extension","category":"upper arms","equipment":"dumbbell","target":"triceps","secondary":["forearms"],"steps":{"en":["Lie flat on a bench with your back and head supported, and your feet flat on the ground.","Hold a dumbbell in one hand with an underhand grip, and extend your arm straight up above your shoulder.","Keeping your upper arm stationary, slowly lower the dumbbell behind your head by bending your elbow.","Pause for a moment at the bottom, then extend your arm back up to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"it":["Sdraiati disteso su una panca con la schiena e la testa sostenute, e i piedi piatti a terra.","Tieni un manubrio con una mano con una presa sottomano e estendi il braccio dritto sopra la spalla.","Mantenendo fermo il braccio superiore, abbassa lentamente il manubrio dietro la testa piegando il gomito.","Fermati un attimo in basso, poi rialza il braccio fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni, poi cambia braccio."]}},{"id":"0347","name":"dumbbell lying pronation","category":"lower arms","equipment":"dumbbell","target":"forearms","secondary":["biceps","shoulders"],"steps":{"en":["Lie flat on a bench with your chest facing down and your arms extended straight down, holding a dumbbell in each hand.","Rotate your palms so they are facing up.","Keeping your upper arms stationary, exhale and curl the dumbbells as you rotate your palms to face down.","Inhale and slowly lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"it":["Sdraiati disteso su una panca con il petto rivolto verso il basso e le braccia distese verso il basso, tenendo un manubrio in ogni mano.","Ruota i palmi in modo che siano rivolti verso l'alto.","Mantenendo ferme le braccia superiori, espira e arriccia i manubri mentre ruoti i palmi per farli rivolti verso il basso.","Inspira e abbassa lentamente i manubri fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"2705","name":"dumbbell lying pronation on floor","category":"lower arms","equipment":"dumbbell","target":"forearms","secondary":["biceps","triceps"],"steps":{"en":["Lie flat on the floor with your face down and your arms extended straight out in front of you, holding a dumbbell in each hand.","Rotate your palms so they are facing down towards the floor.","Keeping your arms straight, lift the dumbbells off the floor by contracting your forearms.","Continue lifting until your forearms are fully contracted and the dumbbells are at shoulder level.","Hold for a moment, then slowly lower the dumbbells back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Sdraiati a terra con la faccia in giù e le braccia distese davanti a te, tenendo un manubrio in ogni mano.","Ruota i palmi in modo che siano rivolti verso il pavimento.","Tenendo le braccia dritte, solleva i manubri da terra contraendo gli avambracci.","Continua a sollevare sollevando finché gli avambracci non sono completamente contratti e i manubri non sono all'altezza delle spalle.","Tieni fermo per un momento, poi abbassa lentamente i manubri fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"1284","name":"dumbbell lying pullover on exercise ball","category":"chest","equipment":"dumbbell","target":"pectorals","secondary":["triceps","shoulders","back"],"steps":{"en":["Sit on an exercise ball and roll forward until your upper back is resting on the ball.","Hold a dumbbell with both hands and extend your arms straight up over your chest.","Slowly lower the dumbbell behind your head while keeping your arms straight.","Pause for a moment, then raise the dumbbell back to the starting position.","Repeat for the desired number of repetitions."],"it":["Siediti su una palla da ginnastica e rotola in avanti finché la parte superiore della schiena non si appoggia sulla palla.","Tieni un manubrio con entrambe le mani e allunga le braccia dritte sopra il petto.","Abbassa lentamente il manubrio dietro la testa mantenendo le braccia dritte.","Fermati un attimo, poi solleva il manubrio di nuovo alla posizione di partenza.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"1328","name":"dumbbell lying rear delt row","category":"back","equipment":"dumbbell","target":"upper back","secondary":["shoulders","biceps"],"steps":{"en":["Lie face down on a flat bench with a dumbbell in each hand, palms facing inwards.","Extend your arms straight down towards the floor, keeping a slight bend in your elbows.","Engaging your back muscles, lift the dumbbells up towards your chest, squeezing your shoulder blades together.","Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Sdraiati a faccia in giù su una panca piatta con un manubrio in ogni mano, i palmi rivolti verso l'interno.","Allunga le braccia dritte verso il pavimento, mantenendo una leggera piega dei gomiti.","Attivando i muscoli della schiena, solleva i manubri verso il petto, stringendo le scapole insieme.","Fermati un attimo in cima, poi abbassa lentamente i manubri fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0348","name":"dumbbell lying rear lateral raise","category":"shoulders","equipment":"dumbbell","target":"delts","secondary":["traps","rhomboids"],"steps":{"en":["Lie face down on a flat bench with a dumbbell in each hand, palms facing each other.","Extend your arms straight down towards the floor, keeping a slight bend in your elbows.","Engaging your shoulder muscles, lift your arms out to the sides until they are parallel to the floor.","Pause for a moment at the top, then slowly lower your arms back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Sdraiati a faccia in giù su una panca piatta con un manubrio in ogni mano, i palmi uno verso l'altro.","Allunga le braccia dritte verso il pavimento, mantenendo una leggera piega dei gomiti.","Attivando i muscoli delle spalle, alza le braccia ai lati finché non sono parallele al pavimento.","Fermati un attimo in cima, poi abbassa lentamente le braccia fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"1735","name":"dumbbell lying single extension","category":"upper arms","equipment":"dumbbell","target":"triceps","secondary":["shoulders"],"steps":{"en":["Lie flat on a bench with a dumbbell in one hand and your arm fully extended above your chest.","Lower the dumbbell in a controlled manner towards your forehead, keeping your upper arm stationary.","Pause briefly at the bottom of the movement, then extend your arm back to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"it":["Sdraiati disteso su una panca con un manubrio in una mano e il braccio completamente esteso sopra il petto.","Abbassa il manubrio in modo controllato verso la fronte, mantenendo fermo il braccio superiore.","Fermati brevemente alla fine del movimento, poi estendi il braccio di nuovo alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni, poi cambia braccio."]}},{"id":"0349","name":"dumbbell lying supination","category":"lower arms","equipment":"dumbbell","target":"forearms","secondary":["biceps","shoulders"],"steps":{"en":["Lie flat on a bench with your feet flat on the ground.","Hold a dumbbell in each hand with your palms facing up and your arms fully extended.","Keeping your upper arms stationary, curl the dumbbells towards your shoulders by contracting your forearms.","Pause for a moment at the top, then slowly lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"it":["Sdraiati su una panchina con i piedi a terra.","Tieni un manubrio in ogni mano con i palmi rivolti verso l'alto e le braccia completamente distese.","Mantenendo ferme le braccia superiori, arrotola i manubri verso le spalle contraendo gli avambracci.","Fermati un attimo in cima, poi abbassa lentamente i manubri alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"2706","name":"dumbbell lying supination on floor","category":"lower arms","equipment":"dumbbell","target":"forearms","secondary":["biceps","shoulders"],"steps":{"en":["Lie flat on your back on the floor with your legs extended and your arms by your sides, holding a dumbbell in each hand.","Rotate your palms to face up, keeping your elbows close to your sides.","Slowly curl the dumbbells towards your shoulders, squeezing your forearms.","Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Sdraiati sulla schiena sul pavimento con le gambe distese e le braccia lungo i fianchi, tenendo un manubrio in ogni mano.","Ruota i palmi verso l'alto, tenendo i gomiti vicini ai fianchi.","Arrotola lentamente i manubri verso le spalle, stringendo gli avambracci.","Fermati un attimo in cima, poi abbassa lentamente i manubri fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"1661","name":"dumbbell lying supine biceps curl","category":"upper arms","equipment":"dumbbell","target":"biceps","secondary":["forearms"],"steps":{"en":["Lie flat on a bench with your back and head supported, and your feet flat on the ground.","Hold a dumbbell in each hand with your palms facing up and your arms fully extended.","Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"it":["Sdraiati disteso su una panca con la schiena e la testa sostenute, e i piedi piatti a terra.","Tieni un manubrio in ogni mano con i palmi rivolti verso l'alto e le braccia completamente distese.","Mantenendo ferme le braccia superiori, espira e arriccia i pesi mentre contrahi i bicipiti.","Continua ad alzare i pesi finché i bicipiti non sono completamente contratti e i manubri non sono all'altezza delle spalle.","Mantieni la posizione contratta per una breve pausa mentre stringi i bicipiti.","Inspira e inizia lentamente ad abbassare i manubri fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0350","name":"dumbbell lying supine curl","category":"upper arms","equipment":"dumbbell","target":"biceps","secondary":["forearms"],"steps":{"en":["Lie flat on a bench with a dumbbell in each hand, palms facing up and arms fully extended.","Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"it":["Sdraiati piano su una panca con un manubrio in ogni mano, palmi rivolti verso l'alto e braccia completamente distese.","Mantenendo ferme le braccia superiori, espira e arriccia i pesi mentre contrahi i bicipiti.","Continua ad alzare i manubri finché i bicipiti non sono completamente contratti e i manubri non sono all'altezza delle spalle.","Mantieni la posizione contratta per una breve pausa mentre stringi i bicipiti.","Inspira e inizia lentamente ad abbassare i manubri fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0351","name":"dumbbell lying triceps extension","category":"upper arms","equipment":"dumbbell","target":"triceps","secondary":["shoulders"],"steps":{"en":["Lie flat on a bench with a dumbbell in each hand, palms facing each other.","Extend your arms straight up over your chest, keeping your elbows close to your body.","Lower the dumbbells down towards your forehead, bending your elbows.","Pause for a moment, then extend your arms back up to the starting position.","Repeat for the desired number of repetitions."],"it":["Sdraiati disteso su una panchina con un manubrio in ogni mano, i palmi uno verso l'altro.","Allunga le braccia dritte sul petto, tenendo i gomiti vicini al corpo.","Abbassa i manubri verso la fronte, piegando i gomiti.","Fermati un attimo, poi rialza le braccia fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"1662","name":"dumbbell lying wide curl","category":"upper arms","equipment":"dumbbell","target":"biceps","secondary":["forearms"],"steps":{"en":["Lie flat on a bench with a dumbbell in each hand, palms facing up and arms fully extended.","Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"it":["Sdraiati piano su una panca con un manubrio in ogni mano, palmi rivolti verso l'alto e braccia completamente distese.","Mantenendo ferme le braccia superiori, espira e arriccia i pesi mentre contrahi i bicipiti.","Continua ad alzare i pesi finché i bicipiti non sono completamente contratti e i manubri non sono all'altezza delle spalle.","Mantieni la posizione contratta per una breve pausa mentre stringi i bicipiti.","Inspira e inizia lentamente ad abbassare i manubri fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0352","name":"dumbbell neutral grip bench press","category":"upper arms","equipment":"dumbbell","target":"triceps","secondary":["chest","shoulders"],"steps":{"en":["Lie flat on a bench with your feet flat on the ground and your back pressed against the bench.","Hold a dumbbell in each hand with a neutral grip (palms facing each other) and your arms extended straight up over your chest.","Slowly lower the dumbbells down towards your chest, keeping your elbows close to your body.","Pause for a moment at the bottom, then push the dumbbells back up to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."],"it":["Sdraiati disteso su una panca con i piedi piatti a terra e la schiena premuta contro la panca.","Tieni un manubrio in ogni mano con una presa neutra (palmi rivolti l'uno verso l'altro) e le braccia distese verso l'alto sopra il petto.","Abbassa lentamente i manubri verso il petto, tenendo i gomiti vicini al corpo.","Fermati un attimo in basso, poi riporta i manubri alla posizione iniziale, estendendo completamente le braccia.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"1285","name":"dumbbell one arm bench fly","category":"chest","equipment":"dumbbell","target":"pectorals","secondary":["shoulders"],"steps":{"en":["Sit on a flat bench with a dumbbell in one hand, resting it on top of your thigh.","Lie back on the bench, keeping the dumbbell pressed against your thigh.","Using your free hand, help lift the dumbbell up to the starting position.","Hold the dumbbell directly above your shoulder with your arm extended and palm facing inward.","Lower the dumbbell out to the side in a wide arc, keeping a slight bend in your elbow.","Pause when your arm is parallel to the ground, then reverse the movement and bring the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch arms and repeat."],"it":["Siediti su una panca piatta con un manubrio in una mano, appoggiandolo sopra la coscia.","Sdraiati sulla panca, tenendo il manubrio premuto contro la coscia.","Con la mano libera, aiuta a sollevare il manubrio fino alla posizione di partenza.","Tieni il manubrio direttamente sopra la spalla con il braccio esteso e il palmo rivolto verso l'interno.","Abbassa il manubrio di lato in un ampio arco, mantenendo una leggera piega del gomito.","Fermati quando il braccio è parallelo al suolo, poi inverti il movimento e riporta il manubrio alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni, poi cambia braccio e ripeti."]}},{"id":"0292","name":"dumbbell one arm bent-over row","category":"back","equipment":"dumbbell","target":"upper back","secondary":["biceps","forearms"],"steps":{"en":["Stand with your feet shoulder-width apart, holding a dumbbell in one hand with your palm facing your body.","Bend your knees slightly and hinge forward at the hips, keeping your back straight and your core engaged.","Let the dumbbell hang straight down towards the floor, with your arm fully extended.","Pull the dumbbell up towards your chest, keeping your elbow close to your body and squeezing your shoulder blades together.","Pause for a moment at the top, then slowly lower the dumbbell back down to the starting position.","Repeat for the desired number of repetitions, then switch sides."],"it":["Stai in piedi con i piedi a larghezza delle spalle, tenendo un manubrio in una mano con il palmo rivolto verso il corpo.","Flette leggermente le ginocchia e incurva in avanti sui fianchi, mantenendo la schiena dritta e il core attivo.","Lascia che il manubrio penda dritto verso il pavimento, con il braccio completamente esteso.","Tira il manubrio verso il petto, tenendo il gomito vicino al corpo e stringendo le scapole insieme.","Fermati un attimo in cima, poi abbassa lentamente il manubrio fino alla posizione di partenza.","Ripeti per il numero desiderato di ripetizioni, poi cambia lato."]}},{"id":"1286","name":"dumbbell one arm chest fly on exercise ball","category":"chest","equipment":"dumbbell","target":"pectorals","secondary":["shoulders","triceps"],"steps":{"en":["Sit on an exercise ball with a dumbbell in one hand and your feet flat on the ground.","Walk your feet forward, rolling the ball until your upper back is supported on the ball and your head, neck, and shoulders are off the ball.","Extend your arm with the dumbbell straight up above your chest, palm facing inward.","Slowly lower the dumbbell out to the side, keeping a slight bend in your elbow.","Pause for a moment when your arm is parallel to the ground.","Engage your chest muscles to bring the dumbbell back up to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"it":["Siediti su una palla da ginnastica con un manubrio in una mano e i piedi piantati a terra.","Muovi i piedi in avanti, facendo rotolare la palla finché la parte superiore della schiena non è sostenuta sulla palla e testa, collo e spalle non sono più dalla palla.","Allunga il braccio con il manubrio dritto sopra il petto, palmo rivolto verso l'interno.","Abbassa lentamente il manubrio di lato, mantenendo una leggera piega del gomito.","Fermati un attimo quando il braccio è parallelo al suolo.","Attiva i muscoli del petto per riportare il manubrio alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni, poi cambia braccio."]}},{"id":"0353","name":"dumbbell one arm concentration curl (on stability ball)","category":"upper arms","equipment":"dumbbell","target":"biceps","secondary":["forearms"],"steps":{"en":["Sit on a stability ball with your feet flat on the ground and your knees bent at a 90-degree angle.","Hold a dumbbell in one hand with your palm facing up and your arm extended down towards the floor.","Rest your elbow on the inside of your thigh, just above the knee.","Keeping your upper arm stationary, exhale and curl the dumbbell up towards your shoulder while contracting your biceps.","Pause for a moment at the top of the movement, then inhale and slowly lower the dumbbell back down to the starting position.","Repeat for the desired number of repetitions, then switch arms and repeat."],"it":["Siediti su una palla di stabilità con i piedi piatti a terra e le ginocchia piegate a 90 gradi.","Tieni un manubrio in una mano con il palmo rivolto verso l'alto e il braccio teso verso il pavimento.","Appoggia il gomito all'interno della coscia, appena sopra il ginocchio.","Mantenendo fermo il braccio superiore, espira e arrotola il manubrio verso la spalla mentre contrahi i bicipiti.","Fermati un attimo all'inizio del movimento, poi inspira e abbassa lentamente il manubrio fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni, poi cambia braccio e ripeti."]}},{"id":"1287","name":"dumbbell one arm decline chest press","category":"chest","equipment":"dumbbell","target":"pectorals","secondary":["triceps","shoulders"],"steps":{"en":["Lie on a decline bench with a dumbbell in one hand, resting on your chest.","Place your feet flat on the ground and keep your back pressed against the bench.","Extend your arm and push the dumbbell up towards the ceiling, fully extending your elbow.","Pause for a moment at the top, then slowly lower the dumbbell back down to the starting position.","Repeat for the desired number of repetitions, then switch to the other arm."],"it":["Sdraiati su una panchina con un manubrio in una mano, appoggiato sul petto.","Metti i piedi piatti a terra e tieni la schiena premuta contro la panca.","Allunga il braccio e spingi il manubrio verso il soffitto, estendendo completamente il gomito.","Fermati un attimo in cima, poi abbassa lentamente il manubrio fino alla posizione di partenza.","Ripeti per il numero desiderato di ripetizioni, poi passa all'altro braccio."]}},{"id":"1288","name":"dumbbell one arm fly on exercise ball","category":"chest","equipment":"dumbbell","target":"pectorals","secondary":["shoulders","triceps"],"steps":{"en":["Sit on an exercise ball with a dumbbell in one hand and your feet flat on the ground.","Walk your feet forward and roll your body down until your upper back is resting on the exercise ball.","Extend your arm with the dumbbell straight up above your chest, palm facing inwards.","Slowly lower the dumbbell out to the side, keeping a slight bend in your elbow.","Pause for a moment, then squeeze your chest muscles to bring the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"it":["Siediti su una palla da ginnastica con un manubrio in una mano e i piedi piantati a terra.","Fai avanti i piedi e fai girare il corpo verso il basso finché la parte superiore della schiena non si appoggia al pallone da ginnastica.","Allunga il braccio con il manubrio dritto sopra il petto, palmo rivolto verso l'interno.","Abbassa lentamente il manubrio di lato, mantenendo una leggera piega del gomito.","Fermati un attimo, poi stringi i muscoli del petto per riportare il manubrio alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni, poi cambia braccio."]}},{"id":"1736","name":"dumbbell one arm french press on exercise ball","category":"upper arms","equipment":"dumbbell","target":"triceps","secondary":["shoulders"],"steps":{"en":["Sit on an exercise ball with your feet flat on the ground and your back straight.","Hold a dumbbell in one hand with your palm facing up and your elbow bent at a 90-degree angle.","Extend your arm straight up towards the ceiling, keeping your elbow stationary.","Slowly lower the dumbbell back down to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"it":["Siediti su una palla da ginnastica con i piedi piatti a terra e la schiena dritta.","Tieni un manubrio con una mano con il palmo rivolto verso l'alto e il gomito piegato a 90 gradi.","Allunga il braccio dritto verso il soffitto, mantenendo il gomito fermo.","Abbassa lentamente il manubrio fino alla posizione di partenza.","Ripeti per il numero desiderato di ripetizioni, poi cambia braccio."]}},{"id":"1663","name":"dumbbell one arm hammer preacher curl","category":"upper arms","equipment":"dumbbell","target":"biceps","secondary":["forearms"],"steps":{"en":["Sit on a preacher bench with a dumbbell in one hand and your upper arm resting on the pad.","Hold the dumbbell with a neutral grip (palms facing your body).","Keeping your upper arm stationary, exhale and curl the dumbbell up towards your shoulder.","Pause for a moment at the top, squeezing your biceps.","Inhale and slowly lower the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"it":["Siediti su una panca da predicatore con un manubrio in una mano e il braccio superiore appoggiato al cuscinetto.","Tieni il manubrio con una presa neutra (palmi rivolti verso il corpo).","Mantenendo fermo il braccio superiore, espira e arrotola il manubrio verso la spalla.","Fermati un attimo in cima, stringendo i bicipiti.","Inspira e abbassa lentamente il manubrio alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni, poi cambia braccio."]}},{"id":"1621","name":"dumbbell one arm hammer press on exercise ball","category":"upper arms","equipment":"dumbbell","target":"triceps","secondary":["shoulders","chest"],"steps":{"en":["Sit on an exercise ball with your feet flat on the ground and your back straight.","Hold a dumbbell in one hand with your palm facing inwards and your elbow bent at a 90-degree angle.","Place your other hand on your hip for stability.","Press the dumbbell upwards, extending your arm fully.","Pause for a moment at the top, then slowly lower the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"it":["Siediti su una palla da ginnastica con i piedi piatti a terra e la schiena dritta.","Tieni un manubrio con una mano con il palmo rivolto verso l'interno e il gomito piegato a 90 gradi.","Metti l'altra mano sul fianco per stabilità.","Premi il manubrio verso l'alto, estendendo completamente il braccio.","Fermati un attimo in cima, poi abbassa lentamente il manubrio alla posizione di partenza.","Ripeti per il numero desiderato di ripetizioni, poi cambia braccio."]}},{"id":"1289","name":"dumbbell one arm incline chest press","category":"chest","equipment":"dumbbell","target":"pectorals","secondary":["shoulders","triceps"],"steps":{"en":["Adjust the incline bench to a 45-degree angle.","Sit on the bench with your back against the pad and feet flat on the ground.","Hold a dumbbell in one hand with an overhand grip, resting it on your shoulder.","Push the dumbbell up and away from your body, extending your arm fully.","Pause for a moment at the top, then slowly lower the dumbbell back down to the starting position.","Repeat for the desired number of repetitions, then switch to the other arm."],"it":["Regola la panca inclinata a un angolo di 45 gradi.","Siediti sulla panca con la schiena appoggiata al pad e i piedi piatti a terra.","Tieni un manubrio in una mano con una presa sopra la mano, appoggiandolo sulla spalla.","Spingi il manubrio verso l'alto e lontano dal corpo, estendendo completamente il braccio.","Fermati un attimo in cima, poi abbassa lentamente il manubrio fino alla posizione di partenza.","Ripeti per il numero desiderato di ripetizioni, poi passa all'altro braccio."]}},{"id":"0354","name":"dumbbell one arm kickback","category":"upper arms","equipment":"dumbbell","target":"triceps","secondary":["shoulders"],"steps":{"en":["Stand with your feet shoulder-width apart and hold a dumbbell in your right hand.","Bend your knees slightly and hinge forward at the hips, keeping your back straight.","Bring your right elbow up to your side, keeping it bent at a 90-degree angle.","Extend your right arm straight back, squeezing your triceps at the top of the movement.","Slowly lower the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch sides."],"it":["Stai con i piedi a larghezza delle spalle e tieni un manubrio nella mano destra.","Piega leggermente le ginocchia e piega in avanti ai fianchi, mantenendo la schiena dritta.","Alza il gomito destro al fianco, mantenendolo piegato a 90 gradi.","Allunga il braccio destro dritto all'indietro, stringendo i tricipiti nella parte superiore del movimento.","Abbassa lentamente il manubrio fino alla posizione di partenza.","Ripeti per il numero desiderato di ripetizioni, poi cambia lato."]}},{"id":"0355","name":"dumbbell one arm lateral raise","category":"shoulders","equipment":"dumbbell","target":"delts","secondary":["trapezius","triceps"],"steps":{"en":["Stand with your feet shoulder-width apart, holding a dumbbell in one hand with your palm facing your body.","Keep your back straight and your core engaged throughout the exercise.","Raise the dumbbell to the side, keeping your arm straight and your palm facing down.","Continue lifting until your arm is parallel to the ground.","Pause for a moment at the top, then slowly lower the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch to the other arm."],"it":["Stai in piedi con i piedi a larghezza delle spalle, tenendo un manubrio in una mano con il palmo rivolto verso il corpo.","Mantieni la schiena dritta e il core attivo durante tutto l'esercizio.","Alza il manubrio di lato, tenendo il braccio teso e il palmo rivolto verso il basso.","Continua a sollevare il braccio finché il braccio non è parallelo al suolo.","Fermati un attimo in cima, poi abbassa lentamente il manubrio alla posizione di partenza.","Ripeti per il numero desiderato di ripetizioni, poi passa all'altro braccio."]}},{"id":"0356","name":"dumbbell one arm lateral raise with support","category":"shoulders","equipment":"dumbbell","target":"delts","secondary":["trapezius","rotator cuff"],"steps":{"en":["Stand with your feet shoulder-width apart and hold a dumbbell in one hand, with your palm facing your body.","Place your other hand on a stable surface, such as a bench or wall, for support.","Keep your back straight and engage your core.","Raise the dumbbell out to the side, keeping your arm straight and your palm facing down.","Continue lifting until your arm is parallel to the ground.","Pause for a moment at the top, then slowly lower the dumbbell back down to the starting position.","Repeat for the desired number of repetitions, then switch sides."],"it":["Stai con i piedi a larghezza delle spalle e tieni un manubrio in una mano, con il palmo rivolto verso il corpo.","Appoggia l'altra mano su una superficie stabile, come una panca o un muro, per sostenerti.","Tieni la schiena dritta e attiva il core.","Alza il manubrio di lato, tenendo il braccio teso e il palmo rivolto verso il basso.","Continua a sollevare il braccio finché il braccio non è parallelo al suolo.","Fermati un attimo in cima, poi abbassa lentamente il manubrio fino alla posizione di partenza.","Ripeti per il numero desiderato di ripetizioni, poi cambia lato."]}},{"id":"1290","name":"dumbbell one arm press on exercise ball","category":"chest","equipment":"dumbbell","target":"pectorals","secondary":["shoulders","triceps","core"],"steps":{"en":["Sit on an exercise ball with your feet flat on the ground and your knees bent at a 90-degree angle.","Hold a dumbbell in one hand and position it at shoulder height, with your elbow bent and palm facing forward.","Slowly press the dumbbell upward until your arm is fully extended, while keeping your core engaged and maintaining balance on the exercise ball.","Pause for a moment at the top, then slowly lower the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch to the other arm."],"it":["Siediti su una palla da ginnastica con i piedi piatti a terra e le ginocchia piegate a 90 gradi.","Tieni un manubrio in una mano e posizionalo all'altezza delle spalle, con il gomito piegato e il palmo rivolto in avanti.","Premi lentamente il manubrio verso l'alto finché il braccio non è completamente esteso, mantenendo il core attivo e l'equilibrio sulla palla da esercizio.","Fermati un attimo in cima, poi abbassa lentamente il manubrio alla posizione di partenza.","Ripeti per il numero desiderato di ripetizioni, poi passa all'altro braccio."]}},{"id":"1665","name":"dumbbell one arm prone curl","category":"upper arms","equipment":"dumbbell","target":"biceps","secondary":["forearms"],"steps":{"en":["Lie face down on a flat bench with a dumbbell in one hand, palm facing down.","Extend your arm fully, letting it hang straight down towards the floor.","Keeping your upper arm stationary, curl the dumbbell up towards your shoulder by contracting your biceps.","Pause for a moment at the top, then slowly lower the dumbbell back down to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"it":["Sdraiati a faccia in giù su una panca piatta con un manubrio in una mano, il palmo rivolto verso il basso.","Allunga completamente il braccio, lasciandolo pendere dritto verso il pavimento.","Mantenendo fermo la parte superiore del braccio, arrotola il manubrio verso la spalla contraendo i bicipiti.","Fermati un attimo in cima, poi abbassa lentamente il manubrio fino alla posizione di partenza.","Ripeti per il numero desiderato di ripetizioni, poi cambia braccio."]}},{"id":"1666","name":"dumbbell one arm prone hammer curl","category":"upper arms","equipment":"dumbbell","target":"biceps","secondary":["forearms"],"steps":{"en":["Lie face down on a flat bench with a dumbbell in one hand, palm facing your body and arm fully extended.","Keep your upper arm stationary and curl the dumbbell towards your shoulder, contracting your biceps.","Pause for a moment at the top, then slowly lower the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"it":["Sdraiati a faccia in giù su una panca piatta con un manubrio in una mano, il palmo rivolto verso il corpo e il braccio completamente esteso.","Mantieni fermo il braccio superiore e piega il manubrio verso la spalla, contraendo i bicipiti.","Fermati un attimo in cima, poi abbassa lentamente il manubrio alla posizione di partenza.","Ripeti per il numero desiderato di ripetizioni, poi cambia braccio."]}},{"id":"1291","name":"dumbbell one arm pullover on exercise ball","category":"chest","equipment":"dumbbell","target":"pectorals","secondary":["triceps","latissimus dorsi","rhomboids"],"steps":{"en":["Sit on an exercise ball with your feet flat on the ground and your knees bent at a 90-degree angle.","Hold a dumbbell with one hand and extend your arm straight up above your chest.","Slowly lower the dumbbell behind your head while keeping your arm straight.","Pause for a moment, then raise the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"it":["Siediti su una palla da ginnastica con i piedi piatti a terra e le ginocchia piegate a 90 gradi.","Tieni un manubrio con una mano e allunga il braccio dritto sopra il petto.","Abbassa lentamente il manubrio dietro la testa mantenendo il braccio dritto.","Fermati un attimo, poi solleva il manubrio di nuovo alla posizione di partenza.","Ripeti per il numero desiderato di ripetizioni, poi cambia braccio."]}},{"id":"0358","name":"dumbbell one arm reverse wrist curl","category":"lower arms","equipment":"dumbbell","target":"forearms","secondary":["wrist extensors"],"steps":{"en":["Sit on a bench or chair with your feet flat on the ground.","Hold a dumbbell in one hand with an overhand grip, palm facing down.","Rest your forearm on your thigh, with your wrist hanging off the edge.","Slowly lower the dumbbell towards the ground by flexing your wrist.","Pause for a moment at the bottom, then slowly curl your wrist back up towards your body.","Repeat for the desired number of repetitions, then switch to the other arm."],"it":["Siediti su una panca o una sedia con i piedi piatti a terra.","Tieni un manubrio con una mano con una presa sopra la mano, palmo rivolto verso il basso.","Appoggia l'avambraccio sulla coscia, con il polso penzolante dal bordo.","Abbassa lentamente il manubrio verso terra flettendo il polso.","Fermati un attimo in fondo, poi ripiega lentamente il polso verso il corpo.","Ripeti per il numero desiderato di ripetizioni, poi passa all'altro braccio."]}},{"id":"0359","name":"dumbbell one arm reverse fly (with support)","category":"shoulders","equipment":"dumbbell","target":"delts","secondary":["trapezius","rhomboids"],"steps":{"en":["Sit on a bench with your feet flat on the ground and your back straight.","Hold a dumbbell in one hand with your palm facing inwards.","Lean forward and place your free hand on the bench for support.","Keep your arm slightly bent and raise it out to the side until it is parallel to the ground.","Pause for a moment at the top, then slowly lower your arm back down to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"it":["Siediti su una panchina con i piedi piatti a terra e la schiena dritta.","Tieni un manubrio in una mano con il palmo rivolto verso l'interno.","Piegati in avanti e appoggia la mano libera sulla panca per sostenerti.","Tieni il braccio leggermente piegato e sollevalo di lato finché non è parallelo al terreno.","Fermati un attimo in cima, poi abbassa lentamente il braccio fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni, poi cambia braccio."]}},{"id":"1622","name":"dumbbell one arm reverse grip press","category":"chest","equipment":"dumbbell","target":"pectorals","secondary":["triceps","shoulders"],"steps":{"en":["Sit on a flat bench with a dumbbell in one hand, palm facing towards your body.","Place your feet flat on the ground and keep your back straight.","Raise the dumbbell to shoulder height, keeping your elbow close to your body.","Press the dumbbell upwards until your arm is fully extended.","Pause for a moment at the top, then slowly lower the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch to the other arm."],"it":["Siediti su una panca piatta con un manubrio in una mano, il palmo rivolto verso il corpo.","Metti i piedi piatti a terra e tieni la schiena dritta.","Alza il manubrio all'altezza della spalla, tenendo il gomito vicino al corpo.","Premi il manubrio verso l'alto finché il braccio non è completamente esteso.","Fermati un attimo in cima, poi abbassa lentamente il manubrio alla posizione di partenza.","Ripeti per il numero desiderato di ripetizioni, poi passa all'altro braccio."]}},{"id":"1414","name":"dumbbell one arm reverse preacher curl","category":"upper arms","equipment":"dumbbell","target":"biceps","secondary":["forearms"],"steps":{"en":["Sit on a preacher bench with your chest against the pad and your arm extended over the edge of the bench, holding a dumbbell with an underhand grip.","Lower the dumbbell slowly until your arm is fully extended.","Curl the dumbbell back up towards your shoulder, keeping your upper arm stationary.","Squeeze your biceps at the top of the movement, then slowly lower the dumbbell back down to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"it":["Siediti su una panca da predicatore con il petto appoggiato al cuscinetto e il braccio esteso oltre il bordo della panca, tenendo un manubrio con una presa sotto.","Abbassa lentamente il manubrio finché il braccio non è completamente esteso.","Arrotola il manubrio verso la spalla, mantenendo fermo il braccio superiore.","Stringi i bicipiti nella parte alta del movimento, poi abbassa lentamente il manubrio fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni, poi cambia braccio."]}},{"id":"1667","name":"dumbbell one arm reverse spider curl","category":"upper arms","equipment":"dumbbell","target":"biceps","secondary":["forearms"],"steps":{"en":["Stand up straight with a dumbbell in one hand, palm facing down and arm fully extended.","Keeping your upper arm stationary, curl the dumbbell towards your shoulder by flexing your elbow.","Pause for a moment at the top, then slowly lower the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"it":["Alzati dritto con un manubrio in una mano, il palmo rivolto verso il basso e il braccio completamente teso.","Mantenendo fermo il braccio superiore, piega il manubrio verso la spalla flettendo il gomito.","Fermati un attimo in cima, poi abbassa lentamente il manubrio alla posizione di partenza.","Ripeti per il numero desiderato di ripetizioni, poi cambia braccio."]}},{"id":"1668","name":"dumbbell one arm seated bicep curl on exercise ball","category":"upper arms","equipment":"dumbbell","target":"biceps","secondary":["forearms"],"steps":{"en":["Sit on an exercise ball with your feet flat on the ground and your back straight.","Hold a dumbbell in one hand with your palm facing up and your arm fully extended.","Keeping your upper arm stationary, curl the dumbbell towards your shoulder by contracting your biceps.","Pause for a moment at the top, then slowly lower the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"it":["Siediti su una palla da ginnastica con i piedi piatti a terra e la schiena dritta.","Tieni un manubrio in una mano con il palmo rivolto verso l'alto e il braccio completamente esteso.","Mantenendo fermo il braccio superiore, arrotola il manubrio verso la spalla contraendo i bicipiti.","Fermati un attimo in cima, poi abbassa lentamente il manubrio alla posizione di partenza.","Ripeti per il numero desiderato di ripetizioni, poi cambia braccio."]}},{"id":"1669","name":"dumbbell one arm seated hammer curl","category":"upper arms","equipment":"dumbbell","target":"biceps","secondary":["forearms"],"steps":{"en":["Sit on a bench with your back straight and feet flat on the ground.","Hold a dumbbell in one hand with a neutral grip (palms facing each other).","Rest your elbow on the inside of your thigh, just above the knee.","Keeping your upper arm stationary, exhale and curl the dumbbell up towards your shoulder.","Pause for a moment at the top, squeezing your biceps.","Inhale and slowly lower the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"it":["Siediti su una panchina con la schiena dritta e i piedi piatti a terra.","Tieni un manubrio con una mano con una presa neutra (palmi rivolti l'uno verso l'altro).","Appoggia il gomito all'interno della coscia, appena sopra il ginocchio.","Mantenendo fermo il braccio superiore, espira e arrotola il manubrio verso la spalla.","Fermati un attimo in cima, stringendo i bicipiti.","Inspira e abbassa lentamente il manubrio alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni, poi cambia braccio."]}},{"id":"1415","name":"dumbbell one arm seated neutral wrist curl","category":"lower arms","equipment":"dumbbell","target":"forearms","secondary":["biceps","brachialis"],"steps":{"en":["Sit on a bench with your feet flat on the ground and hold a dumbbell in one hand, palm facing up.","Rest your forearm on your thigh, allowing your wrist to hang off the edge.","Keeping your forearm stationary, curl your wrist upward as far as possible.","Pause for a moment at the top, then slowly lower your wrist back down to the starting position.","Repeat for the desired number of repetitions, then switch to the other hand."],"it":["Siediti su una panchina con i piedi piatti a terra e tieni un manubrio in una mano, con il palmo rivolto verso l'alto.","Appoggia l'avambraccio sulla coscia, lasciando che il polso pendi dal bordo.","Mantenendo fermo l'avambraccio, piega il polso verso l'alto il più possibile.","Fermati un attimo in cima, poi abbassa lentamente il polso fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni, poi passa all'altra mano."]}},{"id":"0361","name":"dumbbell one arm shoulder press","category":"shoulders","equipment":"dumbbell","target":"delts","secondary":["triceps","upper back"],"steps":{"en":["Stand with your feet shoulder-width apart and hold a dumbbell in one hand at shoulder level, palm facing forward.","Press the dumbbell upward until your arm is fully extended overhead.","Pause for a moment at the top, then slowly lower the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch to the other arm."],"it":["Stai in piedi con i piedi alla larghezza delle spalle e tieni un manubrio con una mano all'altezza delle spalle, palmo rivolto in avanti.","Premi il manubrio verso l'alto finché il braccio non è completamente esteso sopra la testa.","Fermati un attimo in cima, poi abbassa lentamente il manubrio alla posizione di partenza.","Ripeti per il numero desiderato di ripetizioni, poi passa all'altro braccio."]}},{"id":"0360","name":"dumbbell one arm shoulder press v. 2","category":"shoulders","equipment":"dumbbell","target":"delts","secondary":["triceps","upper back"],"steps":{"en":["Stand with your feet shoulder-width apart and hold a dumbbell in one hand at shoulder level, palm facing forward.","Engage your core and press the dumbbell straight up overhead, fully extending your arm.","Pause for a moment at the top, then slowly lower the dumbbell back to shoulder level.","Repeat for the desired number of repetitions, then switch to the other arm."],"it":["Stai in piedi con i piedi alla larghezza delle spalle e tieni un manubrio con una mano all'altezza delle spalle, palmo rivolto in avanti.","Attiva il core e premi il manubrio dritto sopra la testa, estendendo completamente il braccio.","Fermati un attimo in cima, poi abbassa lentamente il manubrio all'altezza delle spalle.","Ripeti per il numero desiderato di ripetizioni, poi passa all'altro braccio."]}},{"id":"3888","name":"dumbbell one arm snatch","category":"upper legs","equipment":"dumbbell","target":"glutes","secondary":["hamstrings","quadriceps","core"],"steps":{"en":["Stand with your feet shoulder-width apart, holding a dumbbell in one hand with an overhand grip.","Bend your knees slightly and hinge forward at the hips, keeping your back straight and chest up.","Lower the dumbbell towards the ground, keeping it close to your body.","Explosively extend your hips, knees, and ankles, driving the dumbbell upwards in a straight line.","As the dumbbell reaches shoulder height, quickly rotate your hand and punch it overhead, fully extending your arm.","Catch the dumbbell overhead with a slight bend in your knees and hips.","Lower the dumbbell back down to the starting position in a controlled manner.","Repeat for the desired number of repetitions, then switch to the other arm."],"it":["Stai con i piedi a larghezza delle spalle, tenendo un manubrio in una mano con una presa sopra la mano.","Flette leggermente le ginocchia e piega in avanti sui fianchi, mantenendo la schiena dritta e il petto sollevato.","Abbassa il manubrio verso terra, tenendolo vicino al corpo.","Estendi esplosivamente anche fianchi, ginocchia e caviglie, spingendo il manubello verso l'alto in linea retta.","Quando il manubrio raggiunge l'altezza delle spalle, ruota rapidamente la mano e colpiscilo sopra la testa, estendendo completamente il braccio.","Afferra il manubrio sopra la testa con una leggera piega di ginocchia e fianchi.","Abbassa il manubrio di nuovo alla posizione di partenza in modo controllato.","Ripeti per il numero desiderato di ripetizioni, poi passa all'altro braccio."]}},{"id":"1670","name":"dumbbell one arm standing curl","category":"upper arms","equipment":"dumbbell","target":"biceps","secondary":["forearms"],"steps":{"en":["Stand up straight with a dumbbell in one hand, palm facing forward and arm fully extended.","Keeping your upper arm stationary, exhale and curl the weight upward while contracting your biceps.","Continue to raise the dumbbell until your biceps are fully contracted and the dumbbell is at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly lower the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"it":["Alzati dritto con un manubrio in una mano, palmo rivolto in avanti e braccio completamente esteso.","Mantenendo fermo la parte superiore del braccio, espira e arriccia il peso verso l'alto mentre contrai i bicipiti.","Continua ad alzare il manubrio finché i bicipiti non sono completamente contratti e il manubrio non è all'altezza delle spalle.","Mantieni la posizione contratta per una breve pausa mentre stringi i bicipiti.","Inspira e abbassa lentamente il manubrio alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni, poi cambia braccio."]}},{"id":"1671","name":"dumbbell one arm standing hammer curl","category":"upper arms","equipment":"dumbbell","target":"biceps","secondary":["forearms"],"steps":{"en":["Stand up straight with a dumbbell in each hand, palms facing your torso.","Keep your elbows close to your torso and your upper arms stationary.","Exhale and curl the weights while contracting your biceps.","Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai dritto con un manubrio in ogni mano, i palmi rivolti verso il busto.","Tieni i gomiti vicini al busto e le braccia superiori ferme.","Espira e arriccia i pesi mentre contrahi i bicipiti.","Continua ad alzare i pesi finché i bicipiti non sono completamente contratti e i manubri non sono all'altezza delle spalle.","Mantieni la posizione contratta per una breve pausa mentre stringi i bicipiti.","Inspira e inizia lentamente ad abbassare i manubri fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0362","name":"dumbbell one arm triceps extension (on bench)","category":"upper arms","equipment":"dumbbell","target":"triceps","secondary":["shoulders"],"steps":{"en":["Sit on a bench with your back straight and feet flat on the ground.","Hold a dumbbell in one hand and place your other hand on the bench for support.","Raise the dumbbell overhead, keeping your upper arm close to your head and your elbow pointing forward.","Lower the dumbbell behind your head by bending your elbow, keeping your upper arm stationary.","Extend your arm back up to the starting position, fully straightening your elbow.","Repeat for the desired number of repetitions, then switch arms."],"it":["Siediti su una panchina con la schiena dritta e i piedi piatti a terra.","Tieni un manubrio con una mano e appoggia l'altra mano sulla panca per sostenerti.","Alza il manubrio sopra la testa, tenendo il braccio superiore vicino alla testa e il gomito puntato in avanti.","Abbassa il manubrio dietro la testa piegando il gomito, mantenendo fermo il braccio superiore.","Allunga il braccio fino alla posizione iniziale, raddrizzando completamente il gomito.","Ripeti per il numero desiderato di ripetizioni, poi cambia braccio."]}},{"id":"0363","name":"dumbbell one arm upright row","category":"shoulders","equipment":"dumbbell","target":"delts","secondary":["traps","biceps"],"steps":{"en":["Stand with your feet shoulder-width apart, holding a dumbbell in one hand with an overhand grip.","Let the dumbbell hang at arm's length in front of your thighs, with your palm facing your body.","Keeping your back straight and your core engaged, exhale and lift the dumbbell straight up towards your chin, leading with your elbow.","Pause for a moment at the top, then inhale and slowly lower the dumbbell back down to the starting position.","Repeat for the desired number of repetitions, then switch to the other arm."],"it":["Stai con i piedi a larghezza delle spalle, tenendo un manubrio in una mano con una presa sopra la mano.","Lascia che il manubrio penda a distanza di braccio davanti alle cosce, con il palmo rivolto verso il corpo.","Tenendo la schiena dritta e il core attivo, espira e solleva il manubrio verso il mento, iniziando con il gomito.","Fermati un attimo in cima, poi inspira e abbassa lentamente il manubrio fino alla posizione di partenza.","Ripeti per il numero desiderato di ripetizioni, poi passa all'altro braccio."]}},{"id":"0364","name":"dumbbell one arm wrist curl","category":"lower arms","equipment":"dumbbell","target":"forearms","secondary":["biceps","brachialis"],"steps":{"en":["Sit on a bench or chair with your feet flat on the ground.","Hold a dumbbell in one hand with an underhand grip, resting your forearm on your thigh.","Allow your wrist to extend, letting the dumbbell roll down towards your fingers.","Slowly curl your wrist back up, bringing the dumbbell towards your forearm.","Repeat for the desired number of repetitions, then switch to the other hand."],"it":["Siediti su una panca o una sedia con i piedi piatti a terra.","Tieni un manubrio in una mano con una presa sotto, appoggiando l'avambraccio sulla coscia.","Lascia che il polso si estenda, lasciando che il manubrio rotoli verso le dita.","Ripiega lentamente il polso verso l'alto, portando il manubrio verso l'avambraccio.","Ripeti per il numero desiderato di ripetizioni, poi passa all'altra mano."]}},{"id":"1672","name":"dumbbell one arm zottman preacher curl","category":"upper arms","equipment":"dumbbell","target":"biceps","secondary":["forearms"],"steps":{"en":["Sit on a preacher curl bench and hold a dumbbell in one hand with an underhand grip.","Rest your upper arm on the preacher bench pad, allowing your arm to fully extend.","Curl the dumbbell up towards your shoulder, keeping your upper arm stationary.","At the top of the curl, rotate your wrist so that your palm faces up.","Slowly lower the dumbbell back down to the starting position, rotating your wrist back to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"it":["Siediti su una panca da curl preacher e tieni un manubrio in una mano con una presa sotto.","Appoggia il braccio superiore sul cuscinetto da panca predicatorio, permettendo al braccio di estendersi completamente.","Arrotola il manubrio verso la spalla, tenendo fermo il braccio superiore.","In cima al curl, ruota il polso in modo che il palmo sia rivolto verso l'alto.","Abbassa lentamente il manubrio fino alla posizione di partenza, ruotando il polso di nuovo alla posizione di partenza.","Ripeti per il numero desiderato di ripetizioni, poi cambia braccio."]}},{"id":"1292","name":"dumbbell one leg fly on exercise ball","category":"chest","equipment":"dumbbell","target":"pectorals","secondary":["shoulders","triceps"],"steps":{"en":["Sit on an exercise ball with a dumbbell in each hand, palms facing each other.","Place one foot on the ground and extend the other leg straight out in front of you.","Lean forward slightly and bring your arms out to the sides, keeping a slight bend in your elbows.","Slowly lower the dumbbells down and out to the sides, feeling a stretch in your chest.","Pause for a moment at the bottom, then squeeze your chest muscles to bring the dumbbells back up to the starting position.","Repeat for the desired number of repetitions, then switch legs and repeat."],"it":["Siediti su una palla da ginnastica con un manubrio in ogni mano, i palmi rivolti uno verso l'altro.","Metti un piede a terra e estendi l'altra gamba dritta davanti a te.","Inclinati leggermente in avanti e porta le braccia ai lati, mantenendo una leggera piega dei gomiti.","Abbassa lentamente i manubri e i tiri ai lati, sentendo uno stiramento al petto.","Fermati un attimo in basso, poi stringi i muscoli del petto per riportare i manubri alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni, poi cambia gamba e ripeti."]}},{"id":"0365","name":"dumbbell over bench neutral wrist curl","category":"upper arms","equipment":"dumbbell","target":"biceps","secondary":["forearms"],"steps":{"en":["Sit on a bench with your feet flat on the ground and hold a dumbbell in each hand, palms facing up.","Rest your forearms on the bench, allowing your wrists to hang off the edge.","Keeping your upper arms stationary, exhale and curl the dumbbells up towards your shoulders.","Pause for a moment at the top, then inhale and slowly lower the dumbbells back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Siediti su una panchina con i piedi piatti a terra e tieni un manubrio in ciascuna mano, palmi rivolti verso l'alto.","Appoggia gli avambracci sulla panca, lasciando che i polsi penzolano dal bordo.","Tieni ferme le braccia superiori, espira e arriccia i manubri verso le spalle.","Fermati un attimo in cima, poi inspira e abbassa lentamente i manubri fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0366","name":"dumbbell over bench one arm neutral wrist curl","category":"upper arms","equipment":"dumbbell","target":"biceps","secondary":["forearms"],"steps":{"en":["Sit on a bench with a dumbbell in one hand and your arm extended over the bench, palm facing up.","Keep your upper arm stationary and curl the dumbbell towards your shoulder, keeping your wrist in a neutral position.","Pause for a moment at the top, then slowly lower the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"it":["Seduta su una panchina con un manubrio in una mano e il braccio esteso sopra la panca, il palmo rivolto verso l'alto.","Mantieni fermo il braccio superiore e piega il manubrio verso la spalla, mantenendo il polso in posizione neutra.","Fermati un attimo in cima, poi abbassa lentamente il manubrio alla posizione di partenza.","Ripeti per il numero desiderato di ripetizioni, poi cambia braccio."]}},{"id":"1441","name":"dumbbell over bench one arm reverse wrist curl","category":"lower arms","equipment":"dumbbell","target":"forearms","secondary":["biceps","brachialis"],"steps":{"en":["Sit on a bench with your feet flat on the ground and hold a dumbbell in one hand, palm facing down.","Rest your forearm on the bench with your wrist hanging off the edge.","Slowly curl your wrist upwards, bringing the dumbbell towards your forearm.","Pause for a moment at the top, then slowly lower the dumbbell back down to the starting position.","Repeat for the desired number of repetitions, then switch to the other arm."],"it":["Siediti su una panchina con i piedi piatti a terra e tieni un manubrio in una mano, con il palmo rivolto verso il basso.","Appoggia l'avambraccio sulla panca con il polso che penzola dal bordo.","Curva lentamente il polso verso l'alto, portando il manubrio verso l'avambraccio.","Fermati un attimo in cima, poi abbassa lentamente il manubrio fino alla posizione di partenza.","Ripeti per il numero desiderato di ripetizioni, poi passa all'altro braccio."]}},{"id":"0367","name":"dumbbell over bench one arm wrist curl","category":"lower arms","equipment":"dumbbell","target":"forearms","secondary":["biceps","shoulders"],"steps":{"en":["Sit on a bench with your feet flat on the ground and hold a dumbbell in one hand, palm facing down.","Rest your forearm on the bench with your wrist hanging off the edge.","Slowly curl your wrist upwards, bringing the dumbbell towards your forearm.","Pause for a moment at the top, then slowly lower the dumbbell back down to the starting position.","Repeat for the desired number of repetitions, then switch to the other arm."],"it":["Siediti su una panchina con i piedi piatti a terra e tieni un manubrio in una mano, con il palmo rivolto verso il basso.","Appoggia l'avambraccio sulla panca con il polso che penzola dal bordo.","Curva lentamente il polso verso l'alto, portando il manubrio verso l'avambraccio.","Fermati un attimo in cima, poi abbassa lentamente il manubrio fino alla posizione di partenza.","Ripeti per il numero desiderato di ripetizioni, poi passa all'altro braccio."]}},{"id":"0368","name":"dumbbell over bench revers wrist curl","category":"lower arms","equipment":"dumbbell","target":"forearms","secondary":["biceps","brachialis"],"steps":{"en":["Sit on a bench with your feet flat on the ground and hold a dumbbell in each hand, palms facing down.","Rest your forearms on the bench, allowing your wrists to hang off the edge.","Slowly curl your wrists upward, bringing the dumbbells towards your body.","Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Siediti su una panchina con i piedi piatti a terra e tieni un manubrio in ciascuna mano, con i palmi rivolti verso il basso.","Appoggia gli avambracci sulla panca, lasciando che i polsi penzolano dal bordo.","Piega lentamente i polsi verso l'alto, portando i manubri verso il corpo.","Fermati un attimo in cima, poi abbassa lentamente i manubri fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0369","name":"dumbbell over bench wrist curl","category":"lower arms","equipment":"dumbbell","target":"forearms","secondary":["biceps","brachialis"],"steps":{"en":["Sit on a bench with your forearms resting on the bench and your palms facing up, holding a dumbbell in each hand.","Allow your wrists to hang over the edge of the bench.","Slowly curl your wrists upward, squeezing your forearms at the top of the movement.","Pause for a moment, then slowly lower your wrists back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Siediti su una panchina con gli avambracci appoggiati sulla panca e i palmi rivolti verso l'alto, tenendo un manubrio in ogni mano.","Lascia che i polsi sporgano dal bordo della panca.","Ripiega lentamente i polsi verso l'alto, stringendo gli avambracci nella parte alta del movimento.","Fermati un attimo, poi abbassa lentamente i polsi fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"1329","name":"dumbbell palm rotational bent over row","category":"back","equipment":"dumbbell","target":"upper back","secondary":["biceps","forearms"],"steps":{"en":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand with an overhand grip.","Bend forward at the hips, keeping your back straight and your knees slightly bent.","Let your arms hang straight down, palms facing your body.","Engage your core and pull the dumbbells up towards your chest, keeping your elbows close to your body.","As you pull the dumbbells up, rotate your palms so they face away from your body.","Squeeze your shoulder blades together at the top of the movement.","Slowly lower the dumbbells back down to the starting position, rotating your palms back to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai con i piedi a larghezza delle spalle, tenendo un manubrio in ogni mano con una presa sopra la testa.","Piegati in avanti ai fianchi, tenendo la schiena dritta e le ginocchia leggermente piegate.","Lascia che le braccia pendano dritte verso il basso, i palmi rivolti verso il corpo.","Attiva il core e tira i manubri verso il petto, tenendo i gomiti vicini al corpo.","Mentre tiri verso l'alto i manubri, ruota i palmi in modo che siano rivolti lontano dal corpo.","Stringi le scapole insieme nella parte alta del movimento.","Abbassa lentamente i manubri fino alla posizione iniziale, ruotando i palmi di nuovo alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"1623","name":"dumbbell palms in incline bench press","category":"upper arms","equipment":"dumbbell","target":"triceps","secondary":["chest","shoulders"],"steps":{"en":["Set up an incline bench at a 45-degree angle.","Sit on the bench with your back against the backrest and feet flat on the ground.","Hold a dumbbell in each hand with an overhand grip, palms facing inwards.","Extend your arms straight up above your chest, keeping a slight bend in your elbows.","Lower the dumbbells slowly towards your shoulders, keeping your elbows close to your body.","Pause for a moment at the bottom, then press the dumbbells back up to the starting position.","Repeat for the desired number of repetitions."],"it":["Installa una panca inclinata con un angolo di 45 gradi.","Siediti sulla panca con la schiena appoggiata allo schienale e i piedi appoggiati a terra.","Tieni un manubrio in ogni mano con una presa sopra la mano, palmi rivolti verso l'interno.","Allunga le braccia dritte sopra il petto, mantenendo una leggera piega dei gomiti.","Abbassa lentamente i manubri verso le spalle, tenendo i gomiti vicini al corpo.","Fermati un attimo in fondo, poi riporta i manubri alla posizione di partenza.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0370","name":"dumbbell peacher hammer curl","category":"upper arms","equipment":"dumbbell","target":"biceps","secondary":["forearms"],"steps":{"en":["Stand up straight with a dumbbell in each hand, palms facing your torso.","Keep your elbows close to your torso and rotate the palms of your hands until they are facing forward.","This will be your starting position.","Now, keeping the upper arms stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Then, inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the recommended amount of repetitions."],"it":["Stai dritto con un manubrio in ogni mano, i palmi rivolti verso il busto.","Tieni i gomiti vicini al busto e ruota i palmi delle mani finché non sono rivolti in avanti.","Questa sarà la tua posizione di partenza.","Ora, mantenendo ferme le braccia superiori, espira e arriccia i pesi mentre contrahi i bicipiti.","Continua ad alzare i pesi finché i bicipiti non sono completamente contratti e i manubri non sono all'altezza delle spalle.","Mantieni la posizione contratta per una breve pausa mentre stringi i bicipiti.","Poi, inspira e inizia lentamente ad abbassare i manubri fino alla posizione iniziale.","Ripeti per il numero consigliato di ripetizioni."]}},{"id":"0371","name":"dumbbell plyo squat","category":"upper legs","equipment":"dumbbell","target":"glutes","secondary":["quadriceps","hamstrings","calves"],"steps":{"en":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand at your sides.","Lower your body into a squat position by bending your knees and pushing your hips back.","As you reach the bottom of the squat, explode upward, jumping off the ground.","While in the air, quickly switch the position of your feet, landing with your opposite foot forward.","Immediately lower your body back into a squat position and repeat the jump, switching your feet again.","Continue alternating the position of your feet with each jump for the desired number of repetitions."],"it":["Stai con i piedi a larghezza delle spalle, tenendo un manubrio in ogni mano ai lati.","Abbassa il corpo in posizione accovacciata piegando le ginocchia e spingendo i fianchi all'indietro.","Quando arrivi in fondo allo squat, esplodi verso l'alto, saltando da terra.","Mentre sei in aria, cambia rapidamente la posizione dei piedi, atterrando con il piede opposto in avanti.","Abbassa subito il corpo in posizione accovacciata e ripeti il salto, cambiando di nuovo i piedi.","Continua ad alternare la posizione dei piedi ad ogni salto per il numero desiderato di ripetizioni."]}},{"id":"0372","name":"dumbbell preacher curl","category":"upper arms","equipment":"dumbbell","target":"biceps","secondary":["forearms"],"steps":{"en":["Sit on a preacher curl bench with your upper arms resting on the pad and your chest against it.","Hold a dumbbell in each hand with your palms facing up and your arms fully extended.","Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"it":["Siediti su una panca da curl preacher con le braccia superiori appoggiate sul cuscinetto e il petto contro di esso.","Tieni un manubrio in ogni mano con i palmi rivolti verso l'alto e le braccia completamente distese.","Mantenendo ferme le braccia superiori, espira e arriccia i pesi mentre contrahi i bicipiti.","Continua ad alzare i manubri finché i bicipiti non sono completamente contratti e i manubri non sono all'altezza delle spalle.","Mantieni la posizione contratta per una breve pausa mentre stringi i bicipiti.","Inspira e inizia lentamente ad abbassare i manubri fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"1673","name":"dumbbell preacher curl over exercise ball","category":"upper arms","equipment":"dumbbell","target":"biceps","secondary":["forearms"],"steps":{"en":["Sit on an exercise ball with your feet flat on the ground and your back straight.","Hold a dumbbell in one hand with an underhand grip, resting your elbow on the exercise ball.","Keeping your upper arm stationary, exhale and curl the dumbbell up towards your shoulder.","Pause for a moment at the top, then inhale and slowly lower the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"it":["Siediti su una palla da ginnastica con i piedi piatti a terra e la schiena dritta.","Tieni un manubrio in una mano con una presa sottomano, appoggiando il gomito sulla palla da esercizio.","Mantenendo fermo il braccio superiore, espira e arrotola il manubrio verso la spalla.","Fermati un attimo in cima, poi inspira e abbassa lentamente il manubrio alla posizione di partenza.","Ripeti per il numero desiderato di ripetizioni, poi cambia braccio."]}},{"id":"1293","name":"dumbbell press on exercise ball","category":"chest","equipment":"dumbbell","target":"pectorals","secondary":["shoulders","triceps"],"steps":{"en":["Sit on an exercise ball with your feet flat on the ground and dumbbells in each hand, resting on your thighs.","Slowly walk your feet forward, rolling the exercise ball until your lower back is supported on the ball and your knees are at a 90-degree angle.","Raise the dumbbells to shoulder height, palms facing forward.","Press the dumbbells upward until your arms are fully extended.","Pause for a moment at the top, then slowly lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"it":["Siediti su una palla da ginnastica con i piedi piatti a terra e manubri in ciascuna mano, appoggiati sulle cosce.","Muovi lentamente i piedi in avanti, facendo rotolare la palla da esercizio finché la parte bassa della schiena non è sostenuta e le ginocchia sono a un angolo di 90 gradi.","Alza i manubri all'altezza delle spalle, palmi rivolti in avanti.","Premi i manubri verso l'alto finché le braccia non sono completamente estese.","Fermati un attimo in cima, poi abbassa lentamente i manubri alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0373","name":"dumbbell pronate-grip triceps extension","category":"upper arms","equipment":"dumbbell","target":"triceps","secondary":["forearms"],"steps":{"en":["Sit on a bench or chair with your back straight and feet flat on the ground.","Hold a dumbbell with both hands, palms facing down, and extend your arms straight up overhead.","Keeping your upper arms close to your head and elbows pointing forward, slowly lower the dumbbell behind your head by bending your elbows.","Pause for a moment, then extend your arms back up to the starting position.","Repeat for the desired number of repetitions."],"it":["Siediti su una panca o una sedia con la schiena dritta e i piedi piatti a terra.","Tieni un manubrio con entrambe le mani, palmi rivolti verso il basso, e allunga le braccia dritte sopra la testa.","Tenendo le braccia superiori vicine alla testa e i gomiti rivolti in avanti, abbassa lentamente il manubrio dietro la testa piegando i gomiti.","Fermati un attimo, poi rialza le braccia fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0374","name":"dumbbell prone incline curl","category":"upper arms","equipment":"dumbbell","target":"biceps","secondary":["forearms"],"steps":{"en":["Adjust the bench to a 45-degree incline.","Lie face down on the bench with your chest and stomach resting against it.","Hold a dumbbell in each hand with your palms facing down and your arms fully extended.","Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"it":["Regola la panca con un'inclinazione di 45 gradi.","Sdraiati a faccia in giù sulla panchina con petto e pancia appoggiati contro di essa.","Tieni un manubrio in ogni mano con i palmi rivolti verso il basso e le braccia completamente distese.","Mantenendo ferme le braccia superiori, espira e arriccia i pesi mentre contrahi i bicipiti.","Continua ad alzare i pesi finché i bicipiti non sono completamente contratti e i manubri non sono all'altezza delle spalle.","Mantieni la posizione contratta per una breve pausa mentre stringi i bicipiti.","Inspira e inizia lentamente ad abbassare i manubri fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"1674","name":"dumbbell prone incline hammer curl","category":"upper arms","equipment":"dumbbell","target":"biceps","secondary":["forearms"],"steps":{"en":["Adjust the bench to a 45-degree incline.","Lie face down on the bench with a dumbbell in each hand, palms facing each other.","Allow your arms to hang straight down towards the floor, keeping your elbows slightly bent.","Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"it":["Regola la panca con un'inclinazione di 45 gradi.","Sdraiati a faccia in giù sulla panchina con un manubrio in ciascuna mano, i palmi rivolti uno verso l'altro.","Lascia che le braccia pendano dritte verso il pavimento, tenendo i gomiti leggermente piegati.","Mantenendo ferme le braccia superiori, espira e arriccia i pesi mentre contrahi i bicipiti.","Continua ad alzare i manubri finché i bicipiti non sono completamente contratti e i manubri non sono all'altezza delle spalle.","Mantieni la posizione contratta per una breve pausa mentre stringi i bicipiti.","Inspira e inizia lentamente ad abbassare i manubri fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0375","name":"dumbbell pullover","category":"chest","equipment":"dumbbell","target":"pectorals","secondary":["latissimus dorsi","triceps"],"steps":{"en":["Lie flat on a bench with your head at one end and your feet on the floor.","Hold a dumbbell with both hands and extend your arms straight above your chest.","Keeping a slight bend in your elbows, slowly lower the dumbbell behind your head until you feel a stretch in your chest and shoulders.","Pause for a moment, then raise the dumbbell back to the starting position.","Repeat for the desired number of repetitions."],"it":["Sdraiati su una panchina con la testa a un'estremità e i piedi a terra.","Tieni un manubrio con entrambe le mani e estendi le braccia dritte sopra il petto.","Mantenendo una leggera piega dei gomiti, abbassa lentamente il manubrio dietro la testa finché non senti uno stiramento al petto e alle spalle.","Fermati un attimo, poi solleva il manubrio di nuovo alla posizione di partenza.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"1294","name":"dumbbell pullover hip extension on exercise ball","category":"chest","equipment":"dumbbell","target":"pectorals","secondary":["triceps","shoulders","core"],"steps":{"en":["Sit on an exercise ball with your feet flat on the ground and the dumbbell resting on your thighs.","Slowly walk your feet forward, rolling the exercise ball down your back until your head, neck, and upper back are supported on the ball.","Hold the dumbbell with both hands and extend your arms straight up over your chest, keeping a slight bend in your elbows.","Lower the dumbbell behind your head, keeping your arms straight and maintaining control.","Pause for a moment, then raise the dumbbell back to the starting position.","While keeping your arms extended, lift your hips off the ground, squeezing your glutes and engaging your core.","Lower your hips back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Siediti su una palla da ginnastica con i piedi piatti a terra e il manubrio appoggiato sulle cosce.","Muovi lentamente i piedi in avanti, facendo rotolare la palla da esercizio lungo la schiena finché testa, collo e parte superiore della schiena non sono sostenuti sulla palla.","Tieni il manubrio con entrambe le mani e allunga le braccia dritte sopra il petto, mantenendo una leggera piega dei gomiti.","Abbassa il manubrio dietro la testa, mantenendo le braccia dritte e mantenendo il controllo.","Fermati un attimo, poi solleva il manubrio di nuovo alla posizione di partenza.","Mantenendo le braccia distese, solleva i fianchi da terra, stringendo i glutei e attivando il core.","Abbassa i fianchi fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"1295","name":"dumbbell pullover on exercise ball","category":"chest","equipment":"dumbbell","target":"pectorals","secondary":["triceps","latissimus dorsi"],"steps":{"en":["Sit on an exercise ball and hold a dumbbell with both hands above your chest, arms extended.","Slowly lower the dumbbell behind your head while keeping your arms straight.","Pause for a moment, then raise the dumbbell back to the starting position.","Repeat for the desired number of repetitions."],"it":["Siediti su una palla da ginnastica e tieni un manubrio con entrambe le mani sopra il petto, le braccia distese.","Abbassa lentamente il manubrio dietro la testa mantenendo le braccia dritte.","Fermati un attimo, poi solleva il manubrio di nuovo alla posizione di partenza.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"1700","name":"dumbbell push press","category":"shoulders","equipment":"dumbbell","target":"delts","secondary":["triceps","core"],"steps":{"en":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand at shoulder level.","Bend your knees slightly and dip your body down, then explosively extend your legs and press the dumbbells overhead.","Lock out your arms at the top of the movement, then lower the dumbbells back to shoulder level.","Repeat for the desired number of repetitions."],"it":["Stai con i piedi a larghezza delle spalle, tenendo un manubrio in ogni mano all'altezza delle spalle.","Flette leggermente le ginocchia e abbassa il corpo, poi allunga esplosivamente le gambe e spingi i manubri sopra la testa.","Blocca le braccia all'inizio del movimento, poi abbassa i manubri all'altezza delle spalle.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0376","name":"dumbbell raise","category":"shoulders","equipment":"dumbbell","target":"delts","secondary":["traps","rhomboids"],"steps":{"en":["Stand with your feet shoulder-width apart and hold a dumbbell in each hand, palms facing your body.","Keep your back straight and engage your core.","Raise your arms out to the sides until they are parallel to the floor, keeping a slight bend in your elbows.","Pause for a moment at the top, then slowly lower your arms back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai in piedi con i piedi alla larghezza delle spalle e tieni un manubrio in ogni mano, palmi rivolti verso il corpo.","Tieni la schiena dritta e attiva il core.","Alza le braccia ai lati finché non sono parallele al pavimento, mantenendo una leggera piega dei gomiti.","Fermati un attimo in cima, poi abbassa lentamente le braccia fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"2292","name":"dumbbell rear delt raise","category":"shoulders","equipment":"dumbbell","target":"delts","secondary":["trapezius","rhomboids"],"steps":{"en":["Stand with your feet shoulder-width apart and hold a dumbbell in each hand, palms facing your body.","Bend your knees slightly and hinge forward at the hips, keeping your back straight.","Raise your arms out to the sides, keeping a slight bend in your elbows, until they are parallel to the floor.","Pause for a moment at the top, then slowly lower your arms back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai in piedi con i piedi alla larghezza delle spalle e tieni un manubrio in ogni mano, palmi rivolti verso il corpo.","Piega leggermente le ginocchia e piega in avanti ai fianchi, mantenendo la schiena dritta.","Alza le braccia ai lati, mantenendo una leggera piega dei gomiti, finché non sono paralleli al pavimento.","Fermati un attimo in cima, poi abbassa lentamente le braccia fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0377","name":"dumbbell rear delt row_shoulder","category":"shoulders","equipment":"dumbbell","target":"delts","secondary":["trapezius","rhomboids"],"steps":{"en":["Stand with your feet shoulder-width apart and knees slightly bent.","Hold a dumbbell in each hand with your palms facing your body.","Bend forward at the waist, keeping your back straight and your core engaged.","Extend your arms straight down towards the floor, with a slight bend in your elbows.","Raise the dumbbells out to the sides, squeezing your shoulder blades together.","Pause for a moment at the top, then slowly lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai in piedi con i piedi alla larghezza delle spalle e le ginocchia leggermente piegate.","Tieni un manubrio in ciascuna mano con i palmi rivolti verso il corpo.","Piegati in avanti in vita, mantenendo la schiena dritta e il core attivo.","Allunga le braccia dritte verso il pavimento, con una leggera piega dei gomiti.","Alza i manubri ai lati, stringendo le scapole insieme.","Fermati un attimo in cima, poi abbassa lentamente i manubri alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0378","name":"dumbbell rear fly","category":"shoulders","equipment":"dumbbell","target":"delts","secondary":["trapezius","rhomboids"],"steps":{"en":["Stand with your feet shoulder-width apart and hold a dumbbell in each hand.","Bend your knees slightly and hinge forward at the hips, keeping your back straight.","Extend your arms straight down towards the ground, palms facing each other.","Keeping a slight bend in your elbows, lift your arms out to the sides and squeeze your shoulder blades together.","Pause for a moment at the top, then slowly lower your arms back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai con i piedi distanti alla larghezza delle spalle e tieni un manubrio in ciascuna mano.","Piega leggermente le ginocchia e piega in avanti ai fianchi, mantenendo la schiena dritta.","Allunga le braccia dritte verso terra, palmi rivolti l'uno verso l'altro.","Mantenendo una leggera piega dei gomiti, alza le braccia ai lati e stringi le scapole insieme.","Fermati un attimo in cima, poi abbassa lentamente le braccia fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0380","name":"dumbbell rear lateral raise","category":"shoulders","equipment":"dumbbell","target":"delts","secondary":["traps","rhomboids"],"steps":{"en":["Stand with your feet shoulder-width apart and hold a dumbbell in each hand, palms facing your body.","Bend your knees slightly and hinge forward at the hips, keeping your back straight and core engaged.","Raise your arms out to the sides, keeping a slight bend in your elbows, until they are parallel to the floor.","Pause for a moment at the top, then slowly lower your arms back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai in piedi con i piedi alla larghezza delle spalle e tieni un manubrio in ogni mano, palmi rivolti verso il corpo.","Flette leggermente le ginocchia e piega in avanti i fianchi, mantenendo la schiena dritta e il core impegnato.","Alza le braccia ai lati, mantenendo una leggera piega dei gomiti, finché non sono paralleli al pavimento.","Fermati un attimo in cima, poi abbassa lentamente le braccia fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0379","name":"dumbbell rear lateral raise (support head)","category":"shoulders","equipment":"dumbbell","target":"delts","secondary":["traps","rhomboids"],"steps":{"en":["Stand with your feet shoulder-width apart and hold a dumbbell in each hand.","Bend your knees slightly and hinge forward at the hips, keeping your back straight.","Raise your arms out to the sides, keeping a slight bend in your elbows, until they are parallel to the ground.","Pause for a moment at the top, then slowly lower your arms back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai con i piedi distanti alla larghezza delle spalle e tieni un manubrio in ciascuna mano.","Piega leggermente le ginocchia e piega in avanti ai fianchi, mantenendo la schiena dritta.","Alza le braccia ai lati, mantenendo una leggera piega dei gomiti, finché non sono paralleli al suolo.","Fermati un attimo in cima, poi abbassa lentamente le braccia fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0381","name":"dumbbell rear lunge","category":"upper legs","equipment":"dumbbell","target":"glutes","secondary":["quadriceps","hamstrings","calves"],"steps":{"en":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand.","Take a step backward with your right foot, lowering your body into a lunge position.","Bend your left knee and lower your body until your left thigh is parallel to the ground.","Pause for a moment, then push through your left heel to return to the starting position.","Repeat on the other side, stepping back with your left foot."],"it":["Stai con i piedi a larghezza delle spalle, tenendo un manubrio in ciascuna mano.","Fai un passo indietro con il piede destro, abbassando il corpo in posizione di affondamento.","Piega il ginocchio sinistro e abbassa il corpo finché la coscia sinistra non è parallela al suolo.","Fermati un attimo, poi spingi attraverso il tallone sinistro per tornare alla posizione di partenza.","Ripeti dall'altro lato, facendo un passo indietro con il piede sinistro."]}},{"id":"0382","name":"dumbbell revers grip biceps curl","category":"upper arms","equipment":"dumbbell","target":"biceps","secondary":["forearms"],"steps":{"en":["Stand up straight with a dumbbell in each hand, palms facing down and arms fully extended.","Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai dritto con un manubrio in ogni mano, palmi rivolti verso il basso e braccia completamente distese.","Mantenendo ferme le braccia superiori, espira e arriccia i pesi mentre contrahi i bicipiti.","Continua ad alzare i pesi finché i bicipiti non sono completamente contratti e i manubri non sono all'altezza delle spalle.","Mantieni la posizione contratta per una breve pausa mentre stringi i bicipiti.","Inspira e inizia lentamente ad abbassare i manubri fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"1624","name":"dumbbell reverse bench press","category":"chest","equipment":"dumbbell","target":"pectorals","secondary":["triceps","shoulders"],"steps":{"en":["Lie flat on a bench with your feet flat on the ground and your knees bent.","Hold a dumbbell in each hand with an overhand grip, palms facing towards your feet.","Extend your arms straight up towards the ceiling, keeping a slight bend in your elbows.","Slowly lower the dumbbells towards your chest, allowing your elbows to flare out to the sides.","Pause for a moment at the bottom, then push the dumbbells back up to the starting position.","Repeat for the desired number of repetitions."],"it":["Sdraiati disteso su una panchina con i piedi appoggiati a terra e le ginocchia piegate.","Tieni un manubrio in ogni mano con una presa sopra la mano, i palmi rivolti verso i piedi.","Allunga le braccia dritte verso il soffitto, mantenendo una leggera piega dei gomiti.","Abbassa lentamente i manubri verso il petto, permettendo ai gomiti di allargarsi ai lati.","Fermati un attimo in fondo, poi spingi di nuovo i manubri fino alla posizione di partenza.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0383","name":"dumbbell reverse fly","category":"shoulders","equipment":"dumbbell","target":"delts","secondary":["trapezius","rhomboids"],"steps":{"en":["Stand with your feet shoulder-width apart and hold a dumbbell in each hand.","Bend your knees slightly and hinge forward at the hips, keeping your back straight.","Extend your arms straight down in front of you, palms facing each other.","Keeping a slight bend in your elbows, raise your arms out to the sides until they are parallel to the ground.","Pause for a moment at the top, then slowly lower your arms back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai con i piedi distanti alla larghezza delle spalle e tieni un manubrio in ciascuna mano.","Piega leggermente le ginocchia e piega in avanti ai fianchi, mantenendo la schiena dritta.","Allunga le braccia dritte davanti a te, palmi rivolti l'uno verso l'altro.","Mantenendo una leggera piega dei gomiti, alza le braccia ai lati finché non sono parallele al suolo.","Fermati un attimo in cima, poi abbassa lentamente le braccia fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"1330","name":"dumbbell reverse grip incline bench one arm row","category":"back","equipment":"dumbbell","target":"upper back","secondary":["biceps","shoulders"],"steps":{"en":["Set up an incline bench at a 45-degree angle.","Place a dumbbell on the floor next to the bench.","Stand facing the bench with your feet shoulder-width apart.","Bend at the waist and place your left knee and left hand on the bench for support.","Pick up the dumbbell with your right hand using a reverse grip (palm facing down).","Keep your back straight and your core engaged.","Pull the dumbbell up towards your chest, keeping your elbow close to your body.","Squeeze your back muscles at the top of the movement.","Lower the dumbbell back down to the starting position in a controlled manner.","Repeat for the desired number of repetitions.","Switch sides and repeat the exercise with your left arm."],"it":["Installa una panca inclinata con un angolo di 45 gradi.","Metti un manubrio sul pavimento accanto alla panca.","Stai rivolto verso la panchina con i piedi alla larghezza delle spalle.","Piegati in vita e appoggia il ginocchio sinistro e la mano sinistra sulla panca per sostenerti.","Prendi il manubrio con la mano destra usando una presa invertita (palmo rivolto verso il basso).","Tieni la schiena dritta e il core attivo.","Tira il manubrio verso il petto, tenendo il gomito vicino al corpo.","Stringi i muscoli della schiena nella parte alta del movimento.","Abbassa il manubrio di nuovo alla posizione di partenza in modo controllato.","Ripeti per il numero desiderato di ripetizioni.","Cambia lato e ripeti l'esercizio con il braccio sinistro."]}},{"id":"1331","name":"dumbbell reverse grip incline bench two arm row","category":"back","equipment":"dumbbell","target":"upper back","secondary":["biceps","forearms"],"steps":{"en":["Set up an incline bench at a 45-degree angle.","Sit on the bench with your chest against the backrest and your feet flat on the ground.","Hold a dumbbell in each hand with an underhand grip.","Lean forward and let your arms hang straight down, fully extended.","Pull the dumbbells up towards your chest, squeezing your shoulder blades together.","Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Installa una panca inclinata con un angolo di 45 gradi.","Siediti sulla panchina con il petto appoggiato allo schienale e i piedi piatti a terra.","Tieni un manubrio in ogni mano con una presa sottomano.","Piegati in avanti e lascia che le braccia pendano dritte verso il basso, completamente estese.","Tira i manubri verso il petto, stringendo le scapole insieme.","Fermati un attimo in cima, poi abbassa lentamente i manubri fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"2327","name":"dumbbell reverse grip row (female)","category":"back","equipment":"dumbbell","target":"upper back","secondary":["biceps","forearms"],"steps":{"en":["Stand with your feet shoulder-width apart and knees slightly bent.","Hold a dumbbell in each hand with an overhand grip, palms facing your body.","Bend forward at the waist, keeping your back straight and your core engaged.","Let your arms hang straight down, fully extended, with a slight bend in your elbows.","Pull the dumbbells up towards your chest, squeezing your shoulder blades together.","Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai in piedi con i piedi alla larghezza delle spalle e le ginocchia leggermente piegate.","Tieni un manubrio in ciascuna mano con una presa sopra la mano, palmi rivolti verso il corpo.","Piegati in avanti in vita, mantenendo la schiena dritta e il core attivo.","Lascia che le braccia pendano dritte verso il basso, completamente estese, con una leggera piega dei gomiti.","Tira i manubri verso il petto, stringendo le scapole insieme.","Fermati un attimo in cima, poi abbassa lentamente i manubri fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0384","name":"dumbbell reverse preacher curl","category":"upper arms","equipment":"dumbbell","target":"biceps","secondary":["forearms"],"steps":{"en":["Sit on a preacher bench with your upper arms resting on the pad and your chest against the support.","Hold a dumbbell in each hand with an underhand grip, palms facing up.","Keeping your upper arms stationary, exhale and curl the dumbbells as you contract your biceps.","Continue to curl the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"it":["Siediti su una panca da predicatore con le braccia superiori appoggiate sul cuscinetto e il petto appoggiato al supporto.","Tieni un manubrio in ogni mano con una presa sottomano, palmi rivolti verso l'alto.","Mantenendo ferme le braccia superiori, espira e arriccia i manubri mentre contrai i bicipiti.","Continua a arricciare i manubri finché i bicipiti non sono completamente contratti e i manubri non sono all'altezza delle spalle.","Mantieni la posizione contratta per una breve pausa mentre stringi i bicipiti.","Inspira e abbassa lentamente i manubri fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"1675","name":"dumbbell reverse spider curl","category":"upper arms","equipment":"dumbbell","target":"biceps","secondary":["forearms"],"steps":{"en":["Stand up straight with a dumbbell in each hand, palms facing your body and arms fully extended.","Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai dritto con un manubrio in ogni mano, palmi rivolti verso il corpo e braccia completamente distese.","Mantenendo ferme le braccia superiori, espira e arriccia i pesi mentre contrahi i bicipiti.","Continua ad alzare i manubri finché i bicipiti non sono completamente contratti e i manubri non sono all'altezza delle spalle.","Mantieni la posizione contratta per una breve pausa mentre stringi i bicipiti.","Inspira e inizia lentamente ad abbassare i manubri fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0385","name":"dumbbell reverse wrist curl","category":"lower arms","equipment":"dumbbell","target":"forearms","secondary":["biceps","brachialis"],"steps":{"en":["Sit on a bench or chair with your feet flat on the ground.","Hold a dumbbell in each hand with an overhand grip, palms facing down.","Rest your forearms on your thighs, allowing your wrists to hang off the edge.","Slowly curl your wrists upward, bringing the dumbbells towards your body.","Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Siediti su una panca o una sedia con i piedi piatti a terra.","Tieni un manubrio in ogni mano con una presa sopra la mano, palmi rivolti verso il basso.","Appoggia gli avambracci sulle cosce, lasciando che i polsi penzolano dal bordo.","Piega lentamente i polsi verso l'alto, portando i manubri verso il corpo.","Fermati un attimo in cima, poi abbassa lentamente i manubri fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"1459","name":"dumbbell romanian deadlift","category":"upper legs","equipment":"dumbbell","target":"glutes","secondary":["hamstrings","lower back"],"steps":{"en":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand with an overhand grip.","Keeping your back straight and your core engaged, hinge at the hips and lower the dumbbells towards the ground, allowing your knees to bend slightly.","Lower the dumbbells until you feel a stretch in your hamstrings, then push through your heels and engage your glutes to return to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai con i piedi a larghezza delle spalle, tenendo un manubrio in ogni mano con una presa sopra la testa.","Tenendo la schiena dritta e il core attivo, incurvati ai fianchi e abbassa i manubri verso terra, permettendo alle ginocchia di piegarsi leggermente.","Abbassa i manubri finché non senti uno stiramento ai muscoli femorale, poi spingi attraverso i talloni e attiva i glutei per tornare alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0386","name":"dumbbell rotation reverse fly","category":"shoulders","equipment":"dumbbell","target":"delts","secondary":["trapezius","rhomboids"],"steps":{"en":["Stand with your feet shoulder-width apart and hold a dumbbell in each hand, palms facing inwards.","Bend your knees slightly and hinge forward at the hips, keeping your back straight and chest up.","Raise your arms out to the sides, keeping a slight bend in your elbows, until they are parallel to the floor.","Rotate your arms so that your palms are facing downwards.","Slowly lower your arms back to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai con i piedi alla larghezza delle spalle e tieni un manubrio in ogni mano, con i palmi rivolti verso l'interno.","Flette leggermente le ginocchia e piega in avanti sui fianchi, mantenendo la schiena dritta e il petto sollevato.","Alza le braccia ai lati, mantenendo una leggera piega dei gomiti, finché non sono paralleli al pavimento.","Ruota le braccia in modo che i palmi siano rivolti verso il basso.","Abbassa lentamente le braccia fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"2397","name":"dumbbell scott press","category":"shoulders","equipment":"dumbbell","target":"delts","secondary":["triceps","chest"],"steps":{"en":["Sit on a bench with a dumbbell in each hand, palms facing forward.","Raise the dumbbells to shoulder height, with your elbows bent and palms facing forward.","Press the dumbbells upward until your arms are fully extended.","Pause for a moment at the top, then slowly lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"it":["Siediti su una panchina con un manubrio in ciascuna mano, i palmi rivolti in avanti.","Alza i manubri all'altezza delle spalle, con i gomiti piegati e i palmi rivolti in avanti.","Premi i manubri verso l'alto finché le braccia non sono completamente estese.","Fermati un attimo in cima, poi abbassa lentamente i manubri alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0387","name":"dumbbell seated alternate front raise","category":"shoulders","equipment":"dumbbell","target":"delts","secondary":["trapezius","biceps"],"steps":{"en":["Sit on a bench with your back straight and feet flat on the ground.","Hold a dumbbell in each hand with your palms facing your body and arms extended down by your sides.","Keeping your arms straight, raise one dumbbell in front of you until it is parallel to the ground.","Pause for a moment at the top, then slowly lower the dumbbell back down to the starting position.","Repeat with the other arm.","Alternate between arms for the desired number of repetitions."],"it":["Siediti su una panchina con la schiena dritta e i piedi piatti a terra.","Tieni un manubrio in ogni mano con i palmi rivolti verso il corpo e le braccia distese lungo i lati.","Tenendo le braccia dritte, alza un manubrio davanti a te finché non è parallelo al suolo.","Fermati un attimo in cima, poi abbassa lentamente il manubrio fino alla posizione di partenza.","Ripeti con l'altro braccio.","Alternare tra le armi per il numero desiderato di ripetizioni."]}},{"id":"1676","name":"dumbbell seated alternate hammer curl on exercise ball","category":"upper arms","equipment":"dumbbell","target":"biceps","secondary":["forearms"],"steps":{"en":["Sit on an exercise ball with your feet flat on the ground and your back straight.","Hold a dumbbell in each hand with your palms facing your body and your arms fully extended.","Keeping your upper arms stationary, exhale and curl one dumbbell up towards your shoulder while keeping your palm facing your body.","Continue to raise the dumbbell until your biceps are fully contracted and the dumbbell is at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly lower the dumbbell back to the starting position.","Repeat the movement with the opposite arm.","Continue alternating arms for the desired number of repetitions."],"it":["Siediti su una palla da ginnastica con i piedi piatti a terra e la schiena dritta.","Tieni un manubrio in ogni mano con i palmi rivolti verso il corpo e le braccia completamente estese.","Tenendo ferme le braccia superiori, espira e arriccia un manubrio verso la spalla mantenendo il palmo rivolto verso il corpo.","Continua ad alzare il manubrio finché i bicipiti non sono completamente contratti e il manubrio non è all'altezza delle spalle.","Mantieni la posizione contratta per una breve pausa mentre stringi i bicipiti.","Inspira e abbassa lentamente il manubrio alla posizione iniziale.","Ripeti il movimento con il braccio opposto.","Continuare ad alternare le braccia per il numero desiderato di ripetizioni."]}},{"id":"0388","name":"dumbbell seated alternate press","category":"shoulders","equipment":"dumbbell","target":"delts","secondary":["triceps","chest"],"steps":{"en":["Sit on a bench with a dumbbell in each hand, palms facing forward.","Raise the dumbbells to shoulder height, with your elbows bent and palms facing forward.","Press one dumbbell up overhead, fully extending your arm.","Lower the dumbbell back down to shoulder height.","Repeat with the other arm.","Continue alternating arms for the desired number of repetitions."],"it":["Siediti su una panchina con un manubrio in ciascuna mano, i palmi rivolti in avanti.","Alza i manubri all'altezza delle spalle, con i gomiti piegati e i palmi rivolti in avanti.","Premi un manubrio sopra la testa, estendendo completamente il braccio.","Abbassa il manubrio fino all'altezza delle spalle.","Ripeti con l'altro braccio.","Continuare ad alternare le braccia per il numero desiderato di ripetizioni."]}},{"id":"3546","name":"dumbbell seated alternate shoulder","category":"shoulders","equipment":"dumbbell","target":"delts","secondary":["triceps","upper back"],"steps":{"en":["Sit on a bench with your back straight and feet flat on the ground.","Hold a dumbbell in each hand, palms facing inwards, and raise them to shoulder height.","Press one dumbbell up overhead while keeping the other dumbbell at shoulder height.","Lower the raised dumbbell back to shoulder height while simultaneously pressing the other dumbbell up overhead.","Continue alternating between arms for the desired number of repetitions."],"it":["Siediti su una panchina con la schiena dritta e i piedi piatti a terra.","Tieni un manubrio in ogni mano, palmi rivolti verso l'interno, e sollevali all'altezza delle spalle.","Spingi un manubrio sopra la testa mentre l'altro mantiene l'altro all'altezza delle spalle.","Abbassa il manubrio rialzato all'altezza delle spalle mentre contemporaneamente spingi l'altro manubrio sopra la testa.","Continua ad alternare tra le braccia per il numero desiderato di ripetizioni."]}},{"id":"0389","name":"dumbbell seated bench extension","category":"upper arms","equipment":"dumbbell","target":"triceps","secondary":["shoulders"],"steps":{"en":["Sit on a bench with your back straight and feet flat on the ground.","Hold a dumbbell with both hands and extend your arms straight up above your head.","Slowly lower the dumbbell behind your head, keeping your elbows close to your ears.","Pause for a moment, then raise the dumbbell back up to the starting position.","Repeat for the desired number of repetitions."],"it":["Siediti su una panchina con la schiena dritta e i piedi piatti a terra.","Tieni un manubrio con entrambe le mani e allunga le braccia dritte sopra la testa.","Abbassa lentamente il manubrio dietro la testa, tenendo i gomiti vicino alle orecchie.","Fermati un attimo, poi rialza il manubrio alla posizione di partenza.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"2317","name":"dumbbell seated bent arm lateral raise","category":"shoulders","equipment":"dumbbell","target":"delts","secondary":["trapezius","rhomboids"],"steps":{"en":["Sit on a bench with your back straight and feet flat on the ground.","Hold a dumbbell in each hand with your palms facing your body and your arms bent at a 90-degree angle.","Keeping your elbows bent, raise your arms out to the sides until they are parallel to the ground.","Pause for a moment at the top, then slowly lower your arms back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Siediti su una panchina con la schiena dritta e i piedi piatti a terra.","Tieni un manubrio in ogni mano con i palmi rivolti verso il corpo e le braccia piegate a 90 gradi.","Tenendo i gomiti piegati, alza le braccia ai lati finché non sono parallele al suolo.","Fermati un attimo in cima, poi abbassa lentamente le braccia fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"1730","name":"dumbbell seated bent over alternate kickback","category":"upper arms","equipment":"dumbbell","target":"triceps","secondary":["shoulders","back"],"steps":{"en":["Sit on a bench with a dumbbell in each hand, palms facing inwards.","Bend forward at the waist, keeping your back straight and parallel to the ground.","Extend one arm straight back, keeping it close to your body, until your arm is fully extended.","Pause for a moment, then slowly lower the dumbbell back to the starting position.","Repeat with the other arm.","Continue alternating arms for the desired number of repetitions."],"it":["Seduta su una panchina con un manubrio in ogni mano, i palmi rivolti verso l'interno.","Piegati in avanti in vita, mantenendo la schiena dritta e parallela al suolo.","Allunga un braccio dritto all'indietro, tenendolo vicino al corpo, finché il braccio non è completamente esteso.","Fermati un attimo, poi abbassa lentamente il manubrio alla posizione iniziale.","Ripeti con l'altro braccio.","Continuare ad alternare le braccia per il numero desiderato di ripetizioni."]}},{"id":"1737","name":"dumbbell seated bent over triceps extension","category":"upper arms","equipment":"dumbbell","target":"triceps","secondary":["shoulders","back"],"steps":{"en":["Sit on a bench with your feet flat on the ground and hold a dumbbell in each hand.","Bend forward at the waist, keeping your back straight and your head up.","Extend your arms straight back, keeping your elbows close to your head.","Pause for a moment, then slowly lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"it":["Siediti su una panchina con i piedi piatti a terra e tieni un manubrio in ciascuna mano.","Piegati in avanti in vita, tenendo la schiena dritta e la testa sollevata.","Allunga le braccia dritte all'indietro, tenendo i gomiti vicini alla testa.","Fermati un attimo, poi abbassa lentamente i manubri alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"1677","name":"dumbbell seated bicep curl","category":"upper arms","equipment":"dumbbell","target":"biceps","secondary":["forearms"],"steps":{"en":["Sit on a bench with your feet flat on the ground and hold a dumbbell in each hand, palms facing up.","Keep your back straight and your elbows close to your torso.","Exhale and curl the dumbbells up towards your shoulders, contracting your biceps.","Pause for a moment at the top, then inhale and slowly lower the dumbbells back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Siediti su una panchina con i piedi piatti a terra e tieni un manubrio in ciascuna mano, palmi rivolti verso l'alto.","Tieni la schiena dritta e i gomiti vicini al busto.","Espira e arriccia i manubri verso le spalle, contraendo i bicipiti.","Fermati un attimo in cima, poi inspira e abbassa lentamente i manubri fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0390","name":"dumbbell seated biceps curl (on stability ball)","category":"upper arms","equipment":"dumbbell","target":"biceps","secondary":["forearms"],"steps":{"en":["Sit on a stability ball with your feet flat on the ground and your back straight.","Hold a dumbbell in each hand with your palms facing forward and your arms fully extended.","Keeping your upper arms stationary, exhale and curl the dumbbells while contracting your biceps.","Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"it":["Siediti su una palla stabile con i piedi piatti a terra e la schiena dritta.","Tieni un manubrio in ogni mano con i palmi rivolti in avanti e le braccia completamente estese.","Mantenendo ferme le braccia superiori, espira e arriccia i manubri mentre contrahi i bicipiti.","Continua ad alzare i manubri finché i bicipiti non sono completamente contratti e i manubri non sono all'altezza delle spalle.","Mantieni la posizione contratta per una breve pausa mentre stringi i bicipiti.","Inspira e inizia lentamente ad abbassare i manubri fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"3547","name":"dumbbell seated biceps curl to shoulder press","category":"upper arms","equipment":"dumbbell","target":"biceps","secondary":["shoulders"],"steps":{"en":["Sit on a bench with your back straight and feet flat on the ground.","Hold a dumbbell in each hand with your palms facing forward and arms fully extended.","Keeping your elbows close to your sides, curl the dumbbells up towards your shoulders.","Once your forearms are vertical, rotate your wrists so that your palms are facing forward.","Press the dumbbells overhead until your arms are fully extended.","Lower the dumbbells back down to the starting position by reversing the movement.","Repeat for the desired number of repetitions."],"it":["Siediti su una panchina con la schiena dritta e i piedi piatti a terra.","Tieni un manubrio in ogni mano con i palmi rivolti in avanti e le braccia completamente distese.","Tenendo i gomiti vicini ai fianchi, arrotola i manubri verso le spalle.","Una volta che gli avambracci sono verticali, ruota i polsi in modo che i palmi siano rivolti in avanti.","Premi i manubri sopra la testa finché le braccia non sono completamente estese.","Abbassa i manubri fino alla posizione iniziale invertendo il movimento.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"1379","name":"dumbbell seated calf raise","category":"lower legs","equipment":"dumbbell","target":"calves","secondary":["hamstrings"],"steps":{"en":["Sit on a bench or chair with your feet flat on the ground and a dumbbell resting on your thighs.","Place the balls of your feet on a raised surface such as a step or block, with your heels hanging off the edge.","Hold onto the dumbbell for stability.","Raise your heels as high as possible, lifting your body weight onto the balls of your feet.","Pause for a moment at the top, then slowly lower your heels back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Siediti su una panca o una sedia con i piedi piatti a terra e un manubrio appoggiato sulle cosce.","Posiziona le punte dei piedi su una superficie rialzata come un gradino o un blocco, con i talloni che pendono dal bordo.","Tieni il manubrio per stabilità.","Alza i talloni il più in alto possibile, sollevando il peso del corpo sulle punte dei piedi.","Fermati un attimo in cima, poi abbassa lentamente i talloni fino alla posizione di partenza.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0391","name":"dumbbell seated curl","category":"upper arms","equipment":"dumbbell","target":"biceps","secondary":["forearms"],"steps":{"en":["Sit on a bench with your feet flat on the ground and a dumbbell in each hand, palms facing forward.","Keep your back straight and your elbows close to your torso.","Exhale and curl the dumbbells up towards your shoulders, contracting your biceps.","Pause for a moment at the top, then inhale and slowly lower the dumbbells back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Siediti su una panchina con i piedi piatti a terra e un manubrio in ogni mano, i palmi rivolti in avanti.","Tieni la schiena dritta e i gomiti vicini al busto.","Espira e arriccia i manubri verso le spalle, contraendo i bicipiti.","Fermati un attimo in cima, poi inspira e abbassa lentamente i manubri fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0392","name":"dumbbell seated front raise","category":"shoulders","equipment":"dumbbell","target":"delts","secondary":["trapezius","biceps"],"steps":{"en":["Sit on a bench with your feet flat on the ground and a dumbbell in each hand, resting on your thighs.","Keep your back straight and core engaged.","Raise the dumbbells in front of you, with your palms facing down, until they are at shoulder level.","Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Siediti su una panchina con i piedi piatti a terra e un manubrio in ogni mano, appoggiato sulle cosce.","Tieni la schiena dritta e il core attivo.","Alza i manubri davanti a te, con i palmi rivolti verso il basso, finché non sono all'altezza delle spalle.","Fermati un attimo in cima, poi abbassa lentamente i manubri fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"1678","name":"dumbbell seated hammer curl","category":"upper arms","equipment":"dumbbell","target":"biceps","secondary":["forearms"],"steps":{"en":["Sit on a bench with a dumbbell in each hand, palms facing your torso and arms extended straight down.","Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"it":["Siediti su una panchina con un manubrio in ogni mano, i palmi rivolti verso il busto e le braccia distese verso il basso.","Mantenendo ferme le braccia superiori, espira e arriccia i pesi mentre contrahi i bicipiti.","Continua ad alzare i manubri finché i bicipiti non sono completamente contratti e i manubri non sono all'altezza delle spalle.","Mantieni la posizione contratta per una breve pausa mentre stringi i bicipiti.","Inspira e inizia lentamente ad abbassare i manubri fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0393","name":"dumbbell seated inner biceps curl","category":"upper arms","equipment":"dumbbell","target":"biceps","secondary":["forearms"],"steps":{"en":["Sit on a bench with your feet flat on the ground and hold a dumbbell in each hand, palms facing up.","Rest your upper arms on your thighs, allowing the dumbbells to hang down.","Keeping your upper arms stationary, curl the dumbbells up towards your shoulders by contracting your biceps.","Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Siediti su una panchina con i piedi piatti a terra e tieni un manubrio in ciascuna mano, palmi rivolti verso l'alto.","Appoggia le braccia superiori sulle cosce, lasciando che i manubri pendano giù.","Mantenendo ferme le braccia superiori, arrotola i manubri verso le spalle contraendo i bicipiti.","Fermati un attimo in cima, poi abbassa lentamente i manubri fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0394","name":"dumbbell seated kickback","category":"upper arms","equipment":"dumbbell","target":"triceps","secondary":["shoulders"],"steps":{"en":["Sit on a bench with your feet flat on the ground and hold a dumbbell in each hand.","Bend your knees slightly and lean forward from your hips, keeping your back straight.","Bring your upper arms close to your sides and keep your elbows bent at a 90-degree angle.","Extend your arms straight back, squeezing your triceps at the top of the movement.","Pause for a moment, then slowly lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"it":["Siediti su una panchina con i piedi piatti a terra e tieni un manubrio in ciascuna mano.","Flega leggermente le ginocchia e inclinati in avanti dai fianchi, mantenendo la schiena dritta.","Avvicina le braccia superiori ai fianchi e tieni i gomiti piegati a 90 gradi.","Allunga le braccia dritte, stringendo i tricipiti nella parte superiore del movimento.","Fermati un attimo, poi abbassa lentamente i manubri alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0396","name":"dumbbell seated lateral raise","category":"shoulders","equipment":"dumbbell","target":"delts","secondary":["traps","upper back"],"steps":{"en":["Sit on a bench with your feet flat on the ground and a dumbbell in each hand, resting on your thighs.","Keep your back straight and core engaged.","Raise the dumbbells to your sides with a slight bend in your elbows, until your arms are parallel to the ground.","Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Siediti su una panchina con i piedi piatti a terra e un manubrio in ogni mano, appoggiato sulle cosce.","Tieni la schiena dritta e il core attivo.","Alza i manubri ai lati con una leggera piega dei gomiti, finché le braccia non sono parallele al suolo.","Fermati un attimo in cima, poi abbassa lentamente i manubri fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0395","name":"dumbbell seated lateral raise v. 2","category":"shoulders","equipment":"dumbbell","target":"delts","secondary":["traps","triceps"],"steps":{"en":["Sit on a bench with your feet flat on the ground and a dumbbell in each hand, resting on your thighs.","Keep your back straight and core engaged.","Raise the dumbbells to your sides with a slight bend in your elbows, until your arms are parallel to the ground.","Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Siediti su una panchina con i piedi piatti a terra e un manubrio in ogni mano, appoggiato sulle cosce.","Tieni la schiena dritta e il core attivo.","Alza i manubri ai lati con una leggera piega dei gomiti, finché le braccia non sono parallele al suolo.","Fermati un attimo in cima, poi abbassa lentamente i manubri fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0397","name":"dumbbell seated neutral wrist curl","category":"upper arms","equipment":"dumbbell","target":"biceps","secondary":["forearms"],"steps":{"en":["Sit on a bench with your feet flat on the ground and hold a dumbbell in each hand, palms facing each other.","Rest your forearms on your thighs, allowing the dumbbells to hang down.","Keeping your wrists in a neutral position, curl the dumbbells up towards your shoulders.","Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Siediti su una panchina con i piedi piatti a terra e tieni un manubrio in ogni mano, palmi rivolti uno verso l'altro.","Appoggia gli avambracci sulle cosce, lasciando che i manubri pendano giù.","Mantenendo i polsi in posizione neutra, arrotola i manubri verso le spalle.","Fermati un attimo in cima, poi abbassa lentamente i manubri fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"1679","name":"dumbbell seated one arm bicep curl on exercise ball with leg raised","category":"upper arms","equipment":"dumbbell","target":"biceps","secondary":["forearms","shoulders"],"steps":{"en":["Sit on an exercise ball with your feet flat on the ground and your back straight.","Hold a dumbbell in one hand with your palm facing up and your arm fully extended.","Place your other hand on your hip for stability.","Slowly curl the dumbbell towards your shoulder, keeping your upper arm stationary.","Pause for a moment at the top of the movement, squeezing your bicep.","Slowly lower the dumbbell back to the starting position.","Repeat for the desired number of repetitions.","Switch arms and repeat the exercise."],"it":["Siediti su una palla da ginnastica con i piedi piatti a terra e la schiena dritta.","Tieni un manubrio in una mano con il palmo rivolto verso l'alto e il braccio completamente esteso.","Metti l'altra mano sul fianco per stabilità.","Arrotola lentamente il manubrio verso la spalla, mantenendo fermo il braccio superiore.","Fermati un attimo all'inizio del movimento, stringendo il bicipite.","Abbassa lentamente il manubrio fino alla posizione di partenza.","Ripeti per il numero desiderato di ripetizioni.","Cambia braccio e ripeti l'esercizio."]}},{"id":"0398","name":"dumbbell seated one arm kickback","category":"upper arms","equipment":"dumbbell","target":"triceps","secondary":["shoulders"],"steps":{"en":["Sit on a bench with your feet flat on the ground and hold a dumbbell in one hand.","Bend your torso forward at the waist, keeping your back straight and parallel to the ground.","Extend your arm straight back, keeping your elbow close to your body.","Pause for a moment at the top, then slowly lower the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"it":["Siediti su una panchina con i piedi piatti a terra e tieni un manubrio in una mano.","Piega il busto in avanti in vita, mantenendo la schiena dritta e parallela al suolo.","Allunga il braccio dritto all'indietro, tenendo il gomito vicino al corpo.","Fermati un attimo in cima, poi abbassa lentamente il manubrio alla posizione di partenza.","Ripeti per il numero desiderato di ripetizioni, poi cambia braccio."]}},{"id":"0399","name":"dumbbell seated one arm rotate","category":"lower arms","equipment":"dumbbell","target":"forearms","secondary":["shoulders","biceps"],"steps":{"en":["Sit on a bench with your back straight and hold a dumbbell in one hand, resting it on your thigh.","Raise the dumbbell up to shoulder height, keeping your elbow close to your body.","Rotate your forearm outward, away from your body, while keeping your upper arm stationary.","Pause for a moment at the top, then slowly rotate your forearm back to the starting position.","Repeat for the desired number of repetitions, then switch to the other arm."],"it":["Siediti su una panca con la schiena dritta e tieni un manubrio in una mano, appoggiandolo sulla coscia.","Alza il manubrio all'altezza delle spalle, tenendo il gomito vicino al corpo.","Ruota l'avambraccio verso l'esterno, lontano dal corpo, mantenendo fermo la parte superiore del braccio.","Fermati un attimo in cima, poi ruota lentamente l'avambraccio di nuovo alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni, poi passa all'altro braccio."]}},{"id":"0400","name":"dumbbell seated one leg calf raise","category":"lower legs","equipment":"dumbbell","target":"calves","secondary":["hamstrings","glutes"],"steps":{"en":["Sit on a bench or chair with your feet flat on the ground and a dumbbell resting on your right thigh.","Extend your left leg straight out in front of you, keeping your foot flexed.","Place the ball of your right foot on an elevated surface, such as a step or weight plate.","Using your calf muscles, raise your right heel as high as possible.","Pause for a moment at the top, then slowly lower your heel back down to the starting position.","Repeat for the desired number of repetitions, then switch legs."],"it":["Siediti su una panca o una sedia con i piedi piatti a terra e un manubrio appoggiato sulla coscia destra.","Allunga la gamba sinistra dritta davanti a te, mantenendo il piede fletto.","Posiziona la pianta del piede destro su una superficie rialzata, come un gradino o una piastra di peso.","Usando i muscoli del polpaccio, solleva il tallone destro il più in alto possibile.","Fermati un attimo in cima, poi abbassa lentamente il tallone fino alla posizione di partenza.","Ripeti per il numero desiderato di ripetizioni, poi cambia gamba."]}},{"id":"1380","name":"dumbbell seated one leg calf raise - hammer grip","category":"lower legs","equipment":"dumbbell","target":"calves","secondary":["hamstrings","glutes"],"steps":{"en":["Sit on a bench or chair with your feet flat on the ground and a dumbbell resting on your thighs.","Place one foot on a raised surface, such as a step or block, with your heel hanging off the edge.","Hold the dumbbell with a hammer grip, meaning your palms are facing each other and your fingers are wrapped around the handle.","Keeping your core engaged and your back straight, slowly raise your heel as high as possible by pushing through the ball of your foot.","Pause for a moment at the top, then slowly lower your heel back down to the starting position.","Repeat for the desired number of repetitions, then switch to the other leg."],"it":["Siediti su una panca o una sedia con i piedi piatti a terra e un manubrio appoggiato sulle cosce.","Appoggia un piede su una superficie rialzata, come un gradino o un blocco, con il tallone penzolante dal bordo.","Tieni il manubrio con una presa a martello, cioè i palmi dei palmi si rivolgono e le dita avvolgono il manico.","Tenendo il core attivo e la schiena dritta, solleva lentamente il tallone il più in alto possibile spingendo attraverso la pianta del piede.","Fermati un attimo in cima, poi abbassa lentamente il tallone fino alla posizione di partenza.","Ripeti per il numero desiderato di ripetizioni, poi passa all'altra gamba."]}},{"id":"1381","name":"dumbbell seated one leg calf raise - palm up","category":"lower legs","equipment":"dumbbell","target":"calves","secondary":["hamstrings","glutes"],"steps":{"en":["Sit on a bench or chair with your back straight and your feet flat on the ground.","Hold a dumbbell in one hand and place it on top of your thigh, palm facing up.","Lift one leg off the ground and extend it in front of you, keeping your knee slightly bent.","Raise your heel as high as possible by pushing through the ball of your foot.","Pause for a moment at the top, then slowly lower your heel back down.","Repeat for the desired number of repetitions, then switch legs and repeat."],"it":["Siediti su una panca o una sedia con la schiena dritta e i piedi piatti a terra.","Tieni un manubrio in una mano e posalo sopra la coscia, con il palmo rivolto verso l'alto.","Solleva una gamba da terra e estendila davanti a te, mantenendo il ginocchio leggermente piegato.","Alza il tallone il più in alto possibile spingendo attraverso la pianta del piede.","Fermati un attimo in cima, poi abbassa lentamente il tallone.","Ripeti per il numero desiderato di ripetizioni, poi cambia gamba e ripeti."]}},{"id":"0401","name":"dumbbell seated palms up wrist curl","category":"lower arms","equipment":"dumbbell","target":"forearms","secondary":["biceps","shoulders"],"steps":{"en":["Sit on a bench with your feet flat on the ground and hold a dumbbell in each hand, palms facing up.","Rest your forearms on your thighs, allowing your wrists to hang off the edge.","Slowly curl your wrists upward, squeezing your forearms at the top of the movement.","Pause for a moment, then lower your wrists back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Siediti su una panchina con i piedi piatti a terra e tieni un manubrio in ciascuna mano, palmi rivolti verso l'alto.","Appoggia gli avambracci sulle cosce, lasciando che i polsi penzolano dal bordo.","Ripiega lentamente i polsi verso l'alto, stringendo gli avambracci nella parte alta del movimento.","Fermati un attimo, poi abbassa di nuovo i polsi alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0402","name":"dumbbell seated preacher curl","category":"upper arms","equipment":"dumbbell","target":"biceps","secondary":["forearms"],"steps":{"en":["Sit on a preacher curl bench with your feet flat on the floor.","Hold a dumbbell in one hand with an underhand grip, resting your upper arm against the preacher pad.","Keeping your upper arm stationary, exhale and curl the dumbbell up towards your shoulder.","Pause for a moment at the top, then inhale and slowly lower the dumbbell back down to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"it":["Siediti su una panca da preacher curl con i piedi piatti sul pavimento.","Tieni un manubrio in una mano con una presa sotto, appoggiando il braccio superiore al pad predicatorio.","Mantenendo fermo il braccio superiore, espira e arrotola il manubrio verso la spalla.","Fermati un attimo in cima, poi inspira e abbassa lentamente il manubrio fino alla posizione di partenza.","Ripeti per il numero desiderato di ripetizioni, poi cambia braccio."]}},{"id":"0403","name":"dumbbell seated revers grip concentration curl","category":"upper arms","equipment":"dumbbell","target":"biceps","secondary":["forearms"],"steps":{"en":["Sit on a bench with your feet flat on the ground and hold a dumbbell in one hand, palm facing up.","Rest your elbow on the inside of your thigh, just above the knee.","Keeping your upper arm stationary, exhale and curl the dumbbell towards your shoulder.","Pause for a moment at the top, squeezing your biceps.","Inhale and slowly lower the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"it":["Siediti su una panchina con i piedi piatti a terra e tieni un manubrio in una mano, con il palmo rivolto verso l'alto.","Appoggia il gomito all'interno della coscia, appena sopra il ginocchio.","Mantenendo fermo il braccio superiore, espira e arrotola il manubrio verso la spalla.","Fermati un attimo in cima, stringendo i bicipiti.","Inspira e abbassa lentamente il manubrio alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni, poi cambia braccio."]}},{"id":"1738","name":"dumbbell seated reverse grip one arm overhead tricep extension","category":"upper arms","equipment":"dumbbell","target":"triceps","secondary":["shoulders"],"steps":{"en":["Sit on a bench with your back straight and feet flat on the ground.","Hold a dumbbell with an underhand grip and extend your arm straight up overhead.","Lower the dumbbell behind your head by bending your elbow, keeping your upper arm stationary.","Pause for a moment, then extend your arm back up to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"it":["Siediti su una panchina con la schiena dritta e i piedi piatti a terra.","Tieni un manubrio con una presa sotto la mano e estendi il braccio dritto sopra la testa.","Abbassa il manubrio dietro la testa piegando il gomito, mantenendo fermo il braccio superiore.","Fermati un attimo, poi rialza il braccio fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni, poi cambia braccio."]}},{"id":"0405","name":"dumbbell seated shoulder press","category":"shoulders","equipment":"dumbbell","target":"delts","secondary":["triceps","upper back"],"steps":{"en":["Sit on a bench with a dumbbell in each hand, resting on your thighs.","Raise the dumbbells to shoulder height, palms facing forward.","Press the dumbbells upward until your arms are fully extended overhead.","Pause for a moment at the top, then slowly lower the dumbbells back to shoulder height.","Repeat for the desired number of repetitions."],"it":["Siediti su una panchina con un manubrio in ogni mano, appoggiato sulle cosce.","Alza i manubri all'altezza delle spalle, palmi rivolti in avanti.","Premi i manubri verso l'alto finché le braccia non sono completamente estese sopra la testa.","Fermati un attimo in cima, poi abbassa lentamente i manubri all'altezza delle spalle.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0404","name":"dumbbell seated shoulder press (parallel grip)","category":"shoulders","equipment":"dumbbell","target":"delts","secondary":["triceps","upper back"],"steps":{"en":["Sit on a bench with a dumbbell in each hand, palms facing inward.","Raise the dumbbells to shoulder height, elbows bent and palms facing forward.","Press the dumbbells upward until your arms are fully extended overhead.","Pause for a moment at the top, then slowly lower the dumbbells back to shoulder height.","Repeat for the desired number of repetitions."],"it":["Siediti su una panchina con un manubrio in ciascuna mano, i palmi rivolti verso l'interno.","Alza i manubri all'altezza delle spalle, gomiti piegati e palmi rivolti in avanti.","Premi i manubri verso l'alto finché le braccia non sono completamente estese sopra la testa.","Fermati un attimo in cima, poi abbassa lentamente i manubri all'altezza delle spalle.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"2188","name":"dumbbell seated triceps extension","category":"upper arms","equipment":"dumbbell","target":"triceps","secondary":["shoulders"],"steps":{"en":["Sit on a bench with your back straight and feet flat on the ground.","Hold a dumbbell with both hands and extend your arms straight up overhead.","Bend your elbows and lower the dumbbell behind your head, keeping your upper arms close to your ears.","Pause for a moment, then straighten your arms and return to the starting position.","Repeat for the desired number of repetitions."],"it":["Siediti su una panchina con la schiena dritta e i piedi piatti a terra.","Tieni un manubrio con entrambe le mani e allunga le braccia dritte sopra la testa.","Piega i gomiti e abbassa il manubrio dietro la testa, tenendo le braccia superiori vicino alle orecchie.","Fermati un attimo, poi raddrizza le braccia e torna alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0406","name":"dumbbell shrug","category":"back","equipment":"dumbbell","target":"traps","secondary":["shoulders"],"steps":{"en":["Stand with your feet shoulder-width apart and hold a dumbbell in each hand with your palms facing your body.","Keep your arms straight and let the dumbbells hang by your sides.","Raise your shoulders as high as possible, as if you are trying to touch your ears with your shoulders.","Hold the contraction for a second, then slowly lower your shoulders back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai in piedi con i piedi alla larghezza delle spalle e tieni un manubrio in ciascuna mano con i palmi rivolti verso il corpo.","Tieni le braccia dritte e lascia che i manubri pendano lungo i fianchi.","Alza le spalle il più possibile, come se volessi toccare le orecchie con le spalle.","Mantieni la contrazione per un secondo, poi abbassa lentamente le spalle fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0407","name":"dumbbell side bend","category":"waist","equipment":"dumbbell","target":"abs","secondary":["obliques"],"steps":{"en":["Stand up straight with your feet shoulder-width apart and hold a dumbbell in one hand, letting it hang down by your side.","Keeping your back straight and your core engaged, slowly bend sideways at the waist towards the opposite side of the dumbbell, lowering the weight as far as you comfortably can.","Pause for a moment, then slowly return to the starting position.","Repeat for the desired number of repetitions, then switch sides and repeat."],"it":["Stai dritto con i piedi alla larghezza delle spalle e tieni un manubrio in una mano, lasciandolo pendere lungo il fianco.","Tenendo la schiena dritta e il core attivo, piegati lentamente lateralmente in vita verso il lato opposto del manubrio, abbassando il peso il più comodamente possibile.","Fermati un attimo, poi torna lentamente alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni, poi cambia lato e ripeti."]}},{"id":"0408","name":"dumbbell side lying one hand raise","category":"shoulders","equipment":"dumbbell","target":"delts","secondary":["trapezius","rhomboids"],"steps":{"en":["Lie on your side with your legs extended and your head supported by your arm.","Hold a dumbbell in your top hand with your palm facing down.","Keeping your arm straight, raise the dumbbell up to shoulder height.","Pause for a moment at the top, then slowly lower the dumbbell back down to the starting position.","Repeat for the desired number of repetitions, then switch sides."],"it":["Sdraiati su un fianco con le gambe distese e la testa sostenuta dal braccio.","Tieni un manubrio nella mano superiore con il palmo rivolto verso il basso.","Tenendo il braccio dritto, solleva il manubrio all'altezza delle spalle.","Fermati un attimo in cima, poi abbassa lentamente il manubrio fino alla posizione di partenza.","Ripeti per il numero desiderato di ripetizioni, poi cambia lato."]}},{"id":"3664","name":"dumbbell side plank with rear fly","category":"back","equipment":"dumbbell","target":"upper back","secondary":["shoulders","core"],"steps":{"en":["Start by lying on your side with your legs extended and stacked on top of each other.","Place your forearm on the ground directly below your shoulder, keeping your elbow bent at a 90-degree angle.","Hold a dumbbell in your top hand, with your arm extended straight down towards the ground.","Engage your core and lift your hips off the ground, creating a straight line from your head to your heels.","While maintaining the side plank position, lift the dumbbell up towards the ceiling, squeezing your shoulder blades together.","Lower the dumbbell back down to the starting position.","Repeat for the desired number of repetitions, then switch sides."],"it":["Inizia sdraiandoti su un fianco con le gambe distese e sovrapposte una sopra l'altra.","Appoggia l'avambraccio a terra direttamente sotto la spalla, mantenendo il gomito piegato a un angolo di 90 gradi.","Tieni un manubrio nella mano superiore, con il braccio teso verso il basso verso terra.","Attiva il core e solleva i fianchi da terra, creando una linea retta dalla testa ai talloni.","Mantieni la posizione laterale, solleva il manubrio verso il soffitto, stringendo le scapole insieme.","Abbassa il manubrio fino alla posizione di partenza.","Ripeti per il numero desiderato di ripetizioni, poi cambia lato."]}},{"id":"3548","name":"dumbbell single arm overhead carry","category":"shoulders","equipment":"dumbbell","target":"delts","secondary":["traps","core"],"steps":{"en":["Stand tall with your feet shoulder-width apart, holding a dumbbell in one hand.","Raise the dumbbell overhead, fully extending your arm.","Engage your core and keep your back straight as you walk forward, maintaining the dumbbell overhead.","Continue walking for the desired distance or time.","Switch hands and repeat the exercise."],"it":["Stai dritto con i piedi divaricati alla larghezza delle spalle, tenendo un manubrio in una mano.","Alza il manubrio sopra la testa, estendendo completamente il braccio.","Attiva il core e tieni la schiena dritta mentre cammini in avanti, mantenendo il manubrio sopra la testa.","Continua a camminare per la distanza o il tempo desiderato.","Cambia mano e ripeti l'esercizio."]}},{"id":"0409","name":"dumbbell single leg calf raise","category":"lower legs","equipment":"dumbbell","target":"calves","secondary":["ankles"],"steps":{"en":["Stand on the edge of a step or platform with your heels hanging off and your toes on the step.","Hold a dumbbell in one hand and place your other hand on a wall or railing for support.","Raise your heel as high as possible, lifting your body up onto your toes.","Pause for a moment at the top, then slowly lower your heel back down below the step.","Repeat for the desired number of repetitions, then switch to the other leg."],"it":["Stai sul bordo di un gradino o di una piattaforma con i talloni che pendono e le dita dei piedi sul gradino.","Tieni un manubrio in una mano e appoggia l'altra mano su un muro o una ringhiera per sostenerti.","Alza il tallone il più in alto possibile, sollevando il corpo sulle punte dei piedi.","Fermati un attimo in cima, poi abbassa lentamente il tallone sotto il gradino.","Ripeti per il numero desiderato di ripetizioni, poi passa all'altra gamba."]}},{"id":"1757","name":"dumbbell single leg deadlift","category":"upper legs","equipment":"dumbbell","target":"glutes","secondary":["hamstrings","lower back"],"steps":{"en":["Stand with your feet hip-width apart, holding a dumbbell in your right hand.","Shift your weight onto your left leg and lift your right foot slightly off the ground.","Keeping your back straight, hinge forward at the hips and lower the dumbbell towards the ground.","At the same time, extend your right leg straight behind you, maintaining a slight bend in your left knee.","Lower the dumbbell until your torso and right leg are parallel to the ground.","Pause for a moment, then engage your glutes and hamstrings to return to the starting position.","Repeat for the desired number of repetitions, then switch sides."],"it":["Stai in piedi con i piedi alla larghezza dei fianchi, tenendo un manubrio nella mano destra.","Sposta il peso sulla gamba sinistra e solleva leggermente il piede destro da terra.","Tieni la schiena dritta, inclina in avanti i fianchi e abbassa il manubrio verso terra.","Allo stesso tempo, estendi la gamba destra dritta dietro di te, mantenendo una leggera piega del ginocchio sinistro.","Abbassa il manubrio finché il busto e la gamba destra non sono paralleli al suolo.","Fermati un attimo, poi attiva glutei e ispicchi femorale per tornare alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni, poi cambia lato."]}},{"id":"2805","name":"dumbbell single leg deadlift with stepbox support","category":"upper legs","equipment":"dumbbell","target":"glutes","secondary":["hamstrings","lower back"],"steps":{"en":["Stand with your feet hip-width apart, holding a dumbbell in your right hand.","Place your left foot on a stepbox or elevated surface behind you.","Keeping your back straight and core engaged, hinge forward at the hips, lowering the dumbbell towards the ground.","As you lower the dumbbell, simultaneously lift your left leg behind you, maintaining a straight line from head to heel.","Lower the dumbbell until you feel a stretch in your right hamstring, then return to the starting position.","Repeat for the desired number of repetitions, then switch sides."],"it":["Stai in piedi con i piedi alla larghezza dei fianchi, tenendo un manubrio nella mano destra.","Metti il piede sinistro su una scaletta o una superficie rialzata dietro di te.","Tenendo la schiena dritta e il core attivo, piega in avanti ai fianchi, abbassando il manubrio verso terra.","Mentre abbassi il manubrio, solleva contemporaneamente la gamba sinistra dietro di te, mantenendo una linea retta dalla testa al tallone.","Abbassa il manubrio finché non senti uno stiramento al muscolo femorale destro, poi torna alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni, poi cambia lato."]}},{"id":"0410","name":"dumbbell single leg split squat","category":"upper legs","equipment":"dumbbell","target":"quads","secondary":["glutes","hamstrings","calves"],"steps":{"en":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand.","Take a step forward with one foot and position your feet so that your front foot is flat on the ground and your back foot is elevated on a bench or step.","Lower your body by bending your front knee and hip, keeping your back knee slightly bent and your back heel off the ground.","Continue lowering until your front thigh is parallel to the ground, then push through your front heel to return to the starting position.","Repeat for the desired number of repetitions, then switch legs and repeat."],"it":["Stai con i piedi a larghezza delle spalle, tenendo un manubrio in ciascuna mano.","Fai un passo avanti con un piede e posiziona i piedi in modo che il piede anteriore sia piatto a terra e il piede posteriore sollevato su una panca o un gradino.","Abbassa il corpo piegando il ginocchio anteriore e il fianco, mantenendo il ginocchio posteriore leggermente piegato e il tallone posteriore sollevato da terra.","Continua ad abbassare finché la coscia anteriore non è parallela al terreno, poi spingi attraverso il tallone anteriore per tornare alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni, poi cambia gamba e ripeti."]}},{"id":"0411","name":"dumbbell single leg squat","category":"upper legs","equipment":"dumbbell","target":"glutes","secondary":["quadriceps","hamstrings","calves"],"steps":{"en":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand.","Extend one leg forward and keep it off the ground throughout the exercise.","Bend your standing leg and lower your body down as if sitting back into a chair.","Keep your chest up and your back straight.","Pause for a moment at the bottom, then push through your heel to return to the starting position.","Repeat for the desired number of repetitions, then switch legs."],"it":["Stai con i piedi a larghezza delle spalle, tenendo un manubrio in ciascuna mano.","Allunga una gamba in avanti e tienilo sollevato da terra durante l'esercizio.","Piega la gamba in piedi e abbassa il corpo come se fossi seduto di nuovo su una sedia.","Tieni il petto alto e la schiena dritta.","Fermati un attimo in fondo, poi spingi attraverso il tallone per tornare alla posizione di partenza.","Ripeti per il numero desiderato di ripetizioni, poi cambia gamba."]}},{"id":"0413","name":"dumbbell squat","category":"upper legs","equipment":"dumbbell","target":"glutes","secondary":["quadriceps","hamstrings","calves"],"steps":{"en":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand at your sides.","Keeping your chest up and core engaged, lower your body down by bending at the knees and hips, as if sitting back into a chair.","Continue lowering until your thighs are parallel to the ground, or as low as you can comfortably go.","Pause for a moment at the bottom, then push through your heels to return to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai con i piedi a larghezza delle spalle, tenendo un manubrio in ogni mano ai lati.","Tenendo il petto sollevato e il core impegnato, abbassa il corpo piegando ginocchia e fianchi, come se fossi seduto indietro su una sedia.","Continua ad abbassare finché le cosce non sono parallele al suolo, o il più in basso che puoi comodamente.","Fermati un attimo in fondo, poi spingi attraverso i talloni per tornare alla posizione di partenza.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"3560","name":"dumbbell standing alternate hammer curl and press","category":"upper arms","equipment":"dumbbell","target":"biceps","secondary":["forearms","shoulders"],"steps":{"en":["Stand up straight with a dumbbell in each hand, palms facing your body.","Keep your elbows close to your torso and your back straight.","Exhale and curl the dumbbell in your right hand towards your shoulder, keeping your upper arm stationary.","Continue to raise the dumbbell until your biceps are fully contracted and the dumbbell is at shoulder level.","Inhale and slowly lower the dumbbell back to the starting position.","Repeat the curl with your left hand.","After completing the curl with your left hand, exhale and press the dumbbell in your right hand overhead.","Extend your arm fully and hold for a moment at the top.","Inhale and slowly lower the dumbbell back to the starting position.","Repeat the press with your left hand.","Continue alternating between curls and presses for the desired number of repetitions."],"it":["Stai dritto con un manubrio in ogni mano, palmi rivolti verso il corpo.","Tieni i gomiti vicini al busto e la schiena dritta.","Espira e arrotola il manubrio della mano destra verso la spalla, mantenendo fermo il braccio superiore.","Continua ad alzare il manubrio finché i bicipiti non sono completamente contratti e il manubrio non è all'altezza delle spalle.","Inspira e abbassa lentamente il manubrio alla posizione iniziale.","Ripeti il curl con la mano sinistra.","Dopo aver completato il curl con la mano sinistra, espira e premi il manubrio della mano destra sopra la testa.","Allunga completamente il braccio e tieni per un momento la parte superiore.","Inspira e abbassa lentamente il manubrio alla posizione iniziale.","Ripeti la pressione con la mano sinistra.","Continua ad alternare tra ricci e presse per il numero desiderato di ripetizioni."]}},{"id":"0414","name":"dumbbell standing alternate overhead press","category":"shoulders","equipment":"dumbbell","target":"delts","secondary":["triceps","core"],"steps":{"en":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand at shoulder level with your palms facing forward.","Press one dumbbell overhead, fully extending your arm.","Lower the dumbbell back to shoulder level.","Repeat with the other arm.","Continue alternating arms for the desired number of repetitions."],"it":["Stai con i piedi alla larghezza delle spalle, tenendo un manubrio in ogni mano all'altezza delle spalle con i palmi rivolti in avanti.","Premi un manubrio sopra la testa, estendendo completamente il braccio.","Abbassa il manubrio all'altezza delle spalle.","Ripeti con l'altro braccio.","Continuare ad alternare le braccia per il numero desiderato di ripetizioni."]}},{"id":"0415","name":"dumbbell standing alternate raise","category":"shoulders","equipment":"dumbbell","target":"delts","secondary":["traps","forearms"],"steps":{"en":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand with your palms facing your body.","Keep your back straight and your core engaged.","Raise one dumbbell to the side, keeping your arm straight and your palm facing down.","Continue lifting until your arm is parallel to the ground.","Pause for a moment at the top, then slowly lower the dumbbell back to the starting position.","Repeat with the other arm.","Alternate between arms for the desired number of repetitions."],"it":["Stai con i piedi a larghezza delle spalle, tenendo un manubrio in ogni mano con i palmi rivolti verso il corpo.","Tieni la schiena dritta e il core attivo.","Alza un manubrio di lato, tenendo il braccio dritto e il palmo rivolto verso il basso.","Continua a sollevare il braccio finché il braccio non è parallelo al suolo.","Fermati un attimo in cima, poi abbassa lentamente il manubrio alla posizione di partenza.","Ripeti con l'altro braccio.","Alternare tra le armi per il numero desiderato di ripetizioni."]}},{"id":"1739","name":"dumbbell standing alternating tricep kickback","category":"upper arms","equipment":"dumbbell","target":"triceps","secondary":["shoulders"],"steps":{"en":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand.","Bend your knees slightly and hinge forward at the hips, keeping your back straight.","Extend your arms straight back, keeping your elbows close to your body.","Pause for a moment at the top, then slowly lower the dumbbells back to the starting position.","Repeat with the other arm, alternating sides with each repetition."],"it":["Stai con i piedi a larghezza delle spalle, tenendo un manubrio in ciascuna mano.","Piega leggermente le ginocchia e piega in avanti ai fianchi, mantenendo la schiena dritta.","Allunga le braccia dritte all'indietro, tenendo i gomiti vicini al corpo.","Fermati un attimo in cima, poi abbassa lentamente i manubri alla posizione iniziale.","Ripeti con l'altro braccio, alternando i lati ad ogni ripetizione."]}},{"id":"2143","name":"dumbbell standing around world","category":"shoulders","equipment":"dumbbell","target":"delts","secondary":["triceps","forearms"],"steps":{"en":["Stand with your feet shoulder-width apart and hold a dumbbell in each hand.","Extend your arms straight out to the sides at shoulder height, palms facing down.","Keeping your arms straight, slowly rotate your arms in a circular motion, bringing the dumbbells in front of your body and then overhead.","Continue the circular motion, bringing the dumbbells back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai con i piedi distanti alla larghezza delle spalle e tieni un manubrio in ciascuna mano.","Allunga le braccia dritte ai lati all'altezza delle spalle, palmi rivolti verso il basso.","Tenendo le braccia dritte, ruota lentamente le braccia in un movimento circolare, portando i manubri davanti al corpo e poi sopra la testa.","Continua il movimento circolare, riportando i manubri giù alla posizione di partenza.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"1740","name":"dumbbell standing bent over one arm triceps extension","category":"upper arms","equipment":"dumbbell","target":"triceps","secondary":["shoulders","back"],"steps":{"en":["Stand with your feet shoulder-width apart and hold a dumbbell in one hand.","Bend forward at the waist, keeping your back straight and parallel to the ground.","Extend your arm straight back, keeping your elbow close to your body.","Slowly lower the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"it":["Stai con i piedi a larghezza delle spalle e tieni un manubrio con una mano.","Piegati in avanti in vita, mantenendo la schiena dritta e parallela al suolo.","Allunga il braccio dritto all'indietro, tenendo il gomito vicino al corpo.","Abbassa lentamente il manubrio fino alla posizione di partenza.","Ripeti per il numero desiderato di ripetizioni, poi cambia braccio."]}},{"id":"1741","name":"dumbbell standing bent over two arm triceps extension","category":"upper arms","equipment":"dumbbell","target":"triceps","secondary":["shoulders","back"],"steps":{"en":["Stand with your feet shoulder-width apart and hold a dumbbell in each hand.","Bend forward at the waist, keeping your back straight and your knees slightly bent.","Extend your arms straight back, keeping your elbows close to your body.","Slowly lower the dumbbells back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai con i piedi distanti alla larghezza delle spalle e tieni un manubrio in ciascuna mano.","Piegati in avanti in vita, tenendo la schiena dritta e le ginocchia leggermente piegate.","Allunga le braccia dritte all'indietro, tenendo i gomiti vicini al corpo.","Abbassa lentamente i manubri fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0416","name":"dumbbell standing biceps curl","category":"upper arms","equipment":"dumbbell","target":"biceps","secondary":["forearms"],"steps":{"en":["Stand up straight with a dumbbell in each hand, palms facing forward and arms fully extended.","Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai dritto con un manubrio in ogni mano, palmi rivolti in avanti e braccia completamente estese.","Mantenendo ferme le braccia superiori, espira e arriccia i pesi mentre contrahi i bicipiti.","Continua ad alzare i manubri finché i bicipiti non sono completamente contratti e i manubri non sono all'altezza delle spalle.","Mantieni la posizione contratta per una breve pausa mentre stringi i bicipiti.","Inspira e inizia lentamente ad abbassare i manubri fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0417","name":"dumbbell standing calf raise","category":"lower legs","equipment":"dumbbell","target":"calves","secondary":["ankles"],"steps":{"en":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand.","Raise your heels off the ground as high as possible, using your calves.","Pause for a moment at the top, then slowly lower your heels back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai con i piedi a larghezza delle spalle, tenendo un manubrio in ciascuna mano.","Alza i talloni da terra il più in alto possibile, usando i polpacci.","Fermati un attimo in cima, poi abbassa lentamente i talloni fino alla posizione di partenza.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0418","name":"dumbbell standing concentration curl","category":"upper arms","equipment":"dumbbell","target":"biceps","secondary":["forearms"],"steps":{"en":["Stand with your feet shoulder-width apart and hold a dumbbell in one hand, with your arm fully extended and palm facing inwards.","Place your opposite hand on your thigh for support.","Keeping your upper arm stationary, exhale and curl the dumbbell towards your shoulder by contracting your biceps.","Continue to raise the dumbbell until your biceps are fully contracted and the dumbbell is at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly lower the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"it":["Stai in piedi con i piedi alla larghezza delle spalle e tieni un manubrio in una mano, con il braccio completamente esteso e il palmo rivolto verso l'interno.","Metti la mano opposta sulla coscia per sostenerti.","Mantenendo fermo il braccio superiore, espira e arrotola il manubrio verso la spalla contraendo i bicipiti.","Continua ad alzare il manubrio finché i bicipiti non sono completamente contratti e il manubrio non è all'altezza delle spalle.","Mantieni la posizione contratta per una breve pausa mentre stringi i bicipiti.","Inspira e abbassa lentamente il manubrio alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni, poi cambia braccio."]}},{"id":"0419","name":"dumbbell standing front raise above head","category":"shoulders","equipment":"dumbbell","target":"delts","secondary":["trapezius","biceps"],"steps":{"en":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand with an overhand grip.","Keep your arms straight and lift the dumbbells in front of you, raising them above your head.","Pause for a moment at the top, then slowly lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai con i piedi a larghezza delle spalle, tenendo un manubrio in ogni mano con una presa sopra la testa.","Tieni le braccia dritte e solleva i manubri davanti a te, sollevandoli sopra la testa.","Fermati un attimo in cima, poi abbassa lentamente i manubri alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"2321","name":"dumbbell standing inner biceps curl v. 2","category":"upper arms","equipment":"dumbbell","target":"biceps","secondary":["forearms"],"steps":{"en":["Stand up straight with a dumbbell in each hand, palms facing your torso.","Keep your elbows close to your torso and rotate the palms of your hands until they are facing forward.","While holding your upper arms stationary, curl the weights while contracting your biceps.","Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Slowly begin to bring the dumbbells back to the starting position as your breathe in.","Repeat for the recommended amount of repetitions."],"it":["Stai dritto con un manubrio in ogni mano, i palmi rivolti verso il busto.","Tieni i gomiti vicini al busto e ruota i palmi delle mani finché non sono rivolti in avanti.","Mentre tieni fermi le braccia superiori, arriccia i pesi mentre contrai i bicipiti.","Continua ad alzare i pesi finché i bicipiti non sono completamente contratti e i manubri non sono all'altezza delle spalle.","Mantieni la posizione contratta per una breve pausa mentre stringi i bicipiti.","Inizia lentamente a riportare i manubri alla posizione iniziale mentre inspiri.","Ripeti per il numero consigliato di ripetizioni."]}},{"id":"0420","name":"dumbbell standing kickback","category":"upper arms","equipment":"dumbbell","target":"triceps","secondary":["shoulders"],"steps":{"en":["Stand with your feet shoulder-width apart and hold a dumbbell in each hand.","Bend your knees slightly and hinge forward at the hips, keeping your back straight.","Extend your arms straight back, squeezing your triceps at the top of the movement.","Pause for a moment, then slowly lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai con i piedi distanti alla larghezza delle spalle e tieni un manubrio in ciascuna mano.","Piega leggermente le ginocchia e piega in avanti ai fianchi, mantenendo la schiena dritta.","Allunga le braccia dritte, stringendo i tricipiti nella parte superiore del movimento.","Fermati un attimo, poi abbassa lentamente i manubri alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0421","name":"dumbbell standing one arm concentration curl","category":"upper arms","equipment":"dumbbell","target":"biceps","secondary":["forearms"],"steps":{"en":["Stand up straight with your feet shoulder-width apart and hold a dumbbell in one hand, palm facing up.","Place your free hand on your thigh for support.","Keeping your upper arm stationary, exhale and curl the dumbbell towards your shoulder by contracting your biceps.","Continue to raise the dumbbell until your biceps are fully contracted and the dumbbell is at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly lower the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"it":["Stai dritto con i piedi divaricati alla larghezza delle spalle e tieni un manubrio con una mano, palmo rivolto verso l'alto.","Metti la mano libera sulla coscia per sostenerti.","Mantenendo fermo il braccio superiore, espira e arrotola il manubrio verso la spalla contraendo i bicipiti.","Continua ad alzare il manubrio finché i bicipiti non sono completamente contratti e il manubrio non è all'altezza delle spalle.","Mantieni la posizione contratta per una breve pausa mentre stringi i bicipiti.","Inspira e abbassa lentamente il manubrio alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni, poi cambia braccio."]}},{"id":"0422","name":"dumbbell standing one arm curl (over incline bench)","category":"upper arms","equipment":"dumbbell","target":"biceps","secondary":["forearms"],"steps":{"en":["Stand with your feet shoulder-width apart, holding a dumbbell in one hand with your palm facing forward.","Place your other hand on an incline bench for support.","Keeping your upper arm stationary, exhale and curl the dumbbell towards your shoulder by contracting your biceps.","Pause for a moment at the top, then inhale and slowly lower the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"it":["Stai con i piedi a larghezza delle spalle, tenendo un manubrio in una mano con il palmo rivolto in avanti.","Appoggia l'altra mano su una panca inclinata per avere supporto.","Mantenendo fermo il braccio superiore, espira e arrotola il manubrio verso la spalla contraendo i bicipiti.","Fermati un attimo in cima, poi inspira e abbassa lentamente il manubrio alla posizione di partenza.","Ripeti per il numero desiderato di ripetizioni, poi cambia braccio."]}},{"id":"1680","name":"dumbbell standing one arm curl over incline bench","category":"upper arms","equipment":"dumbbell","target":"biceps","secondary":["forearms"],"steps":{"en":["Stand with your feet shoulder-width apart, holding a dumbbell in one hand.","Place your other hand on an incline bench for support.","Keeping your upper arm stationary, curl the dumbbell towards your shoulder by contracting your biceps.","Pause for a moment at the top, then slowly lower the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"it":["Stai in piedi con i piedi alla larghezza delle spalle, tenendo un manubrio in una mano.","Appoggia l'altra mano su una panca inclinata per avere supporto.","Mantenendo fermo il braccio superiore, arrotola il manubrio verso la spalla contraendo i bicipiti.","Fermati un attimo in cima, poi abbassa lentamente il manubrio alla posizione di partenza.","Ripeti per il numero desiderato di ripetizioni, poi cambia braccio."]}},{"id":"0423","name":"dumbbell standing one arm extension","category":"upper arms","equipment":"dumbbell","target":"triceps","secondary":["shoulders"],"steps":{"en":["Stand with your feet shoulder-width apart, holding a dumbbell in one hand.","Raise the dumbbell overhead, fully extending your arm.","Keep your upper arm close to your head and perpendicular to the ground.","Slowly lower the dumbbell behind your head, bending your elbow.","Pause for a moment, then raise the dumbbell back to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai in piedi con i piedi alla larghezza delle spalle, tenendo un manubrio in una mano.","Alza il manubrio sopra la testa, estendendo completamente il braccio.","Tieni il braccio superiore vicino alla testa e perpendicolare al suolo.","Abbassa lentamente il manubrio dietro la testa, piegando il gomito.","Fermati un attimo, poi solleva il manubrio di nuovo alla posizione di partenza.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0424","name":"dumbbell standing one arm palm in press","category":"shoulders","equipment":"dumbbell","target":"delts","secondary":["triceps","core"],"steps":{"en":["Stand with your feet shoulder-width apart, holding a dumbbell in one hand at shoulder height with your palm facing inwards.","Engage your core and keep your back straight.","Press the dumbbell upwards until your arm is fully extended.","Pause for a moment at the top, then slowly lower the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch to the other arm."],"it":["Stai in piedi con i piedi a larghezza delle spalle, tenendo un manubrio in una mano all'altezza delle spalle con il palmo rivolto verso l'interno.","Attiva il core e tieni la schiena dritta.","Premi il manubrio verso l'alto finché il braccio non è completamente esteso.","Fermati un attimo in cima, poi abbassa lentamente il manubrio alla posizione di partenza.","Ripeti per il numero desiderato di ripetizioni, poi passa all'altro braccio."]}},{"id":"0425","name":"dumbbell standing one arm reverse curl","category":"upper arms","equipment":"dumbbell","target":"biceps","secondary":["forearms"],"steps":{"en":["Stand up straight with your feet shoulder-width apart and hold a dumbbell in one hand with an overhand grip.","Keep your arm fully extended and close to your body, with your palm facing down.","Slowly curl the dumbbell up towards your shoulder, keeping your upper arm stationary.","Pause for a moment at the top, then slowly lower the dumbbell back down to the starting position.","Repeat for the desired number of repetitions, then switch to the other arm."],"it":["Stai dritto con i piedi alla larghezza delle spalle e tieni un manubrio in una mano con una presa sopra la mano.","Mantieni il braccio completamente teso e vicino al corpo, con il palmo rivolto verso il basso.","Arrotola lentamente il manubrio verso la spalla, mantenendo fermo il braccio superiore.","Fermati un attimo in cima, poi abbassa lentamente il manubrio fino alla posizione di partenza.","Ripeti per il numero desiderato di ripetizioni, poi passa all'altro braccio."]}},{"id":"0426","name":"dumbbell standing overhead press","category":"shoulders","equipment":"dumbbell","target":"delts","secondary":["triceps","upper back"],"steps":{"en":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand at shoulder level with your palms facing forward.","Press the dumbbells upward until your arms are fully extended overhead.","Pause for a moment at the top, then slowly lower the dumbbells back down to shoulder level.","Repeat for the desired number of repetitions."],"it":["Stai con i piedi alla larghezza delle spalle, tenendo un manubrio in ogni mano all'altezza delle spalle con i palmi rivolti in avanti.","Premi i manubri verso l'alto finché le braccia non sono completamente estese sopra la testa.","Fermati un attimo in cima, poi abbassa lentamente i manubri fino all'altezza delle spalle.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0427","name":"dumbbell standing palms in press","category":"shoulders","equipment":"dumbbell","target":"delts","secondary":["triceps","chest"],"steps":{"en":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand at shoulder level with your palms facing inwards.","Keeping your core engaged and your back straight, press the dumbbells upwards until your arms are fully extended overhead.","Pause for a moment at the top, then slowly lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai con i piedi a larghezza delle spalle, tenendo un manubrio in ogni mano all'altezza delle spalle con i palmi rivolti verso l'interno.","Tenendo il core attivo e la schiena dritta, premi i manubri verso l'alto finché le braccia non sono completamente estese sopra la testa.","Fermati un attimo in cima, poi abbassa lentamente i manubri alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0428","name":"dumbbell standing preacher curl","category":"upper arms","equipment":"dumbbell","target":"biceps","secondary":["forearms"],"steps":{"en":["Stand upright with your feet shoulder-width apart and hold a dumbbell in each hand, palms facing forward.","Rest the back of your upper arms against the preacher bench or an incline bench, with your elbows slightly bent.","Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai in piedi dritti con i piedi alla larghezza delle spalle e tieni un manubrio in ogni mano, palmi rivolti in avanti.","Appoggia la parte posteriore delle braccia contro la panca da predicatore o una panca inclinata, con i gomiti leggermente piegati.","Mantenendo ferme le braccia superiori, espira e arriccia i pesi mentre contrahi i bicipiti.","Continua ad alzare i manubri finché i bicipiti non sono completamente contratti e i manubri non sono all'altezza delle spalle.","Mantieni la posizione contratta per una breve pausa mentre stringi i bicipiti.","Inspira e inizia lentamente ad abbassare i manubri fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0429","name":"dumbbell standing reverse curl","category":"upper arms","equipment":"dumbbell","target":"biceps","secondary":["forearms"],"steps":{"en":["Stand up straight with your feet shoulder-width apart and hold a dumbbell in each hand, palms facing your body.","Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps. Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai dritto con i piedi divaricati alla larghezza delle spalle e tieni un manubrio in ciascuna mano, palmi rivolti verso il corpo.","Mantenendo ferme le braccia superiori, espira e arriccia i pesi mentre contrahi i bicipiti. Continua ad alzare i pesi finché i bicipiti non sono completamente contratti e i manubri non sono all'altezza delle spalle.","Mantieni la posizione contratta per una breve pausa mentre stringi i bicipiti.","Inspira e inizia lentamente ad abbassare i manubri fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0430","name":"dumbbell standing triceps extension","category":"upper arms","equipment":"dumbbell","target":"triceps","secondary":["shoulders"],"steps":{"en":["Stand with your feet shoulder-width apart and hold a dumbbell in one hand.","Raise the dumbbell overhead, keeping your arm straight.","Bend your elbow and lower the dumbbell behind your head, keeping your upper arm stationary.","Extend your arm back up to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai con i piedi a larghezza delle spalle e tieni un manubrio con una mano.","Alza il manubrio sopra la testa, tenendo il braccio dritto.","Piega il gomito e abbassa il manubrio dietro la testa, mantenendo fermo il braccio superiore.","Allunga il braccio fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"2293","name":"dumbbell standing zottman preacher curl","category":"upper arms","equipment":"dumbbell","target":"biceps","secondary":["forearms"],"steps":{"en":["Stand up straight with a dumbbell in each hand, palms facing forward.","Place your upper arms against the preacher bench and keep your elbows slightly bent.","Curl the dumbbells up towards your shoulders while keeping your upper arms stationary.","At the top of the movement, rotate your wrists so that your palms are facing downward.","Slowly lower the dumbbells back to the starting position, rotating your wrists back to the starting position as well.","Repeat for the desired number of repetitions."],"it":["Stai dritto con un manubrio in ciascuna mano, palmi rivolti in avanti.","Appoggia le braccia superiori contro la panca del predicatore e tieni i gomiti leggermente piegati.","Arrotola i manubri verso le spalle mantenendo ferme le braccia superiori.","All'inizio del movimento, ruota i polsi in modo che i palmi siano rivolti verso il basso.","Abbassa lentamente i manubri fino alla posizione di partenza, ruotando anche i polsi di nuovo alla posizione di partenza.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"1684","name":"dumbbell step up single leg balance with bicep curl","category":"upper arms","equipment":"dumbbell","target":"biceps","secondary":["quadriceps","glutes","hamstrings"],"steps":{"en":["Stand in front of a step or platform with a dumbbell in each hand, palms facing your body.","Place your right foot on the step, ensuring your entire foot is in contact with the surface.","Engage your core and push through your right heel to lift your body up onto the step, bringing your left knee up towards your chest.","At the top of the movement, perform a bicep curl by bending your elbows and bringing the dumbbells towards your shoulders.","Lower the dumbbells back down and simultaneously lower your left foot back to the ground.","Repeat the movement on the opposite side, stepping up with your left foot and curling the dumbbells.","Continue alternating sides for the desired number of repetitions."],"it":["Mettiti davanti a un gradino o a una piattaforma con un manubrio in ciascuna mano, i palmi rivolti verso il corpo.","Appoggia il piede destro sul gradino, assicurandoti che tutto il piede sia a contatto con la superficie.","Attiva il core e spingi attraverso il tallone destro per sollevare il corpo sul gradino, portando il ginocchio sinistro verso il petto.","All'inizio del movimento, esegui un curl per il bicipite piegando i gomiti e portando i manubri verso le spalle.","Abbassa di nuovo i manubri e contemporaneamente abbassa il piede sinistro a terra.","Ripeti il movimento dal lato opposto, facendo un passo avanti con il piede sinistro e arricciando i manubri.","Continua ad alternare i lati per il numero desiderato di ripetizioni."]}},{"id":"0431","name":"dumbbell step-up","category":"upper legs","equipment":"dumbbell","target":"glutes","secondary":["quadriceps","hamstrings","calves"],"steps":{"en":["Stand in front of a bench or step with a dumbbell in each hand, palms facing your body.","Place your right foot on the bench or step, ensuring your entire foot is in contact with the surface.","Push through your right heel and lift your body up onto the bench or step, straightening your right leg.","Bring your left foot up onto the bench or step, standing fully upright.","Step back down with your left foot, followed by your right foot, returning to the starting position.","Repeat for the desired number of repetitions, then switch legs."],"it":["Mettiti davanti a una panchina o mettiti un passo con un manubrio in ciascuna mano, i palmi rivolti verso il corpo.","Appoggia il piede destro sulla panca o sul gradino, assicurandoti che tutto il piede sia a contatto con la superficie.","Spingi attraverso il tallone destro e solleva il corpo sulla panca o sul passo, raddrizzando la gamba destra.","Alza il piede sinistro sulla panca o sul gradino, in piedi completamente eretto.","Fai un passo giù con il piede sinistro, seguito dal destro, tornando alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni, poi cambia gamba."]}},{"id":"2796","name":"dumbbell step-up lunge","category":"upper legs","equipment":"dumbbell","target":"quads","secondary":["glutes","hamstrings","calves"],"steps":{"en":["Stand in front of a step or platform with a dumbbell in each hand, palms facing your sides.","Place your right foot on the step, ensuring your entire foot is on the surface.","Push through your right heel and lift your body up onto the step, bringing your left foot up as well.","Once both feet are on the step, lower your left foot back down to the starting position, keeping your right foot on the step.","Repeat the movement, alternating which foot you step up with each time.","Continue for the desired number of repetitions."],"it":["Mettiti davanti a un gradino o a una piattaforma con un manubrio in ogni mano, i palmi rivolti ai lati.","Metti il piede destro sul gradino, assicurandoti che tutto il piede sia in superficie.","Spingi attraverso il tallone destro e solleva il corpo sul gradino, portando anche il piede sinistro verso l'alto.","Una volta che entrambi i piedi sono sul gradino, abbassa il piede sinistro fino alla posizione iniziale, mantenendo il piede destro sul gradino.","Ripeti il movimento, alternando ogni volta con quale piede salire con il piede.","Continua per il numero desiderato di ripetizioni."]}},{"id":"2812","name":"dumbbell step-up split squat","category":"upper legs","equipment":"dumbbell","target":"quads","secondary":["glutes","hamstrings","calves"],"steps":{"en":["Stand in front of a bench or step with a dumbbell in each hand, palms facing your body.","Place your right foot on the bench or step, ensuring your entire foot is in contact with the surface.","Step up onto the bench or step with your right foot, pushing through your heel to lift your body up.","As you step up, simultaneously lift your left knee towards your chest.","Pause at the top of the movement, then slowly lower your left foot back to the ground while keeping your right foot on the bench or step.","Repeat the movement with your left foot on the bench or step.","Continue alternating between your right and left foot for the desired number of repetitions."],"it":["Mettiti davanti a una panchina o mettiti un passo con un manubrio in ciascuna mano, i palmi rivolti verso il corpo.","Appoggia il piede destro sulla panca o sul gradino, assicurandoti che tutto il piede sia a contatto con la superficie.","Sali sulla panca o con il piede destro, spingendo attraverso il tallone per sollevare il corpo.","Mentre ti alzi, solleva contemporaneamente il ginocchio sinistro verso il petto.","Fermati all'inizio del movimento, poi abbassa lentamente il piede sinistro a terra mantenendo il piede destro sulla panca o sul passo.","Ripeti il movimento con il piede sinistro sulla panca o sul passo.","Continua ad alternare tra il piede destro e quello sinistro per il numero desiderato di ripetizioni."]}},{"id":"0432","name":"dumbbell stiff leg deadlift","category":"upper legs","equipment":"dumbbell","target":"glutes","secondary":["hamstrings","lower back"],"steps":{"en":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand with an overhand grip.","Keeping your back straight and your core engaged, hinge at the hips and lower the dumbbells towards the ground, allowing a slight bend in your knees.","Lower the dumbbells until you feel a stretch in your hamstrings, then squeeze your glutes and push through your heels to return to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai con i piedi a larghezza delle spalle, tenendo un manubrio in ogni mano con una presa sopra la testa.","Tieni la schiena dritta e il core attivo, incurva i fianchi e abbassa i manubri verso terra, permettendo una leggera piegatura delle ginocchia.","Abbassa i manubri finché non senti uno stiramento ai muscoli femorale, poi stringi i glutei e spingi attraverso i talloni per tornare alla posizione di partenza.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0433","name":"dumbbell straight arm pullover","category":"chest","equipment":"dumbbell","target":"pectorals","secondary":["latissimus dorsi","triceps"],"steps":{"en":["Lie flat on a bench with your head at one end and your feet planted firmly on the ground.","Hold a dumbbell with both hands and extend your arms straight above your chest.","Keeping your arms straight, slowly lower the dumbbell behind your head in an arc-like motion.","Pause for a moment, then raise the dumbbell back to the starting position.","Repeat for the desired number of repetitions."],"it":["Sdraiati disteso su una panchina con la testa a un'estremità e i piedi ben piantati a terra.","Tieni un manubrio con entrambe le mani e estendi le braccia dritte sopra il petto.","Tenendo le braccia dritte, abbassa lentamente il manubrio dietro la testa in un movimento ad arco.","Fermati un attimo, poi solleva il manubrio di nuovo alla posizione di partenza.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0434","name":"dumbbell straight leg deadlift","category":"upper legs","equipment":"dumbbell","target":"glutes","secondary":["hamstrings","lower back"],"steps":{"en":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand with an overhand grip.","Keeping your back straight and your core engaged, hinge at the hips and lower the dumbbells towards the ground, allowing your torso to lean forward.","Continue lowering the dumbbells until you feel a stretch in your hamstrings, keeping your knees slightly bent.","Pause for a moment at the bottom, then engage your glutes and hamstrings to lift your torso back up to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai con i piedi a larghezza delle spalle, tenendo un manubrio in ogni mano con una presa sopra la testa.","Mantenendo la schiena dritta e il core attivo, incurva i fianchi e abbassa i manubri verso terra, permettendo al busto di inclinarsi in avanti.","Continua ad abbassare i manubri finché non senti uno stiramento ai muscoli femorale, mantenendo le ginocchia leggermente piegate.","Fermati un attimo in basso, poi attiva glutei e muscoli posteriori femorale per sollevare il busto fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"2808","name":"dumbbell sumo pull through","category":"upper legs","equipment":"dumbbell","target":"glutes","secondary":["hamstrings","quadriceps","core"],"steps":{"en":["Stand with your feet wider than shoulder-width apart, toes pointed outwards.","Hold a dumbbell with both hands in front of your body, arms extended.","Bend your knees and lower your hips down into a squat position, keeping your back straight.","Lower the dumbbell down between your legs, keeping your arms straight.","Drive through your heels and extend your hips forward, pulling the dumbbell up and in front of your body.","Squeeze your glutes at the top of the movement, then lower the dumbbell back down between your legs.","Repeat for the desired number of repetitions."],"it":["Stai in piedi con i piedi più allontanati rispetto alla larghezza delle spalle, le dita rivolte verso l'esterno.","Tieni un manubrio con entrambe le mani davanti al corpo, braccia estese.","Flette le ginocchia e abbassa i fianchi in posizione squat, mantenendo la schiena dritta.","Abbassa il manubrio tra le gambe, tenendo le braccia dritte.","Spingi attraverso i talloni e allunga i fianchi in avanti, tirando il manubrio verso l'alto e davanti al corpo.","Stringi i glutei all'inizio del movimento, poi abbassa di nuovo il manubrio tra le gambe.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"2803","name":"dumbbell supported squat","category":"upper legs","equipment":"dumbbell","target":"quads","secondary":["glutes","hamstrings","calves"],"steps":{"en":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand at your sides.","Keeping your chest up and core engaged, slowly lower your body down by bending your knees and pushing your hips back.","Continue lowering until your thighs are parallel to the ground, or as low as you can comfortably go.","Pause for a moment at the bottom, then push through your heels to return to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai con i piedi a larghezza delle spalle, tenendo un manubrio in ogni mano ai lati.","Mantenendo il petto sollevato e il core impegnato, abbassa lentamente il corpo piegando le ginocchia e spingendo indietro i fianchi.","Continua ad abbassare finché le cosce non sono parallele al suolo, o il più in basso che puoi comodamente.","Fermati un attimo in fondo, poi spingi attraverso i talloni per tornare alla posizione di partenza.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0436","name":"dumbbell tate press","category":"upper arms","equipment":"dumbbell","target":"triceps","secondary":["shoulders"],"steps":{"en":["Sit on a flat bench with a dumbbell in each hand, palms facing each other.","Raise the dumbbells to shoulder height, then rotate your wrists so that your palms are facing away from you.","Press the dumbbells up until your arms are fully extended, then lower them back down to shoulder height.","Rotate your wrists back to the starting position and repeat for the desired number of repetitions."],"it":["Siediti su una panchina piatta con un manubrio in ogni mano, i palmi rivolti l'uno verso l'altro.","Alza i manubri all'altezza delle spalle, poi ruota i polsi in modo che i palmi siano rivolti dall'altra parte.","Premi i manubri finché le braccia non sono completamente estese, poi abbassali fino all'altezza delle spalle.","Ruota i polsi di nuovo alla posizione iniziale e ripeti per il numero desiderato di ripetizioni."]}},{"id":"1742","name":"dumbbell tricep kickback with stork stance","category":"upper arms","equipment":"dumbbell","target":"triceps","secondary":["shoulders"],"steps":{"en":["Stand with your feet shoulder-width apart and hold a dumbbell in your right hand.","Bend your knees slightly and hinge forward at the hips, keeping your back straight.","Bring your right elbow up to your side, keeping it bent at a 90-degree angle.","Extend your right arm straight back, squeezing your triceps.","Pause for a moment, then slowly lower the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch sides."],"it":["Stai con i piedi a larghezza delle spalle e tieni un manubrio nella mano destra.","Piega leggermente le ginocchia e piega in avanti ai fianchi, mantenendo la schiena dritta.","Alza il gomito destro al fianco, mantenendolo piegato a 90 gradi.","Allunga il braccio destro dritto all'indietro, stringendo i tricipiti.","Fermati un attimo, poi abbassa lentamente il manubrio alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni, poi cambia lato."]}},{"id":"1743","name":"dumbbell twisting bench press","category":"upper arms","equipment":"dumbbell","target":"triceps","secondary":["chest","shoulders"],"steps":{"en":["Lie flat on a bench with your feet flat on the ground and your back pressed against the bench.","Hold a dumbbell in each hand with an overhand grip, palms facing away from you.","Extend your arms straight up over your chest, keeping a slight bend in your elbows.","Lower the dumbbells down towards your chest, keeping your elbows close to your body.","As you lower the dumbbells, twist your wrists so that your palms face towards you at the bottom of the movement.","Pause for a moment at the bottom, then reverse the movement by pressing the dumbbells back up to the starting position.","As you press the dumbbells up, twist your wrists back to the starting position with palms facing away from you.","Repeat for the desired number of repetitions."],"it":["Sdraiati disteso su una panca con i piedi piatti a terra e la schiena premuta contro la panca.","Tieni un manubrio in ogni mano con una presa sopra la mano, i palmi rivolti verso di espalle.","Allunga le braccia dritte sopra il petto, mantenendo una leggera piega dei gomiti.","Abbassa i manubri verso il petto, tenendo i gomiti vicini al corpo.","Mentre abbassi i manubri, ruota i polsi in modo che i palmi siano rivolti verso di te alla base del movimento.","Fermati un attimo in basso, poi inverti il movimento premendo di nuovo i manubri verso l'alto fino alla posizione di partenza.","Mentre premi i manubri verso l'alto, ruota i polsi verso la posizione iniziale con i palmi rivolti lontano.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0437","name":"dumbbell upright row","category":"shoulders","equipment":"dumbbell","target":"delts","secondary":["traps","biceps"],"steps":{"en":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand with an overhand grip.","Let the dumbbells hang in front of your thighs, with your arms fully extended.","Keeping your back straight and your core engaged, exhale and lift the dumbbells straight up towards your chin, leading with your elbows.","Pause for a moment at the top, then inhale and slowly lower the dumbbells back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai con i piedi a larghezza delle spalle, tenendo un manubrio in ogni mano con una presa sopra la testa.","Lascia che i manubri pendano davanti alle cosce, con le braccia completamente estese.","Tenendo la schiena dritta e il core attivo, espira e solleva i manubri verso il mento, iniziando con i gomiti.","Fermati un attimo in cima, poi inspira e abbassa lentamente i manubri fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"1765","name":"dumbbell upright row (back pov)","category":"shoulders","equipment":"dumbbell","target":"delts","secondary":["traps","biceps"],"steps":{"en":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand with an overhand grip.","Let the dumbbells hang in front of your thighs, with your arms fully extended and your palms facing your body.","Keeping your back straight and your core engaged, exhale and lift the dumbbells straight up towards your chin, leading with your elbows.","Continue lifting until the dumbbells are at shoulder height, with your elbows pointing out to the sides.","Pause for a moment at the top, then inhale and slowly lower the dumbbells back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai con i piedi a larghezza delle spalle, tenendo un manubrio in ogni mano con una presa sopra la testa.","Lascia che i manubri pendano davanti alle cosce, con le braccia completamente estese e i palmi rivolti verso il corpo.","Tenendo la schiena dritta e il core attivo, espira e solleva i manubri verso il mento, iniziando con i gomiti.","Continua a sollevare fino a quando i manubri non sono all'altezza delle spalle, con i gomiti rivolti ai lati.","Fermati un attimo in cima, poi inspira e abbassa lentamente i manubri fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0864","name":"dumbbell upright shoulder external rotation","category":"shoulders","equipment":"dumbbell","target":"delts","secondary":["rotator cuff","trapezius"],"steps":{"en":["Stand with your feet shoulder-width apart and hold a dumbbell in each hand with your palms facing your body.","Raise your arms out to the sides until they are parallel to the ground, keeping your elbows slightly bent.","Rotate your arms externally, bringing the dumbbells up towards your head while keeping your elbows in the same position.","Pause for a moment at the top, then slowly lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai in piedi con i piedi alla larghezza delle spalle e tieni un manubrio in ciascuna mano con i palmi rivolti verso il corpo.","Alza le braccia ai lati finché non sono parallele al suolo, mantenendo i gomiti leggermente piegati.","Ruota le braccia verso l'esterno, portando i manubri verso la testa mantenendo i gomiti nella posizione giusta.","Fermati un attimo in cima, poi abbassa lentamente i manubri alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"5201","name":"dumbbell waiter biceps curl","category":"upper arms","equipment":"dumbbell","target":"biceps","secondary":["forearms","shoulders"],"steps":{"en":["Stand up straight with a dumbbell in each hand, palms facing forward.","Keep your upper arms close to your body and your elbows tucked in.","Slowly curl the dumbbells up towards your shoulders, keeping your wrists straight.","Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai dritto con un manubrio in ciascuna mano, palmi rivolti in avanti.","Tieni le braccia superiori vicine al corpo e i gomiti raccolti.","Arrotola lentamente i manubri verso le spalle, tenendo i polsi dritti.","Fermati un attimo in cima, poi abbassa lentamente i manubri fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0438","name":"dumbbell w-press","category":"shoulders","equipment":"dumbbell","target":"delts","secondary":["triceps","chest"],"steps":{"en":["Sit on a bench with a dumbbell in each hand, palms facing forward.","Raise the dumbbells to shoulder height, elbows bent and palms facing forward.","Press the dumbbells upward until your arms are fully extended overhead.","Lower the dumbbells back to shoulder height.","Repeat for the desired number of repetitions."],"it":["Siediti su una panchina con un manubrio in ciascuna mano, i palmi rivolti in avanti.","Alza i manubri all'altezza delle spalle, gomiti piegati e palmi rivolti in avanti.","Premi i manubri verso l'alto finché le braccia non sono completamente estese sopra la testa.","Abbassa i manubri fino all'altezza delle spalle.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0439","name":"dumbbell zottman curl","category":"upper arms","equipment":"dumbbell","target":"biceps","secondary":["forearms"],"steps":{"en":["Stand up straight with a dumbbell in each hand, palms facing your body.","Keep your elbows close to your torso and rotate your palms to face forward.","Curl the dumbbells up to your shoulders while keeping your upper arms stationary.","At the top of the movement, rotate your wrists so that your palms are facing away from your body.","Slowly lower the dumbbells back to the starting position, rotating your palms back to facing your body.","Repeat for the desired number of repetitions."],"it":["Stai dritto con un manubrio in ogni mano, palmi rivolti verso il corpo.","Tieni i gomiti vicini al busto e ruota i palmi per rivolgerti in avanti.","Arrotola i manubri fino alle spalle mantenendo ferme le braccia superiori.","All'inizio del movimento, ruota i polsi in modo che i palmi siano rivolti lontano dal corpo.","Abbassa lentamente i manubri fino alla posizione iniziale, ruotando i palmi verso il corpo.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"2294","name":"dumbbell zottman preacher curl","category":"upper arms","equipment":"dumbbell","target":"biceps","secondary":["forearms"],"steps":{"en":["Sit on a preacher bench with a dumbbell in each hand, palms facing up and elbows resting on the pad.","Curl the dumbbells up towards your shoulders, keeping your upper arms stationary and your palms facing up.","At the top of the curl, rotate your wrists so that your palms are facing down.","Slowly lower the dumbbells back down to the starting position, rotating your wrists back to the starting position as you do so.","Repeat for the desired number of repetitions."],"it":["Siediti su una panca da predicatore con un manubrio in ogni mano, i palmi rivolti verso l'alto e i gomiti appoggiati sul cuscinetto.","Arrotola i manubri verso le spalle, tenendo ferme le braccia superiori e i palmi rivolti verso l'alto.","In cima al curl, ruota i polsi in modo che i palmi siano rivolti verso il basso.","Abbassa lentamente i manubri fino alla posizione di partenza, ruotando i polsi di nuovo alla posizione iniziale mentre lo fai.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"2189","name":"dumbbells seated triceps extension","category":"upper arms","equipment":"dumbbell","target":"triceps","secondary":["shoulders"],"steps":{"en":["Sit on a bench with your back straight and feet flat on the ground.","Hold a dumbbell in both hands with an overhand grip, and raise it above your head.","Bend your elbows and lower the dumbbell behind your head, keeping your upper arms close to your ears.","Extend your arms and raise the dumbbell back to the starting position.","Repeat for the desired number of repetitions."],"it":["Siediti su una panchina con la schiena dritta e i piedi piatti a terra.","Tieni un manubrio con entrambe le mani con una presa sopra la mano e sollevalo sopra la testa.","Piega i gomiti e abbassa il manubrio dietro la testa, tenendo le braccia superiori vicino alle orecchie.","Allunga le braccia e riporta il manubrio alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"1167","name":"dynamic chest stretch (male)","category":"chest","equipment":"body weight","target":"pectorals","secondary":["shoulders","triceps"],"steps":{"en":["Stand tall with your feet shoulder-width apart.","Extend your arms straight out to the sides, parallel to the ground.","Slowly bring your arms forward, crossing them in front of your body.","Feel the stretch in your chest muscles.","Hold the stretch for 10-30 seconds.","Return to the starting position and repeat for the desired number of repetitions."],"it":["Stai dritto con i piedi a larghezza delle spalle.","Allunga le braccia dritte ai lati, parallele al suolo.","Porta lentamente le braccia in avanti, incrociandole davanti al corpo.","Senti l'allungamento nei muscoli del petto.","Mantieni lo stretch per 10-30 secondi.","Torna alla posizione iniziale e ripeti per il numero desiderato di ripetizioni."]}},{"id":"3287","name":"elbow dips","category":"upper arms","equipment":"body weight","target":"triceps","secondary":["chest","shoulders"],"steps":{"en":["Sit on the edge of a bench or chair with your hands gripping the edge next to your hips.","Slide your hips forward off the bench and straighten your legs, keeping your heels on the ground.","Bend your elbows and lower your body towards the ground, keeping your back close to the bench.","Pause for a moment at the bottom, then push through your hands to straighten your arms and lift your body back up to the starting position.","Repeat for the desired number of repetitions."],"it":["Siediti sul bordo di una panca o di una sedia con le mani che stringono il bordo accanto ai fianchi.","Fai scivolare i fianchi in avanti dalla panca e raddrizzare le gambe, mantenendo i talloni a terra.","Piega i gomiti e abbassa il corpo verso terra, tenendo la schiena vicina alla panca.","Fermati un attimo in basso, poi spingi tra le mani per raddrizzare le braccia e sollevare il corpo fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"1772","name":"elbow lift - reverse push-up","category":"back","equipment":"body weight","target":"upper back","secondary":["triceps","shoulders"],"steps":{"en":["Start by lying face down on the ground with your legs extended and your hands placed directly under your shoulders.","Engage your core and press through your palms to lift your upper body off the ground, keeping your elbows close to your sides.","Pause at the top for a moment, squeezing your upper back muscles.","Slowly lower your body back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Inizia sdraiandoti a faccia in giù a terra con le gambe distese e le mani posizionate direttamente sotto le spalle.","Attiva il core e premi attraverso i palmi per sollevare la parte superiore del corpo da terra, mantenendo i gomiti vicini ai fianchi.","Fermati un attimo in cima, stringendo i muscoli della parte alta della schiena.","Abbassa lentamente il corpo fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"0443","name":"elbow-to-knee","category":"waist","equipment":"body weight","target":"abs","secondary":["obliques"],"steps":{"en":["Start by lying flat on your back with your knees bent and feet flat on the ground.","Place your hands behind your head with your elbows pointing outwards.","Engage your abs and lift your upper body off the ground, bringing your right elbow towards your left knee.","At the same time, bring your left knee towards your right elbow, creating a twisting motion.","Pause for a moment at the top, then slowly lower your upper body and extend your legs back to the starting position.","Repeat the movement, this time bringing your left elbow towards your right knee and your right knee towards your left elbow.","Continue alternating sides for the desired number of repetitions."],"it":["Inizia sdraiandoti sulla schiena con le ginocchia piegate e i piedi piatti a terra.","Metti le mani dietro la testa con i gomiti rivolti verso l'esterno.","Attiva gli addominali e solleva la parte superiore del corpo da terra, avvicinando il gomito destro al ginocchio sinistro.","Allo stesso tempo, porta il ginocchio sinistro verso il gomito destro, creando un movimento di torsione.","Fermati un attimo in alto, poi abbassa lentamente la parte superiore del corpo e riporta le gambe alla posizione iniziale.","Ripeti il movimento, questa volta portando il gomito sinistro verso il ginocchio destro e il ginocchio destro verso il gomito sinistro.","Continua ad alternare i lati per il numero desiderato di ripetizioni."]}},{"id":"3292","name":"elevator","category":"back","equipment":"body weight","target":"upper back","secondary":["shoulders","trapezius"],"steps":{"en":["Stand with your feet shoulder-width apart and your knees slightly bent.","Place your hands on your hips or cross them in front of your chest.","Keeping your back straight, slowly bend forward at the waist, lowering your upper body towards the ground.","Pause for a moment at the bottom, then slowly raise your upper body back up to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai in piedi con i piedi a larghezza delle spalle e le ginocchia leggermente piegate.","Metti le mani sui fianchi o incrociale davanti al petto.","Tieni la schiena dritta, piegati lentamente in avanti in vita, abbassando la parte superiore del corpo verso terra.","Fermati un attimo in basso, poi solleva lentamente la parte superiore del corpo fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"1332","name":"exercise ball alternating arm ups","category":"back","equipment":"stability ball","target":"lats","secondary":["shoulders","core"],"steps":{"en":["Sit on the stability ball with your feet flat on the ground and your back straight.","Hold a dumbbell in each hand with your palms facing inwards and your arms extended down by your sides.","Engage your core and slowly lift one arm up towards your shoulder, keeping your elbow slightly bent.","Pause for a moment at the top, then slowly lower your arm back down to the starting position.","Repeat the movement with the other arm.","Continue alternating arms for the desired number of repetitions."],"it":["Siediti sulla palla di stabilità con i piedi piatti a terra e la schiena dritta.","Tieni un manubrio in ogni mano con i palmi rivolti verso l'interno e le braccia distese lungo i fianchi.","Attiva il core e solleva lentamente un braccio verso la spalla, tenendo il gomito leggermente piegato.","Fermati un attimo in cima, poi abbassa lentamente il braccio fino alla posizione iniziale.","Ripeti il movimento con l'altro braccio.","Continuare ad alternare le braccia per il numero desiderato di ripetizioni."]}},{"id":"1333","name":"exercise ball back extension with arms extended","category":"back","equipment":"stability ball","target":"spine","secondary":["glutes","hamstrings"],"steps":{"en":["Place the stability ball on the ground and lie face down on top of it, with your hips resting on the ball and your feet against a wall for stability.","Extend your arms straight out in front of you, with your palms facing down.","Engage your core and slowly lift your upper body off the ball, keeping your back straight and your neck in line with your spine.","Pause for a moment at the top, then slowly lower your upper body back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Metti la palla di stabilità a terra e sdraiati a faccia in giù sopra di essa, con i fianchi appoggiati sulla palla e i piedi contro un muro per stabilità.","Allunga le braccia dritte davanti a te, con i palmi rivolti verso il basso.","Attiva il core e solleva lentamente la parte superiore del corpo dalla palla, mantenendo la schiena dritta e il collo allineato con la colonna vertebrale.","Fermati un attimo in cima, poi abbassa lentamente la parte superiore del corpo fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"1334","name":"exercise ball back extension with hands behind head","category":"back","equipment":"stability ball","target":"spine","secondary":["glutes","hamstrings"],"steps":{"en":["Place the stability ball on the ground and lie face down on top of it with your hips resting on the ball.","Position your feet against a wall or other stable surface for support.","Cross your arms behind your head, with your hands touching the back of your head.","Engage your core and slowly lift your upper body off the ball, extending your back until your body forms a straight line from your head to your hips.","Pause for a moment at the top of the movement, then slowly lower your upper body back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Metti la palla di stabilità a terra e sdraiati a faccia in giù sopra di essa con i fianchi appoggiati sulla palla.","Posiziona i piedi contro un muro o un'altra superficie stabile per supporto.","Incrocia le braccia dietro la testa, con le mani che toccano la nuca.","Attiva il core e solleva lentamente la parte superiore del corpo dalla palla, estendendo la schiena finché il corpo non forma una linea retta dalla testa ai fianchi.","Fermati un attimo all'inizio del movimento, poi abbassa lentamente la parte superiore del corpo fino alla posizione iniziale.","Ripeti per il numero desiderato di ripetizioni."]}},{"id":"1335","name":"exercise ball back extension with knees off ground","category":"back","equipment":"stability ball","target":"spine","secondary":["glutes","hamstrings"],"steps":{"en":["Place the stability ball on the ground and lie face down on top of it, with your hips resting on the ball and your feet against a wall for stability.","Position your hands behind your head or crossed over your chest.","Engage your core and slowly lift your upper body off the ball, extending your back until your body forms a straight line from your head to your heels.","Pause for a moment at the top, then slowly lower your upper body back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Posiziona la palla di stabilità a terra e sdraiati a faccia in giù sopra di essa, con i fianchi appoggiati sulla palla e i piedi contro un muro per stabilità.","Posiziona le mani dietro la testa o incrociate sul petto.","Coinvolgi il core e solleva lentamente la parte superiore del corpo dalla palla, estendendo la schiena finché il corpo non forma una linea retta dalla testa ai talloni.","Fermati per un momento in alto, quindi abbassa lentamente la parte superiore del corpo fino alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"1336","name":"exercise ball back extension with rotation","category":"back","equipment":"stability ball","target":"spine","secondary":["glutes","hamstrings"],"steps":{"en":["Start by lying face down on the stability ball with your hips resting on the ball and your feet firmly planted on the ground.","Place your hands behind your head or cross them over your chest.","Engage your core and slowly lift your upper body off the ball, extending your back until your body forms a straight line from your head to your heels.","Pause for a moment at the top, then slowly rotate your torso to one side, keeping your hips and legs stable.","Return to the center and repeat the rotation to the other side.","Lower your upper body back down to the starting position and repeat for the desired number of repetitions."],"it":["Inizia sdraiandoti a faccia in giù sulla palla di stabilità con i fianchi appoggiati sulla palla e i piedi saldamente piantati a terra.","Metti le mani dietro la testa o incrociale sul petto.","Coinvolgi il core e solleva lentamente la parte superiore del corpo dalla palla, estendendo la schiena finché il corpo non forma una linea retta dalla testa ai talloni.","Fermati per un momento in alto, quindi ruota lentamente il busto da un lato, mantenendo i fianchi e le gambe stabili.","Ritorna al centro e ripeti la rotazione sull'altro lato.","Abbassa la parte superiore del corpo nella posizione iniziale e ripeti per il numero di ripetizioni desiderato."]}},{"id":"1744","name":"exercise ball dip","category":"upper arms","equipment":"stability ball","target":"triceps","secondary":["chest","shoulders"],"steps":{"en":["Sit on the stability ball with your feet flat on the ground and your knees bent at a 90-degree angle.","Place your hands on the ball beside your hips, fingers pointing forward.","Engage your triceps and push through your hands to lift your body off the ball, straightening your arms.","Lower your body back down by bending your elbows, keeping them close to your sides.","Repeat for the desired number of repetitions."],"it":["Siediti sulla palla di stabilità con i piedi appoggiati a terra e le ginocchia piegate con un angolo di 90 gradi.","Metti le mani sulla palla accanto ai fianchi, con le dita rivolte in avanti.","Coinvolgi i tricipiti e spingi con le mani per sollevare il corpo dalla palla, raddrizzando le braccia.","Abbassa il corpo piegando i gomiti, tenendoli vicini ai fianchi.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"1559","name":"exercise ball hip flexor stretch","category":"upper legs","equipment":"stability ball","target":"glutes","secondary":["quadriceps","hamstrings"],"steps":{"en":["Place the stability ball on the ground and kneel in front of it.","Place your right foot on top of the stability ball, with your knee bent at a 90-degree angle.","Extend your left leg behind you, keeping it straight.","Lean forward, pushing your hips towards the stability ball, until you feel a stretch in your right hip flexor.","Hold the stretch for 20-30 seconds, then switch sides and repeat."],"it":["Posiziona la palla di stabilità a terra e inginocchiati davanti ad essa.","Posiziona il piede destro sopra la palla di stabilità, con il ginocchio piegato con un angolo di 90 gradi.","Estendi la gamba sinistra dietro di te, mantenendola dritta.","Inclinati in avanti, spingendo i fianchi verso la palla di stabilità, finché non senti un allungamento nel flessore dell'anca destra.","Mantieni la posizione per 20-30 secondi, poi cambia lato e ripeti."]}},{"id":"1338","name":"exercise ball hug","category":"back","equipment":"stability ball","target":"spine","secondary":["shoulders","chest"],"steps":{"en":["Sit on the stability ball with your feet flat on the ground and your back straight.","Hold the stability ball with both hands, hugging it close to your chest.","Engage your core muscles and slowly lean back, keeping your back straight and your feet planted on the ground.","Continue leaning back until you feel a stretch in your back muscles.","Hold the position for a few seconds, then slowly return to the starting position.","Repeat for the desired number of repetitions."],"it":["Siediti sulla palla di stabilità con i piedi appoggiati a terra e la schiena dritta.","Tieni la palla di stabilità con entrambe le mani, abbracciandola vicino al petto.","Coinvolgi i muscoli centrali e inclinati lentamente all'indietro, mantenendo la schiena dritta e i piedi ben piantati a terra.","Continua ad inclinarti all'indietro finché non senti un allungamento nei muscoli della schiena.","Mantieni la posizione per qualche secondo, poi torna lentamente alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"1339","name":"exercise ball lat stretch","category":"back","equipment":"stability ball","target":"lats","secondary":["shoulders","triceps"],"steps":{"en":["Sit on a stability ball with your feet flat on the ground and your back straight.","Hold a dumbbell in one hand and extend your arm straight up overhead.","Slowly lean to the opposite side, feeling a stretch in your lat muscle.","Hold the stretch for 20-30 seconds, then return to the starting position.","Repeat on the other side."],"it":["Siediti su una palla stabilizzata con i piedi appoggiati a terra e la schiena dritta.","Tieni un manubrio in una mano ed estendi il braccio verso l'alto.","Inclinati lentamente verso il lato opposto, avvertendo un allungamento nel muscolo lat.","Mantieni l'allungamento per 20-30 secondi, quindi torna alla posizione di partenza.","Ripeti dall'altra parte."]}},{"id":"1341","name":"exercise ball lower back stretch (pyramid)","category":"back","equipment":"stability ball","target":"lats","secondary":["glutes","hamstrings"],"steps":{"en":["Sit on the stability ball with your feet flat on the ground and your knees bent at a 90-degree angle.","Slowly walk your feet forward, rolling the ball down your back until your lower back is resting on the ball.","Place your hands behind your head or cross them over your chest.","Engage your core and slowly lower your upper body towards the ground, allowing your lower back to stretch over the ball.","Hold the stretch for a few seconds, then slowly return to the starting position.","Repeat for the desired number of repetitions."],"it":["Siediti sulla palla di stabilità con i piedi appoggiati a terra e le ginocchia piegate con un angolo di 90 gradi.","Cammina lentamente con i piedi in avanti, facendo rotolare la palla lungo la schiena finché la parte bassa della schiena non si appoggia sulla palla.","Metti le mani dietro la testa o incrociale sul petto.","Coinvolgi il core e abbassa lentamente la parte superiore del corpo verso il suolo, consentendo alla parte bassa della schiena di allungarsi sulla palla.","Mantieni la posizione per alcuni secondi, quindi torna lentamente alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"1342","name":"exercise ball lying side lat stretch","category":"back","equipment":"stability ball","target":"lats","secondary":["shoulders","triceps"],"steps":{"en":["Lie on your side with your legs extended and your head supported by the stability ball.","Place your top arm on the ball for stability.","Reach your top arm overhead and allow your torso to rotate slightly.","Feel the stretch in your lat muscles on the side of your body.","Hold the stretch for 20-30 seconds, then switch sides and repeat."],"it":["Sdraiati su un fianco con le gambe distese e la testa sostenuta dalla palla di stabilità.","Posiziona il braccio superiore sulla palla per stabilità.","Raggiungi il braccio superiore sopra la testa e consenti al busto di ruotare leggermente.","Senti l'allungamento dei muscoli dorsali sul lato del corpo.","Mantieni la posizione per 20-30 secondi, poi cambia lato e ripeti."]}},{"id":"1382","name":"exercise ball on the wall calf raise","category":"lower legs","equipment":"dumbbell","target":"calves","secondary":["hamstrings","quadriceps"],"steps":{"en":["Stand with your back against a wall and place an exercise ball between your lower back and the wall.","Position your feet shoulder-width apart, with your toes pointing forward.","Hold a dumbbell in each hand, with your arms extended by your sides.","Raise your heels off the ground, lifting your body weight onto the balls of your feet.","Pause for a moment at the top, then slowly lower your heels back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Mettiti con la schiena contro un muro e posiziona una palla da ginnastica tra la parte bassa della schiena e il muro.","Posiziona i piedi alla larghezza delle spalle, con le dita dei piedi rivolte in avanti.","Tieni un manubrio in ciascuna mano, con le braccia distese lungo i fianchi.","Solleva i talloni da terra, sollevando il peso del corpo sugli avampiedi.","Fai una pausa per un momento in alto, quindi abbassa lentamente i talloni nella posizione iniziale.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"3241","name":"exercise ball on the wall calf raise (tennis ball between ankles)","category":"lower legs","equipment":"dumbbell","target":"calves","secondary":["hamstrings","quadriceps"],"steps":{"en":["Stand facing a wall with your feet shoulder-width apart.","Place an exercise ball between the wall and your lower back.","Hold a dumbbell in each hand, with your arms extended by your sides.","Place a tennis ball between your ankles.","Raise your heels off the ground, lifting your body up onto your toes.","Pause for a moment at the top, then slowly lower your heels back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Mettiti di fronte a un muro con i piedi alla larghezza delle spalle.","Posiziona una palla da ginnastica tra il muro e la parte bassa della schiena.","Tieni un manubrio in ciascuna mano, con le braccia distese lungo i fianchi.","Metti una pallina da tennis tra le caviglie.","Solleva i talloni da terra, sollevando il corpo sulle punte dei piedi.","Fai una pausa per un momento in alto, quindi abbassa lentamente i talloni nella posizione iniziale.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"3240","name":"exercise ball on the wall calf raise (tennis ball between knees)","category":"lower legs","equipment":"dumbbell","target":"calves","secondary":["quadriceps","hamstrings"],"steps":{"en":["Stand with your back against a wall and place an exercise ball between your lower back and the wall.","Position your feet shoulder-width apart and slightly in front of you.","Hold a dumbbell in each hand, with your arms extended by your sides.","Place a tennis ball between your knees.","Raise your heels off the ground, lifting your body up onto your toes.","Pause for a moment at the top, then slowly lower your heels back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Mettiti con la schiena contro un muro e posiziona una palla da ginnastica tra la parte bassa della schiena e il muro.","Posiziona i piedi alla larghezza delle spalle e leggermente davanti a te.","Tieni un manubrio in ciascuna mano, con le braccia distese lungo i fianchi.","Metti una pallina da tennis tra le ginocchia.","Solleva i talloni da terra, sollevando il corpo sulle punte dei piedi.","Fai una pausa per un momento in alto, quindi abbassa lentamente i talloni nella posizione iniziale.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"1416","name":"exercise ball one leg prone lower body rotation","category":"upper legs","equipment":"stability ball","target":"glutes","secondary":["hamstrings","quadriceps","core"],"steps":{"en":["Lie face down on the stability ball with your hips resting on the ball and your legs extended straight behind you.","Place your hands on the ground in front of you for support.","Engage your glutes and core muscles to stabilize your body.","Slowly lift one leg off the ground, keeping it straight and parallel to the floor.","Rotate your leg outward, away from your body, while keeping your hips and upper body stable.","Pause for a moment at the end of the rotation, then slowly return your leg to the starting position.","Repeat the rotation with the other leg.","Continue alternating legs for the desired number of repetitions."],"it":["Sdraiati a faccia in giù sulla palla di stabilità con i fianchi appoggiati sulla palla e le gambe distese dritte dietro di te.","Metti le mani a terra davanti a te per supporto.","Coinvolgi i tuoi glutei e i muscoli centrali per stabilizzare il tuo corpo.","Sollevare lentamente una gamba da terra, mantenendola dritta e parallela al pavimento.","Ruota la gamba verso l'esterno, lontano dal corpo, mantenendo stabili i fianchi e la parte superiore del corpo.","Fai una pausa per un momento alla fine della rotazione, quindi riporta lentamente la gamba nella posizione iniziale.","Ripeti la rotazione con l'altra gamba.","Continua ad alternare le gambe per il numero di ripetizioni desiderato."]}},{"id":"1417","name":"exercise ball one legged diagonal kick hamstring curl","category":"upper legs","equipment":"stability ball","target":"glutes","secondary":["hamstrings","calves"],"steps":{"en":["Start by lying on your back with your legs extended and your heels resting on top of the stability ball.","Place your arms by your sides for stability.","Engage your glutes and core muscles to lift your hips off the ground, creating a straight line from your shoulders to your heels.","Bend your right knee and bring it towards your chest, keeping your left leg extended and your foot flexed.","Kick your right leg diagonally across your body, extending it fully and engaging your hamstrings.","Slowly return your right leg to the starting position, maintaining control and stability.","Repeat the movement with your left leg, alternating sides for the desired number of repetitions."],"it":["Inizia sdraiandoti sulla schiena con le gambe distese e i talloni appoggiati sulla palla di stabilità.","Metti le braccia lungo i fianchi per stabilità.","Coinvolgi i glutei e i muscoli centrali per sollevare i fianchi da terra, creando una linea retta dalle spalle ai talloni.","Piega il ginocchio destro e portalo verso il petto, mantenendo la gamba sinistra tesa e il piede flesso.","Calcia la gamba destra in diagonale lungo il corpo, estendendola completamente e impegnando i muscoli posteriori della coscia.","Riporta lentamente la gamba destra nella posizione iniziale, mantenendo controllo e stabilità.","Ripeti il ​​movimento con la gamba sinistra, alternando i lati per il numero di ripetizioni desiderato."]}},{"id":"1296","name":"exercise ball pike push up","category":"chest","equipment":"stability ball","target":"pectorals","secondary":["shoulders","triceps","core"],"steps":{"en":["Start in a push-up position with your hands on the floor and your shins resting on the stability ball.","Engage your core and lift your hips up towards the ceiling, rolling the ball towards your hands.","Keep your legs straight and your body in a pike position, forming an inverted V shape.","Bend your elbows and lower your upper body towards the floor, keeping your head in line with your hands.","Push through your hands and extend your arms to return to the starting position.","Repeat for the desired number of repetitions."],"it":["Inizia in una posizione push-up con le mani sul pavimento e gli stinchi appoggiati sulla palla stabilizzante.","Coinvolgi il tuo core e solleva i fianchi verso il soffitto, facendo rotolare la palla verso le mani.","Mantieni le gambe dritte e il corpo in posizione picca, formando una forma a V rovesciata.","Piega i gomiti e abbassa la parte superiore del corpo verso il pavimento, mantenendo la testa in linea con le mani.","Spingi attraverso le mani ed estendi le braccia per tornare alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"1343","name":"exercise ball prone leg raise","category":"back","equipment":"stability ball","target":"spine","secondary":["abdominals","glutes"],"steps":{"en":["Lie face down on a mat with your legs extended and your toes resting on top of the stability ball.","Place your hands on the ground, shoulder-width apart, and engage your core muscles.","Keeping your legs straight, slowly lift them off the ground, using your lower back and glutes to raise them as high as possible.","Pause for a moment at the top, then slowly lower your legs back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Sdraiati a faccia in giù su un tappetino con le gambe distese e le dita dei piedi appoggiate sulla palla stabilizzante.","Appoggia le mani a terra, alla larghezza delle spalle, e contrai i muscoli centrali.","Tenendo le gambe dritte, sollevale lentamente da terra, usando la parte bassa della schiena e i glutei per sollevarle il più in alto possibile.","Fai una pausa per un momento in alto, quindi abbassa lentamente le gambe fino alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"1560","name":"exercise ball seated hamstring stretch","category":"upper legs","equipment":"stability ball","target":"hamstrings","secondary":["glutes","lower back"],"steps":{"en":["Sit on the stability ball with your feet flat on the ground and your knees bent at a 90-degree angle.","Slowly roll the ball forward, walking your feet out until your upper back is resting on the ball and your legs are extended straight in front of you.","Place your hands on your hips for support.","Engage your core and slowly lower your upper body towards the ground, keeping your back straight and your chest lifted.","Stop when you feel a stretch in your hamstrings, and hold the position for 20-30 seconds.","Slowly return to the starting position by pushing through your heels and using your hamstrings to pull yourself back up.","Repeat for the desired number of repetitions."],"it":["Siediti sulla palla di stabilità con i piedi appoggiati a terra e le ginocchia piegate con un angolo di 90 gradi.","Fai rotolare lentamente la palla in avanti, camminando verso l'esterno finché la parte superiore della schiena non si appoggia sulla palla e le gambe sono distese davanti a te.","Metti le mani sui fianchi per supporto.","Coinvolgi il core e abbassa lentamente la parte superiore del corpo verso terra, mantenendo la schiena dritta e il petto sollevato.","Fermati quando senti un allungamento ai muscoli posteriori della coscia e mantieni la posizione per 20-30 secondi.","Ritorna lentamente alla posizione di partenza spingendo con i talloni e usando i muscoli posteriori della coscia per tirarti su.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"1745","name":"exercise ball seated triceps stretch","category":"upper arms","equipment":"stability ball","target":"triceps","secondary":["shoulders"],"steps":{"en":["Sit on a stability ball with your feet flat on the ground and your back straight.","Hold a dumbbell in one hand and extend your arm straight up above your head.","Bend your elbow and lower the dumbbell behind your head, keeping your upper arm close to your ear.","Hold the stretch for a few seconds, then return to the starting position.","Repeat with the other arm."],"it":["Siediti su una palla stabilizzata con i piedi appoggiati a terra e la schiena dritta.","Tieni un manubrio in una mano e allunga il braccio sopra la testa.","Piega il gomito e abbassa il manubrio dietro la testa, mantenendo la parte superiore del braccio vicino all'orecchio.","Mantieni l'allungamento per alcuni secondi, quindi torna alla posizione di partenza.","Ripeti con l'altro braccio."]}},{"id":"1746","name":"exercise ball supine triceps extension","category":"upper arms","equipment":"dumbbell","target":"triceps","secondary":["shoulders"],"steps":{"en":["Sit on an exercise ball with your feet flat on the ground and your knees bent at a 90-degree angle.","Hold a dumbbell with both hands and extend your arms straight up towards the ceiling.","Slowly lower the dumbbell behind your head, keeping your elbows close to your ears.","Pause for a moment, then raise the dumbbell back up to the starting position.","Repeat for the desired number of repetitions."],"it":["Siediti su una palla da ginnastica con i piedi appoggiati a terra e le ginocchia piegate con un angolo di 90 gradi.","Tieni un manubrio con entrambe le mani ed estendi le braccia verso il soffitto.","Abbassa lentamente il manubrio dietro la testa, tenendo i gomiti vicino alle orecchie.","Fai una pausa per un momento, quindi solleva nuovamente il manubrio nella posizione iniziale.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"2133","name":"farmers walk","category":"upper legs","equipment":"dumbbell","target":"quads","secondary":["calves","forearms","core"],"steps":{"en":["Stand up straight with a dumbbell in each hand, palms facing your sides.","Keep your back straight and your shoulders back.","Take small, controlled steps forward, maintaining an upright posture.","Continue walking for the desired distance or time.","To finish, stop walking and carefully lower the dumbbells to your sides."],"it":["Stai dritto con un manubrio in ciascuna mano, i palmi rivolti verso i fianchi.","Tieni la schiena dritta e le spalle indietro.","Fai piccoli passi controllati in avanti, mantenendo una postura eretta.","Continua a camminare per la distanza o il tempo desiderati.","Per finire, smetti di camminare e abbassa con attenzione i manubri lungo i fianchi."]}},{"id":"0455","name":"finger curls","category":"lower arms","equipment":"barbell","target":"forearms","secondary":["wrist flexors","grip muscles"],"steps":{"en":["Sit on a bench with your feet flat on the ground and hold a barbell with an underhand grip, palms facing up.","Rest your forearms on your thighs, allowing your wrists to hang off the edge.","Slowly curl your fingers towards your palms, squeezing the barbell tightly.","Hold the contraction for a moment, then slowly release your fingers back to the starting position.","Repeat for the desired number of repetitions."],"it":["Sedersi su una panca con i piedi appoggiati a terra e tenere un bilanciere con una presa subdola, con i palmi rivolti verso l'alto.","Appoggia gli avambracci sulle cosce, lasciando che i polsi pendano dal bordo.","Piega lentamente le dita verso i palmi delle mani, stringendo forte il bilanciere.","Mantieni la contrazione per un momento, quindi rilascia lentamente le dita tornando alla posizione iniziale.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"3303","name":"flag","category":"waist","equipment":"body weight","target":"abs","secondary":["obliques","shoulders"],"steps":{"en":["Start by gripping a vertical pole with both hands, palms facing each other, and arms fully extended.","Engage your core and lift your legs off the ground, keeping them straight.","Using your core and upper body strength, raise your legs until they are parallel to the ground.","Hold this position for as long as you can, maintaining a straight body line.","Slowly lower your legs back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Inizia afferrando un palo verticale con entrambe le mani, i palmi rivolti l'uno verso l'altro e le braccia completamente distese.","Coinvolgi il tuo core e solleva le gambe da terra, mantenendole dritte.","Usando la forza del core e della parte superiore del corpo, solleva le gambe finché non sono parallele al suolo.","Mantieni questa posizione il più a lungo possibile, mantenendo una linea del corpo dritta.","Abbassa lentamente le gambe fino alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0456","name":"flexion leg sit up (bent knee)","category":"waist","equipment":"body weight","target":"abs","secondary":["hip flexors"],"steps":{"en":["Lie flat on your back with your knees bent and feet flat on the ground.","Place your hands behind your head with your elbows pointing outwards.","Engaging your abs, slowly lift your upper body off the ground, curling forward until your torso is at a 45-degree angle.","At the same time, lift your legs off the ground, bending your knees and bringing them towards your chest.","Pause for a moment at the top, then slowly lower your upper body and legs back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Sdraiati sulla schiena con le ginocchia piegate e i piedi appoggiati a terra.","Metti le mani dietro la testa con i gomiti rivolti verso l'esterno.","Coinvolgendo gli addominali, solleva lentamente la parte superiore del corpo da terra, piegandoti in avanti finché il busto non forma un angolo di 45 gradi.","Allo stesso tempo, solleva le gambe da terra, piegando le ginocchia e portandole verso il petto.","Fermati per un momento in alto, quindi abbassa lentamente la parte superiore del corpo e le gambe fino alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0457","name":"flexion leg sit up (straight arm)","category":"waist","equipment":"body weight","target":"abs","secondary":["hip flexors","quadriceps"],"steps":{"en":["Lie flat on your back with your legs extended and arms straight above your head.","Engaging your abs, lift your upper body off the ground while simultaneously lifting your legs towards your chest.","Reach your hands towards your toes as you lift your upper body and legs.","Pause for a moment at the top, then slowly lower your upper body and legs back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Sdraiati sulla schiena con le gambe distese e le braccia dritte sopra la testa.","Coinvolgendo gli addominali, solleva la parte superiore del corpo da terra sollevando contemporaneamente le gambe verso il petto.","Raggiungi le mani verso le dita dei piedi mentre sollevi la parte superiore del corpo e le gambe.","Fermati per un momento in alto, quindi abbassa lentamente la parte superiore del corpo e le gambe fino alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0458","name":"floor fly (with barbell)","category":"chest","equipment":"barbell","target":"pectorals","secondary":["deltoids","triceps"],"steps":{"en":["Lie flat on your back on the floor with your knees bent and feet flat on the ground.","Hold a barbell with an overhand grip, arms extended straight up over your chest.","Slowly lower the barbell out to the sides, keeping a slight bend in your elbows.","Lower the barbell until your arms are parallel to the floor, feeling a stretch in your chest.","Pause for a moment, then squeeze your chest muscles to bring the barbell back to the starting position.","Repeat for the desired number of repetitions."],"it":["Sdraiati sulla schiena sul pavimento con le ginocchia piegate e i piedi appoggiati a terra.","Tieni un bilanciere con una presa prona, le braccia tese verso l'alto sopra il petto.","Abbassa lentamente il bilanciere lateralmente, mantenendo una leggera piegatura dei gomiti.","Abbassa il bilanciere finché le braccia non sono parallele al pavimento, avvertendo un allungamento nel petto.","Fai una pausa per un momento, quindi contrai i muscoli del torace per riportare il bilanciere nella posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0459","name":"flutter kicks","category":"upper legs","equipment":"body weight","target":"glutes","secondary":["hip flexors","lower abs"],"steps":{"en":["Lie flat on your back with your legs extended and your hands by your sides.","Engage your core and lift your legs off the ground about 6 inches.","Keeping your legs straight, alternate lifting one leg slightly higher than the other.","Continue this fluttering motion for the desired number of repetitions."],"it":["Sdraiati sulla schiena con le gambe distese e le mani lungo i fianchi.","Coinvolgi il tuo core e solleva le gambe da terra di circa 6 pollici.","Tenendo le gambe dritte, alterna il sollevamento di una gamba leggermente più in alto dell'altra.","Continua questo movimento svolazzante per il numero di ripetizioni desiderato."]}},{"id":"1472","name":"forward jump","category":"upper legs","equipment":"body weight","target":"quads","secondary":["calves","hamstrings","glutes"],"steps":{"en":["Stand with your feet shoulder-width apart.","Bend your knees and lower your body into a squat position.","Swing your arms back for momentum.","Jump forward explosively, extending your hips, knees, and ankles.","Land softly on the balls of your feet and immediately go into the next jump.","Repeat for the desired number of repetitions."],"it":["Stai con i piedi alla larghezza delle spalle.","Piega le ginocchia e abbassa il corpo in una posizione tozza.","Oscilla le braccia indietro per dare slancio.","Salta in avanti in modo esplosivo, estendendo i fianchi, le ginocchia e le caviglie.","Atterra dolcemente sulle punte dei piedi ed esegui immediatamente il salto successivo.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"3470","name":"forward lunge (male)","category":"upper legs","equipment":"body weight","target":"glutes","secondary":["quadriceps","hamstrings","calves"],"steps":{"en":["Stand with your feet hip-width apart and hands on your hips.","Take a big step forward with your right foot, lowering your body into a lunge position.","Bend your right knee to about 90 degrees, keeping your knee aligned with your ankle.","Push off with your right foot and return to the starting position.","Repeat with your left leg, alternating sides for the desired number of repetitions."],"it":["Stai in piedi con i piedi alla larghezza dei fianchi e le mani sui fianchi.","Fai un grande passo avanti con il piede destro, abbassando il corpo in una posizione di affondo.","Piega il ginocchio destro a circa 90 gradi, mantenendo il ginocchio allineato con la caviglia.","Spingi con il piede destro e torna alla posizione di partenza.","Ripeti con la gamba sinistra, alternando i lati per il numero di ripetizioni desiderato."]}},{"id":"3194","name":"frankenstein squat","category":"upper legs","equipment":"barbell","target":"glutes","secondary":["quadriceps","hamstrings","calves"],"steps":{"en":["Stand with your feet shoulder-width apart and hold the barbell in front of your body with straight arms.","Keeping your back straight, lower your body by bending at the knees and hips, as if sitting back into a chair.","Continue lowering until your thighs are parallel to the ground, or as low as you can comfortably go.","Pause for a moment, then push through your heels to return to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai con i piedi alla larghezza delle spalle e tieni il bilanciere davanti al corpo con le braccia tese.","Tenendo la schiena dritta, abbassa il corpo piegando le ginocchia e i fianchi, come se fossi seduto su una sedia.","Continua ad abbassare finché le cosce non sono parallele al suolo o il più in basso possibile.","Fai una pausa per un momento, quindi spingi i talloni per tornare alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"2429","name":"frog crunch","category":"waist","equipment":"body weight","target":"abs","secondary":["hip flexors"],"steps":{"en":["Lie flat on your back with your knees bent and feet flat on the ground.","Place your hands behind your head with your elbows pointing outwards.","Engaging your abs, lift your upper body off the ground, curling forward until your torso is at a 45-degree angle.","Pause for a moment at the top, then slowly lower your upper body back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Sdraiati sulla schiena con le ginocchia piegate e i piedi appoggiati a terra.","Metti le mani dietro la testa con i gomiti rivolti verso l'esterno.","Coinvolgendo gli addominali, solleva la parte superiore del corpo da terra, piegandoti in avanti finché il busto non forma un angolo di 45 gradi.","Fermati per un momento in alto, quindi abbassa lentamente la parte superiore del corpo fino alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"3301","name":"frog planche","category":"waist","equipment":"body weight","target":"abs","secondary":["shoulders","chest","triceps"],"steps":{"en":["Start in a push-up position with your hands shoulder-width apart and your feet together.","Bend your elbows and lower your body towards the ground, keeping your back straight.","As you lower your body, lift your feet off the ground and bring your knees towards your chest.","Hold this position for a few seconds, then extend your legs back out and push yourself back up to the starting position.","Repeat for the desired number of repetitions."],"it":["Inizia in una posizione push-up con le mani alla larghezza delle spalle e i piedi uniti.","Piega i gomiti e abbassa il corpo verso terra, mantenendo la schiena dritta.","Mentre abbassi il corpo, solleva i piedi da terra e avvicina le ginocchia al petto.","Mantieni questa posizione per alcuni secondi, quindi allunga le gambe e ritorna alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"3296","name":"front lever","category":"waist","equipment":"body weight","target":"abs","secondary":["lats","shoulders","forearms"],"steps":{"en":["Start by hanging from a pull-up bar with an overhand grip, hands shoulder-width apart.","Engage your core and pull your shoulder blades down and back.","Bend your knees and tuck them towards your chest.","Simultaneously, lift your legs up and extend them straight out in front of you, keeping your body parallel to the ground.","Hold this position for as long as you can, aiming for a full front lever position.","To release, slowly lower your legs back down and return to the starting position.","Repeat for the desired number of repetitions."],"it":["Inizia appendendoti a una barra per trazioni con una presa prona, con le mani alla larghezza delle spalle.","Coinvolgi il tuo core e tira le scapole verso il basso e all'indietro.","Piega le ginocchia e portale verso il petto.","Allo stesso tempo, solleva le gambe ed estendile davanti a te, mantenendo il corpo parallelo al suolo.","Mantieni questa posizione il più a lungo possibile, puntando a una posizione completamente anteriore della leva.","Per rilasciare, abbassare lentamente le gambe e tornare alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"3295","name":"front lever reps","category":"back","equipment":"body weight","target":"upper back","secondary":["core","shoulders"],"steps":{"en":["Hang from a pull-up bar with an overhand grip, palms facing away from you.","Engage your core and pull your shoulder blades down and back.","Keeping your body straight, lift your legs up until they are parallel to the ground.","Hold this position for as long as you can, aiming for 10-20 seconds.","Slowly lower your legs back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Appendi a una barra per trazioni con una presa prona, con i palmi rivolti lontano da te.","Coinvolgi il tuo core e tira le scapole verso il basso e all'indietro.","Mantenendo il corpo dritto, solleva le gambe finché non sono parallele al suolo.","Mantieni questa posizione il più a lungo possibile, mirando a 10-20 secondi.","Abbassa lentamente le gambe fino alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0464","name":"front plank with twist","category":"waist","equipment":"body weight","target":"abs","secondary":["obliques","shoulders"],"steps":{"en":["Start in a high plank position with your hands directly under your shoulders and your body in a straight line from head to toe.","Engage your core and glutes to maintain a stable position.","Rotate your torso to the right, lifting your right arm and extending it towards the ceiling.","Keep your hips and legs stable as you twist.","Hold for a moment, then return to the starting position.","Repeat the twist on the left side.","Continue alternating sides for the desired number of repetitions."],"it":["Inizia in una posizione di plancia alta con le mani direttamente sotto le spalle e il corpo in linea retta dalla testa ai piedi.","Coinvolgi il core e i glutei per mantenere una posizione stabile.","Ruota il busto verso destra, sollevando il braccio destro ed estendendolo verso il soffitto.","Mantieni i fianchi e le gambe stabili mentre giri.","Mantieni la posizione per un momento, quindi torna alla posizione di partenza.","Ripeti la torsione sul lato sinistro.","Continua ad alternare i lati per il numero di ripetizioni desiderato."]}},{"id":"3315","name":"full maltese","category":"waist","equipment":"body weight","target":"abs","secondary":["shoulders","chest"],"steps":{"en":["Start by standing with your feet shoulder-width apart and your arms extended straight out to the sides.","Slowly lean forward, keeping your arms straight, until your upper body is parallel to the ground.","Engage your core and hold this position for a few seconds.","Return to the starting position by pushing through your feet and standing back up.","Repeat for the desired number of repetitions."],"it":["Inizia stando in piedi con i piedi alla larghezza delle spalle e le braccia distese verso i lati.","Piegati lentamente in avanti, mantenendo le braccia tese, finché la parte superiore del corpo non sarà parallela al suolo.","Coinvolgi il tuo core e mantieni questa posizione per alcuni secondi.","Ritorna alla posizione di partenza spingendo con i piedi e rialzandoti.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"3299","name":"full planche","category":"waist","equipment":"body weight","target":"abs","secondary":["shoulders","chest","triceps"],"steps":{"en":["Start in a push-up position with your hands shoulder-width apart and your fingers pointing forward.","Engage your core and slowly shift your weight forward, lifting your feet off the ground.","Continue shifting your weight forward until your body is parallel to the ground, balancing on your hands.","Hold this position for as long as you can, maintaining a straight body line.","Slowly lower your feet back to the ground and return to the starting position.","Repeat for the desired number of repetitions."],"it":["Inizia in una posizione push-up con le mani alla larghezza delle spalle e le dita rivolte in avanti.","Coinvolgi il tuo core e sposta lentamente il peso in avanti, sollevando i piedi da terra.","Continua a spostare il peso in avanti finché il corpo non è parallelo al suolo, in equilibrio sulle mani.","Mantieni questa posizione il più a lungo possibile, mantenendo una linea del corpo dritta.","Abbassa lentamente i piedi a terra e torna alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"3327","name":"full planche push-up","category":"chest","equipment":"body weight","target":"pectorals","secondary":["shoulders","triceps","core"],"steps":{"en":["Start in a push-up position with your hands placed slightly wider than shoulder-width apart.","Engage your core and lower your body down towards the ground, keeping your elbows close to your sides.","As you lower yourself, lean your body forward and lift your feet off the ground, balancing on your hands.","Continue to lower your body until your chest is just above the ground.","Push through your hands and extend your arms to lift your body back up to the starting position.","Maintain a straight line from your head to your heels throughout the movement.","Repeat for the desired number of repetitions."],"it":["Inizia in una posizione push-up con le mani posizionate leggermente più larghe della larghezza delle spalle.","Coinvolgi il core e abbassa il corpo verso terra, mantenendo i gomiti vicini ai fianchi.","Mentre ti abbassi, inclina il corpo in avanti e solleva i piedi da terra, in equilibrio sulle mani.","Continua ad abbassare il corpo finché il petto non si trova appena sopra il suolo.","Spingi attraverso le mani ed estendi le braccia per riportare il corpo alla posizione di partenza.","Mantieni una linea retta dalla testa ai talloni durante tutto il movimento.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0466","name":"gironda sternum chin","category":"back","equipment":"body weight","target":"lats","secondary":["biceps","rhomboids","rear deltoids"],"steps":{"en":["Stand facing a high bar with your feet shoulder-width apart.","Reach up and grab the bar with an overhand grip, slightly wider than shoulder-width apart.","Hang from the bar with your arms fully extended and your body straight.","Engage your lats and biceps to pull your chest up towards the bar, leading with your sternum.","Pause for a moment at the top, then slowly lower yourself back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Mettiti di fronte a una barra alta con i piedi alla larghezza delle spalle.","Allungati e afferra la barra con una presa prona, leggermente più larga della larghezza delle spalle.","Appendi alla barra con le braccia completamente distese e il corpo dritto.","Coinvolgi i dorsali e i bicipiti per sollevare il petto verso la barra, guidando con lo sterno.","Fermati per un momento in alto, quindi abbassati lentamente fino alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"3561","name":"glute bridge march","category":"upper legs","equipment":"body weight","target":"glutes","secondary":["hamstrings","quadriceps"],"steps":{"en":["Lie flat on your back with your knees bent and feet flat on the ground.","Engage your glutes and lift your hips off the ground, forming a straight line from your knees to your shoulders.","While keeping your hips lifted, lift one foot off the ground and bring your knee towards your chest.","Lower your foot back to the ground and repeat the movement with the other leg.","Continue alternating legs in a marching motion while maintaining the bridge position.","Repeat for the desired number of repetitions."],"it":["Sdraiati sulla schiena con le ginocchia piegate e i piedi appoggiati a terra.","Coinvolgi i glutei e solleva i fianchi da terra, formando una linea retta dalle ginocchia alle spalle.","Tenendo i fianchi sollevati, solleva un piede da terra e avvicina il ginocchio al petto.","Riporta il piede a terra e ripeti il ​​movimento con l'altra gamba.","Continua ad alternare le gambe in un movimento di marcia mantenendo la posizione del ponte.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"3523","name":"glute bridge two legs on bench (male)","category":"upper legs","equipment":"body weight","target":"glutes","secondary":["hamstrings","core"],"steps":{"en":["Sit on the edge of a bench with your back against it and your feet flat on the ground.","Place your hands on the bench beside your hips for support.","Engage your glutes and hamstrings, then lift your hips off the bench until your body forms a straight line from your knees to your shoulders.","Pause for a moment at the top, then slowly lower your hips back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Siediti sul bordo di una panca con la schiena appoggiata e i piedi appoggiati a terra.","Metti le mani sulla panca accanto ai fianchi per supporto.","Coinvolgi i glutei e i muscoli posteriori della coscia, quindi solleva i fianchi dalla panca finché il tuo corpo non forma una linea retta dalle ginocchia alle spalle.","Fai una pausa per un momento in alto, quindi abbassa lentamente i fianchi fino alla posizione iniziale.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"3193","name":"glute-ham raise","category":"upper legs","equipment":"body weight","target":"hamstrings","secondary":["glutes","lower back"],"steps":{"en":["Adjust the glute-ham raise machine to fit your body.","Position yourself face down on the machine with your ankles secured.","Place your hands on your chest or cross them over your chest.","Engage your hamstrings and glutes to lift your upper body up towards the ceiling.","Continue lifting until your body is in a straight line from your head to your heels.","Pause for a moment at the top, then slowly lower your body back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Regola la macchina per il sollevamento dei glutei per adattarla al tuo corpo.","Posizionati a faccia in giù sulla macchina con le caviglie fissate.","Metti le mani sul petto o incrociale sul petto.","Coinvolgi i muscoli posteriori della coscia e i glutei per sollevare la parte superiore del corpo verso il soffitto.","Continua a sollevare finché il tuo corpo non è in linea retta dalla testa ai talloni.","Fai una pausa per un momento in alto, quindi abbassa lentamente il corpo fino alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0467","name":"gorilla chin","category":"waist","equipment":"body weight","target":"abs","secondary":["forearms","biceps"],"steps":{"en":["Stand with your feet shoulder-width apart and your knees slightly bent.","Grasp a pull-up bar with an overhand grip, slightly wider than shoulder-width apart.","Hang from the bar with your arms fully extended and your palms facing away from you.","Engage your core and pull your body up towards the bar, bringing your chin above the bar.","Pause for a moment at the top, then slowly lower your body back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai con i piedi alla larghezza delle spalle e le ginocchia leggermente piegate.","Afferrare una barra per trazioni con una presa prona, leggermente più larga della larghezza delle spalle.","Appendi alla barra con le braccia completamente distese e i palmi rivolti lontano da te.","Coinvolgi il core e solleva il corpo verso la barra, portando il mento sopra la barra.","Fai una pausa per un momento in alto, quindi abbassa lentamente il corpo fino alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0469","name":"groin crunch","category":"waist","equipment":"body weight","target":"abs","secondary":["hip flexors","inner thighs"],"steps":{"en":["Lie flat on your back with your knees bent and feet flat on the ground.","Place your hands behind your head with your elbows pointing outwards.","Engaging your abs, lift your legs off the ground, bringing your knees towards your chest.","Pause for a moment at the top, then slowly lower your legs back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Sdraiati sulla schiena con le ginocchia piegate e i piedi appoggiati a terra.","Metti le mani dietro la testa con i gomiti rivolti verso l'esterno.","Coinvolgendo gli addominali, solleva le gambe da terra, portando le ginocchia verso il petto.","Fai una pausa per un momento in alto, quindi abbassa lentamente le gambe fino alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"3221","name":"half knee bends (male)","category":"cardio","equipment":"body weight","target":"cardiovascular system","secondary":["quadriceps","hamstrings","glutes"],"steps":{"en":["Stand with your feet shoulder-width apart.","Bend your knees and lower your body down as if you were sitting back into a chair.","Keep your chest up and your weight in your heels.","Pause for a moment at the bottom, then push through your heels to return to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai con i piedi alla larghezza delle spalle.","Piega le ginocchia e abbassa il corpo come se fossi seduto su una sedia.","Tieni il petto in alto e il peso sui talloni.","Fai una pausa per un momento in fondo, quindi spingi i talloni per tornare alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"3202","name":"half sit-up (male)","category":"waist","equipment":"body weight","target":"abs","secondary":["hip flexors"],"steps":{"en":["Lie flat on your back with your knees bent and feet flat on the ground.","Place your hands behind your head with your elbows pointing outwards.","Engaging your abs, slowly lift your upper body off the ground, curling forward until your torso is at a 45-degree angle.","Pause for a moment at the top, then slowly lower your upper body back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Sdraiati sulla schiena con le ginocchia piegate e i piedi appoggiati a terra.","Metti le mani dietro la testa con i gomiti rivolti verso l'esterno.","Coinvolgendo gli addominali, solleva lentamente la parte superiore del corpo da terra, piegandoti in avanti finché il busto non forma un angolo di 45 gradi.","Fermati per un momento in alto, quindi abbassa lentamente la parte superiore del corpo fino alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"1511","name":"hamstring stretch","category":"upper legs","equipment":"body weight","target":"hamstrings","secondary":["glutes"],"steps":{"en":["Stand with your feet shoulder-width apart.","Step forward with your right foot and shift your weight onto your right leg.","Keeping your back straight, slowly bend forward at the hips, reaching towards your right foot with both hands.","Hold the stretch for 20-30 seconds, then return to the starting position.","Repeat on the other side."],"it":["Stai con i piedi alla larghezza delle spalle.","Fai un passo avanti con il piede destro e sposta il peso sulla gamba destra.","Tenendo la schiena dritta, piegati lentamente in avanti sui fianchi, raggiungendo il piede destro con entrambe le mani.","Mantieni l'allungamento per 20-30 secondi, quindi torna alla posizione di partenza.","Ripeti dall'altra parte."]}},{"id":"3218","name":"hands clasped circular toe touch (male)","category":"upper legs","equipment":"body weight","target":"glutes","secondary":["hamstrings","quadriceps","calves"],"steps":{"en":["Stand with your feet shoulder-width apart and your hands clasped together in front of your chest.","Bend your knees slightly and hinge forward at the hips, keeping your back straight.","Lower your hands towards your toes in a circular motion, reaching as far as you can without straining.","Pause for a moment at the bottom, then slowly return to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai con i piedi alla larghezza delle spalle e le mani intrecciate davanti al petto.","Piega leggermente le ginocchia e fai perno in avanti sui fianchi, mantenendo la schiena dritta.","Abbassa le mani verso le punte dei piedi con un movimento circolare, arrivando il più lontano possibile senza sforzarti.","Fermati per un momento in basso, quindi torna lentamente alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"3215","name":"hands reversed clasped circular toe touch (male)","category":"upper legs","equipment":"body weight","target":"glutes","secondary":["hamstrings","quadriceps","calves"],"steps":{"en":["Stand with your feet shoulder-width apart and your arms extended to the sides.","Bend forward at the waist, keeping your back straight and your knees slightly bent.","Reach down with your hands and clasp them together behind your legs.","Slowly raise your hands up and over your head in a circular motion, keeping your legs straight.","Continue the circular motion until your hands touch your toes.","Reverse the motion and bring your hands back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai con i piedi alla larghezza delle spalle e le braccia distese ai lati.","Piegati in avanti all'altezza della vita, mantenendo la schiena dritta e le ginocchia leggermente piegate.","Abbassa le mani e uniscile dietro le gambe.","Alza lentamente le mani sopra la testa con un movimento circolare, mantenendo le gambe dritte.","Continua il movimento circolare finché le mani non toccano le dita dei piedi.","Invertire il movimento e riportare le mani nella posizione iniziale.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"3302","name":"handstand","category":"upper arms","equipment":"body weight","target":"triceps","secondary":["shoulders","core"],"steps":{"en":["Find an open space with enough room to perform a handstand.","Place your hands on the ground shoulder-width apart, fingers pointing forward.","Kick your legs up towards the wall, using your core and shoulders to maintain balance.","Once in a handstand position, engage your triceps to support your body weight.","Hold the handstand for as long as you can maintain balance.","To come down, slowly lower your legs back to the ground.","Repeat for the desired number of repetitions."],"it":["Trova uno spazio aperto con spazio sufficiente per eseguire una verticale.","Appoggia le mani a terra alla larghezza delle spalle, con le dita rivolte in avanti.","Calcia le gambe verso il muro, usando il core e le spalle per mantenere l'equilibrio.","Una volta in posizione verticale, coinvolgi i tricipiti per sostenere il peso corporeo.","Mantieni la verticale finché riesci a mantenere l'equilibrio.","Per scendere, abbassa lentamente le gambe a terra.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0471","name":"handstand push-up","category":"upper arms","equipment":"body weight","target":"triceps","secondary":["shoulders","chest","core"],"steps":{"en":["Find a wall and face away from it, standing a few feet away.","Place your hands on the ground shoulder-width apart and kick your feet up against the wall, coming into a handstand position.","Bend your elbows and lower your head towards the ground, keeping your body in a straight line.","Push through your hands and extend your arms to return to the starting position.","Repeat for the desired number of repetitions."],"it":["Trova un muro e guardalo lontano, stando a pochi metri di distanza.","Appoggia le mani a terra alla larghezza delle spalle e calcia i piedi contro il muro, arrivando in posizione verticale.","Piega i gomiti e abbassa la testa verso terra, mantenendo il corpo in linea retta.","Spingi attraverso le mani ed estendi le braccia per tornare alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"1764","name":"hanging leg hip raise","category":"waist","equipment":"body weight","target":"abs","secondary":["hip flexors","lower back"],"steps":{"en":["Hang from a pull-up bar with your arms fully extended and your palms facing away from you.","Engage your core and lift your legs up by flexing your hips and knees until your thighs are parallel to the ground.","Pause for a moment at the top, then slowly lower your legs back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Appendi a una barra per trazioni con le braccia completamente distese e i palmi rivolti lontano da te.","Coinvolgi il core e solleva le gambe flettendo i fianchi e le ginocchia finché le cosce non sono parallele al suolo.","Fai una pausa per un momento in alto, quindi abbassa lentamente le gambe fino alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0472","name":"hanging leg raise","category":"waist","equipment":"body weight","target":"abs","secondary":["hip flexors"],"steps":{"en":["Hang from a pull-up bar with your arms fully extended and your palms facing away from you.","Engage your core and lift your legs up in front of you, keeping them straight.","Continue lifting until your legs are parallel to the ground or as high as you can comfortably go.","Pause for a moment at the top, then slowly lower your legs back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Appendi a una barra per trazioni con le braccia completamente distese e i palmi rivolti lontano da te.","Coinvolgi il tuo core e solleva le gambe davanti a te, mantenendole dritte.","Continua a sollevare finché le gambe non sono parallele al suolo o il più in alto possibile.","Fai una pausa per un momento in alto, quindi abbassa lentamente le gambe fino alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"1761","name":"hanging oblique knee raise","category":"waist","equipment":"body weight","target":"abs","secondary":["obliques"],"steps":{"en":["Hang from a pull-up bar with your arms fully extended and your palms facing away from you.","Engage your core and lift your knees towards your chest, twisting your torso to the side as you do so.","Pause for a moment at the top, then slowly lower your legs back down to the starting position.","Repeat on the other side, twisting your torso in the opposite direction.","Continue alternating sides for the desired number of repetitions."],"it":["Appendi a una barra per trazioni con le braccia completamente distese e i palmi rivolti lontano da te.","Coinvolgi il tuo core e solleva le ginocchia verso il petto, ruotando il busto di lato mentre lo fai.","Fai una pausa per un momento in alto, quindi abbassa lentamente le gambe fino alla posizione di partenza.","Ripeti dall'altro lato, ruotando il busto nella direzione opposta.","Continua ad alternare i lati per il numero di ripetizioni desiderato."]}},{"id":"0473","name":"hanging pike","category":"waist","equipment":"body weight","target":"abs","secondary":["hip flexors","shoulders"],"steps":{"en":["Hang from a pull-up bar with your arms fully extended and your palms facing away from you.","Engage your core and lift your legs up towards the bar, keeping them straight.","Continue lifting until your body forms a 'V' shape, with your legs parallel to the ground.","Hold the position for a moment, then slowly lower your legs back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Appendi a una barra per trazioni con le braccia completamente distese e i palmi rivolti lontano da te.","Coinvolgi il core e solleva le gambe verso la barra, mantenendole dritte.","Continua a sollevare finché il tuo corpo non forma una \"V\", con le gambe parallele al suolo.","Mantieni la posizione per un momento, quindi abbassa lentamente le gambe fino alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0474","name":"hanging straight leg hip raise","category":"waist","equipment":"body weight","target":"abs","secondary":["hip flexors"],"steps":{"en":["Hang from a pull-up bar with your arms fully extended and your palms facing away from you.","Engage your core and lift your legs up in front of you until they are parallel to the ground.","Pause for a moment at the top, then slowly lower your legs back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Appendi a una barra per trazioni con le braccia completamente distese e i palmi rivolti lontano da te.","Coinvolgi il tuo core e solleva le gambe davanti a te finché non sono parallele al suolo.","Fai una pausa per un momento in alto, quindi abbassa lentamente le gambe fino alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0475","name":"hanging straight leg raise","category":"waist","equipment":"body weight","target":"abs","secondary":["hip flexors"],"steps":{"en":["Hang from a pull-up bar with your arms fully extended and your palms facing away from you.","Engage your core and lift your legs up in front of you, keeping them straight.","Continue lifting until your legs are parallel to the ground or as high as you can comfortably go.","Pause for a moment at the top, then slowly lower your legs back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Appendi a una barra per trazioni con le braccia completamente distese e i palmi rivolti lontano da te.","Coinvolgi il tuo core e solleva le gambe davanti a te, mantenendole dritte.","Continua a sollevare finché le gambe non sono parallele al suolo o il più in alto possibile.","Fai una pausa per un momento in alto, quindi abbassa lentamente le gambe fino alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0476","name":"hanging straight twisting leg hip raise","category":"waist","equipment":"body weight","target":"abs","secondary":["obliques","hip flexors"],"steps":{"en":["Hang from a pull-up bar with your arms fully extended and your legs straight.","Engage your core and lift your legs up towards your chest, keeping them straight.","Once your legs are parallel to the ground, twist your hips to one side, bringing your legs towards that side.","Pause for a moment, then return to the starting position.","Repeat the movement, but this time twist your hips to the opposite side.","Continue alternating sides for the desired number of repetitions."],"it":["Appendersi a una barra per trazioni con le braccia completamente distese e le gambe dritte.","Coinvolgi il tuo core e solleva le gambe verso il petto, mantenendole dritte.","Una volta che le gambe sono parallele al suolo, ruota i fianchi da un lato, portando le gambe verso quel lato.","Fare una pausa per un momento, quindi tornare alla posizione di partenza.","Ripeti il ​​movimento, ma questa volta ruota i fianchi verso il lato opposto.","Continua ad alternare i lati per il numero di ripetizioni desiderato."]}},{"id":"3636","name":"high knee against wall","category":"cardio","equipment":"body weight","target":"cardiovascular system","secondary":["quadriceps","hamstrings","glutes","calves"],"steps":{"en":["Stand facing a wall with your feet hip-width apart.","Place your hands on the wall for support.","Engage your core and lift your right knee up towards your chest, while keeping your left foot on the ground.","Quickly switch legs, bringing your left knee up towards your chest and lowering your right foot back down.","Continue alternating legs in a running motion, bringing your knees up as high as possible.","Maintain a fast pace and keep your upper body stable throughout the exercise.","Repeat for the desired duration or number of repetitions."],"it":["Mettiti di fronte a un muro con i piedi alla larghezza dei fianchi.","Metti le mani sul muro per supporto.","Coinvolgi il core e solleva il ginocchio destro verso il petto, mantenendo il piede sinistro a terra.","Cambia rapidamente gamba, portando il ginocchio sinistro verso il petto e abbassando il piede destro.","Continua ad alternare le gambe con un movimento di corsa, portando le ginocchia il più in alto possibile.","Mantieni un ritmo veloce e mantieni stabile la parte superiore del corpo durante l'esercizio.","Ripetere per la durata o il numero di ripetizioni desiderato."]}},{"id":"0484","name":"hip raise (bent knee)","category":"waist","equipment":"body weight","target":"abs","secondary":["glutes","hamstrings"],"steps":{"en":["Lie flat on your back with your knees bent and feet flat on the ground.","Place your hands by your sides, palms facing down.","Engage your core and glutes, then lift your hips off the ground until your body forms a straight line from your knees to your shoulders.","Pause for a moment at the top, then slowly lower your hips back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Sdraiati sulla schiena con le ginocchia piegate e i piedi appoggiati a terra.","Metti le mani lungo i fianchi, i palmi rivolti verso il basso.","Coinvolgi il core e i glutei, quindi solleva i fianchi da terra finché il tuo corpo non forma una linea retta dalle ginocchia alle spalle.","Fai una pausa per un momento in alto, quindi abbassa lentamente i fianchi fino alla posizione iniziale.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"1418","name":"hug keens to chest","category":"upper legs","equipment":"body weight","target":"glutes","secondary":["hamstrings","quadriceps"],"steps":{"en":["Start by standing with your feet shoulder-width apart.","Bend your knees and lower your body down into a squat position.","As you squat down, bring your knees up towards your chest and hug them with your arms.","Hold this position for a moment, then slowly return to the starting position.","Repeat for the desired number of repetitions."],"it":["Inizia stando in piedi con i piedi alla larghezza delle spalle.","Piega le ginocchia e abbassa il corpo in una posizione tozza.","Mentre ti accovacci, porta le ginocchia verso il petto e abbracciale con le braccia.","Mantieni questa posizione per un momento, quindi torna lentamente alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"3234","name":"hyght dumbbell fly","category":"chest","equipment":"dumbbell","target":"pectorals","secondary":["shoulders"],"steps":{"en":["Lie flat on a bench with a dumbbell in each hand, palms facing each other.","Extend your arms straight up over your chest, with a slight bend in your elbows.","Keeping a slight bend in your elbows, lower the dumbbells out to the sides in a wide arc until you feel a stretch in your chest.","Pause for a moment, then reverse the movement and bring the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"it":["Sdraiati su una panca con un manubrio in ciascuna mano, i palmi rivolti l'uno verso l'altro.","Estendi le braccia verso l'alto sul petto, con una leggera piegatura dei gomiti.","Mantenendo una leggera piegatura dei gomiti, abbassa i manubri lateralmente descrivendo un ampio arco finché non senti un allungamento nel petto.","Fate una pausa per un attimo, poi invertite il movimento e riportate i manubri nella posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0489","name":"hyperextension","category":"back","equipment":"body weight","target":"spine","secondary":["glutes","hamstrings"],"steps":{"en":["Adjust the hyperextension bench so that your upper thighs are resting on the pad and your feet are secured.","Cross your arms over your chest or place your hands behind your head.","Lower your upper body towards the ground while keeping your back straight.","Pause for a moment at the bottom, then raise your upper body back up until it is in line with your legs.","Repeat for the desired number of repetitions."],"it":["Regola la panca per iperestensione in modo che la parte superiore delle cosce poggi sul cuscinetto e i piedi siano fissati.","Incrocia le braccia sul petto o metti le mani dietro la testa.","Abbassa la parte superiore del corpo verso terra mantenendo la schiena dritta.","Fermati per un momento in basso, quindi solleva la parte superiore del corpo fino a quando non è in linea con le gambe.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0488","name":"hyperextension (on bench)","category":"back","equipment":"body weight","target":"spine","secondary":["glutes","hamstrings"],"steps":{"en":["Adjust the hyperextension bench so that your hips are resting comfortably on the pad and your feet are secured.","Cross your arms over your chest or place your hands behind your head.","Slowly lower your upper body towards the ground while keeping your back straight.","Pause for a moment at the bottom, then raise your upper body back up until it is in line with your legs.","Repeat for the desired number of repetitions."],"it":["Regolare la panca per iperestensione in modo che i fianchi poggino comodamente sul cuscinetto e i piedi siano fissati.","Incrocia le braccia sul petto o metti le mani dietro la testa.","Abbassa lentamente la parte superiore del corpo verso terra mantenendo la schiena dritta.","Fermati per un momento in basso, quindi solleva la parte superiore del corpo fino a quando non è in linea con le gambe.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"3289","name":"impossible dips","category":"upper arms","equipment":"body weight","target":"triceps","secondary":["chest","shoulders"],"steps":{"en":["Position yourself between two parallel bars with your arms fully extended and your body suspended in the air.","Bend your knees and cross your ankles.","Lower your body by bending your elbows until your upper arms are parallel to the ground.","Pause for a moment, then push yourself back up to the starting position by straightening your arms.","Repeat for the desired number of repetitions."],"it":["Posizionati tra due barre parallele con le braccia completamente tese e il corpo sospeso in aria.","Piega le ginocchia e incrocia le caviglie.","Abbassa il corpo piegando i gomiti finché la parte superiore delle braccia non è parallela al suolo.","Fai una pausa per un momento, quindi ritorna alla posizione di partenza raddrizzando le braccia.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"1471","name":"inchworm","category":"waist","equipment":"body weight","target":"abs","secondary":["shoulders","hamstrings"],"steps":{"en":["Start in a standing position with your feet hip-width apart.","Bend forward at the waist and place your hands on the ground in front of you.","Walk your hands forward until you are in a high plank position, with your body in a straight line from head to toe.","Pause for a moment, then walk your hands back towards your feet, keeping your legs as straight as possible.","Once your hands reach your feet, stand back up to the starting position.","Repeat for the desired number of repetitions."],"it":["Inizia in posizione eretta con i piedi alla larghezza dei fianchi.","Piegati in avanti all'altezza della vita e metti le mani a terra davanti a te.","Cammina con le mani in avanti fino a raggiungere una posizione di plancia alta, con il corpo in linea retta dalla testa ai piedi.","Fai una pausa per un momento, quindi riporta le mani verso i piedi, mantenendo le gambe il più dritte possibile.","Una volta che le mani raggiungono i piedi, torna alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"3698","name":"inchworm v. 2","category":"waist","equipment":"body weight","target":"abs","secondary":["shoulders","hamstrings"],"steps":{"en":["Start in a standing position with your feet hip-width apart.","Bend forward at the waist and place your hands on the ground in front of you.","Walk your hands forward until you are in a high plank position, with your body in a straight line from head to toe.","Keeping your legs straight, walk your feet towards your hands, bringing your hips up towards the ceiling.","Continue walking your hands forward, repeating the movement for the desired number of repetitions."],"it":["Inizia in posizione eretta con i piedi alla larghezza dei fianchi.","Piegati in avanti all'altezza della vita e metti le mani a terra davanti a te.","Cammina con le mani in avanti fino a raggiungere una posizione di plancia alta, con il corpo in linea retta dalla testa ai piedi.","Tenendo le gambe dritte, avvicina i piedi alle mani, portando i fianchi verso il soffitto.","Continua a portare le mani in avanti, ripetendo il movimento per il numero di ripetizioni desiderato."]}},{"id":"0490","name":"incline close-grip push-up","category":"upper arms","equipment":"body weight","target":"triceps","secondary":["chest","shoulders"],"steps":{"en":["Place your hands on an elevated surface, such as a bench or step, slightly wider than shoulder-width apart.","Extend your legs behind you, resting on the balls of your feet, with your body forming a straight line from head to heels.","Lower your chest towards the elevated surface by bending your elbows, keeping them close to your sides.","Pause for a moment at the bottom, then push yourself back up to the starting position by straightening your arms.","Repeat for the desired number of repetitions."],"it":["Metti le mani su una superficie rialzata, come una panca o un gradino, leggermente più larga della larghezza delle spalle.","Estendi le gambe dietro di te, appoggiandole sulle punte dei piedi, con il corpo che forma una linea retta dalla testa ai talloni.","Abbassa il petto verso la superficie rialzata piegando i gomiti, tenendoli vicini ai fianchi.","Fai una pausa per un momento in basso, quindi ritorna alla posizione di partenza raddrizzando le braccia.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0491","name":"incline leg hip raise (leg straight)","category":"waist","equipment":"body weight","target":"abs","secondary":["hip flexors"],"steps":{"en":["Lie on an incline bench with your back flat against the bench and your legs extended straight out in front of you.","Place your hands on the sides of the bench for support.","Engaging your abs, lift your legs off the bench, raising them as high as you can while keeping them straight.","Pause for a moment at the top, then slowly lower your legs back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Sdraiati su una panca inclinata con la schiena appoggiata alla panca e le gambe distese davanti a te.","Metti le mani sui lati della panca per supporto.","Coinvolgendo gli addominali, solleva le gambe dalla panca, sollevandole più in alto che puoi mantenendole dritte.","Fai una pausa per un momento in alto, quindi abbassa lentamente le gambe fino alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0492","name":"incline push up depth jump","category":"chest","equipment":"body weight","target":"pectorals","secondary":["triceps","shoulders","core"],"steps":{"en":["Find an elevated surface, such as a bench or step, and place your hands shoulder-width apart on the edge.","Step your feet back, keeping your body in a straight line from head to heels.","Lower your chest towards the edge of the surface, bending your elbows and keeping your body aligned.","Push through your palms to extend your arms and return to the starting position.","Jump off the edge of the surface, landing softly with your knees slightly bent.","Repeat the push-up and depth jump for the desired number of repetitions."],"it":["Trova una superficie rialzata, come una panca o un gradino, e posiziona le mani sul bordo alla larghezza delle spalle.","Porta i piedi indietro, mantenendo il corpo in linea retta dalla testa ai talloni.","Abbassa il petto verso il bordo della superficie, piegando i gomiti e mantenendo il corpo allineato.","Spingi attraverso i palmi delle mani per estendere le braccia e tornare alla posizione di partenza.","Salta dal bordo della superficie, atterrando dolcemente con le ginocchia leggermente piegate.","Ripeti il ​​push-up e il salto in profondità per il numero di ripetizioni desiderato."]}},{"id":"0493","name":"incline push-up","category":"chest","equipment":"body weight","target":"pectorals","secondary":["triceps","shoulders"],"steps":{"en":["Place your hands on an elevated surface, such as a bench or step, slightly wider than shoulder-width apart.","Extend your legs behind you, resting on the balls of your feet, creating a straight line from your head to your heels.","Lower your chest towards the elevated surface by bending your elbows, keeping your body in a straight line.","Pause for a moment at the bottom, then push yourself back up to the starting position by straightening your arms.","Repeat for the desired number of repetitions."],"it":["Metti le mani su una superficie rialzata, come una panca o un gradino, leggermente più larga della larghezza delle spalle.","Estendi le gambe dietro di te, appoggiandole sulle punte dei piedi, creando una linea retta dalla testa ai talloni.","Abbassa il petto verso la superficie rialzata piegando i gomiti, mantenendo il corpo in linea retta.","Fai una pausa per un momento in basso, quindi ritorna alla posizione di partenza raddrizzando le braccia.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"3785","name":"incline push-up (on box)","category":"chest","equipment":"body weight","target":"pectorals","secondary":["triceps","shoulders"],"steps":{"en":["Place your hands on the edge of a box or elevated surface, slightly wider than shoulder-width apart.","Extend your legs behind you, resting on the balls of your feet, creating a straight line from your head to your heels.","Lower your chest towards the box by bending your elbows, keeping your body in a straight line.","Pause for a moment at the bottom, then push yourself back up to the starting position by straightening your arms.","Repeat for the desired number of repetitions."],"it":["Metti le mani sul bordo di una scatola o di una superficie rialzata, leggermente più larghe della larghezza delle spalle.","Estendi le gambe dietro di te, appoggiandole sulle punte dei piedi, creando una linea retta dalla testa ai talloni.","Abbassa il petto verso il box piegando i gomiti, mantenendo il corpo in linea retta.","Fai una pausa per un momento in basso, quindi ritorna alla posizione di partenza raddrizzando le braccia.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0494","name":"incline reverse grip push-up","category":"chest","equipment":"body weight","target":"pectorals","secondary":["triceps","shoulders"],"steps":{"en":["Place your hands on the edge of a bench or elevated surface, slightly wider than shoulder-width apart.","Extend your legs behind you, resting on the balls of your feet, creating a straight line from your head to your heels.","Lower your chest towards the bench by bending your elbows, keeping them close to your sides.","Pause for a moment at the bottom, then push yourself back up to the starting position by extending your arms.","Repeat for the desired number of repetitions."],"it":["Metti le mani sul bordo di una panca o di una superficie elevata, leggermente più larghe della larghezza delle spalle.","Estendi le gambe dietro di te, appoggiandole sulle punte dei piedi, creando una linea retta dalla testa ai talloni.","Abbassa il petto verso la panca piegando i gomiti, tenendoli vicini ai fianchi.","Fai una pausa per un momento in basso, quindi spingiti nuovamente nella posizione di partenza estendendo le braccia.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"3011","name":"incline scapula push up","category":"chest","equipment":"body weight","target":"serratus anterior","secondary":["triceps","shoulders"],"steps":{"en":["Set up an incline bench at a 45-degree angle.","Place your hands on the bench slightly wider than shoulder-width apart.","Position your feet on the ground, hip-width apart.","Lower your chest towards the bench, keeping your elbows tucked in.","As you lower, retract your shoulder blades, squeezing your scapulae together.","Push through your palms to extend your arms and return to the starting position.","Repeat for the desired number of repetitions."],"it":["Installa una panca inclinata con un angolo di 45 gradi.","Metti le mani sulla panca leggermente più larghe della larghezza delle spalle.","Posiziona i piedi a terra, alla larghezza dei fianchi.","Abbassa il petto verso la panca, mantenendo i gomiti piegati.","Mentre ti abbassi, ritrai le scapole, stringendo insieme le scapole.","Spingi attraverso i palmi delle mani per estendere le braccia e tornare alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0495","name":"incline twisting sit-up","category":"waist","equipment":"body weight","target":"abs","secondary":["obliques"],"steps":{"en":["Set up an incline bench at a 45-degree angle.","Lie down on the bench with your feet secured under the foot pads.","Place your hands behind your head or across your chest.","Engage your abs and lift your upper body off the bench, curling forward.","As you curl up, twist your torso to one side, bringing your elbow towards the opposite knee.","Pause for a moment at the top, then slowly lower your upper body back down to the starting position.","Repeat the movement, this time twisting your torso to the other side.","Continue alternating sides for the desired number of repetitions."],"it":["Installa una panca inclinata con un angolo di 45 gradi.","Sdraiati sulla panca con i piedi fissati sotto i poggiapiedi.","Metti le mani dietro la testa o sul petto.","Coinvolgi gli addominali e solleva la parte superiore del corpo dalla panca, piegandoti in avanti.","Mentre ti rannicchi, ruota il busto da un lato, portando il gomito verso il ginocchio opposto.","Fermati per un momento in alto, quindi abbassa lentamente la parte superiore del corpo fino alla posizione di partenza.","Ripeti il ​​movimento, questa volta ruotando il busto dall'altra parte.","Continua ad alternare i lati per il numero di ripetizioni desiderato."]}},{"id":"0496","name":"inverse leg curl (bench support)","category":"upper legs","equipment":"body weight","target":"hamstrings","secondary":["glutes","calves"],"steps":{"en":["Lie face down on a bench with your hips at the edge and your legs extended straight behind you.","Hold onto the bench for support.","Keeping your upper body still, bend your knees and curl your legs towards your glutes.","Pause for a moment at the top, then slowly extend your legs back to the starting position.","Repeat for the desired number of repetitions."],"it":["Sdraiati a faccia in giù su una panca con i fianchi sul bordo e le gambe distese dietro di te.","Tieniti sulla panca per supporto.","Tenendo ferma la parte superiore del corpo, piega le ginocchia e piega le gambe verso i glutei.","Fai una pausa per un momento in alto, quindi estendi lentamente le gambe fino alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"2400","name":"inverse leg curl (on pull-up cable machine)","category":"upper legs","equipment":"body weight","target":"hamstrings","secondary":["glutes","calves"],"steps":{"en":["Adjust the cable machine so that the ankle straps are at the lowest setting.","Lie face down on the bench with your legs extended and the ankle straps attached to your feet.","Hold onto the handles of the bench for stability.","Bend your knees and curl your legs towards your glutes, squeezing your hamstrings.","Pause for a moment at the top of the movement, then slowly lower your legs back to the starting position.","Repeat for the desired number of repetitions."],"it":["Regolare la macchina per cavi in ​​modo che le cinghie della caviglia siano nella posizione più bassa.","Sdraiati a faccia in giù sulla panca con le gambe distese e le cinghie alla caviglia attaccate ai piedi.","Aggrapparsi alle maniglie della panca per stabilità.","Piega le ginocchia e piega le gambe verso i glutei, contraendo i muscoli posteriori della coscia.","Fai una pausa per un momento nella parte superiore del movimento, quindi abbassa lentamente le gambe nella posizione iniziale.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0499","name":"inverted row","category":"back","equipment":"body weight","target":"upper back","secondary":["biceps","forearms"],"steps":{"en":["Set up a bar at waist height or use a suspension trainer.","Stand facing the bar or suspension trainer, with your feet shoulder-width apart.","Grab the bar or handles with an overhand grip, slightly wider than shoulder-width apart.","Lean back, keeping your body straight and your heels on the ground.","Pull your chest towards the bar or handles, squeezing your shoulder blades together.","Pause for a moment at the top, then slowly lower yourself back to the starting position.","Repeat for the desired number of repetitions."],"it":["Installa una barra all'altezza della vita o usa un trainer per le sospensioni.","Mettiti di fronte alla barra o al trainer in sospensione, con i piedi alla larghezza delle spalle.","Afferra la barra o le maniglie con una presa prona, leggermente più larga della larghezza delle spalle.","Appoggiati all'indietro, mantenendo il corpo dritto e i talloni a terra.","Tira il petto verso la barra o le maniglie, stringendo insieme le scapole.","Fermati per un momento in alto, quindi abbassati lentamente nella posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"2300","name":"inverted row bent knees","category":"back","equipment":"body weight","target":"upper back","secondary":["biceps","forearms"],"steps":{"en":["Set up a bar at waist height and lie underneath it.","Grab the bar with an overhand grip, slightly wider than shoulder-width apart.","Position your body so that your heels are on the ground and your body is straight.","Pull your chest up towards the bar by squeezing your shoulder blades together.","Pause for a moment at the top, then slowly lower your body back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Posiziona una barra all'altezza della vita e sdraiati sotto di essa.","Afferra la barra con una presa prona, leggermente più larga della larghezza delle spalle.","Posiziona il corpo in modo che i talloni siano a terra e il corpo sia dritto.","Solleva il petto verso la sbarra stringendo insieme le scapole.","Fai una pausa per un momento in alto, quindi abbassa lentamente il corpo fino alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"2298","name":"inverted row on bench","category":"back","equipment":"body weight","target":"upper back","secondary":["biceps","forearms"],"steps":{"en":["Set up a bench at a height that allows your body to hang freely underneath it.","Lie face up on the ground with your head towards the bench.","Reach up and grab the bench with an overhand grip, slightly wider than shoulder-width apart.","Position your body so that your heels are on the ground and your arms are fully extended.","Engage your core and squeeze your shoulder blades together as you pull your chest up towards the bench.","Pause for a moment at the top of the movement, then slowly lower your body back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Posiziona una panca ad un'altezza che permetta al tuo corpo di penzolare liberamente sotto di essa.","Sdraiati a terra con la testa rivolta verso la panca.","Allungati e afferra la panca con una presa prona, leggermente più larga della larghezza delle spalle.","Posiziona il corpo in modo che i talloni siano a terra e le braccia siano completamente distese.","Coinvolgi il core e stringi insieme le scapole mentre sollevi il petto verso la panca.","Fai una pausa per un momento nella parte superiore del movimento, quindi abbassa lentamente il corpo fino alla posizione iniziale.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0497","name":"inverted row v. 2","category":"back","equipment":"body weight","target":"upper back","secondary":["biceps","forearms"],"steps":{"en":["Set up a bar at waist height on a Smith machine or use a suspension trainer.","Stand facing the bar or suspension trainer and grab it with an overhand grip, hands shoulder-width apart.","Walk your feet forward, leaning back until your body is at a slight angle.","Keep your body straight and pull your chest up towards the bar or handles, squeezing your shoulder blades together.","Pause for a moment at the top, then slowly lower yourself back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Installa una barra all'altezza della vita su una macchina Smith o usa un trainer per sospensioni.","Mettiti di fronte alla barra o al trainer in sospensione e afferralo con una presa prona, con le mani alla larghezza delle spalle.","Cammina con i piedi in avanti, inclinandoti all'indietro finché il tuo corpo non forma una leggera angolazione.","Mantieni il corpo dritto e solleva il petto verso la barra o le maniglie, stringendo insieme le scapole.","Fermati per un momento in alto, quindi abbassati lentamente fino alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0498","name":"inverted row with straps","category":"back","equipment":"body weight","target":"upper back","secondary":["biceps","forearms"],"steps":{"en":["Set up a suspension trainer or straps at chest height.","Stand facing the anchor point and grab the handles with an overhand grip.","Walk your feet forward, leaning back until your body is at an angle.","Keep your body straight and engage your core.","Pull your chest towards the handles, squeezing your shoulder blades together.","Pause for a moment at the top, then slowly lower yourself back to the starting position.","Repeat for the desired number of repetitions."],"it":["Installa un trainer in sospensione o delle cinghie all'altezza del petto.","Mettiti di fronte al punto di ancoraggio e afferra le maniglie con una presa prona.","Cammina con i piedi in avanti, inclinandoti all'indietro finché il corpo non forma un angolo.","Mantieni il corpo dritto e coinvolgi il core.","Tira il petto verso le maniglie, stringendo insieme le scapole.","Fermati per un momento in alto, quindi abbassati lentamente nella posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"1419","name":"iron cross stretch","category":"upper legs","equipment":"body weight","target":"glutes","secondary":["hamstrings","quadriceps"],"steps":{"en":["Lie flat on your back with your arms extended out to the sides.","Raise your legs up towards the ceiling, keeping them straight.","Slowly lower your legs to one side, aiming to touch the floor with your feet.","Hold the stretch for a few seconds, then return your legs to the starting position.","Repeat the stretch on the other side.","Continue alternating sides for the desired number of repetitions."],"it":["Sdraiati sulla schiena con le braccia distese lungo i fianchi.","Alza le gambe verso il soffitto, mantenendole dritte.","Abbassa lentamente le gambe da un lato, cercando di toccare il pavimento con i piedi.","Mantieni l'allungamento per alcuni secondi, quindi riporta le gambe nella posizione iniziale.","Ripeti l'allungamento dall'altro lato.","Continua ad alternare i lati per il numero di ripetizioni desiderato."]}},{"id":"1297","name":"isometric chest squeeze","category":"chest","equipment":"body weight","target":"pectorals","secondary":["triceps","shoulders"],"steps":{"en":["Stand with your feet shoulder-width apart and your knees slightly bent.","Extend your arms straight out in front of you, parallel to the ground, with your palms facing each other.","Squeeze your chest muscles together as hard as you can, while keeping your arms straight.","Hold this position for a few seconds, focusing on contracting your chest muscles.","Release the squeeze and relax your chest muscles.","Repeat for the desired number of repetitions."],"it":["Stai con i piedi alla larghezza delle spalle e le ginocchia leggermente piegate.","Estendi le braccia davanti a te, parallele al suolo, con i palmi delle mani uno di fronte all'altro.","Contrai i muscoli del torace più forte che puoi, mantenendo le braccia tese.","Mantieni questa posizione per alcuni secondi, concentrandoti sulla contrazione dei muscoli del torace.","Rilascia la contrazione e rilassa i muscoli del torace.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0500","name":"isometric wipers","category":"chest","equipment":"body weight","target":"pectorals","secondary":["shoulders","triceps","core"],"steps":{"en":["Start by lying flat on your back on a mat or bench.","Extend your arms straight out to the sides, perpendicular to your body.","Engage your core and lift both legs off the ground, keeping them together and straight.","Slowly lower your legs to one side, aiming to touch the ground with your feet while maintaining control.","Pause for a moment, then use your core to lift your legs back to the starting position.","Repeat the movement, this time lowering your legs to the opposite side.","Continue alternating sides for the desired number of repetitions."],"it":["Inizia sdraiandoti sulla schiena su un tappetino o una panca.","Estendi le braccia verso i lati, perpendicolari al corpo.","Coinvolgi il core e solleva entrambe le gambe da terra, mantenendole unite e dritte.","Abbassa lentamente le gambe da un lato, cercando di toccare il suolo con i piedi mantenendo il controllo.","Fai una pausa per un momento, quindi usa il core per riportare le gambe nella posizione iniziale.","Ripeti il ​​movimento, questa volta abbassando le gambe sul lato opposto.","Continua ad alternare i lati per il numero di ripetizioni desiderato."]}},{"id":"0501","name":"jack burpee","category":"cardio","equipment":"body weight","target":"cardiovascular system","secondary":["quadriceps","hamstrings","calves","shoulders","triceps","core"],"steps":{"en":["Start in a standing position with your feet shoulder-width apart.","Lower your body into a squat position, placing your hands on the ground in front of you.","Kick your feet back, landing in a push-up position.","Perform a push-up, lowering your chest to the ground and then pushing back up.","Jump your feet forward, landing in a squat position.","Jump up explosively, reaching your arms overhead.","Land softly and immediately lower back into the squat position to begin the next repetition."],"it":["Inizia in posizione eretta con i piedi alla larghezza delle spalle.","Abbassa il corpo in una posizione tozza, appoggiando le mani a terra davanti a te.","Calcia indietro i piedi, atterrando in una posizione push-up.","Esegui un push-up, abbassando il petto a terra e poi spingendolo verso l'alto.","Salta i piedi in avanti, atterrando in posizione tozza.","Salta in modo esplosivo, portando le braccia sopra la testa.","Atterra dolcemente e abbassati immediatamente nella posizione tozza per iniziare la ripetizione successiva."]}},{"id":"3224","name":"jack jump (male)","category":"cardio","equipment":"body weight","target":"cardiovascular system","secondary":["quadriceps","calves"],"steps":{"en":["Stand with your feet together and your arms by your sides.","Jump up, spreading your feet apart and raising your arms above your head.","As you land, quickly jump back to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai con i piedi uniti e le braccia lungo i fianchi.","Salta in alto, allargando i piedi e alzando le braccia sopra la testa.","Mentre atterri, torna rapidamente alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0507","name":"jackknife sit-up","category":"waist","equipment":"body weight","target":"abs","secondary":["hip flexors"],"steps":{"en":["Lie flat on your back with your legs extended and your arms overhead.","Engage your core and lift your legs and upper body simultaneously, reaching your hands towards your toes.","Pause for a moment at the top, then slowly lower your legs and upper body back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Sdraiati sulla schiena con le gambe distese e le braccia sopra la testa.","Coinvolgi il core e solleva contemporaneamente le gambe e la parte superiore del corpo, portando le mani verso le dita dei piedi.","Fermati per un momento in alto, quindi abbassa lentamente le gambe e la parte superiore del corpo fino alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0508","name":"janda sit-up","category":"waist","equipment":"body weight","target":"abs","secondary":["hip flexors","lower back"],"steps":{"en":["Lie flat on your back with your knees bent and feet flat on the ground.","Place your hands behind your head with your elbows pointing outwards.","Engaging your abs, slowly lift your upper body off the ground, curling forward until your torso is at a 45-degree angle.","Pause for a moment at the top, then slowly lower your upper body back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Sdraiati sulla schiena con le ginocchia piegate e i piedi appoggiati a terra.","Metti le mani dietro la testa con i gomiti rivolti verso l'esterno.","Coinvolgendo gli addominali, solleva lentamente la parte superiore del corpo da terra, piegandoti in avanti finché il busto non forma un angolo di 45 gradi.","Fermati per un momento in alto, quindi abbassa lentamente la parte superiore del corpo fino alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0514","name":"jump squat","category":"upper legs","equipment":"body weight","target":"glutes","secondary":["quadriceps","hamstrings","calves"],"steps":{"en":["Stand with your feet shoulder-width apart.","Lower your body into a squat position by bending your knees and pushing your hips back.","Jump explosively off the ground, extending your hips, knees, and ankles.","While in mid-air, quickly bring your arms forward for balance.","Land softly on the balls of your feet and immediately go into the next repetition.","Repeat for the desired number of repetitions."],"it":["Stai con i piedi alla larghezza delle spalle.","Abbassa il corpo in una posizione tozza piegando le ginocchia e spingendo indietro i fianchi.","Salta in modo esplosivo da terra, estendendo i fianchi, le ginocchia e le caviglie.","Mentre sei a mezz'aria, porta rapidamente le braccia in avanti per mantenere l'equilibrio.","Atterra dolcemente sulle punte dei piedi e passa immediatamente alla ripetizione successiva.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0513","name":"jump squat v. 2","category":"upper legs","equipment":"body weight","target":"glutes","secondary":["quadriceps","hamstrings","calves"],"steps":{"en":["Stand with your feet shoulder-width apart.","Lower your body into a squat position by bending your knees and pushing your hips back.","Jump explosively, extending your hips and knees fully.","Land softly on the balls of your feet and immediately lower your body back into a squat position.","Repeat for the desired number of repetitions."],"it":["Stai con i piedi alla larghezza delle spalle.","Abbassa il corpo in una posizione tozza piegando le ginocchia e spingendo indietro i fianchi.","Salta in modo esplosivo, estendendo completamente le anche e le ginocchia.","Atterra dolcemente sulle punte dei piedi e riporta immediatamente il corpo in posizione tozza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0555","name":"kick out sit","category":"upper legs","equipment":"body weight","target":"hamstrings","secondary":["quadriceps","glutes"],"steps":{"en":["Sit on the edge of a bench or chair with your feet flat on the ground and your knees bent at a 90-degree angle.","Lean back slightly and place your hands on the edge of the bench or chair for support.","Engaging your hamstrings, lift your feet off the ground and extend your legs straight out in front of you.","Pause for a moment at the top, then slowly bend your knees and bring your feet back towards your body.","Repeat for the desired number of repetitions."],"it":["Siediti sul bordo di una panca o di una sedia con i piedi appoggiati a terra e le ginocchia piegate con un angolo di 90 gradi.","Appoggiati leggermente all'indietro e metti le mani sul bordo della panca o della sedia per sostenerti.","Coinvolgendo i muscoli posteriori della coscia, solleva i piedi da terra ed estendi le gambe davanti a te.","Fermati un attimo in alto, poi piega lentamente le ginocchia e riporta i piedi verso il corpo.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0558","name":"kipping muscle up","category":"back","equipment":"body weight","target":"lats","secondary":["biceps","triceps","shoulders","core"],"steps":{"en":["Start by hanging from a pull-up bar with an overhand grip, hands slightly wider than shoulder-width apart.","Engage your core and use a swinging motion to generate momentum.","As you swing forward, pull your chest towards the bar, using your lats and biceps to initiate the movement.","Continue the upward motion until your chest reaches the bar, then transition into a dip position by pushing down on the bar and extending your arms.","Lower yourself back down to the starting position by bending your arms and controlling the descent.","Repeat for the desired number of repetitions."],"it":["Inizia appendendoti a una barra per trazioni con una presa prona, con le mani leggermente più larghe della larghezza delle spalle.","Coinvolgi il tuo core e usa un movimento oscillante per generare slancio.","Mentre ti muovi in ​​avanti, tira il petto verso la barra, usando i dorsali e i bicipiti per iniziare il movimento.","Continua il movimento verso l'alto finché il petto non raggiunge la barra, quindi passa alla posizione dip spingendo verso il basso la barra ed estendendo le braccia.","Abbassati nuovamente nella posizione di partenza piegando le braccia e controllando la discesa.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"3640","name":"knee touch crunch","category":"waist","equipment":"body weight","target":"abs","secondary":["hip flexors"],"steps":{"en":["Lie flat on your back with your knees bent and feet flat on the ground.","Place your hands behind your head with your elbows pointing outwards.","Engaging your abs, lift your shoulder blades off the ground and reach your right hand towards your left knee.","Return to the starting position and repeat, this time reaching your left hand towards your right knee.","Continue alternating sides for the desired number of repetitions."],"it":["Sdraiati sulla schiena con le ginocchia piegate e i piedi appoggiati a terra.","Metti le mani dietro la testa con i gomiti rivolti verso l'esterno.","Coinvolgendo gli addominali, solleva le scapole da terra e allunga la mano destra verso il ginocchio sinistro.","Ritorna alla posizione di partenza e ripeti, questa volta portando la mano sinistra verso il ginocchio destro.","Continua ad alternare i lati per il numero di ripetizioni desiderato."]}},{"id":"1420","name":"kneeling jump squat","category":"upper legs","equipment":"barbell","target":"glutes","secondary":["quadriceps","hamstrings","calves"],"steps":{"en":["Start by kneeling on the ground with your feet hip-width apart and your toes pointing forward.","Hold a barbell across your upper back, resting it on your shoulders.","Engage your core and glutes, then explosively jump up into the air, extending your hips and knees.","As you jump, push through your toes and fully extend your ankles, knees, and hips.","Land softly back on the ground, bending your knees to absorb the impact.","Immediately go into the next repetition, repeating the jump squat motion."],"it":["Inizia in ginocchio a terra con i piedi alla larghezza dei fianchi e le dita dei piedi rivolte in avanti.","Tieni un bilanciere sulla parte superiore della schiena, appoggiandolo sulle spalle.","Coinvolgi il core e i glutei, quindi salta in aria in modo esplosivo, estendendo i fianchi e le ginocchia.","Mentre salti, spingi le dita dei piedi ed estendi completamente caviglie, ginocchia e fianchi.","Atterra dolcemente a terra, piegando le ginocchia per assorbire l'impatto.","Passa immediatamente alla ripetizione successiva, ripetendo il movimento dello squat salto."]}},{"id":"1346","name":"kneeling lat stretch","category":"back","equipment":"body weight","target":"lats","secondary":["shoulders","triceps"],"steps":{"en":["Kneel on the ground with your knees hip-width apart and your toes pointing back.","Extend your arms overhead and interlace your fingers.","Keeping your back straight, slowly lean to the right side, feeling a stretch in your left lat muscle.","Hold the stretch for 20-30 seconds, then return to the starting position.","Repeat the stretch on the left side, leaning to the left and feeling a stretch in your right lat muscle.","Continue alternating sides for the desired number of repetitions."],"it":["Inginocchiati a terra con le ginocchia alla larghezza dei fianchi e le dita dei piedi rivolte all'indietro.","Estendi le braccia sopra la testa e intreccia le dita.","Tenendo la schiena dritta, inclinati lentamente verso il lato destro, avvertendo un allungamento nel muscolo lat sinistro.","Mantieni l'allungamento per 20-30 secondi, quindi torna alla posizione di partenza.","Ripeti l'allungamento sul lato sinistro, inclinandoti a sinistra e avvertendo un allungamento nel muscolo lat destro.","Continua ad alternare i lati per il numero di ripetizioni desiderato."]}},{"id":"3239","name":"kneeling plank tap shoulder (male)","category":"waist","equipment":"body weight","target":"abs","secondary":["shoulders","triceps"],"steps":{"en":["Start in a kneeling position with your hands on the ground, shoulder-width apart.","Extend your legs behind you, resting on your toes, and lift your body into a plank position.","Keeping your core engaged and your hips stable, lift one hand off the ground and tap the opposite shoulder.","Return the hand to the ground and repeat with the other hand.","Continue alternating sides for the desired number of repetitions."],"it":["Inizia in posizione inginocchiata con le mani a terra, alla larghezza delle spalle.","Estendi le gambe dietro di te, appoggiandoti sulle punte dei piedi e solleva il corpo in una posizione di plancia.","Mantenendo il core impegnato e i fianchi stabili, solleva una mano da terra e tocca la spalla opposta.","Riporta la mano a terra e ripeti con l'altra mano.","Continua ad alternare i lati per il numero di ripetizioni desiderato."]}},{"id":"3211","name":"kneeling push-up (male)","category":"chest","equipment":"body weight","target":"pectorals","secondary":["triceps","shoulders"],"steps":{"en":["Start by kneeling on the ground with your hands shoulder-width apart, fingers pointing forward.","Extend your legs behind you, resting on the balls of your feet, so that your body forms a straight line from head to heels.","Engage your core and lower your body towards the ground by bending your elbows, keeping them close to your sides.","Continue lowering until your chest is just above the ground, then push back up to the starting position by straightening your arms.","Repeat for the desired number of repetitions."],"it":["Inizia in ginocchio a terra con le mani alla larghezza delle spalle, le dita rivolte in avanti.","Estendi le gambe dietro di te, appoggiandole sulle punte dei piedi, in modo che il tuo corpo formi una linea retta dalla testa ai talloni.","Coinvolgi il core e abbassa il corpo verso terra piegando i gomiti, tenendoli vicini ai fianchi.","Continua ad abbassarti finché il petto non si trova appena sopra il suolo, quindi torna alla posizione iniziale raddrizzando le braccia.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"3288","name":"korean dips","category":"chest","equipment":"body weight","target":"pectorals","secondary":["triceps","shoulders"],"steps":{"en":["Position yourself between two parallel bars with your arms extended and supporting your body weight.","Lower your body by bending your elbows until your upper arms are parallel to the ground.","Pause for a moment, then push yourself back up to the starting position by straightening your arms.","Repeat for the desired number of repetitions."],"it":["Posizionati tra due barre parallele con le braccia tese e sostenendo il peso del corpo.","Abbassa il corpo piegando i gomiti finché la parte superiore delle braccia non è parallela al suolo.","Fai una pausa per un momento, quindi ritorna alla posizione di partenza raddrizzando le braccia.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"3418","name":"l-pull-up","category":"back","equipment":"body weight","target":"lats","secondary":["biceps","forearms"],"steps":{"en":["Grab the pull-up bar with an overhand grip, slightly wider than shoulder-width apart.","Hang with your arms fully extended and your body straight.","Engage your lats and biceps to pull your body up towards the bar, keeping your elbows close to your body.","Continue pulling until your chin is above the bar.","Pause for a moment at the top, then slowly lower your body back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Afferra la barra per trazioni con una presa prona, leggermente più larga della larghezza delle spalle.","Appendere con le braccia completamente distese e il corpo dritto.","Coinvolgi i dorsali e i bicipiti per sollevare il corpo verso la barra, mantenendo i gomiti vicini al corpo.","Continua a tirare finché il mento non è sopra la barra.","Fai una pausa per un momento in alto, quindi abbassa lentamente il corpo fino alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"3419","name":"l-sit on floor","category":"waist","equipment":"body weight","target":"abs","secondary":["hip flexors"],"steps":{"en":["Sit on the floor with your legs extended in front of you.","Place your hands on the floor beside your hips, fingers pointing forward.","Engage your core and lift your legs off the ground, keeping them straight.","Try to bring your legs parallel to the floor, forming an 'L' shape with your body.","Hold this position for as long as you can.","Slowly lower your legs back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Siediti sul pavimento con le gambe distese davanti a te.","Metti le mani sul pavimento accanto ai fianchi, con le dita rivolte in avanti.","Coinvolgi il tuo core e solleva le gambe da terra, mantenendole dritte.","Cerca di portare le gambe parallele al pavimento, formando una \"L\" con il tuo corpo.","Mantieni questa posizione il più a lungo possibile.","Abbassa lentamente le gambe fino alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0562","name":"landmine 180","category":"waist","equipment":"barbell","target":"abs","secondary":["obliques","quadriceps"],"steps":{"en":["Stand with your feet shoulder-width apart and hold the barbell with both hands in front of your chest.","Bend your knees slightly and rotate your torso to the right, swinging the barbell down towards your right hip.","As you reach the bottom of the movement, quickly reverse the motion and rotate your torso to the left, swinging the barbell up and across your body towards your left shoulder.","Continue this twisting motion, alternating sides, for the desired number of repetitions."],"it":["Stare con i piedi alla larghezza delle spalle e tenere il bilanciere con entrambe le mani davanti al petto.","Piega leggermente le ginocchia e ruota il busto verso destra, facendo oscillare il bilanciere verso il fianco destro.","Quando raggiungi la fine del movimento, inverti rapidamente il movimento e ruota il busto verso sinistra, facendo oscillare il bilanciere verso l'alto e attraverso il corpo verso la spalla sinistra.","Continua questo movimento di torsione, alternando i lati, per il numero di ripetizioni desiderato."]}},{"id":"3237","name":"landmine lateral raise","category":"shoulders","equipment":"barbell","target":"delts","secondary":["traps","upper back"],"steps":{"en":["Stand with your feet shoulder-width apart and knees slightly bent.","Hold the barbell with an overhand grip, resting it on the front of your shoulders.","Keeping your core engaged and back straight, lift the barbell up and away from your body, raising it to shoulder height.","Pause for a moment at the top, then slowly lower the barbell back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai in piedi con i piedi alla larghezza delle spalle e le ginocchia leggermente piegate.","Tieni il bilanciere con una presa prona, appoggiandolo sulla parte anteriore delle spalle.","Mantenendo il core impegnato e la schiena dritta, solleva il bilanciere verso l'alto e lontano dal corpo, sollevandolo all'altezza delle spalle.","Fermati per un momento in alto, quindi abbassa lentamente il bilanciere nella posizione iniziale.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"3300","name":"lean planche","category":"waist","equipment":"body weight","target":"abs","secondary":["shoulders","chest","triceps"],"steps":{"en":["Start in a push-up position with your hands shoulder-width apart and your body straight.","Engage your core and slowly shift your weight forward, bringing your shoulders past your hands.","Keep your elbows slightly bent and your body straight as you lean forward.","Hold this position for a few seconds, then slowly return to the starting position.","Repeat for the desired number of repetitions."],"it":["Inizia in una posizione push-up con le mani alla larghezza delle spalle e il corpo dritto.","Coinvolgi il tuo core e sposta lentamente il peso in avanti, portando le spalle oltre le mani.","Tieni i gomiti leggermente piegati e il corpo dritto mentre ti pieghi in avanti.","Mantieni questa posizione per alcuni secondi, quindi torna lentamente alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"2271","name":"left hook. boxing","category":"shoulders","equipment":"body weight","target":"delts","secondary":["biceps","triceps","forearms"],"steps":{"en":["Stand with your feet shoulder-width apart and your knees slightly bent.","Keep your left hand up to protect your face and your right hand by your chin.","Rotate your hips and pivot on your left foot as you extend your left arm forward in a punching motion.","Twist your torso and engage your core muscles to generate power in the punch.","Snap your arm back to the starting position and repeat for the desired number of repetitions."],"it":["Stai con i piedi alla larghezza delle spalle e le ginocchia leggermente piegate.","Tieni la mano sinistra alzata per proteggere il viso e la mano destra vicino al mento.","Ruota i fianchi e fai perno sul piede sinistro mentre estendi il braccio sinistro in avanti con un movimento di pugno.","Ruota il busto e coinvolgi i muscoli centrali per generare potenza nel pugno.","Riporta il braccio nella posizione iniziale e ripeti per il numero di ripetizioni desiderato."]}},{"id":"0570","name":"leg pull in flat bench","category":"waist","equipment":"body weight","target":"abs","secondary":["hip flexors","lower back"],"steps":{"en":["Sit on a flat bench with your legs extended straight out in front of you.","Place your hands on the bench beside your hips for support.","Engage your abs and lift your legs off the ground, bringing your knees towards your chest.","Pause for a moment at the top, then slowly lower your legs back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Siediti su una panca piana con le gambe distese davanti a te.","Metti le mani sulla panca accanto ai fianchi per supporto.","Contrai gli addominali e solleva le gambe da terra, portando le ginocchia verso il petto.","Fai una pausa per un momento in alto, quindi abbassa lentamente le gambe fino alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"1576","name":"leg up hamstring stretch","category":"upper legs","equipment":"body weight","target":"hamstrings","secondary":["glutes"],"steps":{"en":["Lie flat on your back with your legs extended.","Bend one knee and bring it towards your chest, holding onto your thigh or shin.","Straighten your leg as much as possible while keeping it elevated.","Hold the stretch for 20-30 seconds.","Repeat with the other leg."],"it":["Sdraiati sulla schiena con le gambe distese.","Piega un ginocchio e portalo verso il petto, tenendoti sulla coscia o sullo stinco.","Raddrizza la gamba il più possibile mantenendola sollevata.","Mantieni l'allungamento per 20-30 secondi.","Ripeti con l'altra gamba."]}},{"id":"0574","name":"lever bent over row","category":"back","equipment":"barbell","target":"upper back","secondary":["biceps","forearms"],"steps":{"en":["Stand with your feet shoulder-width apart and knees slightly bent.","Hold the barbell with an overhand grip, hands slightly wider than shoulder-width apart.","Bend forward at the hips, keeping your back straight and chest up.","Pull the barbell towards your lower chest, squeezing your shoulder blades together.","Pause for a moment at the top, then slowly lower the barbell back to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai in piedi con i piedi alla larghezza delle spalle e le ginocchia leggermente piegate.","Tieni il bilanciere con una presa prona, con le mani leggermente più larghe della larghezza delle spalle.","Piegati in avanti sui fianchi, mantenendo la schiena dritta e il petto in alto.","Tirare il bilanciere verso la parte inferiore del torace, stringendo insieme le scapole.","Fermati per un momento in alto, quindi abbassa lentamente il bilanciere nella posizione iniziale.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0589","name":"lever one arm bent over row","category":"back","equipment":"barbell","target":"upper back","secondary":["biceps","forearms"],"steps":{"en":["Stand with your feet shoulder-width apart, knees slightly bent, and hold a barbell with an overhand grip.","Bend forward at the hips, keeping your back straight and your head up.","Let the barbell hang in front of you with your arms fully extended.","Pull the barbell up towards your chest, keeping your elbows close to your body.","Squeeze your shoulder blades together at the top of the movement.","Lower the barbell back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Stare con i piedi alla larghezza delle spalle, le ginocchia leggermente piegate e tenere un bilanciere con una presa prona.","Piegati in avanti sui fianchi, mantenendo la schiena dritta e la testa alta.","Lascia che il bilanciere penda davanti a te con le braccia completamente distese.","Tira il bilanciere verso il petto, mantenendo i gomiti vicini al corpo.","Stringi le scapole insieme nella parte superiore del movimento.","Abbassare nuovamente il bilanciere nella posizione iniziale.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"3013","name":"low glute bridge on floor","category":"upper legs","equipment":"body weight","target":"glutes","secondary":["hamstrings","core"],"steps":{"en":["Lie flat on your back with your knees bent and feet flat on the ground.","Place your arms by your sides, palms facing down.","Engage your glutes and core, then lift your hips off the ground until your body forms a straight line from your knees to your shoulders.","Pause for a moment at the top, squeezing your glutes.","Slowly lower your hips back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Sdraiati sulla schiena con le ginocchia piegate e i piedi appoggiati a terra.","Metti le braccia lungo i fianchi, i palmi rivolti verso il basso.","Coinvolgi i glutei e il core, quindi solleva i fianchi da terra finché il tuo corpo non forma una linea retta dalle ginocchia alle spalle.","Fermati un attimo in alto, contraendo i glutei.","Abbassa lentamente i fianchi fino alla posizione iniziale.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"1352","name":"lower back curl","category":"back","equipment":"body weight","target":"spine","secondary":["glutes","hamstrings"],"steps":{"en":["Lie flat on your stomach with your legs extended and your arms by your sides.","Engage your glutes and hamstrings, and slowly lift your upper body off the ground, curling your back upwards.","Pause for a moment at the top, then slowly lower your upper body back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Sdraiati a pancia in giù con le gambe distese e le braccia lungo i fianchi.","Coinvolgi i glutei e i muscoli posteriori della coscia e solleva lentamente la parte superiore del corpo da terra, incurvando la schiena verso l'alto.","Fermati per un momento in alto, quindi abbassa lentamente la parte superiore del corpo fino alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"3582","name":"lunge with jump","category":"upper legs","equipment":"body weight","target":"glutes","secondary":["quadriceps","hamstrings","calves"],"steps":{"en":["Start by standing with your feet shoulder-width apart.","Take a step forward with your right foot, lowering your body into a lunge position.","Push off with your right foot and jump into the air, switching the position of your feet mid-air.","Land softly with your left foot forward and immediately lower your body into a lunge position.","Continue alternating between lunges and jumps for the desired number of repetitions."],"it":["Inizia stando in piedi con i piedi alla larghezza delle spalle.","Fai un passo avanti con il piede destro, abbassando il corpo in una posizione di affondo.","Spingi con il piede destro e salta in aria, cambiando la posizione dei piedi a mezz'aria.","Atterra dolcemente con il piede sinistro in avanti e abbassa immediatamente il corpo in una posizione di affondo.","Continua ad alternare affondi e salti per il numero di ripetizioni desiderato."]}},{"id":"1688","name":"lunge with twist","category":"waist","equipment":"body weight","target":"abs","secondary":["quadriceps","glutes","hamstrings"],"steps":{"en":["Start by standing with your feet shoulder-width apart.","Take a step forward with your right foot, lowering your body into a lunge position.","As you lunge, twist your torso to the right, bringing your left elbow towards your right knee.","Pause for a moment, then return to the starting position.","Repeat on the other side, stepping forward with your left foot and twisting your torso to the left.","Continue alternating sides for the desired number of repetitions."],"it":["Inizia stando in piedi con i piedi alla larghezza delle spalle.","Fai un passo avanti con il piede destro, abbassando il corpo in una posizione di affondo.","Mentre fai un affondo, ruota il busto verso destra, portando il gomito sinistro verso il ginocchio destro.","Fare una pausa per un momento, quindi tornare alla posizione di partenza.","Ripeti dall'altro lato, facendo un passo avanti con il piede sinistro e ruotando il busto verso sinistra.","Continua ad alternare i lati per il numero di ripetizioni desiderato."]}},{"id":"0613","name":"lying (side) quads stretch","category":"upper legs","equipment":"body weight","target":"quads","secondary":["hamstrings"],"steps":{"en":["Lie on your side with your legs straight.","Bend your top leg and grab your ankle or foot with your hand.","Gently pull your ankle or foot towards your glutes until you feel a stretch in your quads.","Hold the stretch for 20-30 seconds.","Release the stretch and repeat on the other side."],"it":["Sdraiati su un fianco con le gambe dritte.","Piega la gamba superiore e afferra la caviglia o il piede con la mano.","Tira delicatamente la caviglia o il piede verso i glutei finché non senti un allungamento nei quadricipiti.","Mantieni l'allungamento per 20-30 secondi.","Rilascia l'allungamento e ripeti dall'altro lato."]}},{"id":"2312","name":"lying elbow to knee","category":"waist","equipment":"body weight","target":"abs","secondary":["hip flexors","lower back"],"steps":{"en":["Lie flat on your back with your knees bent and feet flat on the ground.","Place your hands behind your head with your elbows pointing outwards.","Engage your abs and lift your upper body off the ground, bringing your right elbow towards your left knee.","At the same time, extend your right leg straight out and lift it off the ground.","Pause for a moment, then return to the starting position.","Repeat the movement, this time bringing your left elbow towards your right knee and extending your left leg.","Continue alternating sides for the desired number of repetitions."],"it":["Sdraiati sulla schiena con le ginocchia piegate e i piedi appoggiati a terra.","Metti le mani dietro la testa con i gomiti rivolti verso l'esterno.","Contrai gli addominali e solleva la parte superiore del corpo da terra, portando il gomito destro verso il ginocchio sinistro.","Allo stesso tempo, stendi la gamba destra e sollevala da terra.","Fare una pausa per un momento, quindi tornare alla posizione di partenza.","Ripeti il ​​movimento, questa volta portando il gomito sinistro verso il ginocchio destro ed estendendo la gamba sinistra.","Continua ad alternare i lati per il numero di ripetizioni desiderato."]}},{"id":"0620","name":"lying leg raise flat bench","category":"waist","equipment":"body weight","target":"abs","secondary":["hip flexors"],"steps":{"en":["Lie flat on a flat bench with your back pressed against it.","Place your hands under your glutes for support.","Keep your legs straight and together, and lift them up towards the ceiling.","Pause for a moment at the top, then slowly lower your legs back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Sdraiati su una panca piana con la schiena premuta contro di essa.","Metti le mani sotto i glutei per supporto.","Tieni le gambe dritte e unite e sollevale verso il soffitto.","Fai una pausa per un momento in alto, quindi abbassa lentamente le gambe fino alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0865","name":"lying leg-hip raise","category":"waist","equipment":"body weight","target":"abs","secondary":["hip flexors"],"steps":{"en":["Lie flat on your back with your legs extended and your arms by your sides.","Place your hands under your glutes for support.","Engage your core and lift your legs off the ground, raising them towards the ceiling.","Pause for a moment at the top, then slowly lower your legs back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Sdraiati sulla schiena con le gambe distese e le braccia lungo i fianchi.","Metti le mani sotto i glutei per supporto.","Coinvolgi il tuo core e solleva le gambe da terra, sollevandole verso il soffitto.","Fai una pausa per un momento in alto, quindi abbassa lentamente le gambe fino alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0624","name":"march sit (wall)","category":"upper legs","equipment":"body weight","target":"glutes","secondary":["quadriceps","hamstrings","calves"],"steps":{"en":["Stand with your back against a wall and your feet hip-width apart.","Slowly slide your back down the wall until your knees are bent at a 90-degree angle.","Lift your right foot off the ground and bring your knee towards your chest.","Lower your right foot back down and lift your left foot off the ground, bringing your knee towards your chest.","Continue alternating between lifting your right and left foot for the desired number of repetitions."],"it":["Stai con la schiena contro un muro e i piedi divaricati alla larghezza dei fianchi.","Fai scivolare lentamente la schiena lungo il muro finché le ginocchia non saranno piegate con un angolo di 90 gradi.","Solleva il piede destro da terra e porta il ginocchio verso il petto.","Abbassa di nuovo il piede destro e solleva il piede sinistro da terra, portando il ginocchio verso il petto.","Continua alternando il sollevamento del piede destro e sinistro per il numero di ripetizioni desiderato."]}},{"id":"0627","name":"mixed grip chin-up","category":"back","equipment":"body weight","target":"lats","secondary":["biceps","forearms"],"steps":{"en":["Grab the pull-up bar with an underhand grip (palms facing towards you) and your hands slightly wider than shoulder-width apart.","Hang from the bar with your arms fully extended and your feet off the ground.","Engage your back muscles and pull your body up towards the bar, leading with your chest.","Continue pulling until your chin is above the bar.","Pause for a moment at the top, then slowly lower your body back down to the starting position with control.","Repeat for the desired number of repetitions."],"it":["Afferra la barra per trazioni con una presa subdola (palmi rivolti verso di te) e le mani leggermente più larghe della larghezza delle spalle.","Appendi alla barra con le braccia completamente distese e i piedi sollevati da terra.","Coinvolgi i muscoli della schiena e solleva il corpo verso la barra, guidando con il petto.","Continua a tirare finché il mento non è sopra la barra.","Fai una pausa per un momento in alto, quindi abbassa lentamente il corpo fino alla posizione iniziale con controllo.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"3217","name":"modified hindu push-up (male)","category":"chest","equipment":"body weight","target":"pectorals","secondary":["triceps","shoulders","core"],"steps":{"en":["Start in a push-up position with your hands slightly wider than shoulder-width apart and your feet hip-width apart.","Lower your body towards the ground, bending your elbows and keeping your core engaged.","As you lower your body, shift your weight back and lift your hips up towards the ceiling, creating an inverted V shape with your body.","Continue to lower your body until your chest is just above the ground, then reverse the movement, pushing your hips back down and extending your arms to return to the starting position.","Repeat for the desired number of repetitions."],"it":["Inizia in una posizione push-up con le mani leggermente più larghe della larghezza delle spalle e i piedi alla larghezza dei fianchi.","Abbassa il corpo verso terra, piegando i gomiti e mantenendo il core impegnato.","Mentre abbassi il corpo, sposta il peso indietro e solleva i fianchi verso il soffitto, creando una forma a V rovesciata con il tuo corpo.","Continua ad abbassare il corpo finché il petto non si trova appena sopra il suolo, quindi inverti il ​​movimento, spingendo i fianchi verso il basso ed estendendo le braccia per tornare alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"1421","name":"modified push up to lower arms","category":"lower arms","equipment":"body weight","target":"forearms","secondary":["triceps","chest","shoulders"],"steps":{"en":["Start in a push-up position with your hands directly under your shoulders and your body in a straight line.","Lower your body down towards the ground by bending your elbows, keeping them close to your sides.","Once your elbows are at a 90-degree angle, lower your forearms to the ground, keeping your elbows directly under your shoulders.","Pause for a moment, then push through your palms to lift your forearms back up to the starting position.","Repeat for the desired number of repetitions."],"it":["Inizia in una posizione push-up con le mani direttamente sotto le spalle e il corpo in linea retta.","Abbassa il corpo verso terra piegando i gomiti, tenendoli vicini ai fianchi.","Una volta che i gomiti hanno formato un angolo di 90 gradi, abbassa gli avambracci a terra, mantenendo i gomiti direttamente sotto le spalle.","Fai una pausa per un momento, quindi spingi attraverso i palmi delle mani per riportare gli avambracci nella posizione iniziale.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0628","name":"monster walk","category":"upper legs","equipment":"body weight","target":"glutes","secondary":["hamstrings","quadriceps"],"steps":{"en":["Place a resistance band around your ankles.","Stand with your feet shoulder-width apart and slightly bend your knees.","Take a step to the side with your right foot, maintaining tension on the resistance band.","Follow with your left foot, stepping to the side to return to the starting position.","Repeat for the desired number of repetitions, then switch sides."],"it":["Posiziona una fascia di resistenza intorno alle caviglie.","Stai con i piedi alla larghezza delle spalle e piega leggermente le ginocchia.","Fai un passo laterale con il piede destro, mantenendo la tensione sulla fascia di resistenza.","Segui con il piede sinistro, facendo un passo laterale per tornare alla posizione di partenza.","Ripeti per il numero di ripetizioni desiderato, quindi cambia lato."]}},{"id":"0630","name":"mountain climber","category":"cardio","equipment":"body weight","target":"cardiovascular system","secondary":["core","shoulders","triceps"],"steps":{"en":["Start in a high plank position with your hands directly under your shoulders and your body in a straight line.","Engage your core and bring your right knee towards your chest, then quickly switch and bring your left knee towards your chest.","Continue alternating legs in a running motion, keeping your hips low and your core engaged.","Maintain a steady pace and breathe evenly throughout the exercise.","Repeat for the desired number of repetitions."],"it":["Inizia in una posizione di plancia alta con le mani direttamente sotto le spalle e il corpo in linea retta.","Coinvolgi il core e porta il ginocchio destro verso il petto, quindi cambia rapidamente e porta il ginocchio sinistro verso il petto.","Continua ad alternare le gambe con un movimento di corsa, mantenendo i fianchi bassi e il core impegnato.","Mantieni un ritmo costante e respira in modo uniforme durante l'esercizio.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0631","name":"muscle up","category":"back","equipment":"body weight","target":"lats","secondary":["biceps","triceps","shoulders","chest"],"steps":{"en":["Start by hanging from a pull-up bar with your palms facing away from you and your arms fully extended.","Engage your core and pull your body up towards the bar, leading with your chest.","As you reach the top of the movement, transition your grip so that your palms are facing towards you.","Continue pulling yourself up until your chest is above the bar and your arms are fully flexed.","Reverse the movement by slowly lowering yourself back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Inizia appendendoti a una barra per trazioni con i palmi delle mani rivolti lontano da te e le braccia completamente distese.","Coinvolgi il core e solleva il corpo verso la barra, guidando con il petto.","Quando raggiungi la parte superiore del movimento, cambia la presa in modo che i palmi delle mani siano rivolti verso di te.","Continua a sollevarti finché il petto non è sopra la barra e le braccia sono completamente flesse.","Invertire il movimento abbassandosi lentamente fino alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"1401","name":"muscle-up (on vertical bar)","category":"back","equipment":"body weight","target":"lats","secondary":["biceps","triceps","forearms"],"steps":{"en":["Start by hanging from a vertical bar with your palms facing away from you and your arms fully extended.","Engage your core and pull your body up towards the bar, leading with your chest.","As you pull yourself up, lean back slightly and bring your elbows towards your sides.","Continue pulling until your chest reaches the bar and your elbows are fully bent.","Pause for a moment at the top, then slowly lower yourself back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Inizia appendendoti a una barra verticale con i palmi rivolti lontano da te e le braccia completamente distese.","Coinvolgi il core e solleva il corpo verso la barra, guidando con il petto.","Mentre ti tiri su, inclinati leggermente all'indietro e porta i gomiti verso i fianchi.","Continua a tirare finché il petto non raggiunge la barra e i gomiti sono completamente piegati.","Fermati per un momento in alto, quindi abbassati lentamente fino alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"2328","name":"narrow push-up on exercise ball","category":"upper arms","equipment":"stability ball","target":"triceps","secondary":["chest","shoulders"],"steps":{"en":["Place the stability ball on the ground and position yourself in a push-up position with your hands on the ball, slightly narrower than shoulder-width apart.","Engage your core and keep your body in a straight line from head to toe.","Lower your chest towards the ball by bending your elbows, keeping them close to your body.","Pause for a moment at the bottom, then push yourself back up to the starting position by straightening your arms.","Repeat for the desired number of repetitions."],"it":["Posiziona la palla di stabilità a terra e posizionati in una posizione di push-up con le mani sulla palla, leggermente più strette della larghezza delle spalle.","Coinvolgi il tuo core e mantieni il corpo in linea retta dalla testa ai piedi.","Abbassa il petto verso la palla piegando i gomiti, tenendoli vicini al corpo.","Fai una pausa per un momento in basso, quindi ritorna alla posizione di partenza raddrizzando le braccia.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"1403","name":"neck side stretch","category":"neck","equipment":"body weight","target":"levator scapulae","secondary":["trapezius","sternocleidomastoid"],"steps":{"en":["Stand or sit up straight with your shoulders relaxed.","Tilt your head to one side, bringing your ear towards your shoulder.","Hold the stretch for 15-30 seconds.","Repeat on the other side.","Perform 2-4 sets on each side."],"it":["Stai in piedi o seduto con la schiena dritta e le spalle rilassate.","Inclina la testa da un lato, portando l'orecchio verso la spalla.","Mantieni l'allungamento per 15-30 secondi.","Ripeti dall'altra parte.","Esegui 2-4 serie su ciascun lato."]}},{"id":"0634","name":"negative crunch","category":"waist","equipment":"body weight","target":"abs","secondary":["hip flexors"],"steps":{"en":["Lie flat on your back with your knees bent and feet flat on the ground.","Place your hands behind your head with your elbows pointing outwards.","Engaging your abs, slowly lift your upper body off the ground, curling forward until your torso is at a 45-degree angle.","Pause for a moment at the top, then slowly lower your upper body back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Sdraiati sulla schiena con le ginocchia piegate e i piedi appoggiati a terra.","Metti le mani dietro la testa con i gomiti rivolti verso l'esterno.","Coinvolgendo gli addominali, solleva lentamente la parte superiore del corpo da terra, piegandoti in avanti finché il busto non forma un angolo di 45 gradi.","Fermati per un momento in alto, quindi abbassa lentamente la parte superiore del corpo fino alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"1495","name":"oblique crunch v. 2","category":"waist","equipment":"body weight","target":"abs","secondary":["obliques"],"steps":{"en":["Lie on your back with your knees bent and feet flat on the ground.","Place your hands behind your head or cross them over your chest.","Engage your abs and lift your shoulder blades off the ground, rotating your torso to one side.","Pause for a moment, then lower your shoulder blades back down to the starting position.","Repeat on the other side.","Continue alternating sides for the desired number of repetitions."],"it":["Sdraiati sulla schiena con le ginocchia piegate e i piedi appoggiati a terra.","Metti le mani dietro la testa o incrociale sul petto.","Coinvolgi gli addominali e solleva le scapole da terra, ruotando il busto da un lato.","Fai una pausa per un momento, quindi abbassa le scapole nella posizione iniziale.","Ripeti dall'altra parte.","Continua ad alternare i lati per il numero di ripetizioni desiderato."]}},{"id":"0635","name":"oblique crunches floor","category":"waist","equipment":"body weight","target":"abs","secondary":["obliques"],"steps":{"en":["Lie on your back with your knees bent and feet flat on the floor.","Place your hands behind your head or cross them over your chest.","Engage your abs and lift your shoulder blades off the floor, rotating your torso to one side.","Pause for a moment, then lower your shoulder blades back down to the floor.","Repeat on the other side, alternating sides with each repetition."],"it":["Sdraiati sulla schiena con le ginocchia piegate e i piedi appoggiati sul pavimento.","Metti le mani dietro la testa o incrociale sul petto.","Coinvolgi gli addominali e solleva le scapole dal pavimento, ruotando il busto da un lato.","Fai una pausa per un momento, quindi abbassa le scapole sul pavimento.","Ripeti dall'altro lato, alternando i lati ad ogni ripetizione."]}},{"id":"1355","name":"one arm against wall","category":"back","equipment":"body weight","target":"lats","secondary":["shoulders","triceps"],"steps":{"en":["Stand facing a wall with your feet shoulder-width apart.","Extend one arm straight out in front of you and place your palm against the wall.","Engage your core and lean your body forward, keeping your arm straight and your back flat.","Slowly push against the wall with your palm, activating your lat muscles.","Hold the position for a few seconds, then release and repeat with the other arm."],"it":["Mettiti di fronte a un muro con i piedi alla larghezza delle spalle.","Estendi un braccio davanti a te e posiziona il palmo della mano contro il muro.","Coinvolgi il core e inclina il corpo in avanti, mantenendo il braccio dritto e la schiena piatta.","Spingi lentamente contro il muro con il palmo della mano, attivando i muscoli dorsali.","Mantieni la posizione per qualche secondo, poi rilascia e ripeti con l'altro braccio."]}},{"id":"0638","name":"one arm chin-up","category":"back","equipment":"body weight","target":"lats","secondary":["biceps","forearms"],"steps":{"en":["Stand facing a pull-up bar with your feet shoulder-width apart.","Reach up and grab the bar with an underhand grip, with one hand gripping the bar and the other hand holding your wrist for support.","Hang from the bar with your arm fully extended, keeping your body straight and your core engaged.","Pull yourself up towards the bar by bending your elbow and squeezing your back muscles.","Continue pulling until your chin is above the bar, then slowly lower yourself back down to the starting position.","Repeat for the desired number of repetitions, then switch arms and repeat."],"it":["Mettiti di fronte a una barra per trazioni con i piedi alla larghezza delle spalle.","Allunga la mano e afferra la barra con una presa subdola, con una mano che afferra la barra e l'altra mano che tiene il polso per supporto.","Appendi alla barra con il braccio completamente esteso, mantenendo il corpo dritto e il core impegnato.","Tirati verso la sbarra piegando il gomito e contraendo i muscoli della schiena.","Continua a tirare finché il mento non è sopra la barra, quindi abbassati lentamente fino alla posizione iniziale.","Ripeti per il numero di ripetizioni desiderato, quindi cambia braccio e ripeti."]}},{"id":"0639","name":"one arm dip","category":"upper arms","equipment":"body weight","target":"triceps","secondary":["chest","shoulders"],"steps":{"en":["Stand facing away from a bench or chair, with your feet shoulder-width apart.","Place one hand on the bench or chair behind you, fingers pointing towards your body.","Extend your legs out in front of you, keeping your heels on the ground.","Bend your elbows and lower your body towards the ground, keeping your back close to the bench or chair.","Pause for a moment at the bottom, then push through your palms to straighten your arms and return to the starting position.","Repeat for the desired number of repetitions, then switch sides and repeat with the other arm."],"it":["Stai in piedi di fronte a una panca o una sedia, con i piedi alla larghezza delle spalle.","Metti una mano sulla panca o sulla sedia dietro di te, con le dita rivolte verso il tuo corpo.","Estendi le gambe davanti a te, mantenendo i talloni a terra.","Piega i gomiti e abbassa il corpo verso terra, mantenendo la schiena vicina alla panca o alla sedia.","Fai una pausa per un momento in basso, quindi spingi attraverso i palmi delle mani per raddrizzare le braccia e tornare alla posizione di partenza.","Ripeti per il numero di ripetizioni desiderato, quindi cambia lato e ripeti con l'altro braccio."]}},{"id":"1773","name":"one arm towel row","category":"back","equipment":"body weight","target":"upper back","secondary":["biceps","forearms"],"steps":{"en":["Stand with your feet shoulder-width apart, knees slightly bent, and hold a towel with one hand.","Bend forward at the waist, keeping your back straight and your core engaged.","Extend your arm fully, allowing the towel to hang in front of you.","Pull the towel towards your chest, squeezing your shoulder blades together.","Pause for a moment at the top, then slowly lower the towel back to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"it":["Stare con i piedi alla larghezza delle spalle, le ginocchia leggermente piegate e tenere un asciugamano con una mano.","Piegati in avanti all'altezza della vita, mantenendo la schiena dritta e il core impegnato.","Estendi completamente il braccio, lasciando che l'asciugamano penda davanti a te.","Tira l'asciugamano verso il petto, stringendo insieme le scapole.","Fermati per un momento in alto, quindi abbassa lentamente l'asciugamano nella posizione iniziale.","Ripeti per il numero di ripetizioni desiderato, quindi cambia braccio."]}},{"id":"1386","name":"one leg donkey calf raise","category":"lower legs","equipment":"body weight","target":"calves","secondary":["hamstrings","glutes"],"steps":{"en":["Stand with your feet shoulder-width apart, toes pointing forward.","Place your hands on a stable surface for support, such as a wall or a bar.","Lift one leg off the ground, keeping your knee slightly bent.","Raise your heel as high as possible, using your calf muscles.","Pause for a moment at the top, then slowly lower your heel back down.","Repeat for the desired number of repetitions, then switch legs."],"it":["Stai con i piedi alla larghezza delle spalle, le dita dei piedi rivolte in avanti.","Appoggia le mani su una superficie stabile come supporto, come un muro o una barra.","Sollevare una gamba da terra, mantenendo il ginocchio leggermente piegato.","Alza il tallone il più in alto possibile, usando i muscoli del polpaccio.","Fai una pausa per un momento in alto, quindi abbassa lentamente il tallone.","Ripeti per il numero di ripetizioni desiderato, quindi cambia gamba."]}},{"id":"1387","name":"one leg floor calf raise","category":"lower legs","equipment":"body weight","target":"calves","secondary":["ankles","feet"],"steps":{"en":["Stand with your feet hip-width apart and place your hands on a wall or sturdy object for balance.","Lift one foot off the ground and balance on the other foot.","Slowly raise your heel off the ground, lifting your body up onto the ball of your foot.","Pause for a moment at the top, then slowly lower your heel back down to the starting position.","Repeat for the desired number of repetitions, then switch legs and repeat."],"it":["Stare con i piedi alla larghezza dei fianchi e appoggiare le mani su un muro o un oggetto robusto per mantenere l'equilibrio.","Sollevare un piede da terra e restare in equilibrio sull'altro piede.","Solleva lentamente il tallone da terra, sollevando il corpo sulla pianta del piede.","Fai una pausa per un momento in alto, quindi abbassa lentamente il tallone fino alla posizione iniziale.","Ripeti per il numero di ripetizioni desiderato, quindi cambia gamba e ripeti."]}},{"id":"1476","name":"one leg squat","category":"upper legs","equipment":"body weight","target":"glutes","secondary":["quadriceps","hamstrings","calves"],"steps":{"en":["Stand with your feet shoulder-width apart.","Extend one leg forward, keeping it off the ground.","Bend your standing leg and lower your body down as if sitting back into a chair.","Keep your chest up and your back straight.","Push through your heel to return to the starting position.","Repeat with the other leg."],"it":["Stai con i piedi alla larghezza delle spalle.","Estendi una gamba in avanti, tenendola sollevata da terra.","Piega la gamba in piedi e abbassa il corpo come se fossi seduto su una sedia.","Tieni il petto in alto e la schiena dritta.","Spingi attraverso il tallone per tornare alla posizione di partenza.","Ripeti con l'altra gamba."]}},{"id":"0642","name":"outside leg kick push-up","category":"upper legs","equipment":"body weight","target":"glutes","secondary":["quadriceps","hamstrings","calves"],"steps":{"en":["Start in a push-up position with your hands slightly wider than shoulder-width apart and your feet together.","Lower your body towards the ground by bending your elbows, keeping your back straight and core engaged.","As you push back up, kick one leg out to the side, extending it fully and engaging your glutes.","Return your leg to the starting position and repeat the push-up, alternating legs with each repetition.","Continue alternating leg kicks and push-ups for the desired number of repetitions."],"it":["Inizia in una posizione push-up con le mani leggermente più larghe della larghezza delle spalle e i piedi uniti.","Abbassa il corpo verso terra piegando i gomiti, mantenendo la schiena dritta e il core impegnato.","Mentre ti spingi verso l'alto, calcia una gamba di lato, estendendola completamente e impegnando i glutei.","Riporta la gamba nella posizione iniziale e ripeti il ​​push-up, alternando le gambe ad ogni ripetizione.","Continua ad alternare calci alle gambe e flessioni per il numero di ripetizioni desiderato."]}},{"id":"0643","name":"overhead triceps stretch","category":"upper arms","equipment":"body weight","target":"triceps","secondary":["shoulders"],"steps":{"en":["Stand or sit upright with your feet shoulder-width apart.","Extend one arm overhead, bending at the elbow so that your hand reaches towards the opposite shoulder blade.","With your other hand, gently pull the elbow of the extended arm towards the opposite side of your head, feeling a stretch in your triceps.","Hold the stretch for 15-30 seconds, then release.","Repeat on the other side."],"it":["Stai in piedi o seduto in posizione eretta con i piedi alla larghezza delle spalle.","Estendi un braccio sopra la testa, piegandoti al gomito in modo che la mano raggiunga la scapola opposta.","Con l'altra mano, tira delicatamente il gomito del braccio teso verso il lato opposto della testa, sentendo l'allungamento dei tricipiti.","Mantieni la posizione per 15-30 secondi, quindi rilascia.","Ripeti dall'altra parte."]}},{"id":"3147","name":"pelvic tilt","category":"waist","equipment":"body weight","target":"abs","secondary":["lower back"],"steps":{"en":["Lie flat on your back with your knees bent and feet flat on the ground.","Place your hands by your sides.","Engage your abs and tilt your pelvis upward, pressing your lower back into the ground.","Hold this position for a few seconds, focusing on contracting your abs.","Release the tilt and return to the starting position.","Repeat for the desired number of repetitions."],"it":["Sdraiati sulla schiena con le ginocchia piegate e i piedi appoggiati a terra.","Metti le mani lungo i fianchi.","Coinvolgi gli addominali e inclina il bacino verso l'alto, premendo la parte bassa della schiena a terra.","Mantieni questa posizione per qualche secondo, concentrandoti sulla contrazione degli addominali.","Rilasciare l'inclinazione e tornare alla posizione iniziale.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"1422","name":"pelvic tilt into bridge","category":"upper legs","equipment":"body weight","target":"glutes","secondary":["hamstrings","core"],"steps":{"en":["Lie on your back with your knees bent and feet flat on the ground.","Place your arms by your sides with your palms facing down.","Engage your glutes and core muscles.","Tilt your pelvis upward, lifting your hips off the ground.","Hold the bridge position for a few seconds.","Slowly lower your hips back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Sdraiati sulla schiena con le ginocchia piegate e i piedi appoggiati a terra.","Posiziona le braccia lungo i fianchi con i palmi rivolti verso il basso.","Coinvolgi i tuoi glutei e i muscoli centrali.","Inclina il bacino verso l'alto, sollevando i fianchi da terra.","Mantieni la posizione del ponte per alcuni secondi.","Abbassa lentamente i fianchi fino alla posizione iniziale.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"3662","name":"pike-to-cobra push-up","category":"upper legs","equipment":"body weight","target":"glutes","secondary":["core","shoulders","triceps"],"steps":{"en":["Start in a push-up position with your hands slightly wider than shoulder-width apart and your feet together.","Engage your core and lift your hips up towards the ceiling, forming an inverted V shape with your body.","Lower your upper body towards the ground by bending your elbows, keeping them close to your body.","As you lower down, shift your weight forward and transition into a cobra pose by straightening your arms and lifting your chest up.","Reverse the movement by bending your elbows and lowering your chest back down towards the ground.","Push through your hands to return to the inverted V position.","Continue the movement by lowering your hips back down towards the ground, returning to the starting push-up position.","Repeat for the desired number of repetitions."],"it":["Inizia in una posizione push-up con le mani leggermente più larghe della larghezza delle spalle e i piedi uniti.","Coinvolgi il core e solleva i fianchi verso il soffitto, formando una forma a V rovesciata con il tuo corpo.","Abbassa la parte superiore del corpo verso terra piegando i gomiti, tenendoli vicini al corpo.","Mentre ti abbassi, sposta il peso in avanti e passa alla posa del cobra raddrizzando le braccia e sollevando il petto.","Invertire il movimento piegando i gomiti e abbassando il petto verso terra.","Spingi tra le mani per tornare alla posizione a V invertita.","Continua il movimento abbassando i fianchi verso terra, tornando alla posizione iniziale di push-up.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"1306","name":"plyo push up","category":"chest","equipment":"body weight","target":"pectorals","secondary":["triceps","shoulders","core"],"steps":{"en":["Start in a high plank position with your hands slightly wider than shoulder-width apart.","Lower your chest towards the ground by bending your elbows, keeping your body in a straight line.","Push explosively off the ground, using your chest muscles to propel your upper body off the ground.","Land softly with your hands back in the starting position.","Repeat for the desired number of repetitions."],"it":["Inizia in una posizione di plancia alta con le mani leggermente più larghe della larghezza delle spalle.","Abbassa il petto verso terra piegando i gomiti, mantenendo il corpo in linea retta.","Spingi in modo esplosivo da terra, usando i muscoli del torace per spingere la parte superiore del corpo da terra.","Atterra dolcemente con le mani nella posizione iniziale.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"1687","name":"posterior step to overhead reach","category":"waist","equipment":"body weight","target":"abs","secondary":["glutes","hamstrings","quadriceps","shoulders"],"steps":{"en":["Stand with your feet hip-width apart and your arms by your sides.","Take a step back with your right foot, landing on the ball of your foot.","Bend your left knee and lower your body into a lunge position.","As you lower into the lunge, simultaneously reach your arms overhead.","Pause for a moment at the bottom of the lunge, then return to the starting position by pushing through your left heel and bringing your right foot forward.","Repeat the movement on the other side, stepping back with your left foot and bending your right knee.","Continue alternating sides for the desired number of repetitions."],"it":["Stai con i piedi alla larghezza dei fianchi e le braccia lungo i fianchi.","Fai un passo indietro con il piede destro, atterrando sulla punta del piede.","Piega il ginocchio sinistro e abbassa il corpo in una posizione di affondo.","Mentre ti abbassi nell'affondo, allunga contemporaneamente le braccia sopra la testa.","Fermati per un momento nella parte inferiore dell'affondo, quindi torna alla posizione di partenza spingendo il tallone sinistro e portando il piede destro in avanti.","Ripeti il ​​movimento dall'altro lato, facendo un passo indietro con il piede sinistro e piegando il ginocchio destro.","Continua ad alternare i lati per il numero di ripetizioni desiderato."]}},{"id":"3119","name":"potty squat","category":"waist","equipment":"body weight","target":"abs","secondary":["quadriceps","glutes"],"steps":{"en":["Stand with your feet shoulder-width apart, toes pointing slightly outward.","Lower your body down by bending your knees and pushing your hips back as if you were sitting on a chair.","Keep your chest up and your back straight throughout the movement.","Lower yourself until your thighs are parallel to the ground or as low as you can comfortably go.","Pause for a moment at the bottom, then push through your heels to return to the starting position.","Repeat for the desired number of repetitions."],"it":["Stare con i piedi alla larghezza delle spalle, le dita dei piedi leggermente rivolte verso l'esterno.","Abbassa il corpo piegando le ginocchia e spingendo indietro i fianchi come se fossi seduto su una sedia.","Tieni il petto in alto e la schiena dritta durante tutto il movimento.","Abbassati finché le cosce non sono parallele al suolo o il più in basso possibile.","Fai una pausa per un momento in fondo, quindi spingi i talloni per tornare alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"3132","name":"potty squat with support","category":"upper legs","equipment":"body weight","target":"glutes","secondary":["quadriceps","hamstrings","calves"],"steps":{"en":["Stand with your feet shoulder-width apart, toes pointing slightly outward.","Hold onto a stable support, such as a chair or wall, for balance.","Lower your body down into a squat position by bending your knees and pushing your hips back.","Keep your chest up and your back straight throughout the movement.","Pause for a moment at the bottom, then push through your heels to return to the starting position.","Repeat for the desired number of repetitions."],"it":["Stare con i piedi alla larghezza delle spalle, le dita dei piedi leggermente rivolte verso l'esterno.","Tieniti su un supporto stabile, come una sedia o un muro, per mantenere l'equilibrio.","Abbassa il corpo in una posizione tozza piegando le ginocchia e spingendo indietro i fianchi.","Tieni il petto in alto e la schiena dritta durante tutto il movimento.","Fai una pausa per un momento in fondo, quindi spingi i talloni per tornare alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0648","name":"power clean","category":"upper legs","equipment":"barbell","target":"hamstrings","secondary":["glutes","quadriceps","calves"],"steps":{"en":["Start with the barbell on the ground in front of you, with your feet shoulder-width apart.","Bend down and grip the barbell with an overhand grip, slightly wider than shoulder-width apart.","Keep your back straight and chest up as you lift the barbell off the ground, extending your hips and knees.","As the barbell reaches your mid-thigh, explosively pull it upwards, shrugging your shoulders and pulling your elbows high and to the sides.","As the barbell reaches its highest point, quickly drop underneath it, rotating your elbows around and catching the barbell on your shoulders in a front squat position.","Stand up with the barbell, fully extending your hips and knees.","Lower the barbell back down to the starting position, keeping control of the weight throughout the movement.","Repeat for the desired number of repetitions."],"it":["Inizia con il bilanciere a terra davanti a te, con i piedi alla larghezza delle spalle.","Piegati verso il basso e afferra il bilanciere con una presa prona, leggermente più larga della larghezza delle spalle.","Tieni la schiena dritta e il petto in alto mentre sollevi il bilanciere da terra, estendendo le anche e le ginocchia.","Quando il bilanciere raggiunge la metà della coscia, tiralo in modo esplosivo verso l'alto, alzando le spalle e tirando i gomiti in alto e lateralmente.","Quando il bilanciere raggiunge il punto più alto, abbassati rapidamente sotto di esso, ruotando i gomiti e afferrando il bilanciere sulle spalle in posizione di front squat.","Alzati con il bilanciere, estendendo completamente le anche e le ginocchia.","Abbassare il bilanciere nella posizione iniziale, mantenendo il controllo del peso durante tutto il movimento.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"3665","name":"power point plank","category":"waist","equipment":"body weight","target":"abs","secondary":["shoulders","triceps","glutes"],"steps":{"en":["Start in a high plank position with your hands directly under your shoulders and your body in a straight line from head to toe.","Engage your core and squeeze your glutes to maintain a stable position.","Lower your body down onto your forearms, one arm at a time, maintaining a straight line from head to toe.","Hold this position for the desired amount of time, keeping your core and glutes engaged.","To return to the starting position, push through your forearms and lift your body back up into a high plank position.","Repeat for the desired number of repetitions."],"it":["Inizia in una posizione di plancia alta con le mani direttamente sotto le spalle e il corpo in linea retta dalla testa ai piedi.","Coinvolgi il core e contrai i glutei per mantenere una posizione stabile.","Abbassa il corpo sugli avambracci, un braccio alla volta, mantenendo una linea retta dalla testa ai piedi.","Mantieni questa posizione per il tempo desiderato, mantenendo impegnati il ​​core e i glutei.","Per tornare alla posizione di partenza, spingi gli avambracci e solleva il corpo in una posizione di plancia alta.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"3203","name":"prisoner half sit-up (male)","category":"waist","equipment":"body weight","target":"abs","secondary":["hip flexors"],"steps":{"en":["Lie flat on your back with your knees bent and feet flat on the ground.","Place your hands behind your head with your elbows pointing outwards.","Engaging your abs, slowly lift your upper body off the ground, curling forward until your torso is at a 45-degree angle.","Pause for a moment at the top, then slowly lower your upper body back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Sdraiati sulla schiena con le ginocchia piegate e i piedi appoggiati a terra.","Metti le mani dietro la testa con i gomiti rivolti verso l'esterno.","Coinvolgendo gli addominali, solleva lentamente la parte superiore del corpo da terra, piegandoti in avanti finché il busto non forma un angolo di 45 gradi.","Fermati per un momento in alto, quindi abbassa lentamente la parte superiore del corpo fino alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"1707","name":"prone twist on stability ball","category":"waist","equipment":"stability ball","target":"abs","secondary":["obliques","lower back"],"steps":{"en":["Start by lying face down on a stability ball with your feet shoulder-width apart and your toes touching the ground.","Place your hands behind your head or cross them over your chest.","Engage your core muscles and slowly lift your upper body off the ball, keeping your back straight.","Rotate your torso to one side, bringing your shoulder towards your hip. Keep your hips and legs stable throughout the movement.","Pause for a moment, then return to the starting position.","Repeat the rotation to the other side.","Continue alternating sides for the desired number of repetitions."],"it":["Inizia sdraiandoti a faccia in giù su una palla stabilizzante con i piedi alla larghezza delle spalle e le dita dei piedi che toccano il suolo.","Metti le mani dietro la testa o incrociale sul petto.","Coinvolgi i muscoli centrali e solleva lentamente la parte superiore del corpo dalla palla, mantenendo la schiena dritta.","Ruota il busto da un lato, portando la spalla verso il fianco. Mantieni i fianchi e le gambe stabili durante tutto il movimento.","Fare una pausa per un momento, quindi tornare alla posizione di partenza.","Ripeti la rotazione sull'altro lato.","Continua ad alternare i lati per il numero di ripetizioni desiderato."]}},{"id":"0651","name":"pull up (neutral grip)","category":"back","equipment":"body weight","target":"lats","secondary":["biceps","forearms"],"steps":{"en":["Hang from a pull-up bar with a neutral grip (palms facing each other) and your arms fully extended.","Engage your core and squeeze your shoulder blades together.","Pull your body up towards the bar by bending your elbows and driving your elbows down towards your hips.","Continue pulling until your chin is above the bar.","Pause for a moment at the top, then slowly lower your body back down to the starting position with control.","Repeat for the desired number of repetitions."],"it":["Appendersi a una barra per trazioni con una presa neutra (palmi rivolti uno verso l'altro) e le braccia completamente distese.","Coinvolgi il tuo core e stringi insieme le scapole.","Tira il corpo verso la barra piegando i gomiti e spingendoli verso i fianchi.","Continua a tirare finché il mento non è sopra la barra.","Fai una pausa per un momento in alto, quindi abbassa lentamente il corpo fino alla posizione iniziale con controllo.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0650","name":"pull-in (on stability ball)","category":"waist","equipment":"stability ball","target":"abs","secondary":["hip flexors"],"steps":{"en":["Start by sitting on the stability ball with your feet flat on the ground and your knees bent at a 90-degree angle.","Place your hands on the sides of the stability ball for support.","Engage your abs and slowly roll your hips forward, bringing your knees towards your chest.","Pause for a moment at the top of the movement, then slowly extend your legs back to the starting position.","Repeat for the desired number of repetitions."],"it":["Inizia sedendoti sulla palla di stabilità con i piedi appoggiati a terra e le ginocchia piegate con un angolo di 90 gradi.","Metti le mani sui lati della palla stabilizzante per supporto.","Coinvolgi gli addominali e ruota lentamente i fianchi in avanti, portando le ginocchia verso il petto.","Fai una pausa per un momento nella parte superiore del movimento, quindi estendi lentamente le gambe fino alla posizione iniziale.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0652","name":"pull-up","category":"back","equipment":"body weight","target":"lats","secondary":["biceps","forearms"],"steps":{"en":["Hang from a pull-up bar with your palms facing away from you and your arms fully extended.","Engage your core and squeeze your shoulder blades together.","Pull your body up towards the bar by bending your elbows and bringing your chest towards the bar.","Pause at the top of the movement, then slowly lower your body back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Appendi a una barra per trazioni con i palmi delle mani rivolti lontano da te e le braccia completamente distese.","Coinvolgi il tuo core e stringi insieme le scapole.","Tira il corpo verso la sbarra piegando i gomiti e portando il petto verso la sbarra.","Fai una pausa nella parte superiore del movimento, quindi abbassa lentamente il corpo fino alla posizione iniziale.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"1689","name":"push and pull bodyweight","category":"chest","equipment":"body weight","target":"pectorals","secondary":["triceps","deltoids"],"steps":{"en":["Start in a push-up position with your hands slightly wider than shoulder-width apart and your body in a straight line.","Lower your chest towards the ground by bending your elbows, keeping your body straight.","Push through your palms to extend your arms and return to the starting position.","From the push-up position, pull your chest towards the ground by bending your elbows, keeping your body straight.","Push through your palms to extend your arms and return to the starting position.","Repeat for the desired number of repetitions."],"it":["Inizia in una posizione push-up con le mani leggermente più larghe della larghezza delle spalle e il corpo in linea retta.","Abbassa il petto verso terra piegando i gomiti, mantenendo il corpo dritto.","Spingi attraverso i palmi delle mani per estendere le braccia e tornare alla posizione di partenza.","Dalla posizione delle flessioni, avvicina il petto a terra piegando i gomiti, mantenendo il corpo dritto.","Spingi attraverso i palmi delle mani per estendere le braccia e tornare alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"3638","name":"push to run","category":"cardio","equipment":"body weight","target":"cardiovascular system","secondary":["quadriceps","hamstrings","calves"],"steps":{"en":["Start in a push-up position with your hands shoulder-width apart and your body in a straight line.","Lower your chest towards the ground by bending your elbows, keeping your body straight.","Push through your hands to extend your arms and return to the starting position.","Quickly bring one knee towards your chest, then quickly switch and bring the other knee towards your chest.","Continue alternating knees as fast as you can while maintaining good form.","Continue for the desired duration or number of repetitions."],"it":["Inizia in una posizione push-up con le mani alla larghezza delle spalle e il corpo in linea retta.","Abbassa il petto verso terra piegando i gomiti, mantenendo il corpo dritto.","Spingi attraverso le mani per estendere le braccia e tornare alla posizione di partenza.","Porta rapidamente un ginocchio verso il petto, quindi cambia rapidamente e porta l'altro ginocchio verso il petto.","Continua ad alternare le ginocchia il più velocemente possibile mantenendo una buona forma.","Continuare per la durata o il numero di ripetizioni desiderati."]}},{"id":"0662","name":"push-up","category":"chest","equipment":"body weight","target":"pectorals","secondary":["triceps","deltoids","core"],"steps":{"en":["Start in a high plank position with your hands slightly wider than shoulder-width apart and your feet together.","Engage your core and lower your body towards the ground by bending your elbows, keeping your body in a straight line.","Pause for a moment when your chest is just above the ground, then push yourself back up to the starting position by straightening your arms.","Repeat for the desired number of repetitions."],"it":["Inizia in una posizione di plancia alta con le mani leggermente più larghe della larghezza delle spalle e i piedi uniti.","Coinvolgi il core e abbassa il corpo verso terra piegando i gomiti, mantenendo il corpo in linea retta.","Fai una pausa per un momento quando il petto è appena sopra il suolo, quindi ritorna alla posizione di partenza raddrizzando le braccia.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0655","name":"push-up (on stability ball)","category":"chest","equipment":"stability ball","target":"pectorals","secondary":["triceps","shoulders","core"],"steps":{"en":["Place the stability ball on the ground and position yourself facing down with your hands on the ball, shoulder-width apart.","Extend your legs straight out behind you, balancing on your toes.","Engage your core and lower your chest towards the ball by bending your elbows, keeping your body in a straight line.","Pause for a moment at the bottom, then push yourself back up to the starting position by straightening your arms.","Repeat for the desired number of repetitions."],"it":["Posiziona la palla di stabilità a terra e posizionati a faccia in giù con le mani sulla palla, alla larghezza delle spalle.","Estendi le gambe dietro di te, in equilibrio sulle punte dei piedi.","Coinvolgi il core e abbassa il petto verso la palla piegando i gomiti, mantenendo il corpo in linea retta.","Fai una pausa per un momento in basso, quindi ritorna alla posizione di partenza raddrizzando le braccia.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0656","name":"push-up (on stability ball)","category":"chest","equipment":"stability ball","target":"pectorals","secondary":["triceps","shoulders","core"],"steps":{"en":["Place the stability ball on the ground and position yourself facing down with your hands on the ball, shoulder-width apart.","Extend your legs straight out behind you, balancing on your toes.","Engage your core and lower your chest towards the ball by bending your elbows, keeping your body in a straight line.","Pause for a moment at the bottom, then push yourself back up to the starting position by straightening your arms.","Repeat for the desired number of repetitions."],"it":["Posiziona la palla di stabilità a terra e posizionati a faccia in giù con le mani sulla palla, alla larghezza delle spalle.","Estendi le gambe dietro di te, in equilibrio sulle punte dei piedi.","Coinvolgi il core e abbassa il petto verso la palla piegando i gomiti, mantenendo il corpo in linea retta.","Fai una pausa per un momento in basso, quindi ritorna alla posizione di partenza raddrizzando le braccia.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0659","name":"push-up (wall)","category":"chest","equipment":"body weight","target":"pectorals","secondary":["triceps","deltoids"],"steps":{"en":["Stand facing a wall, about arm's length away.","Place your hands on the wall at shoulder height, slightly wider than shoulder-width apart.","Step back a few feet, keeping your body straight and your feet hip-width apart.","Bend your elbows and lower your chest towards the wall, keeping your body in a straight line.","Push back up to the starting position, straightening your arms.","Repeat for the desired number of repetitions."],"it":["Mettiti di fronte a un muro, a circa un braccio di distanza.","Appoggia le mani sul muro all'altezza delle spalle, leggermente più larghe della larghezza delle spalle.","Fai un passo indietro di qualche metro, mantenendo il corpo dritto e i piedi divaricati alla larghezza dei fianchi.","Piega i gomiti e abbassa il petto verso il muro, mantenendo il corpo in linea retta.","Spingiti indietro fino alla posizione di partenza, raddrizzando le braccia.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0658","name":"push-up (wall) v. 2","category":"chest","equipment":"body weight","target":"pectorals","secondary":["triceps","shoulders"],"steps":{"en":["Stand facing a wall, about arm's length away.","Place your hands on the wall at shoulder height, slightly wider than shoulder-width apart.","Step back with your feet, keeping them hip-width apart.","Engage your core and keep your body in a straight line from head to heels.","Bend your elbows and lower your chest towards the wall, keeping your body straight.","Pause for a moment, then push yourself back to the starting position.","Repeat for the desired number of repetitions."],"it":["Mettiti di fronte a un muro, a circa un braccio di distanza.","Appoggia le mani sul muro all'altezza delle spalle, leggermente più larghe della larghezza delle spalle.","Fai un passo indietro con i piedi, tenendoli alla larghezza dei fianchi.","Coinvolgi il tuo core e mantieni il corpo in linea retta dalla testa ai talloni.","Piega i gomiti e abbassa il petto verso il muro, mantenendo il corpo dritto.","Fai una pausa per un momento, quindi ritorna alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0660","name":"push-up close-grip off dumbbell","category":"upper arms","equipment":"dumbbell","target":"triceps","secondary":["chest","shoulders"],"steps":{"en":["Start in a push-up position with your hands placed close together, directly under your shoulders.","Hold a dumbbell in each hand, resting them on the ground.","Lower your body towards the ground by bending your elbows, keeping them close to your sides.","Push through your palms to extend your arms and return to the starting position.","Repeat for the desired number of repetitions."],"it":["Inizia in una posizione push-up con le mani ravvicinate, direttamente sotto le spalle.","Tieni un manubrio in ciascuna mano, appoggiandolo a terra.","Abbassa il corpo verso terra piegando i gomiti, tenendoli vicini ai fianchi.","Spingi attraverso i palmi delle mani per estendere le braccia e tornare alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0661","name":"push-up inside leg kick","category":"upper legs","equipment":"body weight","target":"glutes","secondary":["quadriceps","hamstrings","calves","core"],"steps":{"en":["Start in a push-up position with your hands slightly wider than shoulder-width apart and your feet together.","Lower your body towards the ground by bending your elbows, keeping your back straight and your core engaged.","As you push back up, lift one leg off the ground and kick it out to the side, keeping it straight.","Lower your leg back down and repeat the push-up, then switch to the other leg.","Continue alternating leg kicks with each push-up repetition."],"it":["Inizia in una posizione push-up con le mani leggermente più larghe della larghezza delle spalle e i piedi uniti.","Abbassa il corpo verso terra piegando i gomiti, mantenendo la schiena dritta e il core impegnato.","Mentre ti spingi verso l'alto, solleva una gamba da terra e calciala di lato, mantenendola dritta.","Abbassa di nuovo la gamba e ripeti il ​​push-up, quindi passa all'altra gamba.","Continua ad alternare i calci delle gambe ad ogni ripetizione di push-up."]}},{"id":"1467","name":"push-up on lower arms","category":"upper arms","equipment":"body weight","target":"triceps","secondary":["chest","shoulders"],"steps":{"en":["Start in a plank position with your forearms on the ground and elbows directly below your shoulders.","Engage your core and keep your body in a straight line from head to toe.","Lower your chest towards the ground by bending your elbows, keeping them close to your body.","Pause for a moment at the bottom, then push yourself back up to the starting position.","Repeat for the desired number of repetitions."],"it":["Inizia in una posizione di plancia con gli avambracci a terra e i gomiti direttamente sotto le spalle.","Coinvolgi il tuo core e mantieni il corpo in linea retta dalla testa ai piedi.","Abbassa il petto verso terra piegando i gomiti, tenendoli vicini al corpo.","Fai una pausa per un momento in basso, quindi spingiti indietro fino alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"3145","name":"push-up plus","category":"chest","equipment":"body weight","target":"pectorals","secondary":["triceps","shoulders"],"steps":{"en":["Start in a high plank position with your hands slightly wider than shoulder-width apart and your body in a straight line from head to heels.","Lower your body towards the ground by bending your elbows, keeping them close to your sides.","Once your chest is just above the ground, push through your hands to extend your arms and lift your upper body up.","At the top of the movement, protract your shoulder blades by pushing your upper back towards the ceiling.","Pause for a moment, then reverse the movement by retracting your shoulder blades and lowering your body back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Inizia in una posizione di plancia alta con le mani leggermente più larghe della larghezza delle spalle e il corpo in linea retta dalla testa ai talloni.","Abbassa il corpo verso terra piegando i gomiti, tenendoli vicini ai fianchi.","Una volta che il petto è appena sopra il suolo, spingi con le mani per estendere le braccia e sollevare la parte superiore del corpo.","Nella parte superiore del movimento, protrarre le scapole spingendo la parte superiore della schiena verso il soffitto.","Fai una pausa per un momento, quindi inverti il ​​movimento ritraendo le scapole e abbassando il corpo nella posizione iniziale.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0664","name":"push-up to side plank","category":"waist","equipment":"body weight","target":"abs","secondary":["shoulders","chest","triceps"],"steps":{"en":["Start in a push-up position with your hands shoulder-width apart and your body in a straight line.","Lower your body towards the ground by bending your elbows, keeping your core engaged.","Push back up to the starting position.","Shift your weight onto your left hand and rotate your body to the right, lifting your right arm towards the ceiling.","Hold the side plank position for a few seconds, then return to the starting position.","Repeat the push-up and side plank on the opposite side.","Continue alternating sides for the desired number of repetitions."],"it":["Inizia in una posizione push-up con le mani alla larghezza delle spalle e il corpo in linea retta.","Abbassa il corpo verso terra piegando i gomiti, mantenendo il core impegnato.","Spingi indietro fino alla posizione di partenza.","Sposta il peso sulla mano sinistra e ruota il corpo verso destra, sollevando il braccio destro verso il soffitto.","Mantieni la posizione della plancia laterale per alcuni secondi, quindi torna alla posizione di partenza.","Ripeti il ​​push-up e il plank laterale sul lato opposto.","Continua ad alternare i lati per il numero di ripetizioni desiderato."]}},{"id":"3533","name":"quads","category":"upper legs","equipment":"body weight","target":"quads","secondary":["hamstrings","glutes"],"steps":{"en":["Stand with your feet shoulder-width apart.","Lower your body by bending your knees and pushing your hips back as if sitting on a chair.","Keep your chest up and your back straight.","Lower yourself until your thighs are parallel to the ground.","Push through your heels to return to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai con i piedi alla larghezza delle spalle.","Abbassa il corpo piegando le ginocchia e spingendo indietro i fianchi come se fossi seduto su una sedia.","Tieni il petto in alto e la schiena dritta.","Abbassati finché le cosce non sono parallele al suolo.","Spingi i talloni per tornare alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"3201","name":"quarter sit-up","category":"waist","equipment":"body weight","target":"abs","secondary":["hip flexors"],"steps":{"en":["Lie flat on your back with your knees bent and feet flat on the ground.","Place your hands behind your head with your elbows pointing outwards.","Engaging your abs, slowly lift your upper body off the ground, curling forward until your torso is at a 45-degree angle.","Pause for a moment at the top, then slowly lower your upper body back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Sdraiati sulla schiena con le ginocchia piegate e i piedi appoggiati a terra.","Metti le mani dietro la testa con i gomiti rivolti verso l'esterno.","Coinvolgendo gli addominali, solleva lentamente la parte superiore del corpo da terra, piegandoti in avanti finché il busto non forma un angolo di 45 gradi.","Fermati per un momento in alto, quindi abbassa lentamente la parte superiore del corpo fino alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"3552","name":"quick feet v. 2","category":"upper legs","equipment":"body weight","target":"quads","secondary":["calves","hamstrings"],"steps":{"en":["Stand with your feet shoulder-width apart and your arms by your sides.","Begin by rapidly moving your feet up and down, as if you were running in place.","Keep your movements quick and light, focusing on staying on the balls of your feet.","Continue for the desired duration or number of repetitions."],"it":["Stai con i piedi alla larghezza delle spalle e le braccia lungo i fianchi.","Inizia muovendo rapidamente i piedi su e giù, come se stessi correndo sul posto.","Mantieni i movimenti rapidi e leggeri, concentrandoti sul rimanere sulle punte dei piedi.","Continuare per la durata o il numero di ripetizioni desiderati."]}},{"id":"0666","name":"raise single arm push-up","category":"chest","equipment":"body weight","target":"pectorals","secondary":["triceps","shoulders","core"],"steps":{"en":["Start in a push-up position with your hands slightly wider than shoulder-width apart and your feet together.","Extend one arm straight out to the side, parallel to the ground.","Lower your body towards the ground by bending your elbows, keeping your back straight and core engaged.","Push back up to the starting position, using your chest muscles to lift your body.","Repeat with the other arm extended."],"it":["Inizia in una posizione push-up con le mani leggermente più larghe della larghezza delle spalle e i piedi uniti.","Estendi un braccio di lato, parallelo al suolo.","Abbassa il corpo verso terra piegando i gomiti, mantenendo la schiena dritta e il core impegnato.","Spingiti indietro fino alla posizione di partenza, usando i muscoli del torace per sollevare il corpo.","Ripeti con l'altro braccio esteso."]}},{"id":"0668","name":"rear decline bridge","category":"upper legs","equipment":"body weight","target":"glutes","secondary":["hamstrings","lower back"],"steps":{"en":["Lie on your back with your feet flat on the ground and your knees bent.","Place your arms by your sides with your palms facing down.","Engage your glutes and hamstrings, and lift your hips off the ground until your body forms a straight line from your knees to your shoulders.","Hold this position for a few seconds, then slowly lower your hips back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Sdraiati sulla schiena con i piedi appoggiati a terra e le ginocchia piegate.","Posiziona le braccia lungo i fianchi con i palmi rivolti verso il basso.","Coinvolgi i glutei e i muscoli posteriori della coscia e solleva i fianchi da terra finché il tuo corpo non forma una linea retta dalle ginocchia alle spalle.","Mantieni questa posizione per alcuni secondi, quindi abbassa lentamente i fianchi fino alla posizione iniziale.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0669","name":"rear deltoid stretch","category":"shoulders","equipment":"body weight","target":"delts","secondary":["trapezius","rhomboids"],"steps":{"en":["Stand tall with your feet shoulder-width apart.","Extend your right arm across your chest, placing your left hand on your right elbow.","Gently pull your right arm towards your left shoulder, feeling a stretch in your right shoulder.","Hold the stretch for 15-30 seconds, then release.","Repeat on the other side."],"it":["Stai in piedi con i piedi alla larghezza delle spalle.","Estendi il braccio destro sul petto, posizionando la mano sinistra sul gomito destro.","Tira delicatamente il braccio destro verso la spalla sinistra, avvertendo un allungamento nella spalla destra.","Mantieni la posizione per 15-30 secondi, quindi rilascia.","Ripeti dall'altra parte."]}},{"id":"0670","name":"rear pull-up","category":"back","equipment":"body weight","target":"lats","secondary":["biceps","forearms"],"steps":{"en":["Grab the pull-up bar with an overhand grip, slightly wider than shoulder-width apart.","Hang from the bar with your arms fully extended and your body straight.","Engage your back muscles and pull your body up towards the bar, keeping your elbows close to your body.","Continue pulling until your chin is above the bar.","Pause for a moment at the top, then slowly lower your body back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Afferra la barra per trazioni con una presa prona, leggermente più larga della larghezza delle spalle.","Appendi alla barra con le braccia completamente distese e il corpo dritto.","Coinvolgi i muscoli della schiena e solleva il corpo verso la barra, mantenendo i gomiti vicini al corpo.","Continua a tirare finché il mento non è sopra la barra.","Fai una pausa per un momento in alto, quindi abbassa lentamente il corpo fino alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0872","name":"reverse crunch","category":"waist","equipment":"body weight","target":"abs","secondary":["hip flexors"],"steps":{"en":["Lie flat on your back with your arms extended along your sides.","Bend your knees and lift your feet off the ground, bringing your thighs perpendicular to the floor.","Contract your abs and curl your hips off the floor, bringing your knees towards your chest.","Pause for a moment at the top, then slowly lower your hips back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Sdraiati sulla schiena con le braccia distese lungo i fianchi.","Piega le ginocchia e solleva i piedi da terra, portando le cosce perpendicolari al pavimento.","Contrai gli addominali e solleva i fianchi dal pavimento, portando le ginocchia verso il petto.","Fai una pausa per un momento in alto, quindi abbassa lentamente i fianchi fino alla posizione iniziale.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0672","name":"reverse dip","category":"upper arms","equipment":"body weight","target":"triceps","secondary":["chest","shoulders"],"steps":{"en":["Position yourself between two parallel bars with your arms fully extended and your body straight.","Lower your body by bending your elbows until your upper arms are parallel to the ground.","Pause for a moment, then push yourself back up to the starting position by straightening your arms.","Repeat for the desired number of repetitions."],"it":["Posizionati tra due barre parallele con le braccia completamente distese e il corpo dritto.","Abbassa il corpo piegando i gomiti finché la parte superiore delle braccia non è parallela al suolo.","Fai una pausa per un momento, quindi ritorna alla posizione di partenza raddrizzando le braccia.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0674","name":"reverse grip pull-up","category":"back","equipment":"body weight","target":"lats","secondary":["biceps","forearms"],"steps":{"en":["Grab the pull-up bar with an underhand grip, hands shoulder-width apart.","Hang from the bar with your arms fully extended and your body straight.","Engage your back muscles and pull your body up towards the bar, leading with your chest.","Continue pulling until your chin is above the bar.","Pause for a moment at the top, then slowly lower your body back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Afferra la barra per trazioni con una presa subdola, con le mani alla larghezza delle spalle.","Appendi alla barra con le braccia completamente distese e il corpo dritto.","Coinvolgi i muscoli della schiena e solleva il corpo verso la barra, guidando con il petto.","Continua a tirare finché il mento non è sopra la barra.","Fai una pausa per un momento in alto, quindi abbassa lentamente il corpo fino alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0675","name":"reverse hyper extension (on stability ball)","category":"upper legs","equipment":"stability ball","target":"glutes","secondary":["hamstrings","lower back"],"steps":{"en":["Lie face down on a stability ball with your hips resting on the ball and your legs extended straight behind you.","Place your hands on the ground in front of you for stability.","Engaging your glutes and hamstrings, lift your legs up towards the ceiling as high as you can.","Pause for a moment at the top, then slowly lower your legs back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Sdraiati a faccia in giù su una palla stabilizzata con i fianchi appoggiati sulla palla e le gambe distese dietro di te.","Metti le mani a terra davanti a te per stabilità.","Coinvolgendo i glutei e i muscoli posteriori della coscia, solleva le gambe verso il soffitto più in alto che puoi.","Fai una pausa per un momento in alto, quindi abbassa lentamente le gambe fino alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"1423","name":"reverse hyper on flat bench","category":"upper legs","equipment":"body weight","target":"glutes","secondary":["hamstrings","lower back"],"steps":{"en":["Lie face down on a flat bench with your hips at the edge and your legs hanging off the bench.","Hold onto the bench for stability.","Keeping your legs straight, raise them up towards the ceiling as high as you can.","Squeeze your glutes at the top of the movement.","Slowly lower your legs back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Sdraiati a faccia in giù su una panca piana con i fianchi sul bordo e le gambe pendenti dalla panca.","Tieniti sulla panca per stabilità.","Tenendo le gambe dritte, sollevale verso il soffitto più in alto che puoi.","Contrai i glutei nella parte superiore del movimento.","Abbassa lentamente le gambe fino alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"3663","name":"reverse plank with leg lift","category":"waist","equipment":"body weight","target":"abs","secondary":["glutes","hamstrings","shoulders"],"steps":{"en":["Sit on the ground with your legs extended in front of you and your hands resting on the ground behind you, fingers pointing towards your feet.","Press through your hands and lift your hips off the ground, coming into a reverse plank position.","Engage your core and lift one leg off the ground, extending it straight up towards the ceiling.","Hold for a moment, then lower your leg back down.","Repeat with the other leg.","Continue alternating legs for the desired number of repetitions."],"it":["Siediti a terra con le gambe distese davanti a te e le mani appoggiate a terra dietro di te, con le dita rivolte verso i tuoi piedi.","Premi tra le mani e solleva i fianchi da terra, arrivando in una posizione di plancia inversa.","Coinvolgi il core e solleva una gamba da terra, estendendola verso il soffitto.","Mantieni la posizione per un momento, quindi abbassa nuovamente la gamba.","Ripeti con l'altra gamba.","Continua ad alternare le gambe per il numero di ripetizioni desiderato."]}},{"id":"0677","name":"ring dips","category":"upper arms","equipment":"body weight","target":"triceps","secondary":["chest","shoulders"],"steps":{"en":["Start by hanging from the rings with your arms fully extended and your body straight.","Lower your body by bending your elbows until your shoulders are below your elbows.","Push yourself back up to the starting position by straightening your arms.","Repeat for the desired number of repetitions."],"it":["Inizia appendendoti agli anelli con le braccia completamente distese e il corpo dritto.","Abbassa il corpo piegando i gomiti finché le spalle non sono sotto i gomiti.","Spingiti indietro fino alla posizione di partenza raddrizzando le braccia.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"2571","name":"rocking frog stretch","category":"upper legs","equipment":"body weight","target":"glutes","secondary":["hamstrings","quadriceps"],"steps":{"en":["Start by kneeling on the ground with your knees hip-width apart.","Place your hands on the ground in front of you for support.","Slowly lean forward, shifting your weight onto your hands and extending your legs behind you.","Keep your back straight and engage your glutes as you push your hips back and up towards the ceiling.","Hold this position for a few seconds, feeling a stretch in your glutes.","Slowly return to the starting position by bending your knees and lowering your hips back down.","Repeat for the desired number of repetitions."],"it":["Inizia in ginocchio a terra con le ginocchia alla larghezza dei fianchi.","Metti le mani a terra davanti a te per supporto.","Piegati lentamente in avanti, spostando il peso sulle mani ed estendendo le gambe dietro di te.","Tieni la schiena dritta e contrai i glutei mentre spingi i fianchi indietro e verso il soffitto.","Mantieni questa posizione per alcuni secondi, avvertendo l'allungamento dei glutei.","Ritorna lentamente alla posizione di partenza piegando le ginocchia e abbassando i fianchi.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0678","name":"rocky pull-up pulldown","category":"back","equipment":"body weight","target":"lats","secondary":["biceps","forearms"],"steps":{"en":["Stand in front of a pull-up bar with your feet shoulder-width apart.","Reach up and grab the bar with an overhand grip, slightly wider than shoulder-width apart.","Hang from the bar with your arms fully extended and your body straight.","Engage your back muscles and pull your body up towards the bar, leading with your chest.","Pause for a moment at the top, then slowly lower your body back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Mettiti di fronte a una barra per trazioni con i piedi alla larghezza delle spalle.","Allungati e afferra la barra con una presa prona, leggermente più larga della larghezza delle spalle.","Appendi alla barra con le braccia completamente distese e il corpo dritto.","Coinvolgi i muscoli della schiena e solleva il corpo verso la barra, guidando con il petto.","Fai una pausa per un momento in alto, quindi abbassa lentamente il corpo fino alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0685","name":"run","category":"cardio","equipment":"body weight","target":"cardiovascular system","secondary":["quadriceps","hamstrings","calves"],"steps":{"en":["Start by standing upright with your feet hip-width apart.","Engage your core and keep your upper body relaxed.","Begin jogging in place, lifting your knees up towards your chest and landing softly on the balls of your feet.","Maintain a steady pace and continue jogging for the desired duration or distance.","Remember to breathe deeply and maintain good posture throughout the exercise."],"it":["Inizia stando in piedi con i piedi alla larghezza dei fianchi.","Coinvolgi il tuo core e mantieni la parte superiore del corpo rilassata.","Inizia a fare jogging sul posto, sollevando le ginocchia verso il petto e atterrando dolcemente sulle punte dei piedi.","Mantenere un ritmo costante e continuare a fare jogging per la durata o la distanza desiderata.","Ricordatevi di respirare profondamente e di mantenere una buona postura durante l'esercizio."]}},{"id":"0684","name":"run (equipment)","category":"cardio","equipment":"body weight","target":"cardiovascular system","secondary":["quadriceps","hamstrings","calves"],"steps":{"en":["Start by standing upright with your feet hip-width apart.","Engage your core and keep your upper body relaxed.","Begin jogging in place, lifting your knees up towards your chest and landing softly on the balls of your feet.","Maintain a steady pace and continue jogging for the desired duration or distance.","Remember to breathe deeply and maintain good posture throughout the exercise."],"it":["Inizia stando in piedi con i piedi alla larghezza dei fianchi.","Coinvolgi il tuo core e mantieni la parte superiore del corpo rilassata.","Inizia a fare jogging sul posto, sollevando le ginocchia verso il petto e atterrando dolcemente sulle punte dei piedi.","Mantenere un ritmo costante e continuare a fare jogging per la durata o la distanza desiderata.","Ricordatevi di respirare profondamente e di mantenere una buona postura durante l'esercizio."]}},{"id":"1585","name":"runners stretch","category":"upper legs","equipment":"body weight","target":"hamstrings","secondary":["calves","quadriceps"],"steps":{"en":["Stand with your feet hip-width apart.","Take a step forward with your right foot, keeping your left foot planted.","Bend your right knee and lower your body down, keeping your left leg straight.","Place your hands on your right thigh for support.","Hold the stretch for 20-30 seconds, then switch sides and repeat."],"it":["Stai con i piedi alla larghezza dei fianchi.","Fai un passo avanti con il piede destro, mantenendo il piede sinistro ben piantato.","Piega il ginocchio destro e abbassa il corpo, mantenendo la gamba sinistra dritta.","Metti le mani sulla coscia destra per supporto.","Mantieni la posizione per 20-30 secondi, poi cambia lato e ripeti."]}},{"id":"0687","name":"russian twist","category":"waist","equipment":"body weight","target":"abs","secondary":["obliques"],"steps":{"en":["Sit on the ground with your knees bent and feet flat on the floor.","Lean back slightly while keeping your back straight and your core engaged.","Hold your hands together in front of your chest or hold a weight if desired.","Lift your feet off the ground, balancing on your sit bones.","Twist your torso to the right, bringing your hands or weight towards the right side of your body.","Pause for a moment, then twist your torso to the left, bringing your hands or weight towards the left side of your body.","Continue alternating sides for the desired number of repetitions."],"it":["Sedersi a terra con le ginocchia piegate e i piedi appoggiati sul pavimento.","Appoggiati leggermente all'indietro mantenendo la schiena dritta e il core impegnato.","Tieni le mani unite davanti al petto o tieni un peso se lo desideri.","Solleva i piedi da terra, in equilibrio sulle ossa del sedere.","Ruota il busto verso destra, portando le mani o il peso verso il lato destro del corpo.","Fai una pausa per un momento, quindi ruota il busto verso sinistra, portando le mani o il peso verso il lato sinistro del corpo.","Continua ad alternare i lati per il numero di ripetizioni desiderato."]}},{"id":"3012","name":"scapula dips","category":"back","equipment":"body weight","target":"traps","secondary":["rhomboids","deltoids"],"steps":{"en":["Start by standing with your feet shoulder-width apart and your arms extended in front of you.","Bend your knees slightly and hinge forward at the hips, keeping your back straight.","Lower your body by bending your elbows and retracting your shoulder blades, as if you are trying to squeeze a pencil between them.","Pause for a moment at the bottom, then push through your hands to extend your elbows and return to the starting position.","Repeat for the desired number of repetitions."],"it":["Inizia stando in piedi con i piedi alla larghezza delle spalle e le braccia distese davanti a te.","Piega leggermente le ginocchia e fai perno in avanti sui fianchi, mantenendo la schiena dritta.","Abbassa il corpo piegando i gomiti e ritraendo le scapole, come se stessi cercando di infilare una matita tra di loro.","Fai una pausa per un momento in basso, quindi spingi con le mani per estendere i gomiti e tornare alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"3021","name":"scapula push-up","category":"chest","equipment":"body weight","target":"serratus anterior","secondary":["triceps","shoulders"],"steps":{"en":["Start in a high plank position with your hands directly under your shoulders and your body in a straight line.","Lower your chest towards the ground, keeping your elbows close to your body.","As you lower, squeeze your shoulder blades together and push your chest forward.","Pause for a moment at the bottom, then push back up to the starting position.","Repeat for the desired number of repetitions."],"it":["Inizia in una posizione di plancia alta con le mani direttamente sotto le spalle e il corpo in linea retta.","Abbassa il petto verso terra, mantenendo i gomiti vicini al corpo.","Mentre ti abbassi, stringi le scapole e spingi il petto in avanti.","Fai una pausa per un momento in basso, quindi torna alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0688","name":"scapular pull-up","category":"back","equipment":"body weight","target":"traps","secondary":["biceps","rhomboids","rear deltoids"],"steps":{"en":["Start by hanging from a pull-up bar with your palms facing away from you and your arms fully extended.","Retract your shoulder blades by pulling them down and back.","Engage your back muscles and pull your body up towards the bar, focusing on squeezing your shoulder blades together.","Pause for a moment at the top of the movement, then slowly lower your body back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Inizia appendendoti a una barra per trazioni con i palmi delle mani rivolti lontano da te e le braccia completamente distese.","Ritira le scapole tirandole verso il basso e all'indietro.","Coinvolgi i muscoli della schiena e solleva il corpo verso la barra, concentrandoti sulla contrazione delle scapole.","Fai una pausa per un momento nella parte superiore del movimento, quindi abbassa lentamente il corpo fino alla posizione iniziale.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"3219","name":"scissor jumps (male)","category":"cardio","equipment":"body weight","target":"cardiovascular system","secondary":["quadriceps","hamstrings","calves"],"steps":{"en":["Stand with your feet shoulder-width apart.","Jump off the ground and simultaneously cross your right leg in front of your left leg.","As you land, quickly switch legs, crossing your left leg in front of your right leg.","Continue alternating legs and jumping as quickly as possible.","Repeat for the desired number of repetitions."],"it":["Stai con i piedi alla larghezza delle spalle.","Salta da terra e contemporaneamente incrocia la gamba destra davanti alla gamba sinistra.","Mentre atterri, cambia rapidamente gamba, incrociando la gamba sinistra davanti a quella destra.","Continua ad alternare le gambe e a saltare il più velocemente possibile.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"1390","name":"seated calf stretch (male)","category":"lower legs","equipment":"body weight","target":"calves","secondary":["hamstrings"],"steps":{"en":["Sit on the edge of a chair or bench with your feet flat on the ground.","Extend one leg straight out in front of you, keeping your heel on the ground.","Lean forward slightly, feeling a stretch in your calf muscle.","Hold the stretch for 20-30 seconds.","Switch legs and repeat the stretch."],"it":["Siediti sul bordo di una sedia o di una panca con i piedi appoggiati a terra.","Estendi una gamba davanti a te, mantenendo il tallone a terra.","Piegati leggermente in avanti, avvertendo un allungamento del muscolo del polpaccio.","Mantieni l'allungamento per 20-30 secondi.","Cambia gamba e ripeti l'allungamento."]}},{"id":"1424","name":"seated glute stretch","category":"upper legs","equipment":"body weight","target":"glutes","secondary":["hamstrings"],"steps":{"en":["Sit on the ground with your legs extended in front of you.","Bend your right knee and cross your right ankle over your left thigh.","Place your right hand on the ground behind you for support.","With your left hand, gently press down on your right knee to deepen the stretch.","Hold the stretch for 30 seconds to 1 minute.","Switch sides and repeat."],"it":["Siediti a terra con le gambe distese davanti a te.","Piega il ginocchio destro e incrocia la caviglia destra sopra la coscia sinistra.","Metti la mano destra a terra dietro di te per supporto.","Con la mano sinistra, premi delicatamente verso il basso il ginocchio destro per approfondire l'allungamento.","Mantieni l'allungamento da 30 secondi a 1 minuto.","Cambia lato e ripeti."]}},{"id":"0689","name":"seated leg raise","category":"waist","equipment":"body weight","target":"abs","secondary":["hip flexors"],"steps":{"en":["Sit on a flat bench with your back straight and your feet flat on the ground.","Place your hands on the sides of the bench for support.","Keeping your legs straight, slowly raise them up in front of you until they are parallel to the ground.","Pause for a moment at the top, then slowly lower your legs back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Siediti su una panca piana con la schiena dritta e i piedi appoggiati a terra.","Metti le mani sui lati della panca per supporto.","Tenendo le gambe dritte, sollevale lentamente davanti a te finché non sono parallele al suolo.","Fai una pausa per un momento in alto, quindi abbassa lentamente le gambe fino alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0690","name":"seated lower back stretch","category":"back","equipment":"body weight","target":"lats","secondary":["glutes","hamstrings"],"steps":{"en":["Sit on the edge of a chair with your feet flat on the ground.","Place your hands on your thighs or on the sides of the chair for support.","Slowly lean forward from your hips, keeping your back straight.","Feel the stretch in your lower back and hold for 20-30 seconds.","Slowly return to the starting position and repeat for the desired number of repetitions."],"it":["Siediti sul bordo di una sedia con i piedi appoggiati a terra.","Metti le mani sulle cosce o sui lati della sedia per sostenerti.","Piegati lentamente in avanti dai fianchi, mantenendo la schiena dritta.","Senti l'allungamento nella parte bassa della schiena e mantieni la posizione per 20-30 secondi.","Ritorna lentamente alla posizione iniziale e ripeti per il numero di ripetizioni desiderato."]}},{"id":"2567","name":"seated piriformis stretch","category":"upper legs","equipment":"body weight","target":"glutes","secondary":["hamstrings"],"steps":{"en":["Sit on the ground with your legs extended in front of you.","Bend your right knee and place your right foot on the outside of your left knee.","Place your left elbow on the outside of your right knee and gently twist your torso to the right.","Hold the stretch for 20-30 seconds, then switch sides and repeat."],"it":["Siediti a terra con le gambe distese davanti a te.","Piega il ginocchio destro e posiziona il piede destro all'esterno del ginocchio sinistro.","Posiziona il gomito sinistro all'esterno del ginocchio destro e ruota delicatamente il busto verso destra.","Mantieni la posizione per 20-30 secondi, poi cambia lato e ripeti."]}},{"id":"0691","name":"seated side crunch (wall)","category":"waist","equipment":"body weight","target":"abs","secondary":["obliques"],"steps":{"en":["Sit on the floor with your back against a wall and your legs extended in front of you.","Bend your knees and place your feet flat on the floor, hip-width apart.","Place your hands behind your head with your elbows pointing outwards.","Engage your abs and lean to one side, bringing your elbow towards your hip.","Pause for a moment, then return to the starting position.","Repeat on the other side.","Continue alternating sides for the desired number of repetitions."],"it":["Siediti sul pavimento con la schiena contro un muro e le gambe distese davanti a te.","Piega le ginocchia e posiziona i piedi sul pavimento, alla larghezza dei fianchi.","Metti le mani dietro la testa con i gomiti rivolti verso l'esterno.","Contrai gli addominali e inclinati da un lato, portando il gomito verso l'anca.","Fare una pausa per un momento, quindi tornare alla posizione di partenza.","Ripeti dall'altra parte.","Continua ad alternare i lati per il numero di ripetizioni desiderato."]}},{"id":"1587","name":"seated wide angle pose sequence","category":"upper legs","equipment":"body weight","target":"hamstrings","secondary":["quadriceps","calves"],"steps":{"en":["Sit on the ground with your legs extended in a wide angle.","Flex your feet and engage your quadriceps.","Place your hands on the ground behind you for support.","Keeping your back straight, lean forward from your hips.","Continue leaning forward until you feel a stretch in your hamstrings.","Hold this position for a few breaths.","Slowly release the stretch and return to the starting position.","Repeat for the desired number of repetitions."],"it":["Sedersi a terra con le gambe distese ad ampio angolo.","Fletti i piedi e coinvolgi i quadricipiti.","Metti le mani a terra dietro di te per supporto.","Tenendo la schiena dritta, piegati in avanti dai fianchi.","Continua a piegarti in avanti finché non senti un allungamento nei muscoli posteriori della coscia.","Mantieni questa posizione per alcuni respiri.","Rilascia lentamente l'allungamento e torna alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0697","name":"self assisted inverse leg curl","category":"upper legs","equipment":"body weight","target":"hamstrings","secondary":["glutes","calves"],"steps":{"en":["Lie flat on your back on a mat or bench with your legs extended.","Place your hands by your sides or under your glutes for support.","Bend your knees and lift your feet off the ground, bringing your thighs towards your chest.","Pause for a moment at the top, then slowly lower your legs back to the starting position.","Repeat for the desired number of repetitions."],"it":["Sdraiati sulla schiena su un tappetino o una panca con le gambe distese.","Metti le mani lungo i fianchi o sotto i glutei per supporto.","Piega le ginocchia e solleva i piedi da terra, portando le cosce verso il petto.","Fai una pausa per un momento in alto, quindi abbassa lentamente le gambe nella posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"1766","name":"self assisted inverse leg curl","category":"upper legs","equipment":"body weight","target":"hamstrings","secondary":["glutes","calves"],"steps":{"en":["Lie face down on a leg curl machine with your legs extended and your ankles hooked under the padded lever.","Place your hands on the side handles of the machine for support.","Keeping your upper body stationary, exhale and curl your legs upward as far as possible.","Hold the contracted position for a brief pause as you squeeze your hamstrings.","Slowly lower your legs back to the starting position while inhaling.","Repeat for the desired number of repetitions."],"it":["Sdraiati a faccia in giù su una macchina per leg curl con le gambe distese e le caviglie agganciate sotto la leva imbottita.","Appoggiare le mani sulle maniglie laterali della macchina per sostenersi.","Mantenendo ferma la parte superiore del corpo, espira e piega le gambe verso l'alto il più possibile.","Mantieni la posizione contratta per una breve pausa mentre contrai i muscoli posteriori della coscia.","Abbassa lentamente le gambe nella posizione iniziale mentre inspiri.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0696","name":"self assisted inverse leg curl (on floor)","category":"upper legs","equipment":"body weight","target":"hamstrings","secondary":["glutes","calves"],"steps":{"en":["Lie flat on your back with your legs extended and your arms by your sides.","Bend your knees and place your feet flat on the ground, hip-width apart.","Lift your hips off the ground, engaging your glutes and hamstrings.","Slowly curl your legs towards your glutes, keeping your hips lifted.","Pause for a moment at the top, then slowly extend your legs back to the starting position.","Lower your hips back down to the ground.","Repeat for the desired number of repetitions."],"it":["Sdraiati sulla schiena con le gambe distese e le braccia lungo i fianchi.","Piega le ginocchia e appoggia i piedi a terra, alla larghezza dei fianchi.","Solleva i fianchi da terra, impegnando i glutei e i muscoli posteriori della coscia.","Piega lentamente le gambe verso i glutei, mantenendo i fianchi sollevati.","Fai una pausa per un momento in alto, quindi estendi lentamente le gambe fino alla posizione di partenza.","Abbassa i fianchi a terra.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"3222","name":"semi squat jump (male)","category":"cardio","equipment":"body weight","target":"cardiovascular system","secondary":["quadriceps","hamstrings","calves"],"steps":{"en":["Stand with your feet shoulder-width apart.","Bend your knees and lower your body into a squat position.","Jump explosively, extending your hips and knees while swinging your arms for momentum.","Land softly on the balls of your feet and immediately go into the next repetition.","Repeat for the desired number of repetitions."],"it":["Stai con i piedi alla larghezza delle spalle.","Piega le ginocchia e abbassa il corpo in una posizione tozza.","Salta in modo esplosivo, estendendo le anche e le ginocchia mentre fai oscillare le braccia per dare slancio.","Atterra dolcemente sulle punte dei piedi e passa immediatamente alla ripetizione successiva.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"3656","name":"short stride run","category":"cardio","equipment":"body weight","target":"cardiovascular system","secondary":["quadriceps","hamstrings","calves"],"steps":{"en":["Find an open space or a treadmill to perform the exercise.","Stand tall with your feet hip-width apart.","Start jogging in place, lifting your knees high and pumping your arms.","After a few seconds, start taking short strides forward, maintaining a quick pace.","Continue running with short strides for the desired duration or distance."],"it":["Trova uno spazio aperto o un tapis roulant per eseguire l'esercizio.","Stai in piedi con i piedi alla larghezza dei fianchi.","Inizia a fare jogging sul posto, sollevando le ginocchia in alto e pompando le braccia.","Dopo alcuni secondi, inizia a fare brevi passi in avanti, mantenendo un ritmo veloce.","Continua a correre a passi brevi per la durata o la distanza desiderata."]}},{"id":"1763","name":"shoulder grip pull-up","category":"back","equipment":"body weight","target":"lats","secondary":["biceps","forearms"],"steps":{"en":["Grab the pull-up bar with a shoulder-width grip, palms facing away from you.","Hang freely with your arms fully extended.","Engage your back muscles and pull your body up towards the bar until your chin is above the bar.","Pause for a moment at the top, then slowly lower your body back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Afferra la barra per trazioni con una presa alla larghezza delle spalle, con i palmi rivolti lontano da te.","Appendersi liberamente con le braccia completamente distese.","Coinvolgi i muscoli della schiena e solleva il corpo verso la barra finché il mento non è sopra la barra.","Fai una pausa per un momento in alto, quindi abbassa lentamente il corpo fino alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"3699","name":"shoulder tap","category":"waist","equipment":"body weight","target":"abs","secondary":["shoulders","triceps"],"steps":{"en":["Start in a high plank position with your hands directly under your shoulders and your body in a straight line.","Engage your core and lift your right hand off the ground, reaching across to tap your left shoulder.","Place your right hand back on the ground and repeat with your left hand tapping your right shoulder.","Continue alternating shoulder taps while keeping your hips and torso stable.","Repeat for the desired number of repetitions."],"it":["Inizia in una posizione di plancia alta con le mani direttamente sotto le spalle e il corpo in linea retta.","Coinvolgi il tuo core e solleva la mano destra da terra, allungandoti per toccare la spalla sinistra.","Riporta la mano destra a terra e ripeti con la mano sinistra toccando la spalla destra.","Continua ad alternare i colpi sulle spalle mantenendo i fianchi e il busto stabili.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0699","name":"shoulder tap push-up","category":"chest","equipment":"body weight","target":"pectorals","secondary":["triceps","core"],"steps":{"en":["Start in a high plank position with your hands slightly wider than shoulder-width apart and your body in a straight line from head to heels.","Lower your body towards the ground by bending your elbows, keeping them close to your sides.","As you push back up, lift your right hand off the ground and tap your left shoulder.","Return your right hand to the ground and repeat the push-up, this time lifting your left hand and tapping your right shoulder.","Continue alternating shoulder taps with each push-up repetition.","Maintain a stable core and avoid excessive hip rotation throughout the exercise.","Repeat for the desired number of repetitions."],"it":["Inizia in una posizione di plancia alta con le mani leggermente più larghe della larghezza delle spalle e il corpo in linea retta dalla testa ai talloni.","Abbassa il corpo verso terra piegando i gomiti, tenendoli vicini ai fianchi.","Mentre ti spingi verso l'alto, solleva la mano destra da terra e tocca la spalla sinistra.","Riporta la mano destra a terra e ripeti il ​​push-up, questa volta sollevando la mano sinistra e toccando la spalla destra.","Continua ad alternare i colpi sulle spalle con ogni ripetizione di push-up.","Mantieni un core stabile ed evita un'eccessiva rotazione dell'anca durante l'esercizio.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"1774","name":"side bridge hip abduction","category":"upper legs","equipment":"body weight","target":"abductors","secondary":["glutes","obliques"],"steps":{"en":["Lie on your side with your legs extended and stacked on top of each other.","Prop yourself up on your forearm, keeping your elbow directly below your shoulder.","Engage your core and lift your hips off the ground, creating a straight line from your head to your feet.","While keeping your core engaged, lift your top leg as high as possible without rotating your hips.","Pause for a moment at the top, then lower your leg back down.","Repeat for the desired number of repetitions, then switch sides."],"it":["Sdraiati su un fianco con le gambe distese e impilate una sopra l'altra.","Appoggiati sull'avambraccio, mantenendo il gomito direttamente sotto la spalla.","Coinvolgi il tuo core e solleva i fianchi da terra, creando una linea retta dalla testa ai piedi.","Mantenendo il core impegnato, solleva la gamba superiore il più in alto possibile senza ruotare i fianchi.","Fai una pausa per un momento in alto, quindi abbassa nuovamente la gamba.","Ripeti per il numero di ripetizioni desiderato, quindi cambia lato."]}},{"id":"0705","name":"side bridge v. 2","category":"waist","equipment":"body weight","target":"abs","secondary":["obliques","glutes"],"steps":{"en":["Lie on your side with your legs extended and stacked on top of each other.","Place your forearm on the ground directly below your shoulder, with your elbow bent at a 90-degree angle.","Engage your core and lift your hips off the ground, creating a straight line from your head to your feet.","Hold this position for the desired amount of time.","Lower your hips back down to the starting position.","Repeat on the other side."],"it":["Sdraiati su un fianco con le gambe distese e impilate una sopra l'altra.","Posiziona l'avambraccio a terra direttamente sotto la spalla, con il gomito piegato con un angolo di 90 gradi.","Coinvolgi il tuo core e solleva i fianchi da terra, creando una linea retta dalla testa ai piedi.","Mantieni questa posizione per il tempo desiderato.","Abbassa i fianchi fino alla posizione di partenza.","Ripeti dall'altra parte."]}},{"id":"0709","name":"side hip (on parallel bars)","category":"waist","equipment":"body weight","target":"abs","secondary":["obliques","hip flexors"],"steps":{"en":["Stand between two parallel bars with your feet shoulder-width apart.","Place your hands on the bars and lift your body off the ground, supporting your weight on your arms.","Engage your abs and slowly lift your legs to the side, keeping them straight.","Pause for a moment at the top, then slowly lower your legs back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Mettiti tra due barre parallele con i piedi alla larghezza delle spalle.","Metti le mani sulle barre e solleva il corpo da terra, sostenendo il peso sulle braccia.","Coinvolgi gli addominali e solleva lentamente le gambe di lato, mantenendole dritte.","Fai una pausa per un momento in alto, quindi abbassa lentamente le gambe fino alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0710","name":"side hip abduction","category":"upper legs","equipment":"body weight","target":"abductors","secondary":["glutes","quadriceps"],"steps":{"en":["Stand with your feet shoulder-width apart and your hands on your hips.","Shift your weight to one leg and lift the opposite leg out to the side, keeping it straight.","Pause for a moment at the top, then slowly lower your leg back down to the starting position.","Repeat on the other side.","Continue alternating sides for the desired number of repetitions."],"it":["Stai con i piedi alla larghezza delle spalle e le mani sui fianchi.","Sposta il peso su una gamba e solleva la gamba opposta lateralmente, mantenendola dritta.","Fai una pausa per un momento in alto, quindi abbassa lentamente la gamba fino alla posizione iniziale.","Ripeti dall'altra parte.","Continua ad alternare i lati per il numero di ripetizioni desiderato."]}},{"id":"1358","name":"side lying floor stretch","category":"back","equipment":"body weight","target":"lats","secondary":["obliques","glutes"],"steps":{"en":["Lie on your side with your legs straight and your bottom arm extended straight overhead.","Bend your top knee and place your foot on the ground in front of your bottom leg.","Reach your top arm over your head and grab onto something stable, like a wall or a piece of furniture.","Slowly lift your bottom leg off the ground, keeping it straight, until you feel a stretch in your side.","Hold the stretch for 20-30 seconds, then slowly lower your leg back down.","Repeat on the other side."],"it":["Sdraiati su un fianco con le gambe dritte e il braccio inferiore teso sopra la testa.","Piega il ginocchio superiore e posiziona il piede a terra davanti alla gamba inferiore.","Allunga il braccio superiore sopra la testa e afferra qualcosa di stabile, come un muro o un mobile.","Solleva lentamente la gamba inferiore da terra, mantenendola dritta, finché non senti un allungamento nel fianco.","Mantieni la posizione per 20-30 secondi, quindi abbassa lentamente la gamba.","Ripeti dall'altra parte."]}},{"id":"3667","name":"side lying hip adduction (male)","category":"upper legs","equipment":"body weight","target":"adductors","secondary":["glutes","hamstrings"],"steps":{"en":["Lie on your side with your legs straight and stacked on top of each other.","Place your bottom arm under your head for support.","Engage your adductors and lift your top leg as high as possible without rotating your hips or leaning backward.","Pause for a moment at the top, then slowly lower your leg back down to the starting position.","Repeat for the desired number of repetitions, then switch sides."],"it":["Sdraiati su un fianco con le gambe dritte e impilate una sopra l'altra.","Posiziona il braccio inferiore sotto la testa per supporto.","Coinvolgi i tuoi adduttori e solleva la gamba superiore il più in alto possibile senza ruotare i fianchi o inclinarti all'indietro.","Fai una pausa per un momento in alto, quindi abbassa lentamente la gamba fino alla posizione iniziale.","Ripeti per il numero di ripetizioni desiderato, quindi cambia lato."]}},{"id":"1775","name":"side plank hip adduction","category":"upper legs","equipment":"body weight","target":"adductors","secondary":["obliques","glutes"],"steps":{"en":["Start by lying on your side with your legs extended and stacked on top of each other.","Prop yourself up on your forearm, keeping your elbow directly below your shoulder.","Engage your core and lift your hips off the ground, creating a straight line from your head to your feet.","While maintaining the side plank position, lift your top leg towards the ceiling, keeping it straight.","Slowly lower your leg back down to the starting position.","Repeat for the desired number of repetitions, then switch sides."],"it":["Inizia sdraiandoti su un fianco con le gambe distese e impilate una sopra l'altra.","Appoggiati sull'avambraccio, mantenendo il gomito direttamente sotto la spalla.","Coinvolgi il tuo core e solleva i fianchi da terra, creando una linea retta dalla testa ai piedi.","Mantenendo la posizione della plancia laterale, solleva la gamba superiore verso il soffitto, mantenendola dritta.","Abbassa lentamente la gamba fino alla posizione di partenza.","Ripeti per il numero di ripetizioni desiderato, quindi cambia lato."]}},{"id":"0716","name":"side push neck stretch","category":"neck","equipment":"body weight","target":"levator scapulae","secondary":["trapezius","sternocleidomastoid"],"steps":{"en":["Stand or sit up straight with your shoulders relaxed.","Tilt your head to the right, bringing your right ear towards your right shoulder.","Place your right hand on the left side of your head and gently apply pressure to increase the stretch.","Hold the stretch for 15-30 seconds.","Repeat on the other side, tilting your head to the left and applying pressure with your left hand.","Repeat the stretch 2-3 times on each side."],"it":["Stai in piedi o seduto con la schiena dritta e le spalle rilassate.","Inclina la testa verso destra, portando l'orecchio destro verso la spalla destra.","Posiziona la mano destra sul lato sinistro della testa ed esercita una leggera pressione per aumentare l'allungamento.","Mantieni l'allungamento per 15-30 secondi.","Ripeti dall'altro lato, inclinando la testa a sinistra ed esercitando pressione con la mano sinistra.","Ripeti l'allungamento 2-3 volte su ciascun lato."]}},{"id":"0717","name":"side push-up","category":"upper arms","equipment":"body weight","target":"triceps","secondary":["shoulders","chest","core"],"steps":{"en":["Start by lying on your side with your legs extended and stacked on top of each other.","Place your bottom hand on the ground directly under your shoulder, fingers pointing forward.","Press through your bottom hand to lift your body off the ground, keeping your legs straight and your core engaged.","Extend your top arm straight up towards the ceiling, creating a straight line from your head to your heels.","Lower your body back down to the starting position with control.","Repeat for the desired number of repetitions, then switch sides."],"it":["Inizia sdraiandoti su un fianco con le gambe distese e impilate una sopra l'altra.","Posiziona la mano inferiore a terra direttamente sotto la spalla, con le dita rivolte in avanti.","Premi con la mano inferiore per sollevare il corpo da terra, mantenendo le gambe dritte e il core impegnato.","Estendi il braccio superiore verso il soffitto, creando una linea retta dalla testa ai talloni.","Abbassa il corpo nella posizione iniziale mantenendo il controllo.","Ripeti per il numero di ripetizioni desiderato, quindi cambia lato."]}},{"id":"0721","name":"side wrist pull stretch","category":"lower arms","equipment":"body weight","target":"forearms","secondary":["wrists","hands"],"steps":{"en":["Stand with your feet shoulder-width apart and your arms extended in front of you.","Extend your right arm out to the side, parallel to the ground, with your palm facing down.","With your left hand, grab your right hand and gently pull it towards your body, feeling a stretch in your right forearm.","Hold the stretch for 15-30 seconds, then release.","Repeat on the other side."],"it":["Stai con i piedi alla larghezza delle spalle e le braccia distese davanti a te.","Estendi il braccio destro lateralmente, parallelo al suolo, con il palmo rivolto verso il basso.","Con la mano sinistra, afferra la mano destra e tirala delicatamente verso il corpo, sentendo l'allungamento dell'avambraccio destro.","Mantieni la posizione per 15-30 secondi, quindi rilascia.","Ripeti dall'altra parte."]}},{"id":"0720","name":"side-to-side chin","category":"back","equipment":"body weight","target":"lats","secondary":["biceps","forearms"],"steps":{"en":["Stand with your feet shoulder-width apart and your knees slightly bent.","Grasp a pull-up bar with an overhand grip, hands slightly wider than shoulder-width apart.","Hang from the bar with your arms fully extended and your body relaxed.","Pull yourself up by bending your elbows and bringing your chin towards the bar, while keeping your body straight.","Once your chin is above the bar, lower yourself back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai con i piedi alla larghezza delle spalle e le ginocchia leggermente piegate.","Afferrare una barra per trazioni con una presa prona, le mani leggermente più larghe della larghezza delle spalle.","Appendi alla sbarra con le braccia completamente distese e il corpo rilassato.","Tirati su piegando i gomiti e portando il mento verso la sbarra, mantenendo il corpo dritto.","Una volta che il mento è sopra la barra, abbassati nuovamente nella posizione iniziale.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"3213","name":"side-to-side toe touch (male)","category":"waist","equipment":"body weight","target":"abs","secondary":["obliques","hip flexors"],"steps":{"en":["Stand with your feet shoulder-width apart and your arms extended to the sides.","Bend at the waist to the right, reaching your right hand towards your right foot while keeping your left hand extended to the side.","Return to the starting position and then bend at the waist to the left, reaching your left hand towards your left foot while keeping your right hand extended to the side.","Repeat the side-to-side bending motion for the desired number of repetitions."],"it":["Stai con i piedi alla larghezza delle spalle e le braccia distese ai lati.","Piega la vita verso destra, portando la mano destra verso il piede destro mantenendo la mano sinistra estesa di lato.","Ritorna alla posizione di partenza e poi piegati in vita a sinistra, portando la mano sinistra verso il piede sinistro mantenendo la mano destra estesa di lato.","Ripeti il ​​movimento di piegamento da lato a lato per il numero di ripetizioni desiderato."]}},{"id":"0725","name":"single arm push-up","category":"chest","equipment":"body weight","target":"pectorals","secondary":["triceps","shoulders","core"],"steps":{"en":["Start in a push-up position with your hands shoulder-width apart and one hand placed slightly wider than the other.","Engage your core and lower your body towards the ground by bending your elbows, keeping your back straight.","As you lower yourself, shift your weight to one side and lift the opposite arm off the ground, extending it straight out to the side.","Push through your chest and triceps to raise your body back up to the starting position, while simultaneously lowering your extended arm back to the ground.","Repeat the movement, alternating the arm you extend with each repetition."],"it":["Inizia in una posizione push-up con le mani alla larghezza delle spalle e una mano posizionata leggermente più larga dell'altra.","Coinvolgi il core e abbassa il corpo verso terra piegando i gomiti e mantenendo la schiena dritta.","Mentre ti abbassi, sposta il peso su un lato e solleva il braccio opposto da terra, estendendolo lateralmente.","Spingi attraverso il petto e i tricipiti per riportare il corpo alla posizione iniziale, abbassando contemporaneamente il braccio esteso a terra.","Ripeti il ​​movimento, alternando il braccio che estendi ad ogni ripetizione."]}},{"id":"3645","name":"single leg bridge with outstretched leg","category":"upper legs","equipment":"body weight","target":"glutes","secondary":["hamstrings","quadriceps"],"steps":{"en":["Lie on your back with your knees bent and feet flat on the ground.","Extend one leg straight out in front of you.","Engage your glutes and lift your hips off the ground, forming a straight line from your knees to your shoulders.","Hold for a moment at the top, then slowly lower your hips back down to the starting position.","Repeat for the desired number of repetitions, then switch legs."],"it":["Sdraiati sulla schiena con le ginocchia piegate e i piedi appoggiati a terra.","Estendi una gamba davanti a te.","Coinvolgi i glutei e solleva i fianchi da terra, formando una linea retta dalle ginocchia alle spalle.","Mantieni la posizione in alto per un momento, quindi abbassa lentamente i fianchi fino alla posizione iniziale.","Ripeti per il numero di ripetizioni desiderato, quindi cambia gamba."]}},{"id":"0727","name":"single leg calf raise (on a dumbbell)","category":"lower legs","equipment":"dumbbell","target":"calves","secondary":["ankles","feet"],"steps":{"en":["Stand with your feet hip-width apart and hold a dumbbell in one hand.","Lift one foot off the ground and balance on the other foot.","Slowly raise your heel as high as possible, using your calf muscles.","Pause for a moment at the top, then slowly lower your heel back down.","Repeat for the desired number of repetitions, then switch to the other leg."],"it":["Stare con i piedi alla larghezza dei fianchi e tenere un manubrio in una mano.","Sollevare un piede da terra e restare in equilibrio sull'altro piede.","Solleva lentamente il tallone il più in alto possibile, usando i muscoli del polpaccio.","Fai una pausa per un momento in alto, quindi abbassa lentamente il tallone.","Ripeti per il numero di ripetizioni desiderato, quindi passa all'altra gamba."]}},{"id":"0730","name":"single leg platform slide","category":"upper legs","equipment":"body weight","target":"hamstrings","secondary":["glutes","quadriceps"],"steps":{"en":["Start by standing with one foot on a platform or slide board.","Bend your knee slightly and slide the foot on the platform backward, extending your leg.","Keep your core engaged and maintain a straight posture throughout the movement.","Slowly return to the starting position by sliding your foot back to the initial position.","Repeat the movement for the desired number of repetitions, then switch legs."],"it":["Inizia stando con un piede su una piattaforma o una tavola scorrevole.","Piega leggermente il ginocchio e fai scivolare indietro il piede sulla pedana, estendendo la gamba.","Mantieni il core impegnato e mantieni una postura dritta durante tutto il movimento.","Ritorna lentamente alla posizione di partenza facendo scorrere il piede nella posizione iniziale.","Ripeti il ​​movimento per il numero di ripetizioni desiderato, quindi cambia gamba."]}},{"id":"1759","name":"single leg squat (pistol) male","category":"upper legs","equipment":"body weight","target":"glutes","secondary":["quadriceps","hamstrings","calves"],"steps":{"en":["Stand with your feet shoulder-width apart and arms extended in front of you.","Lift your right foot off the ground and extend it forward.","Slowly lower your body down by bending your left knee and pushing your hips back.","Keep your chest up and your back straight as you lower yourself down.","Lower until your left thigh is parallel to the ground, or as low as you can comfortably go.","Pause for a moment at the bottom, then push through your left heel to return to the starting position.","Repeat for the desired number of repetitions, then switch legs."],"it":["Stai con i piedi alla larghezza delle spalle e le braccia distese davanti a te.","Solleva il piede destro da terra ed estendilo in avanti.","Abbassa lentamente il corpo piegando il ginocchio sinistro e spingendo indietro i fianchi.","Tieni il petto in alto e la schiena dritta mentre ti abbassi.","Abbassati finché la coscia sinistra non è parallela al suolo o il più in basso possibile.","Fermati per un momento in basso, quindi spingi attraverso il tallone sinistro per tornare alla posizione di partenza.","Ripeti per il numero di ripetizioni desiderato, quindi cambia gamba."]}},{"id":"1489","name":"sissy squat","category":"upper legs","equipment":"body weight","target":"quads","secondary":["calves","glutes"],"steps":{"en":["Stand with your feet shoulder-width apart and your toes pointing slightly outward.","Hold onto a stable object for balance if needed.","Slowly lower your body by bending your knees and leaning back, keeping your torso upright.","Continue lowering until your thighs are parallel to the ground or as far as you can comfortably go.","Pause for a moment, then push through your heels to return to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai con i piedi alla larghezza delle spalle e le dita dei piedi leggermente rivolte verso l'esterno.","Se necessario, aggrapparsi a un oggetto stabile per mantenere l'equilibrio.","Abbassa lentamente il corpo piegando le ginocchia e appoggiandoti all'indietro, mantenendo il busto eretto.","Continua ad abbassarti finché le cosce non sono parallele al suolo o il più lontano possibile.","Fai una pausa per un momento, quindi spingi i talloni per tornare alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0735","name":"sit-up v. 2","category":"waist","equipment":"body weight","target":"abs","secondary":["hip flexors"],"steps":{"en":["Lie flat on your back with your knees bent and feet flat on the ground.","Place your hands behind your head with your elbows pointing outwards.","Engaging your abs, slowly lift your upper body off the ground, curling forward until your torso is at a 45-degree angle.","Pause for a moment at the top, then slowly lower your upper body back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Sdraiati sulla schiena con le ginocchia piegate e i piedi appoggiati a terra.","Metti le mani dietro la testa con i gomiti rivolti verso l'esterno.","Coinvolgendo gli addominali, solleva lentamente la parte superiore del corpo da terra, piegandoti in avanti finché il busto non forma un angolo di 45 gradi.","Fermati per un momento in alto, quindi abbassa lentamente la parte superiore del corpo fino alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"3679","name":"sit-up with arms on chest","category":"waist","equipment":"body weight","target":"abs","secondary":["hip flexors"],"steps":{"en":["Lie flat on your back with your knees bent and feet flat on the ground.","Cross your arms over your chest.","Engaging your abs, lift your upper body off the ground towards your knees.","Pause for a moment at the top, then slowly lower your upper body back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Sdraiati sulla schiena con le ginocchia piegate e i piedi appoggiati a terra.","Incrocia le braccia sul petto.","Coinvolgendo gli addominali, solleva la parte superiore del corpo da terra verso le ginocchia.","Fermati per un momento in alto, quindi abbassa lentamente la parte superiore del corpo fino alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"3361","name":"skater hops","category":"cardio","equipment":"body weight","target":"cardiovascular system","secondary":["quadriceps","hamstrings","glutes","calves"],"steps":{"en":["Stand with your feet shoulder-width apart.","Bend your knees slightly and jump to the right, landing on your right foot.","As you land, swing your left leg behind your right leg and tap the ground with your left toes.","Immediately jump to the left, landing on your left foot.","As you land, swing your right leg behind your left leg and tap the ground with your right toes.","Continue alternating sides, jumping and tapping the ground with each leg.","Repeat for the desired number of repetitions."],"it":["Stai con i piedi alla larghezza delle spalle.","Piega leggermente le ginocchia e salta a destra, atterrando sul piede destro.","Mentre atterri, porta la gamba sinistra dietro quella destra e tocca il terreno con la punta del piede sinistro.","Salta immediatamente a sinistra, atterrando con il piede sinistro.","Mentre atterri, porta la gamba destra dietro quella sinistra e tocca il terreno con la punta del piede destro.","Continua ad alternare i lati, saltando e toccando il terreno con ciascuna gamba.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"3671","name":"ski step","category":"cardio","equipment":"body weight","target":"cardiovascular system","secondary":["quadriceps","hamstrings","glutes","calves"],"steps":{"en":["Stand with your feet shoulder-width apart.","Bend your knees slightly and keep your back straight.","Jump to the right, landing on your right foot while swinging your left leg behind your right leg.","Immediately jump to the left, landing on your left foot while swinging your right leg behind your left leg.","Continue alternating jumps from side to side, mimicking a skiing motion.","Repeat for the desired number of repetitions."],"it":["Stai con i piedi alla larghezza delle spalle.","Piega leggermente le ginocchia e mantieni la schiena dritta.","Salta a destra, atterrando sul piede destro mentre fai oscillare la gamba sinistra dietro quella destra.","Salta immediatamente a sinistra, atterrando sul piede sinistro mentre fai oscillare la gamba destra dietro quella sinistra.","Continua alternando i salti da un lato all'altro, imitando il movimento dello sci.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"3304","name":"skin the cat","category":"back","equipment":"body weight","target":"upper back","secondary":["shoulders","core"],"steps":{"en":["Start by hanging from a bar with your arms fully extended and your body relaxed.","Engage your core and lift your legs up, bringing your knees towards your chest.","Continue to lift your legs up and over your head, allowing your body to pass through the arms.","Once your legs are fully extended over your head, begin to lower them back down towards the starting position.","As you lower your legs, allow your body to pass back through the arms until you are hanging with your arms fully extended again.","Repeat for the desired number of repetitions."],"it":["Inizia appendendoti a una barra con le braccia completamente distese e il corpo rilassato.","Coinvolgi il tuo core e solleva le gambe, portando le ginocchia verso il petto.","Continua a sollevare le gambe sopra la testa, permettendo al corpo di passare attraverso le braccia.","Una volta che le gambe sono completamente distese sopra la testa, inizia ad abbassarle nuovamente verso la posizione di partenza.","Mentre abbassi le gambe, lascia che il corpo passi indietro attraverso le braccia finché non ti ritrovi di nuovo sospeso con le braccia completamente distese.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0776","name":"snatch pull","category":"upper legs","equipment":"barbell","target":"quads","secondary":["hamstrings","glutes","calves"],"steps":{"en":["Stand with your feet shoulder-width apart and the barbell on the ground in front of you.","Bend your knees and hinge at the hips to lower into a squat position, gripping the barbell with an overhand grip.","Keep your back straight and chest up as you drive through your heels to lift the barbell off the ground, extending your hips and knees.","As the barbell reaches hip level, explosively pull it upwards, shrugging your shoulders and pulling your elbows high and to the sides.","As the barbell reaches its highest point, quickly drop underneath it, pulling yourself into a deep squat position.","Catch the barbell overhead with your arms fully extended and your knees bent.","Stand up by extending your hips and knees, keeping the barbell overhead.","Lower the barbell back down to the starting position by reversing the movement.","Repeat for the desired number of repetitions."],"it":["Stai con i piedi alla larghezza delle spalle e il bilanciere a terra davanti a te.","Piega le ginocchia e fai perno sui fianchi per abbassarti in posizione tozza, afferrando il bilanciere con una presa prona.","Tieni la schiena dritta e il petto in alto mentre spingi i talloni per sollevare il bilanciere da terra, estendendo i fianchi e le ginocchia.","Quando il bilanciere raggiunge il livello dei fianchi, tiralo in modo esplosivo verso l'alto, alzando le spalle e tirando i gomiti in alto e lateralmente.","Quando il bilanciere raggiunge il punto più alto, scendi rapidamente sotto di esso, assumendo una posizione di squat profondo.","Afferra il bilanciere sopra la testa con le braccia completamente distese e le ginocchia piegate.","Alzati estendendo le anche e le ginocchia, mantenendo il bilanciere sopra la testa.","Abbassare nuovamente il bilanciere nella posizione iniziale invertendo il movimento.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0777","name":"spell caster","category":"waist","equipment":"dumbbell","target":"abs","secondary":["obliques","lower back"],"steps":{"en":["Stand with your feet shoulder-width apart and hold a dumbbell in one hand.","Bend your knees slightly and hinge forward at the waist, keeping your back straight.","Extend your arm with the dumbbell towards the opposite foot, rotating your torso as you do so.","Return to the starting position and repeat on the other side.","Continue alternating sides for the desired number of repetitions."],"it":["Stare con i piedi alla larghezza delle spalle e tenere un manubrio in una mano.","Piega leggermente le ginocchia e fai perno in avanti all'altezza della vita, mantenendo la schiena dritta.","Estendi il braccio con il manubrio verso il piede opposto, ruotando il busto mentre lo fai.","Ritorna alla posizione di partenza e ripeti dall'altro lato.","Continua ad alternare i lati per il numero di ripetizioni desiderato."]}},{"id":"1362","name":"sphinx","category":"back","equipment":"body weight","target":"spine","secondary":["glutes","hamstrings"],"steps":{"en":["Lie face down on the ground with your forearms flat on the floor, elbows directly under your shoulders.","Engage your core and lift your chest off the ground, keeping your forearms and toes on the floor.","Hold this position for a few seconds, making sure to keep your neck in a neutral position.","Slowly lower your chest back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Sdraiati a faccia in giù a terra con gli avambracci appoggiati sul pavimento, i gomiti direttamente sotto le spalle.","Coinvolgi il tuo core e solleva il petto da terra, mantenendo gli avambracci e le dita dei piedi sul pavimento.","Mantieni questa posizione per alcuni secondi, assicurandoti di mantenere il collo in una posizione neutra.","Abbassa lentamente il petto fino alla posizione iniziale.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0778","name":"spider crawl push up","category":"upper legs","equipment":"body weight","target":"glutes","secondary":["core","chest","shoulders"],"steps":{"en":["Start in a push-up position with your hands slightly wider than shoulder-width apart and your feet together.","Bring your right knee towards your right elbow, keeping it off the ground.","As you bring your right knee back, simultaneously lower your body towards the ground by bending your elbows.","Push back up to the starting position and repeat with your left knee towards your left elbow.","Continue alternating sides for the desired number of repetitions."],"it":["Inizia in una posizione push-up con le mani leggermente più larghe della larghezza delle spalle e i piedi uniti.","Porta il ginocchio destro verso il gomito destro, mantenendolo sollevato da terra.","Mentre porti indietro il ginocchio destro, abbassa contemporaneamente il corpo verso terra piegando i gomiti.","Spingi indietro fino alla posizione iniziale e ripeti con il ginocchio sinistro verso il gomito sinistro.","Continua ad alternare i lati per il numero di ripetizioni desiderato."]}},{"id":"1363","name":"spine stretch","category":"back","equipment":"body weight","target":"spine","secondary":["hamstrings","glutes"],"steps":{"en":["Sit on the ground with your legs extended in front of you.","Place your hands on the ground behind you, fingers pointing towards your body.","Engage your core and slowly lean back, keeping your back straight.","Continue leaning back until you feel a stretch in your spine.","Hold the stretch for a few seconds, then slowly return to the starting position.","Repeat for the desired number of repetitions."],"it":["Siediti a terra con le gambe distese davanti a te.","Appoggia le mani a terra dietro di te, con le dita rivolte verso il tuo corpo.","Coinvolgi il tuo core e inclinati lentamente all'indietro, mantenendo la schiena dritta.","Continua ad inclinarti all'indietro finché non senti un allungamento nella colonna vertebrale.","Mantieni la posizione per alcuni secondi, quindi torna lentamente alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"2329","name":"spine twist","category":"waist","equipment":"body weight","target":"abs","secondary":["obliques","lower back"],"steps":{"en":["Sit on the ground with your legs extended in front of you.","Bend your knees and place your feet flat on the ground, hip-width apart.","Place your hands behind your head with your elbows pointing outwards.","Engage your abs and slowly twist your torso to the right, bringing your right elbow towards your left knee.","Pause for a moment at the end of the twist, then slowly return to the starting position.","Repeat the twist to the left side, bringing your left elbow towards your right knee.","Continue alternating sides for the desired number of repetitions."],"it":["Siediti a terra con le gambe distese davanti a te.","Piega le ginocchia e appoggia i piedi a terra, alla larghezza dei fianchi.","Metti le mani dietro la testa con i gomiti rivolti verso l'esterno.","Contrai gli addominali e ruota lentamente il busto verso destra, portando il gomito destro verso il ginocchio sinistro.","Fare una pausa per un momento alla fine della torsione, quindi tornare lentamente alla posizione di partenza.","Ripeti la torsione sul lato sinistro, portando il gomito sinistro verso il ginocchio destro.","Continua ad alternare i lati per il numero di ripetizioni desiderato."]}},{"id":"2368","name":"split squats","category":"upper legs","equipment":"body weight","target":"quads","secondary":["glutes","hamstrings","calves"],"steps":{"en":["Stand with your feet shoulder-width apart.","Take a step forward with one foot and place it about two feet in front of the other foot.","Lower your body by bending your knees and hips, keeping your back straight.","Continue lowering until your front thigh is parallel to the ground, and your back knee is hovering just above the ground.","Pause for a moment, then push through your front heel to return to the starting position.","Repeat for the desired number of repetitions, then switch legs and repeat."],"it":["Stai con i piedi alla larghezza delle spalle.","Fai un passo avanti con un piede e posizionalo a circa mezzo metro davanti all'altro piede.","Abbassa il corpo piegando le ginocchia e le anche, mantenendo la schiena dritta.","Continua ad abbassarti finché la coscia anteriore non è parallela al suolo e il ginocchio posteriore si libra appena sopra il suolo.","Fai una pausa per un momento, quindi spingi il tallone anteriore per tornare alla posizione di partenza.","Ripeti per il numero di ripetizioni desiderato, quindi cambia gamba e ripeti."]}},{"id":"0786","name":"squat jerk","category":"upper legs","equipment":"barbell","target":"quads","secondary":["glutes","hamstrings","calves","core"],"steps":{"en":["Start with the barbell resting on your shoulders, with your feet shoulder-width apart.","Lower your body into a squat position, keeping your chest up and your knees tracking over your toes.","As you reach the bottom of the squat, explosively drive through your legs and push the barbell overhead.","As the barbell reaches its peak, quickly drop into a split position, with one foot forward and one foot back.","Catch the barbell overhead with your arms fully extended and your back knee slightly touching the ground.","Stand up from the split position, bringing your feet back together.","Lower the barbell back to your shoulders and repeat for the desired number of repetitions."],"it":["Inizia con il bilanciere appoggiato sulle spalle, con i piedi alla larghezza delle spalle.","Abbassa il corpo in una posizione tozza, mantenendo il petto sollevato e le ginocchia che seguono le dita dei piedi.","Quando raggiungi il fondo dello squat, spingi in modo esplosivo attraverso le gambe e spingi il bilanciere sopra la testa.","Quando il bilanciere raggiunge il suo apice, scendi rapidamente in una posizione divisa, con un piede avanti e l'altro indietro.","Afferra il bilanciere sopra la testa con le braccia completamente distese e il ginocchio posteriore che tocca leggermente il suolo.","Alzati dalla posizione divisa, riunendo i piedi.","Abbassa il bilanciere sulle spalle e ripeti per il numero di ripetizioni desiderato."]}},{"id":"1685","name":"squat to overhead reach","category":"upper legs","equipment":"body weight","target":"quads","secondary":["glutes","hamstrings","core"],"steps":{"en":["Stand with your feet shoulder-width apart and toes slightly turned out.","Lower your body down into a squat position by bending your knees and pushing your hips back.","As you come up from the squat, extend your arms overhead, reaching towards the ceiling.","Return to the starting position by lowering your arms and bending your knees to squat down again.","Repeat for the desired number of repetitions."],"it":["Stai con i piedi alla larghezza delle spalle e le dita dei piedi leggermente rivolte verso l'esterno.","Abbassa il corpo in una posizione tozza piegando le ginocchia e spingendo indietro i fianchi.","Quando ti alzi dallo squat, estendi le braccia sopra la testa, raggiungendo il soffitto.","Ritorna alla posizione di partenza abbassando le braccia e piegando le ginocchia per accovacciarti nuovamente.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"1686","name":"squat to overhead reach with twist","category":"upper legs","equipment":"body weight","target":"quads","secondary":["glutes","hamstrings","core"],"steps":{"en":["Stand with your feet shoulder-width apart and toes slightly turned out.","Lower your body into a squat position by bending your knees and pushing your hips back.","As you come up from the squat, raise your arms overhead and twist your torso to one side.","Return to the starting position and repeat the squat, this time twisting your torso to the opposite side.","Continue alternating sides with each squat repetition."],"it":["Stai con i piedi alla larghezza delle spalle e le dita dei piedi leggermente rivolte verso l'esterno.","Abbassa il corpo in una posizione tozza piegando le ginocchia e spingendo indietro i fianchi.","Quando ti alzi dallo squat, alza le braccia sopra la testa e ruota il busto da un lato.","Ritorna alla posizione di partenza e ripeti lo squat, questa volta ruotando il busto sul lato opposto.","Continua ad alternare i lati con ogni ripetizione di squat."]}},{"id":"2297","name":"stability ball crunch (full range hands behind head)","category":"waist","equipment":"stability ball","target":"abs","secondary":["hip flexors"],"steps":{"en":["Sit on the stability ball with your feet flat on the ground and your knees bent at a 90-degree angle.","Place your hands behind your head with your elbows pointing outwards.","Engaging your abs, slowly curl your upper body forward, bringing your chest towards your knees.","Pause for a moment at the top, then slowly lower your upper body back to the starting position.","Repeat for the desired number of repetitions."],"it":["Siediti sulla palla di stabilità con i piedi appoggiati a terra e le ginocchia piegate con un angolo di 90 gradi.","Metti le mani dietro la testa con i gomiti rivolti verso l'esterno.","Coinvolgendo gli addominali, piega lentamente la parte superiore del corpo in avanti, portando il petto verso le ginocchia.","Fermati per un momento in alto, quindi abbassa lentamente la parte superiore del corpo nella posizione iniziale.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"3291","name":"stalder press","category":"upper arms","equipment":"body weight","target":"triceps","secondary":["shoulders","core"],"steps":{"en":["Start by standing with your feet shoulder-width apart and your arms extended overhead.","Bend your knees slightly and engage your core.","Lower your body down into a squat position while keeping your arms extended overhead.","As you squat down, press your arms down towards the ground, engaging your triceps.","Pause for a moment at the bottom of the squat, then push through your heels to stand back up while simultaneously raising your arms back overhead.","Repeat for the desired number of repetitions."],"it":["Inizia stando in piedi con i piedi alla larghezza delle spalle e le braccia distese sopra la testa.","Piega leggermente le ginocchia e coinvolgi il core.","Abbassa il corpo in una posizione tozza mantenendo le braccia distese sopra la testa.","Mentre ti accovacci, premi le braccia verso terra, impegnando i tricipiti.","Fai una pausa per un momento nella parte inferiore dello squat, quindi spingi i talloni per rialzarti sollevando contemporaneamente le braccia sopra la testa.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"3669","name":"standing archer","category":"back","equipment":"body weight","target":"upper back","secondary":["shoulders","biceps","forearms"],"steps":{"en":["Stand with your feet shoulder-width apart and your knees slightly bent.","Extend your arms straight out in front of you at shoulder height, parallel to the ground.","Rotate your torso to the right, keeping your arms extended and your back straight.","As you rotate, extend your right arm forward and your left arm back, mimicking the motion of drawing a bowstring.","Hold the position for a moment, then return to the starting position.","Repeat the motion, this time rotating your torso to the left and extending your left arm forward and your right arm back.","Continue alternating sides for the desired number of repetitions."],"it":["Stai con i piedi alla larghezza delle spalle e le ginocchia leggermente piegate.","Estendi le braccia davanti a te all'altezza delle spalle, parallele al suolo.","Ruota il busto verso destra, mantenendo le braccia tese e la schiena dritta.","Mentre ruoti, estendi il braccio destro in avanti e il braccio sinistro indietro, imitando il movimento di tendere una corda dell'arco.","Mantieni la posizione per un momento, quindi torna alla posizione di partenza.","Ripeti il ​​movimento, questa volta ruotando il busto verso sinistra ed estendendo il braccio sinistro in avanti e il braccio destro indietro.","Continua ad alternare i lati per il numero di ripetizioni desiderato."]}},{"id":"0788","name":"standing behind neck press","category":"shoulders","equipment":"barbell","target":"delts","secondary":["triceps","upper back"],"steps":{"en":["Stand with your feet shoulder-width apart and hold the barbell behind your neck with an overhand grip.","Keep your back straight and core engaged.","Press the barbell overhead by extending your arms, fully extending your elbows.","Pause for a moment at the top, then slowly lower the barbell back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai con i piedi alla larghezza delle spalle e tieni il bilanciere dietro il collo con una presa prona.","Tieni la schiena dritta e il core impegnato.","Premi il bilanciere sopra la testa estendendo le braccia, estendendo completamente i gomiti.","Fermati per un momento in alto, quindi abbassa lentamente il bilanciere nella posizione iniziale.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"1490","name":"standing calf raise (on a staircase)","category":"lower legs","equipment":"body weight","target":"calves","secondary":["ankles","feet"],"steps":{"en":["Stand on the edge of a step or a sturdy platform with your heels hanging off and your toes on the step.","Hold onto a railing or wall for balance if needed.","Slowly raise your heels as high as possible, lifting your body weight onto the balls of your feet.","Pause for a moment at the top, then slowly lower your heels back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Mettiti sul bordo di un gradino o su una piattaforma robusta con i talloni pendenti e le dita dei piedi sul gradino.","Se necessario, aggrapparsi a una ringhiera o a un muro per mantenere l'equilibrio.","Solleva lentamente i talloni il più in alto possibile, sollevando il peso del corpo sugli avampiedi.","Fai una pausa per un momento in alto, quindi abbassa lentamente i talloni nella posizione iniziale.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"1397","name":"standing calves","category":"lower legs","equipment":"body weight","target":"calves","secondary":["hamstrings","glutes"],"steps":{"en":["Stand with your feet shoulder-width apart, toes pointing forward.","Raise your heels off the ground as high as possible, standing on your toes.","Hold the position for a moment, then slowly lower your heels back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai con i piedi alla larghezza delle spalle, le dita dei piedi rivolte in avanti.","Solleva i talloni da terra il più in alto possibile, stando sulle punte dei piedi.","Mantieni la posizione per un momento, quindi abbassa lentamente i talloni fino alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"1398","name":"standing calves calf stretch","category":"lower legs","equipment":"body weight","target":"calves","secondary":["hamstrings","glutes"],"steps":{"en":["Stand facing a wall or sturdy object, about an arm's length away.","Place your hands on the wall or object at shoulder height.","Step back with one foot, keeping your heel flat on the ground.","Bend your front knee slightly and lean forward, keeping your back leg straight.","You should feel a stretch in your calf muscle.","Hold the stretch for 20-30 seconds.","Repeat on the other leg."],"it":["Mettiti di fronte a un muro o a un oggetto robusto, a circa un braccio di distanza.","Appoggia le mani sul muro o sull'oggetto all'altezza delle spalle.","Fai un passo indietro con un piede, mantenendo il tallone appoggiato a terra.","Piega leggermente il ginocchio anteriore e piegati in avanti, mantenendo la gamba posteriore dritta.","Dovresti sentire un allungamento nel muscolo del polpaccio.","Mantieni l'allungamento per 20-30 secondi.","Ripeti sull'altra gamba."]}},{"id":"0794","name":"standing lateral stretch","category":"back","equipment":"body weight","target":"lats","secondary":["shoulders","obliques"],"steps":{"en":["Stand with your feet shoulder-width apart and your knees slightly bent.","Extend your arms straight out to the sides, parallel to the ground.","Slowly lean your upper body to one side, feeling a stretch in your side and lats.","Hold the stretch for 15-30 seconds.","Return to the starting position and repeat on the other side.","Repeat for the desired number of repetitions."],"it":["Stai con i piedi alla larghezza delle spalle e le ginocchia leggermente piegate.","Estendi le braccia verso i lati, parallele al suolo.","Inclina lentamente la parte superiore del corpo da un lato, avvertendo un allungamento nei fianchi e nei dorsali.","Mantieni l'allungamento per 15-30 secondi.","Ritorna alla posizione di partenza e ripeti dall'altro lato.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"1364","name":"standing pelvic tilt","category":"back","equipment":"body weight","target":"spine","secondary":["abdominals"],"steps":{"en":["Stand with your feet shoulder-width apart and your knees slightly bent.","Place your hands on your hips or let them hang by your sides.","Engage your core muscles and tilt your pelvis forward, pushing your lower back towards the wall behind you.","Hold the position for a few seconds, then release and return to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai con i piedi alla larghezza delle spalle e le ginocchia leggermente piegate.","Metti le mani sui fianchi o lasciale pendere lungo i fianchi.","Coinvolgi i muscoli centrali e inclina il bacino in avanti, spingendo la parte bassa della schiena verso il muro dietro di te.","Mantieni la posizione per qualche secondo, poi rilascia e torna alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0795","name":"standing single leg curl","category":"upper legs","equipment":"body weight","target":"hamstrings","secondary":["glutes"],"steps":{"en":["Stand with your feet hip-width apart and your hands on your hips.","Shift your weight onto your left leg and lift your right foot off the ground, bending your knee.","Slowly curl your right heel towards your glutes, squeezing your hamstring.","Pause for a moment at the top, then slowly lower your right foot back down to the starting position.","Repeat for the desired number of repetitions, then switch legs."],"it":["Stai in piedi con i piedi alla larghezza dei fianchi e le mani sui fianchi.","Sposta il peso sulla gamba sinistra e solleva il piede destro da terra, piegando il ginocchio.","Piega lentamente il tallone destro verso i glutei, contraendo i tendini del ginocchio.","Fai una pausa per un momento in alto, quindi abbassa lentamente il piede destro fino alla posizione iniziale.","Ripeti per il numero di ripetizioni desiderato, quindi cambia gamba."]}},{"id":"3223","name":"star jump (male)","category":"cardio","equipment":"body weight","target":"cardiovascular system","secondary":["quadriceps","hamstrings","calves"],"steps":{"en":["Stand with your feet shoulder-width apart and your arms by your sides.","Bend your knees slightly and jump up explosively.","As you jump, spread your legs and extend your arms out to the sides, forming a star shape with your body.","Land softly on the balls of your feet with your knees slightly bent.","Repeat for the desired number of repetitions."],"it":["Stai con i piedi alla larghezza delle spalle e le braccia lungo i fianchi.","Piega leggermente le ginocchia e salta in modo esplosivo.","Mentre salti, allarga le gambe ed estendi le braccia ai lati, formando una forma a stella con il tuo corpo.","Atterra dolcemente sulle punte dei piedi con le ginocchia leggermente piegate.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"3314","name":"straddle maltese","category":"waist","equipment":"body weight","target":"abs","secondary":["shoulders","chest"],"steps":{"en":["Start by hanging from a pair of rings with your arms fully extended and your body in a straight line.","Spread your legs wide apart, forming a straddle position.","Engage your core and slowly lower your body until your arms are parallel to the ground.","Hold this position for a few seconds, then push yourself back up to the starting position.","Repeat for the desired number of repetitions."],"it":["Inizia appendendoti a un paio di anelli con le braccia completamente distese e il corpo in linea retta.","Allarga le gambe, formando una posizione a cavalcioni.","Coinvolgi il core e abbassa lentamente il corpo finché le braccia non sono parallele al suolo.","Mantieni questa posizione per alcuni secondi, quindi spingiti indietro fino alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"3298","name":"straddle planche","category":"waist","equipment":"body weight","target":"abs","secondary":["shoulders","triceps","chest"],"steps":{"en":["Start in a push-up position with your hands shoulder-width apart and your feet spread wide apart.","Engage your core and slowly shift your weight forward, bringing your shoulders over your hands.","Bend your elbows and lower your body towards the ground, keeping your elbows close to your sides.","Pause for a moment at the bottom, then push through your hands to straighten your arms and lift your body back up to the starting position.","Repeat for the desired number of repetitions."],"it":["Inizia in una posizione push-up con le mani alla larghezza delle spalle e i piedi ben divaricati.","Coinvolgi il tuo core e sposta lentamente il peso in avanti, portando le spalle sopra le mani.","Piega i gomiti e abbassa il corpo verso terra, mantenendo i gomiti vicini ai fianchi.","Fai una pausa per un momento in fondo, quindi spingi con le mani per raddrizzare le braccia e riportare il corpo alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"1427","name":"straight leg outer hip abductor","category":"upper legs","equipment":"body weight","target":"abductors","secondary":["glutes","hamstrings"],"steps":{"en":["Lie on your side with your legs straight and stacked on top of each other.","Place your bottom arm under your head for support.","Engage your core and lift your top leg as high as possible without rotating your hips or leaning backward.","Pause for a moment at the top, then slowly lower your leg back down to the starting position.","Repeat for the desired number of repetitions, then switch sides."],"it":["Sdraiati su un fianco con le gambe dritte e impilate una sopra l'altra.","Posiziona il braccio inferiore sotto la testa per supporto.","Coinvolgi il core e solleva la gamba superiore il più in alto possibile senza ruotare i fianchi o inclinarti all'indietro.","Fai una pausa per un momento in alto, quindi abbassa lentamente la gamba fino alla posizione iniziale.","Ripeti per il numero di ripetizioni desiderato, quindi cambia lato."]}},{"id":"0803","name":"superman push-up","category":"chest","equipment":"body weight","target":"pectorals","secondary":["core","shoulders"],"steps":{"en":["Start in a high plank position with your hands slightly wider than shoulder-width apart and your feet together.","Engage your core and lower your body towards the ground, keeping your elbows close to your sides.","As you lower your body, simultaneously lift your right arm and left leg off the ground, extending them straight out.","Pause for a moment at the top, then lower your arm and leg back down while pushing yourself back up to the starting position.","Repeat the movement, this time lifting your left arm and right leg.","Continue alternating sides for the desired number of repetitions."],"it":["Inizia in una posizione di plancia alta con le mani leggermente più larghe della larghezza delle spalle e i piedi uniti.","Coinvolgi il core e abbassa il corpo verso terra, mantenendo i gomiti vicini ai fianchi.","Mentre abbassi il corpo, solleva contemporaneamente il braccio destro e la gamba sinistra da terra, estendendoli verso l'esterno.","Fai una pausa per un momento in alto, quindi abbassa il braccio e la gamba mentre ti spingi indietro fino alla posizione di partenza.","Ripeti il ​​movimento, questa volta sollevando il braccio sinistro e la gamba destra.","Continua ad alternare i lati per il numero di ripetizioni desiderato."]}},{"id":"0805","name":"suspended abdominal fallout","category":"waist","equipment":"body weight","target":"abs","secondary":["obliques","hip flexors"],"steps":{"en":["Attach a suspension trainer to a high anchor point and adjust the straps to waist height.","Stand facing away from the anchor point and hold the handles with your arms extended in front of you.","Lean forward at the waist, keeping your body straight and your core engaged.","Lower your body as far as you can while maintaining control and tension in your abs.","Pause for a moment at the bottom, then slowly raise your body back up to the starting position.","Repeat for the desired number of repetitions."],"it":["Attacca un trainer in sospensione a un punto di ancoraggio alto e regola le cinghie all'altezza della vita.","Stai di fronte al punto di ancoraggio e tieni le maniglie con le braccia tese davanti a te.","Inclinati in avanti all'altezza della vita, mantenendo il corpo dritto e il core impegnato.","Abbassa il corpo il più possibile mantenendo il controllo e la tensione negli addominali.","Fai una pausa per un momento in basso, quindi solleva lentamente il corpo fino alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0806","name":"suspended push-up","category":"chest","equipment":"body weight","target":"pectorals","secondary":["triceps","shoulders","core"],"steps":{"en":["Find a suspension trainer and adjust it to an appropriate height.","Stand facing away from the anchor point and hold the handles with an overhand grip.","Walk your feet forward, leaning your body forward until your weight is supported by the suspension trainer.","Keep your body straight from head to heels, engage your core, and lower your chest towards the handles.","Push through your chest and arms to return to the starting position.","Repeat for the desired number of repetitions."],"it":["Trova un trainer per le sospensioni e regolalo a un'altezza adeguata.","Stare di fronte al punto di ancoraggio e tenere le maniglie con una presa prona.","Cammina con i piedi in avanti, inclinando il corpo in avanti finché il tuo peso non è supportato dal trainer per le sospensioni.","Mantieni il corpo dritto dalla testa ai talloni, contrai il core e abbassa il petto verso le maniglie.","Spingi attraverso il petto e le braccia per tornare alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0807","name":"suspended reverse crunch","category":"waist","equipment":"body weight","target":"abs","secondary":["hip flexors"],"steps":{"en":["Hang from a pull-up bar with your arms fully extended and your palms facing away from you.","Engage your core and lift your knees up towards your chest, curling your pelvis towards your ribcage.","Pause for a moment at the top, then slowly lower your knees back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Appendi a una barra per trazioni con le braccia completamente distese e i palmi rivolti lontano da te.","Coinvolgi il core e solleva le ginocchia verso il petto, arricciando il bacino verso la cassa toracica.","Fai una pausa per un momento in alto, quindi abbassa lentamente le ginocchia fino alla posizione iniziale.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0808","name":"suspended row","category":"back","equipment":"body weight","target":"upper back","secondary":["biceps","shoulders"],"steps":{"en":["Set up a suspension trainer at an appropriate height.","Stand facing the anchor point with your feet shoulder-width apart.","Hold the handles with an overhand grip, palms facing each other.","Lean back, keeping your body straight and your heels on the ground.","Pull your chest towards the handles, squeezing your shoulder blades together.","Pause for a moment at the top, then slowly lower yourself back to the starting position.","Repeat for the desired number of repetitions."],"it":["Installa un trainer per le sospensioni a un'altezza adeguata.","Stai di fronte al punto di ancoraggio con i piedi alla larghezza delle spalle.","Afferra le maniglie con una presa prona, con i palmi rivolti l'uno verso l'altro.","Appoggiati all'indietro, mantenendo il corpo dritto e i talloni a terra.","Tira il petto verso le maniglie, stringendo insieme le scapole.","Fermati per un momento in alto, quindi abbassati lentamente nella posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0809","name":"suspended split squat","category":"upper legs","equipment":"body weight","target":"quads","secondary":["glutes","hamstrings","calves"],"steps":{"en":["Stand facing away from a suspension trainer with your feet shoulder-width apart.","Extend one leg forward and place the top of your foot in the foot cradle of the suspension trainer.","Bend your standing leg and lower your body down into a lunge position, keeping your chest up and your knee in line with your toes.","Push through your heel to return to the starting position.","Repeat for the desired number of repetitions, then switch legs."],"it":["Stai di fronte a un trainer in sospensione con i piedi alla larghezza delle spalle.","Estendi una gamba in avanti e posiziona la parte superiore del piede nel supporto del trainer in sospensione.","Piega la gamba in piedi e abbassa il corpo in una posizione di affondo, mantenendo il petto sollevato e il ginocchio in linea con le dita dei piedi.","Spingi attraverso il tallone per tornare alla posizione di partenza.","Ripeti per il numero di ripetizioni desiderato, quindi cambia gamba."]}},{"id":"3433","name":"swimmer kicks v. 2 (male)","category":"upper legs","equipment":"body weight","target":"glutes","secondary":["hamstrings","quadriceps","calves"],"steps":{"en":["Lie face down on a mat with your arms extended overhead.","Engage your core and lift your chest and legs off the ground simultaneously.","Kick your legs up and down in a fluttering motion, as if you were swimming.","Continue kicking for the desired number of repetitions.","Lower your chest and legs back down to the starting position."],"it":["Sdraiati a faccia in giù su un tappetino con le braccia distese sopra la testa.","Coinvolgi il tuo core e solleva il petto e le gambe da terra contemporaneamente.","Calcia le gambe su e giù con un movimento svolazzante, come se stessi nuotando.","Continua a calciare per il numero di ripetizioni desiderato.","Abbassa il petto e le gambe fino alla posizione di partenza."]}},{"id":"3318","name":"swing 360","category":"cardio","equipment":"body weight","target":"cardiovascular system","secondary":["shoulders","core"],"steps":{"en":["Stand with your feet shoulder-width apart and knees slightly bent.","Hold your arms straight out in front of you, parallel to the ground.","Engage your core and swing your arms in a circular motion, rotating your torso as you do so.","Continue the circular motion, swinging your arms and rotating your torso for the desired number of repetitions.","Remember to breathe throughout the exercise."],"it":["Stai in piedi con i piedi alla larghezza delle spalle e le ginocchia leggermente piegate.","Tieni le braccia tese davanti a te, parallele al suolo.","Coinvolgi il tuo core e fai oscillare le braccia con un movimento circolare, ruotando il busto mentre lo fai.","Continua il movimento circolare, facendo oscillare le braccia e ruotando il busto per il numero di ripetizioni desiderato.","Ricordatevi di respirare durante l'esercizio."]}},{"id":"1753","name":"three bench dip","category":"upper arms","equipment":"body weight","target":"triceps","secondary":["chest","shoulders"],"steps":{"en":["Sit on a bench with your hands gripping the edge, fingers pointing forward.","Slide your butt off the bench, supporting your weight with your hands.","Bend your elbows and lower your body until your upper arms are parallel to the ground.","Push yourself back up to the starting position.","Repeat for the desired number of repetitions."],"it":["Sedersi su una panca con le mani che afferrano il bordo e le dita rivolte in avanti.","Fai scivolare il sedere fuori dalla panca, sostenendo il peso con le mani.","Piega i gomiti e abbassa il corpo finché la parte superiore delle braccia non è parallela al suolo.","Spingiti indietro fino alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0814","name":"triceps dip","category":"upper arms","equipment":"body weight","target":"triceps","secondary":["chest","shoulders"],"steps":{"en":["Sit on the edge of a bench or chair with your hands gripping the edge, fingers pointing forward.","Slide your butt off the bench, supporting your weight with your hands.","Bend your elbows and lower your body towards the ground, keeping your back close to the bench.","Pause for a moment at the bottom, then push yourself back up to the starting position.","Repeat for the desired number of repetitions."],"it":["Sedersi sul bordo di una panca o di una sedia con le mani che afferrano il bordo e le dita rivolte in avanti.","Fai scivolare il sedere fuori dalla panca, sostenendo il peso con le mani.","Piega i gomiti e abbassa il corpo verso terra, mantenendo la schiena aderente alla panca.","Fai una pausa per un momento in basso, quindi spingiti indietro fino alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0812","name":"triceps dip (bench leg)","category":"upper arms","equipment":"body weight","target":"triceps","secondary":["chest","shoulders"],"steps":{"en":["Sit on the edge of a bench with your hands gripping the edge, fingers pointing forward.","Walk your feet forward, sliding your butt off the bench, and straighten your arms.","Bend your elbows and lower your body towards the ground, keeping your back close to the bench.","Push through your palms to straighten your arms and return to the starting position.","Repeat for the desired number of repetitions."],"it":["Sedersi sul bordo di una panca con le mani che afferrano il bordo, le dita rivolte in avanti.","Cammina con i piedi in avanti, facendo scivolare il sedere fuori dalla panca e raddrizza le braccia.","Piega i gomiti e abbassa il corpo verso terra, mantenendo la schiena aderente alla panca.","Spingi attraverso i palmi delle mani per raddrizzare le braccia e tornare alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0813","name":"triceps dip (between benches)","category":"upper arms","equipment":"body weight","target":"triceps","secondary":["chest","shoulders"],"steps":{"en":["Sit on a bench with your hands gripping the edge of the bench, fingers pointing forward.","Slide your butt off the bench, supporting your weight with your hands.","Bend your elbows and lower your body towards the ground, keeping your back close to the bench.","Pause for a moment at the bottom, then push yourself back up to the starting position.","Repeat for the desired number of repetitions."],"it":["Sedersi su una panca con le mani afferrate al bordo della panca, con le dita rivolte in avanti.","Fai scivolare il sedere fuori dalla panca, sostenendo il peso con le mani.","Piega i gomiti e abbassa il corpo verso terra, mantenendo la schiena aderente alla panca.","Fai una pausa per un momento in basso, quindi spingiti indietro fino alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0815","name":"triceps dips floor","category":"upper arms","equipment":"body weight","target":"triceps","secondary":["chest","shoulders"],"steps":{"en":["Sit on the edge of a chair or bench with your hands next to your hips, fingers pointing forward.","Slide your butt off the front of the chair with your legs extended in front of you.","Straighten your arms, keeping a little bend in your elbows to keep tension on your triceps and off your elbow joints.","Slowly bend your elbows to lower your body toward the floor until your elbows are at about a 90-degree angle.","Once you reach the bottom of the movement, press down into the chair to straighten your elbows, returning to the starting position.","Repeat for the desired number of repetitions."],"it":["Siediti sul bordo di una sedia o di una panca con le mani vicino ai fianchi e le dita rivolte in avanti.","Fai scivolare il sedere dalla parte anteriore della sedia con le gambe distese davanti a te.","Raddrizza le braccia, piegando leggermente i gomiti per mantenere la tensione sui tricipiti e sulle articolazioni del gomito.","Piega lentamente i gomiti per abbassare il corpo verso il pavimento finché i gomiti non raggiungono un angolo di circa 90 gradi.","Una volta raggiunta la fine del movimento, spingi verso il basso sulla sedia per raddrizzare i gomiti, tornando alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0816","name":"triceps press","category":"upper arms","equipment":"body weight","target":"triceps","secondary":["shoulders"],"steps":{"en":["Stand with your feet shoulder-width apart and your knees slightly bent.","Extend your arms straight out in front of you, parallel to the ground.","Bend your elbows and lower your body towards the ground, keeping your upper arms close to your sides.","Pause for a moment at the bottom, then push yourself back up to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai con i piedi alla larghezza delle spalle e le ginocchia leggermente piegate.","Estendi le braccia davanti a te, parallele al suolo.","Piega i gomiti e abbassa il corpo verso terra, mantenendo la parte superiore delle braccia vicina ai fianchi.","Fai una pausa per un momento in basso, quindi spingiti indietro fino alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0817","name":"triceps stretch","category":"upper arms","equipment":"body weight","target":"triceps","secondary":["shoulders"],"steps":{"en":["Stand or sit upright with your back straight.","Extend one arm overhead, bending it at the elbow.","Place your opposite hand on the bent elbow and gently pull it towards your head.","Hold the stretch for 15-30 seconds, feeling a gentle stretch in your triceps.","Release the stretch and repeat on the other arm."],"it":["Stai in piedi o siediti con la schiena dritta.","Estendi un braccio sopra la testa, piegandolo all'altezza del gomito.","Metti la mano opposta sul gomito piegato e tirala delicatamente verso la testa.","Mantieni l'allungamento per 15-30 secondi, avvertendo un leggero allungamento nei tricipiti.","Rilascia l'allungamento e ripeti sull'altro braccio."]}},{"id":"0871","name":"tuck crunch","category":"waist","equipment":"body weight","target":"abs","secondary":["hip flexors"],"steps":{"en":["Lie flat on your back with your knees bent and feet flat on the ground.","Place your hands behind your head with your elbows pointing outwards.","Engaging your abs, lift your shoulder blades off the ground and bring your knees towards your chest, simultaneously curling your upper body towards your knees.","Pause for a moment at the top, then slowly lower your shoulder blades and extend your legs back to the starting position.","Repeat for the desired number of repetitions."],"it":["Sdraiati sulla schiena con le ginocchia piegate e i piedi appoggiati a terra.","Metti le mani dietro la testa con i gomiti rivolti verso l'esterno.","Coinvolgendo gli addominali, solleva le scapole da terra e porta le ginocchia verso il petto, piegando contemporaneamente la parte superiore del corpo verso le ginocchia.","Fai una pausa per un momento in alto, quindi abbassa lentamente le scapole ed estendi le gambe nella posizione iniziale.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"1466","name":"twist hip lift","category":"upper legs","equipment":"body weight","target":"glutes","secondary":["obliques","hamstrings"],"steps":{"en":["Lie on your back with your knees bent and feet flat on the ground.","Place your hands by your sides for support.","Engage your glutes and lift your hips off the ground, forming a straight line from your knees to your shoulders.","While keeping your hips lifted, twist your lower body to the right side, bringing your knees towards the ground.","Return to the starting position and repeat the twist to the left side.","Continue alternating twists for the desired number of repetitions."],"it":["Sdraiati sulla schiena con le ginocchia piegate e i piedi appoggiati a terra.","Metti le mani lungo i fianchi per supporto.","Coinvolgi i glutei e solleva i fianchi da terra, formando una linea retta dalle ginocchia alle spalle.","Tenendo i fianchi sollevati, ruota la parte inferiore del corpo verso il lato destro, portando le ginocchia verso terra.","Ritorna alla posizione iniziale e ripeti la rotazione sul lato sinistro.","Continua ad alternare le torsioni per il numero di ripetizioni desiderato."]}},{"id":"2802","name":"twisted leg raise","category":"waist","equipment":"body weight","target":"abs","secondary":["obliques","hip flexors"],"steps":{"en":["Lie flat on your back with your legs extended and your arms by your sides.","Place your hands under your glutes for support.","Engage your abs and lift both legs off the ground, keeping them straight.","As you lift your legs, twist your hips to one side, bringing your legs towards your opposite shoulder.","Pause for a moment at the top, then slowly lower your legs back down to the starting position.","Repeat the movement, this time twisting your hips to the other side.","Continue alternating sides for the desired number of repetitions."],"it":["Sdraiati sulla schiena con le gambe distese e le braccia lungo i fianchi.","Metti le mani sotto i glutei per supporto.","Coinvolgi gli addominali e solleva entrambe le gambe da terra, mantenendole dritte.","Mentre sollevi le gambe, ruota i fianchi da un lato, portando le gambe verso la spalla opposta.","Fai una pausa per un momento in alto, quindi abbassa lentamente le gambe fino alla posizione di partenza.","Ripeti il ​​movimento, questa volta ruotando i fianchi verso l'altro lato.","Continua ad alternare i lati per il numero di ripetizioni desiderato."]}},{"id":"2801","name":"twisted leg raise (female)","category":"waist","equipment":"body weight","target":"abs","secondary":["obliques","hip flexors"],"steps":{"en":["Lie flat on your back with your legs extended and your arms by your sides.","Bend your knees and lift your legs off the ground, bringing them towards your chest.","As you lift your legs, twist your hips to one side, bringing your knees towards your opposite shoulder.","Pause for a moment at the top, then slowly lower your legs back down to the starting position.","Repeat the movement, this time twisting your hips to the other side.","Continue alternating sides for the desired number of repetitions."],"it":["Sdraiati sulla schiena con le gambe distese e le braccia lungo i fianchi.","Piega le ginocchia e solleva le gambe da terra, portandole verso il petto.","Mentre sollevi le gambe, ruota i fianchi da un lato, portando le ginocchia verso la spalla opposta.","Fai una pausa per un momento in alto, quindi abbassa lentamente le gambe fino alla posizione di partenza.","Ripeti il ​​movimento, questa volta ruotando i fianchi verso l'altro lato.","Continua ad alternare i lati per il numero di ripetizioni desiderato."]}},{"id":"3231","name":"two toe touch (male)","category":"back","equipment":"body weight","target":"spine","secondary":["hamstrings","glutes"],"steps":{"en":["Stand with your feet shoulder-width apart and your arms extended out to the sides.","Bend forward at the waist, keeping your back straight and your knees slightly bent.","Reach down towards your toes with both hands, keeping your legs straight.","Pause for a moment at the bottom, then slowly return to the starting position.","Repeat for the desired number of repetitions."],"it":["Stai con i piedi alla larghezza delle spalle e le braccia distese ai lati.","Piegati in avanti all'altezza della vita, mantenendo la schiena dritta e le ginocchia leggermente piegate.","Raggiungi le punte dei piedi con entrambe le mani, mantenendo le gambe dritte.","Fermati per un momento in basso, quindi torna lentamente alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"1365","name":"upper back stretch","category":"back","equipment":"body weight","target":"upper back","secondary":["shoulders"],"steps":{"en":["Stand up straight with your feet shoulder-width apart.","Extend your arms straight in front of you, parallel to the ground.","Interlace your fingers and rotate your palms away from your body.","Slowly raise your arms overhead, keeping them straight and parallel to each other.","As you raise your arms, squeeze your shoulder blades together.","Hold the stretch for 15-30 seconds, then release and repeat."],"it":["Stai dritto con i piedi alla larghezza delle spalle.","Estendi le braccia davanti a te, parallele al suolo.","Intreccia le dita e ruota i palmi delle mani lontano dal corpo.","Alza lentamente le braccia sopra la testa, mantenendole dritte e parallele tra loro.","Mentre alzi le braccia, stringi insieme le scapole.","Mantieni l'allungamento per 15-30 secondi, quindi rilascia e ripeti."]}},{"id":"1366","name":"upward facing dog","category":"back","equipment":"body weight","target":"spine","secondary":["shoulders","chest"],"steps":{"en":["Lie face down on the floor with your legs extended behind you.","Place your hands on the floor next to your lower ribs, fingers pointing forward.","Press your hands firmly into the floor and straighten your arms, lifting your torso and thighs off the ground.","Roll your shoulders back and down, opening your chest and lifting your gaze towards the ceiling.","Hold this position for a few breaths, then slowly lower your body back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Sdraiati a faccia in giù sul pavimento con le gambe distese dietro di te.","Metti le mani sul pavimento vicino alle costole inferiori, con le dita rivolte in avanti.","Premi saldamente le mani sul pavimento e raddrizza le braccia, sollevando il busto e le cosce da terra.","Ruota le spalle indietro e in basso, aprendo il petto e sollevando lo sguardo verso il soffitto.","Mantieni questa posizione per alcuni respiri, quindi abbassa lentamente il corpo fino alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"3420","name":"v-sit on floor","category":"waist","equipment":"body weight","target":"abs","secondary":["hip flexors"],"steps":{"en":["Sit on the floor with your legs extended in front of you.","Lean back slightly and lift your legs off the ground, keeping them straight.","Simultaneously, lift your upper body off the ground and reach your arms towards your legs.","Hold this position for a few seconds, then slowly lower your upper body and legs back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Siediti sul pavimento con le gambe distese davanti a te.","Inclinati leggermente all'indietro e solleva le gambe da terra, mantenendole dritte.","Allo stesso tempo, solleva la parte superiore del corpo da terra e allunga le braccia verso le gambe.","Mantieni questa posizione per alcuni secondi, quindi abbassa lentamente la parte superiore del corpo e le gambe fino alla posizione iniziale.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0826","name":"vertical leg raise (on parallel bars)","category":"waist","equipment":"body weight","target":"abs","secondary":["hip flexors"],"steps":{"en":["Hang from the parallel bars with your arms fully extended and your body straight.","Engage your core and lift your legs up in front of you, keeping them straight.","Continue lifting until your legs are parallel to the ground or slightly higher.","Pause for a moment at the top, then slowly lower your legs back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Appendi alle parallele con le braccia completamente distese e il corpo dritto.","Coinvolgi il tuo core e solleva le gambe davanti a te, mantenendole dritte.","Continua a sollevare finché le gambe non sono parallele al suolo o leggermente più alte.","Fai una pausa per un momento in alto, quindi abbassa lentamente le gambe fino alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"3655","name":"walking high knees lunge","category":"cardio","equipment":"body weight","target":"cardiovascular system","secondary":["quadriceps","hamstrings","glutes","calves"],"steps":{"en":["Stand with your feet hip-width apart.","Lift your right knee up towards your chest as high as you can while balancing on your left leg.","Step forward with your right foot and lower your body into a lunge position, bending both knees to a 90-degree angle.","Push off with your right foot and bring your left knee up towards your chest.","Step forward with your left foot and lower your body into a lunge position.","Continue alternating legs and lunging forward, keeping your core engaged and maintaining a steady pace.","Repeat for the desired number of repetitions."],"it":["Stai con i piedi alla larghezza dei fianchi.","Solleva il ginocchio destro verso il petto il più in alto possibile mentre sei in equilibrio sulla gamba sinistra.","Fai un passo avanti con il piede destro e abbassa il corpo in una posizione di affondo, piegando entrambe le ginocchia con un angolo di 90 gradi.","Spingi con il piede destro e porta il ginocchio sinistro verso il petto.","Fai un passo avanti con il piede sinistro e abbassa il corpo in una posizione di affondo.","Continua ad alternare le gambe e ad affonderti in avanti, mantenendo il core impegnato e mantenendo un ritmo costante.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"1460","name":"walking lunge","category":"upper legs","equipment":"body weight","target":"glutes","secondary":["quadriceps","hamstrings","calves"],"steps":{"en":["Stand with your feet shoulder-width apart.","Take a step forward with your right leg, lowering your body into a lunge position.","Keep your torso upright and your front knee aligned with your ankle.","Push off with your right foot and bring your left foot forward, stepping into a lunge position with your left leg.","Continue alternating legs and walking forward, maintaining a controlled and steady pace.","Repeat for the desired number of repetitions."],"it":["Stai con i piedi alla larghezza delle spalle.","Fai un passo avanti con la gamba destra, abbassando il corpo in una posizione di affondo.","Mantieni il busto in posizione verticale e il ginocchio anteriore allineato con la caviglia.","Spingi con il piede destro e porta il piede sinistro in avanti, assumendo una posizione di affondo con la gamba sinistra.","Continua ad alternare le gambe e a camminare in avanti, mantenendo un ritmo controllato e costante.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"3637","name":"wheel run","category":"cardio","equipment":"body weight","target":"cardiovascular system","secondary":["quadriceps","hamstrings","calves"],"steps":{"en":["Start in a plank position with your hands on the wheel and your body straight.","Engage your core and start rolling the wheel forward by extending your arms.","Continue rolling until your body is fully extended and your arms are overhead.","Reverse the movement by pulling the wheel back towards your body, using your core and arms.","Repeat for the desired number of repetitions."],"it":["Inizia in una posizione di plancia con le mani sul volante e il corpo dritto.","Coinvolgi il tuo core e inizia a far rotolare la ruota in avanti estendendo le braccia.","Continua a rotolare finché il tuo corpo non è completamente esteso e le tue braccia sono sopra la testa.","Invertire il movimento tirando indietro la ruota verso il corpo, utilizzando il core e le braccia.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"1429","name":"wide grip pull-up","category":"back","equipment":"body weight","target":"lats","secondary":["biceps","forearms"],"steps":{"en":["Hang from a pull-up bar with your palms facing away from you and your hands wider than shoulder-width apart.","Engage your core and squeeze your shoulder blades together.","Pull your body up towards the bar until your chin is above the bar.","Lower your body back down to the starting position with control.","Repeat for the desired number of repetitions."],"it":["Appendi a una barra per trazioni con i palmi rivolti lontano da te e le mani più larghe della larghezza delle spalle.","Coinvolgi il tuo core e stringi insieme le scapole.","Tira il corpo verso la barra finché il mento non è sopra la barra.","Abbassa il corpo nella posizione iniziale mantenendo il controllo.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"1367","name":"wide grip rear pull-up","category":"back","equipment":"body weight","target":"lats","secondary":["biceps","forearms"],"steps":{"en":["Grab the pull-up bar with a wide overhand grip, hands slightly wider than shoulder-width apart.","Hang from the bar with your arms fully extended and your body straight.","Engage your back muscles and pull your body up towards the bar, leading with your chest.","Continue pulling until your chin is above the bar.","Pause for a moment at the top, then slowly lower your body back down to the starting position.","Repeat for the desired number of repetitions."],"it":["Afferra la barra per trazioni con un'ampia presa prona, con le mani leggermente più larghe della larghezza delle spalle.","Appendi alla barra con le braccia completamente distese e il corpo dritto.","Coinvolgi i muscoli della schiena e solleva il corpo verso la barra, guidando con il petto.","Continua a tirare finché il mento non è sopra la barra.","Fai una pausa per un momento in alto, quindi abbassa lentamente il corpo fino alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"1311","name":"wide hand push up","category":"chest","equipment":"body weight","target":"pectorals","secondary":["triceps","shoulders"],"steps":{"en":["Start in a high plank position with your hands wider than shoulder-width apart.","Keep your body in a straight line from head to toe.","Lower your chest towards the ground by bending your elbows, keeping them close to your sides.","Push through your palms to extend your arms and return to the starting position.","Repeat for the desired number of repetitions."],"it":["Inizia in una posizione di plancia alta con le mani più larghe della larghezza delle spalle.","Mantieni il corpo in linea retta dalla testa ai piedi.","Abbassa il petto verso terra piegando i gomiti, tenendoli vicini ai fianchi.","Spingi attraverso i palmi delle mani per estendere le braccia e tornare alla posizione di partenza.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"2363","name":"wide-grip chest dip on high parallel bars","category":"chest","equipment":"body weight","target":"pectorals","secondary":["triceps","shoulders"],"steps":{"en":["Position yourself on the parallel bars with your arms fully extended and your body suspended in the air.","Lean forward slightly and lower your body by bending your elbows until your chest is just above the bars.","Pause for a moment, then push yourself back up to the starting position by straightening your arms.","Repeat for the desired number of repetitions."],"it":["Posizionati sulle parallele con le braccia completamente distese e il corpo sospeso in aria.","Inclinati leggermente in avanti e abbassa il corpo piegando i gomiti finché il petto non si trova appena sopra le sbarre.","Fai una pausa per un momento, quindi ritorna alla posizione di partenza raddrizzando le braccia.","Ripetere per il numero di ripetizioni desiderato."]}},{"id":"0858","name":"wind sprints","category":"waist","equipment":"body weight","target":"abs","secondary":["quadriceps","hamstrings","calves"],"steps":{"en":["Find an open space or a track to perform the exercise.","Start by standing with your feet shoulder-width apart.","Begin running as fast as you can, pumping your arms and driving your knees up.","Continue sprinting for a specific distance or time period.","Rest and repeat for the desired number of repetitions."],"it":["Trova uno spazio aperto o una pista per eseguire l'esercizio.","Inizia stando in piedi con i piedi alla larghezza delle spalle.","Inizia a correre il più velocemente possibile, pompando le braccia e sollevando le ginocchia.","Continua a correre per una distanza o un periodo di tempo specifico.","Riposa e ripeti per il numero di ripetizioni desiderato."]}},{"id":"1604","name":"world greatest stretch","category":"upper legs","equipment":"body weight","target":"hamstrings","secondary":["glutes","quadriceps","calves"],"steps":{"en":["Start in a lunge position with your right foot forward and your left foot back.","Place your hands on the ground on either side of your right foot.","Lower your left knee to the ground and extend your right leg, keeping your right foot flat on the ground.","Rotate your torso to the right, reaching your right arm up towards the ceiling.","Hold this position for a few seconds, then return to the starting position.","Switch sides and repeat the stretch with your left foot forward."],"it":["Inizia in una posizione di affondo con il piede destro in avanti e il piede sinistro indietro.","Appoggia le mani a terra su entrambi i lati del piede destro.","Abbassa il ginocchio sinistro a terra ed estendi la gamba destra, mantenendo il piede destro appoggiato a terra.","Ruota il busto verso destra, allungando il braccio destro verso il soffitto.","Mantieni questa posizione per alcuni secondi, quindi torna alla posizione di partenza.","Cambia lato e ripeti l'allungamento con il piede sinistro in avanti."]}},{"id":"1428","name":"wrist circles","category":"lower arms","equipment":"body weight","target":"forearms","secondary":["hands","wrists"],"steps":{"en":["Extend your arms straight out in front of you.","Make a fist with both hands.","Rotate your wrists in a circular motion, keeping your arms still.","Continue the wrist circles for the desired number of repetitions."],"it":["Estendi le braccia davanti a te.","Chiudi il pugno con entrambe le mani.","Ruota i polsi con un movimento circolare, mantenendo le braccia ferme.","Continua i cerchi del polso per il numero di ripetizioni desiderato."]}},{"id":"cx-trx-row","name":"TRX row","name_it":"Rematore al TRX","category":"back","equipment":"trx","target":"upper back","secondary":["biceps","core"],"steps":{"en":["Grab the TRX handles, lean back with arms extended, body straight like a plank, heels grounded.","Pull your chest to the handles, driving your elbows back and squeezing your shoulder blades together.","Lower yourself back with control until your arms are fully extended.","Walk your feet forward (more horizontal body) to make it harder, backward to make it easier."],"it":["Afferra le maniglie del TRX, inclinati all'indietro con le braccia tese, corpo dritto come un plank, talloni a terra.","Tira il petto verso le maniglie portando i gomiti indietro e stringendo le scapole.","Torna giù in modo controllato fino a braccia completamente distese.","Avanza con i piedi (corpo più orizzontale) per aumentare la difficoltà, arretra per ridurla."]}},{"id":"cx-trx-chest-press","name":"TRX chest press","name_it":"Spinte al TRX","category":"chest","equipment":"trx","target":"pectorals","secondary":["triceps","core","delts"],"steps":{"en":["Face away from the anchor, handles at chest height, arms extended, body in a straight incline plank.","Bend your elbows and lower your chest between the handles, keeping your body rigid.","Press back up to full arm extension without letting your hips sag.","Step back (body more horizontal) to increase difficulty."],"it":["Dai le spalle all'ancoraggio, maniglie all'altezza del petto, braccia tese, corpo in plank inclinato.","Piega i gomiti e porta il petto tra le maniglie, mantenendo il corpo rigido.","Spingi fino a distendere completamente le braccia senza far cedere i fianchi.","Arretra con i piedi (corpo più orizzontale) per aumentare la difficoltà."]}},{"id":"cx-trx-squat","name":"TRX squat","name_it":"Squat al TRX","category":"upper legs","equipment":"trx","target":"quads","secondary":["glutes","hamstrings"],"steps":{"en":["Hold the handles with light tension, feet shoulder-width apart.","Sit your hips back and down into a deep squat, keeping your chest up.","Use the straps only as light balance support, not to pull yourself up.","Drive through your heels to stand back up."],"it":["Tieni le maniglie con leggera tensione, piedi alla larghezza delle spalle.","Porta i fianchi indietro e in basso in uno squat profondo, petto alto.","Usa le cinghie solo come leggero supporto per l'equilibrio, non per tirarti su.","Spingi sui talloni per tornare in piedi."]}},{"id":"cx-trx-single-leg-squat","name":"TRX single-leg squat","name_it":"Squat monopodalico al TRX","category":"upper legs","equipment":"trx","target":"quads","secondary":["glutes","core"],"steps":{"en":["Hold the handles, lift one foot off the floor in front of you.","Squat down on the standing leg as deep as you can, using the straps for balance.","Drive through the heel to stand up. Complete all reps, then switch legs."],"it":["Tieni le maniglie e solleva un piede da terra davanti a te.","Scendi in squat sulla gamba d'appoggio più in basso che puoi, usando le cinghie per l'equilibrio.","Spingi sul tallone per risalire. Completa le ripetizioni, poi cambia gamba."]}},{"id":"cx-trx-y-fly","name":"TRX Y fly","name_it":"Alzate a Y al TRX","category":"shoulders","equipment":"trx","target":"delts","secondary":["upper back","traps"],"steps":{"en":["Lean back holding the handles, arms extended in front of your chest, body straight.","Raise your arms up and out into a Y shape while your body comes upright, keeping arms straight.","Lower back with control. Keep your core braced throughout."],"it":["Inclinati indietro tenendo le maniglie, braccia tese davanti al petto, corpo dritto.","Alza le braccia in alto e in fuori formando una Y mentre il corpo torna verticale, braccia sempre tese.","Torna indietro in modo controllato. Core sempre contratto."]}},{"id":"cx-trx-biceps-curl","name":"TRX biceps curl","name_it":"Curl bicipiti al TRX","category":"upper arms","equipment":"trx","target":"biceps","secondary":["forearms"],"steps":{"en":["Lean back with arms extended, palms facing up, body straight.","Curl your hands toward your forehead by bending only your elbows, keeping upper arms still.","Lower back slowly to full extension."],"it":["Inclinati indietro con le braccia tese, palmi verso l'alto, corpo dritto.","Porta le mani verso la fronte piegando solo i gomiti, braccia superiori ferme.","Torna lentamente alla posizione di partenza a braccia tese."]}},{"id":"cx-trx-triceps-extension","name":"TRX triceps extension","name_it":"Estensioni tricipiti al TRX","category":"upper arms","equipment":"trx","target":"triceps","secondary":["core"],"steps":{"en":["Face away from the anchor, arms extended overhead-forward, body leaning into the straps.","Bend your elbows and let your head move between your hands, keeping elbows pointing forward.","Extend your arms back to straight, pressing your body up."],"it":["Dai le spalle all'ancoraggio, braccia tese in avanti-alto, corpo inclinato sulle cinghie.","Piega i gomiti lasciando passare la testa tra le mani, gomiti sempre in avanti.","Distendi le braccia spingendo il corpo verso l'alto."]}},{"id":"cx-trx-pike","name":"TRX pike","name_it":"Pike al TRX","category":"waist","equipment":"trx","target":"abs","secondary":["delts","hip flexors"],"steps":{"en":["Put your feet in the straps and get into a push-up position, hands under shoulders.","Keeping legs straight, lift your hips up toward the ceiling into an inverted V.","Lower back to plank with control. Don't let your hips sag between reps."],"it":["Infila i piedi nelle cinghie e mettiti in posizione di push-up, mani sotto le spalle.","A gambe tese, solleva i fianchi verso il soffitto formando una V rovesciata.","Torna in plank in modo controllato. Non far cedere i fianchi tra le ripetizioni."]}},{"id":"cx-trx-face-pull","name":"TRX face pull","name_it":"Face pull al TRX","category":"shoulders","equipment":"trx","target":"delts","secondary":["upper back","traps"],"steps":{"en":["Lean back holding the handles, arms extended, palms down.","Pull the handles toward the sides of your face, elbows high and wide.","Squeeze your shoulder blades, then return with control. Great for posture and MTB shoulders."],"it":["Inclinati indietro tenendo le maniglie, braccia tese, palmi in giù.","Tira le maniglie ai lati del viso, gomiti alti e larghi.","Stringi le scapole, poi torna in modo controllato. Ottimo per la postura e le spalle da MTB."]}},{"id":"cx-trx-hamstring-curl","name":"TRX hamstring curl","name_it":"Leg curl al TRX","category":"upper legs","equipment":"trx","target":"hamstrings","secondary":["glutes","core"],"steps":{"en":["Lie on your back, heels in the straps, arms on the floor.","Lift your hips into a bridge, then pull your heels toward your glutes.","Extend your legs back out without dropping your hips."],"it":["Sdraiati sulla schiena, talloni nelle cinghie, braccia a terra.","Solleva i fianchi in ponte, poi tira i talloni verso i glutei.","Distendi le gambe senza far scendere i fianchi."]}},{"id":"cx-air-squat","name":"Air squat","name_it":"Squat a corpo libero","category":"upper legs","equipment":"body weight","target":"quads","secondary":["glutes","hamstrings"],"steps":{"en":["Stand with feet shoulder-width apart, toes slightly out.","Sit your hips back and down until your thighs are at least parallel to the floor, chest up.","Drive through your heels to stand back up, squeezing your glutes at the top."],"it":["In piedi, piedi alla larghezza delle spalle, punte leggermente in fuori.","Porta i fianchi indietro e in basso finché le cosce sono almeno parallele al pavimento, petto alto.","Spingi sui talloni per risalire, contraendo i glutei in alto."]}},{"id":"cx-plank","name":"Plank","name_it":"Plank sui gomiti","category":"waist","equipment":"body weight","target":"abs","secondary":["glutes","lower back"],"steps":{"en":["Forearms on the floor, elbows under shoulders, legs extended behind you.","Form a straight line from head to heels; brace your abs and squeeze your glutes.","Hold for the target time. Don't let your hips sag or pike up."],"it":["Avambracci a terra, gomiti sotto le spalle, gambe distese dietro.","Forma una linea retta dalla testa ai talloni; contrai addome e glutei.","Mantieni per il tempo previsto. Non far cedere né alzare i fianchi."]}},{"id":"cx-side-plank","name":"Side plank","name_it":"Plank laterale","category":"waist","equipment":"body weight","target":"obliques","secondary":["glutes","shoulders"],"steps":{"en":["Lie on your side, forearm on the floor, elbow under your shoulder, feet stacked.","Lift your hips to form a straight line from head to feet.","Hold for the target time, then switch sides."],"it":["Sdraiati su un fianco, avambraccio a terra, gomito sotto la spalla, piedi uno sull'altro.","Solleva i fianchi formando una linea retta dalla testa ai piedi.","Mantieni per il tempo previsto, poi cambia lato."]}},{"id":"cx-superman","name":"Superman","name_it":"Superman","category":"back","equipment":"body weight","target":"spine","secondary":["glutes","hamstrings"],"steps":{"en":["Lie face down, arms extended in front of you.","Lift your arms, chest and legs off the floor at the same time, squeezing your lower back and glutes.","Hold one second at the top, then lower with control."],"it":["Sdraiati a pancia in giù, braccia distese in avanti.","Solleva contemporaneamente braccia, petto e gambe da terra, contraendo lombari e glutei.","Tieni un secondo in alto, poi scendi in modo controllato."]}},{"id":"cx-jumping-jacks","name":"Jumping jacks","name_it":"Jumping jacks","category":"cardio","equipment":"body weight","target":"cardiovascular system","secondary":["calves","delts"],"steps":{"en":["Stand with feet together, arms at your sides.","Jump your feet out wide while swinging your arms overhead.","Jump back to the start. Keep a steady rhythm for the target time."],"it":["In piedi, piedi uniti, braccia lungo i fianchi.","Salta divaricando le gambe e portando le braccia sopra la testa.","Torna alla posizione di partenza con un altro salto. Ritmo costante per il tempo previsto."]}},{"id":"cx-high-knees","name":"High knees","name_it":"Corsa ginocchia alte","category":"cardio","equipment":"body weight","target":"cardiovascular system","secondary":["quads","calves"],"steps":{"en":["Run in place, driving your knees up to hip height.","Stay on the balls of your feet and pump your arms.","Keep the pace high for the target time."],"it":["Corri sul posto portando le ginocchia all'altezza dei fianchi.","Resta sull'avampiede e muovi le braccia a ritmo.","Mantieni un ritmo alto per il tempo previsto."]}},{"id":"cx-march","name":"March in place","name_it":"Marcia sul posto","category":"cardio","equipment":"body weight","target":"cardiovascular system","secondary":["hip flexors"],"steps":{"en":["March in place lifting your knees comfortably, swinging your arms.","Gradually increase the pace to warm up your whole body."],"it":["Marcia sul posto sollevando le ginocchia, muovendo le braccia.","Aumenta gradualmente il ritmo per riscaldare tutto il corpo."]}},{"id":"cx-arm-circles","name":"Arm circles","name_it":"Cerchi con le braccia","category":"shoulders","equipment":"body weight","target":"delts","secondary":["traps"],"steps":{"en":["Extend your arms out to the sides at shoulder height.","Make small circles forward, gradually increasing their size.","Halfway through the time, reverse direction."],"it":["Distendi le braccia lateralmente all'altezza delle spalle.","Disegna piccoli cerchi in avanti, aumentandone gradualmente l'ampiezza.","A metà tempo, inverti la direzione."]}},{"id":"cx-ball-leg-curl","name":"Swiss ball leg curl","name_it":"Leg curl con fitball","category":"upper legs","equipment":"stability ball","target":"hamstrings","secondary":["glutes","core"],"steps":{"en":["Lie on your back with your heels on top of the ball, arms on the floor.","Lift your hips into a bridge position.","Pull the ball toward your glutes by bending your knees, then roll it back out without dropping your hips."],"it":["Sdraiati sulla schiena con i talloni sulla palla, braccia a terra.","Solleva i fianchi in posizione di ponte.","Tira la palla verso i glutei piegando le ginocchia, poi falla rotolare indietro senza abbassare i fianchi."]}}];
